'use client';
import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import {
    Brain, Zap, DollarSign, Clock, TrendingUp, RefreshCw,
    AlertTriangle, CheckCircle2, BarChart3, Activity, Cpu, Trash2,
} from 'lucide-react';

// ── 색상 시스템 ────────────────────────────────────────────
const T = {
    heading: '#0f172a', body: '#1e293b', sub: '#475569',
    muted: '#64748b', faint: '#94a3b8',
    border: '#d1d5db', borderSub: '#e5e7eb',
    bg: '#f8f9fc', card: '#ffffff',
};

interface UsageSummary {
    totalCalls: number;
    successCalls: number;
    failedCalls: number;
    totalTokensIn: number;
    totalTokensOut: number;
    totalCostUSD: number;
    avgDurationMs: number;
    byEndpoint: Record<string, { calls: number; tokens: number; cost: number }>;
    byProvider: Record<string, { calls: number; tokens: number; cost: number }>;
    recentCalls: Array<{
        endpoint: string; provider: string; model: string;
        tokensIn: number; tokensOut: number; costUSD: number;
        durationMs: number; success: boolean; timestamp: string;
    }>;
}

interface Briefing {
    highlights: string[];
    actionItems: string[];
    summary: string;
}

// ── 통계 카드 ──────────────────────────────────────────────
function StatCard({ icon: Icon, label, value, sub, color }: {
    icon: React.ElementType; label: string; value: string | number; sub?: string; color: string;
}) {
    return (
        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
            className="p-5 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
            <div className="flex items-center gap-2 mb-2">
                <div className="w-8 h-8 rounded-lg flex items-center justify-center" style={{ background: `${color}15` }}>
                    <Icon className="w-4 h-4" style={{ color }} />
                </div>
                <span className="text-xs font-bold" style={{ color: T.muted }}>{label}</span>
            </div>
            <div className="text-2xl font-black" style={{ color: T.heading }}>{value}</div>
            {sub && <p className="text-xs mt-1" style={{ color: T.faint }}>{sub}</p>}
        </motion.div>
    );
}

export default function AIDashboardPage() {
    const [usage, setUsage] = useState<UsageSummary | null>(null);
    const [briefing, setBriefing] = useState<Briefing | null>(null);
    const [loading, setLoading] = useState(true);
    const [briefLoading, setBriefLoading] = useState(false);

    const fetchUsage = useCallback(async () => {
        try {
            const res = await fetch('/api/ai-usage');
            if (res.ok) setUsage(await res.json());
        } catch { /* silent */ }
    }, []);

    const fetchBriefing = useCallback(async () => {
        setBriefLoading(true);
        try {
            const res = await fetch('/api/ai-brief');
            if (res.ok) setBriefing(await res.json());
        } catch { /* silent */ }
        setBriefLoading(false);
    }, []);

    useEffect(() => {
        const init = async () => {
            await Promise.all([fetchUsage(), fetchBriefing()]);
            setLoading(false);
        };
        init();
    }, [fetchUsage, fetchBriefing]);

    const handleReset = async () => {
        if (!confirm('AI 사용량 로그를 초기화하시겠습니까?')) return;
        await fetch('/api/ai-usage', { method: 'DELETE' });
        fetchUsage();
    };

    const successRate = usage ? (usage.totalCalls > 0 ? Math.round((usage.successCalls / usage.totalCalls) * 100) : 100) : 0;

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center" style={{ background: T.bg }}>
                <RefreshCw className="w-6 h-6 animate-spin" style={{ color: T.muted }} />
            </div>
        );
    }

    return (
        <div className="min-h-screen py-8 px-4" style={{ background: T.bg }}>
            <div className="max-w-6xl mx-auto">

                {/* 헤더 */}
                <div className="flex items-center justify-between mb-6">
                    <div>
                        <h1 className="text-2xl font-black flex items-center gap-2" style={{ color: T.heading }}>
                            <Brain className="w-6 h-6" style={{ color: '#8b5cf6' }} />
                            AI 현황 대시보드
                        </h1>
                        <p className="text-sm mt-1" style={{ color: T.muted }}>AI 사용량, 비용, 브리핑을 한 눈에 확인합니다</p>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => { fetchUsage(); fetchBriefing(); }}
                            className="flex items-center gap-1.5 text-xs font-bold px-3 py-2 rounded-lg transition-colors"
                            style={{ background: T.card, border: `1px solid ${T.border}`, color: T.body }}>
                            <RefreshCw className="w-3.5 h-3.5" /> 새로고침
                        </button>
                        <button onClick={handleReset}
                            className="flex items-center gap-1.5 text-xs font-bold px-3 py-2 rounded-lg transition-colors"
                            style={{ background: '#fef2f2', color: '#ef4444', border: '1px solid #fecaca' }}>
                            <Trash2 className="w-3.5 h-3.5" /> 초기화
                        </button>
                    </div>
                </div>

                {/* 통계 카드 그리드 */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                    <StatCard icon={Zap} label="총 API 호출" value={usage?.totalCalls ?? 0} sub={`성공 ${usage?.successCalls ?? 0} / 실패 ${usage?.failedCalls ?? 0}`} color="#6366f1" />
                    <StatCard icon={DollarSign} label="총 비용 (USD)" value={`$${(usage?.totalCostUSD ?? 0).toFixed(4)}`} sub="예상 비용" color="#10b981" />
                    <StatCard icon={BarChart3} label="총 토큰" value={((usage?.totalTokensIn ?? 0) + (usage?.totalTokensOut ?? 0)).toLocaleString()} sub={`입력 ${(usage?.totalTokensIn ?? 0).toLocaleString()} / 출력 ${(usage?.totalTokensOut ?? 0).toLocaleString()}`} color="#f59e0b" />
                    <StatCard icon={Clock} label="평균 응답 시간" value={`${((usage?.avgDurationMs ?? 0) / 1000).toFixed(1)}s`} sub={`성공률 ${successRate}%`} color="#8b5cf6" />
                </div>

                <div className="grid md:grid-cols-3 gap-6">

                    {/* AI 브리핑 (2/3) */}
                    <div className="md:col-span-2 space-y-4">
                        <div className="p-6 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                            <div className="flex items-center justify-between mb-4">
                                <h2 className="font-black text-base flex items-center gap-2" style={{ color: T.heading }}>
                                    <Activity className="w-4 h-4" style={{ color: '#f59e0b' }} />
                                    오늘의 AI 브리핑
                                </h2>
                                <button onClick={fetchBriefing} disabled={briefLoading}
                                    className="text-xs font-bold px-3 py-1.5 rounded-lg"
                                    style={{ background: '#fef3c7', color: '#d97706', border: '1px solid #fde68a' }}>
                                    {briefLoading ? '생성 중...' : '다시 생성'}
                                </button>
                            </div>

                            {briefing ? (
                                <>
                                    {briefing.summary && (
                                        <p className="text-sm mb-4 leading-relaxed" style={{ color: T.body }}>{briefing.summary}</p>
                                    )}
                                    <div className="grid md:grid-cols-2 gap-4">
                                        <div>
                                            <h3 className="text-xs font-black mb-2 flex items-center gap-1" style={{ color: T.muted }}>
                                                <TrendingUp className="w-3.5 h-3.5" /> 주요 하이라이트
                                            </h3>
                                            <div className="space-y-2">
                                                {briefing.highlights.map((h, i) => (
                                                    <div key={i} className="flex items-start gap-2 text-sm" style={{ color: T.body }}>
                                                        <CheckCircle2 className="w-3.5 h-3.5 mt-0.5 flex-shrink-0" style={{ color: '#4ade80' }} />
                                                        <span>{h}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                        <div>
                                            <h3 className="text-xs font-black mb-2 flex items-center gap-1" style={{ color: T.muted }}>
                                                <AlertTriangle className="w-3.5 h-3.5" /> 액션 아이템
                                            </h3>
                                            <div className="space-y-2">
                                                {briefing.actionItems.map((a, i) => (
                                                    <div key={i} className="flex items-start gap-2 text-sm" style={{ color: T.body }}>
                                                        <Zap className="w-3.5 h-3.5 mt-0.5 flex-shrink-0" style={{ color: '#f59e0b' }} />
                                                        <span>{a}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                </>
                            ) : (
                                <p className="text-sm" style={{ color: T.faint }}>브리핑을 생성하려면 &quot;다시 생성&quot; 버튼을 클릭하세요.</p>
                            )}
                        </div>

                        {/* 최근 호출 기록 */}
                        <div className="p-6 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                            <h2 className="font-black text-base mb-4 flex items-center gap-2" style={{ color: T.heading }}>
                                <Cpu className="w-4 h-4" style={{ color: '#6366f1' }} />
                                최근 API 호출 기록
                            </h2>
                            <div className="overflow-x-auto">
                                <table className="w-full text-xs">
                                    <thead>
                                        <tr style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                            {['엔드포인트', 'Provider', '토큰(IN/OUT)', '비용', '시간', '상태'].map(h => (
                                                <th key={h} className="py-2 px-2 text-left font-bold" style={{ color: T.muted }}>{h}</th>
                                            ))}
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {(usage?.recentCalls ?? []).slice(0, 10).map((c, i) => (
                                            <tr key={i} style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                                <td className="py-2 px-2 font-bold" style={{ color: T.body }}>{c.endpoint}</td>
                                                <td className="py-2 px-2" style={{ color: T.sub }}>
                                                    <span className="px-1.5 py-0.5 rounded text-[10px] font-bold"
                                                        style={{
                                                            background: c.provider === 'claude' ? '#fef3c7' : c.provider === 'openai' ? '#d1fae5' : '#dbeafe',
                                                            color: c.provider === 'claude' ? '#92400e' : c.provider === 'openai' ? '#065f46' : '#1e40af',
                                                        }}>
                                                        {c.provider}
                                                    </span>
                                                </td>
                                                <td className="py-2 px-2" style={{ color: T.sub }}>{c.tokensIn}/{c.tokensOut}</td>
                                                <td className="py-2 px-2" style={{ color: T.sub }}>${c.costUSD.toFixed(4)}</td>
                                                <td className="py-2 px-2" style={{ color: T.sub }}>{(c.durationMs / 1000).toFixed(1)}s</td>
                                                <td className="py-2 px-2">
                                                    {c.success
                                                        ? <CheckCircle2 className="w-3.5 h-3.5" style={{ color: '#4ade80' }} />
                                                        : <AlertTriangle className="w-3.5 h-3.5" style={{ color: '#f87171' }} />
                                                    }
                                                </td>
                                            </tr>
                                        ))}
                                        {(usage?.recentCalls ?? []).length === 0 && (
                                            <tr><td colSpan={6} className="py-8 text-center" style={{ color: T.faint }}>아직 호출 기록이 없습니다</td></tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>

                    {/* 사이드바 (1/3) */}
                    <div className="space-y-4">
                        {/* Provider별 사용량 */}
                        <div className="p-5 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                            <h3 className="font-black text-sm mb-3" style={{ color: T.heading }}>Provider별 사용량</h3>
                            {Object.entries(usage?.byProvider ?? {}).map(([prov, data]) => (
                                <div key={prov} className="mb-3 pb-3" style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                    <div className="flex items-center justify-between mb-1">
                                        <span className="text-xs font-bold" style={{ color: T.body }}>{prov}</span>
                                        <span className="text-xs" style={{ color: T.muted }}>{data.calls}회</span>
                                    </div>
                                    <div className="w-full h-1.5 rounded-full" style={{ background: T.borderSub }}>
                                        <div className="h-full rounded-full" style={{
                                            width: `${usage ? Math.min(100, (data.calls / Math.max(1, usage.totalCalls)) * 100) : 0}%`,
                                            background: prov === 'claude' ? '#c9a84c' : prov === 'openai' ? '#10a37f' : '#4285f4',
                                        }} />
                                    </div>
                                    <p className="text-[10px] mt-1" style={{ color: T.faint }}>${data.cost.toFixed(4)} · {data.tokens.toLocaleString()} tokens</p>
                                </div>
                            ))}
                            {Object.keys(usage?.byProvider ?? {}).length === 0 && (
                                <p className="text-xs" style={{ color: T.faint }}>데이터 없음</p>
                            )}
                        </div>

                        {/* Endpoint별 사용량 */}
                        <div className="p-5 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                            <h3 className="font-black text-sm mb-3" style={{ color: T.heading }}>Endpoint별 호출</h3>
                            {Object.entries(usage?.byEndpoint ?? {}).sort(([, a], [, b]) => b.calls - a.calls).map(([ep, data]) => (
                                <div key={ep} className="flex items-center justify-between py-1.5" style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                    <span className="text-xs font-medium truncate max-w-[120px]" style={{ color: T.body }}>{ep}</span>
                                    <div className="flex items-center gap-2">
                                        <span className="text-xs font-bold" style={{ color: '#6366f1' }}>{data.calls}</span>
                                        <span className="text-[10px]" style={{ color: T.faint }}>${data.cost.toFixed(4)}</span>
                                    </div>
                                </div>
                            ))}
                            {Object.keys(usage?.byEndpoint ?? {}).length === 0 && (
                                <p className="text-xs" style={{ color: T.faint }}>데이터 없음</p>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Eye, Send, Edit3, RefreshCw, CheckCircle2, Mail, Smartphone, Monitor, User } from 'lucide-react';
import Link from 'next/link';
import { leadStore, calcSubscription } from '@/lib/leadStore';
import { fillTemplate, DRIP_SEQUENCE } from '@/lib/dripStore';

// ── 이메일 미리보기 + 개인화 편집 + 확정 발송 UI ─────────────

const BASE_SUBJECT = '[IBS 법률] {company}님의 개인정보처리방침 — AI 리스크 분석 결과';
const BASE_PREHEADER = '개인정보보호법 위반 {issueCount}건 발견. 지금 확인하세요.';

function buildHookEmailHtml(vars: Record<string, string>, customMsg: string): string {
    return `<!DOCTYPE html>
<html>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:'Apple SD Gothic Neo',Pretendard,sans-serif">
<div style="max-width:600px;margin:0 auto;background:#f1f5f9;padding:24px 0">

  <!-- 헤더 -->
  <div style="background:#04091a;border-radius:16px 16px 0 0;padding:28px 32px;text-align:center">
    <p style="color:#c9a84c;font-size:24px;font-weight:900;margin:0">⚖️ IBS 법률사무소</p>
    <p style="color:#94a3b8;font-size:13px;margin:6px 0 0">프랜차이즈 전문 법률 서비스 · 45,000개사 자문 실적</p>
  </div>

  <!-- 리스크 배너 -->
  <div style="background:#fef2f2;border-left:4px solid #f87171;padding:20px 32px;margin:0">
    <p style="color:#dc2626;font-size:15px;font-weight:900;margin:0 0 6px">🔴 ${vars.riskLevel} 리스크 — ${vars.issueCount}건 위반 가능성 발견</p>
    <p style="color:#374151;font-size:13px;margin:0">과징금 최대 <strong>3,000만원</strong> 부과 가능 항목이 포함되어 있습니다.</p>
  </div>

  <!-- 본문 -->
  <div style="background:#fff;padding:28px 32px">
    <p style="color:#1e293b;font-size:15px;margin:0 0 16px">${vars.contactName} 담당자님께,</p>
    <p style="color:#374151;line-height:1.7;margin:0 0 20px">
      안녕하세요. IBS 법률사무소입니다.<br/>
      <strong>${vars.company}</strong>의 개인정보처리방침을 AI로 분석한 결과를 전달드립니다.
    </p>

    ${customMsg ? `<div style="background:#fef9ec;border-left:4px solid #c9a84c;padding:16px;margin-bottom:20px;border-radius:0 8px 8px 0">
      <p style="color:#92400e;font-size:13px;font-weight:bold;margin:0 0 4px">변호사 메모</p>
      <p style="color:#374151;font-size:13px;margin:0;line-height:1.6">${customMsg}</p>
    </div>` : ''}

    <!-- 분석 결과 테이블 -->
    <table style="width:100%;border-collapse:collapse;margin:0 0 24px">
      <thead>
        <tr style="background:#f8fafc">
          <th style="padding:10px 12px;text-align:left;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">항목</th>
          <th style="padding:10px 12px;text-align:center;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">리스크</th>
          <th style="padding:10px 12px;text-align:left;color:#64748b;font-size:12px;border-bottom:2px solid #e2e8f0">근거</th>
        </tr>
      </thead>
      <tbody>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b;border-bottom:1px solid #f1f5f9">수집항목 과다수집</td><td style="padding:10px;text-align:center"><span style="background:#fef2f2;color:#dc2626;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">고위험</span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">개보법 §16</td></tr>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b;border-bottom:1px solid #f1f5f9">제3자 제공 미명시</td><td style="padding:10px;text-align:center"><span style="background:#fef2f2;color:#dc2626;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">고위험</span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">개보법 §17</td></tr>
        <tr><td style="padding:10px 12px;font-size:13px;color:#1e293b">보유기간 일부 누락</td><td style="padding:10px;text-align:center"><span style="background:#fffbeb;color:#d97706;font-size:11px;font-weight:bold;padding:2px 8px;border-radius:20px">주의</span></td><td style="padding:10px 12px;font-size:12px;color:#64748b">개보법 §21</td></tr>
      </tbody>
    </table>

    <!-- CTA -->
    <div style="text-align:center;padding:20px 0 8px">
      <a href="http://localhost:3000/landing?cid=${vars.leadId}" style="background:linear-gradient(135deg,#c9a84c,#e8c87a);color:#0a0e1a;text-decoration:none;padding:16px 36px;border-radius:10px;font-weight:900;font-size:15px;display:inline-block">
        무료 분석 결과 전체 보기 →
      </a>
    </div>
    <p style="text-align:center;color:#94a3b8;font-size:12px;margin:12px 0 0">버튼 클릭 시 사업자번호로 로그인하여 전체 결과를 확인하실 수 있습니다</p>
  </div>

  <!-- 실적 배너 -->
  <div style="background:#0f172a;padding:20px 32px;display:flex;justify-content:space-around;text-align:center">
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">1,000억+</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">자문 기업 엑시트</p></div>
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">80,000+</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">법률 자문 건수</p></div>
    <div><p style="color:#c9a84c;font-size:20px;font-weight:900;margin:0">45,000+</p><p style="color:#64748b;font-size:11px;margin:4px 0 0">회원사</p></div>
  </div>

  <!-- 풋터 -->
  <div style="background:#04091a;border-radius:0 0 16px 16px;padding:16px 32px;text-align:center">
    <p style="color:#475569;font-size:11px;margin:0">IBS 법률사무소 | 대표번호 02-1234-5678 | <a href="#" style="color:#475569">수신거부</a></p>
  </div>
</div>
</body>
</html>`;
}

export default function EmailPreviewPage({
    searchParams,
}: { searchParams: Promise<{ leadId?: string; embed?: string }> }) {
    const params = React.use(searchParams);
    const leadId = params.leadId || 'lead_001';
    const isEmbed = params.embed === 'true';
    const lead = leadStore.getById(leadId);
    const sub = calcSubscription(lead?.storeCount || 0);

    const vars: Record<string, string> = {
        company: lead?.companyName || '(주)샘플회사',
        contactName: lead?.contactName || '담당자',
        leadId,
        issueCount: String(lead?.issueCount || 0),
        riskLevel: lead?.riskLevel || 'HIGH',
        riskScore: String(lead?.riskScore || 0),
        storeCount: String(lead?.storeCount || 0),
        bizType: lead?.bizType || '',
        monthlyFee: sub.monthly.toLocaleString(),
    };

    const [subject, setSubject] = useState(fillTemplate(BASE_SUBJECT, vars));
    const [customMsg, setCustomMsg] = useState('');
    const [viewMode, setViewMode] = useState<'desktop' | 'mobile'>('desktop');
    const [editTab, setEditTab] = useState<'subject' | 'message'>('subject');
    const [sending, setSending] = useState(false);
    const [sent, setSent] = useState(false);

    const htmlPreview = buildHookEmailHtml(vars, customMsg);

    const handleSend = async () => {
        setSending(true);
        try {
            await fetch('/api/email', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ type: 'company_hook', leadId, lawyerNote: customMsg, customSubject: subject }),
            });
            setSent(true);
        } catch { alert('발송 오류'); }
        setSending(false);
    };

    return (
        <div className={isEmbed ? 'px-2 py-3' : 'min-h-screen px-4 py-8 max-w-[1600px] mx-auto'} style={{ background: '#f8f9fc' }}>
            {/* 상단 헤더 — embed 시 숨김 */}
            {!isEmbed && (
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-4">
                        <Link href="/admin/leads">
                            <button className="flex items-center gap-1.5 text-sm font-medium rounded-lg px-3 py-1.5 transition-colors hover:bg-slate-100" style={{ color: '#64748b' }}>
                                <ArrowLeft className="w-4 h-4" /> 리드 목록
                            </button>
                        </Link>
                        <div className="h-5 w-px" style={{ background: '#d1d5db' }} />
                        <div>
                            <span className="text-base font-black" style={{ color: '#1e293b' }}>이메일 미리보기 — {lead?.companyName}</span>
                            <span className="ml-2 text-xs px-2 py-0.5 rounded-full font-bold" style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fca5a5' }}>
                                {lead?.riskLevel} {lead?.issueCount}건
                            </span>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {/* 뷰 토글 */}
                        <div className="flex rounded-lg overflow-hidden" style={{ border: '1px solid #d1d5db' }}>
                            {(['desktop', 'mobile'] as const).map(m => (
                                <button key={m} onClick={() => setViewMode(m)}
                                    className="px-3 py-1.5 text-xs font-bold transition-colors"
                                    style={{ background: viewMode === m ? '#fffbeb' : '#ffffff', color: viewMode === m ? '#b8960a' : '#94a3b8', borderRight: m === 'desktop' ? '1px solid #d1d5db' : 'none' }}>
                                    {m === 'desktop' ? <Monitor className="w-4 h-4" /> : <Smartphone className="w-4 h-4" />}
                                </button>
                            ))}
                        </div>
                        {sent ? (
                            <div className="flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-bold"
                                style={{ background: '#dcfce7', color: '#16a34a', border: '1px solid #86efac' }}>
                                <CheckCircle2 className="w-4 h-4" /> 발송 완료!
                            </div>
                        ) : (
                            <button onClick={handleSend} disabled={sending}
                                className="flex items-center gap-2 px-5 py-2 rounded-lg font-black text-sm disabled:opacity-50"
                                style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#0a0e1a' }}>
                                {sending ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                                발송 확정
                            </button>
                        )}
                    </div>
                </div>
            )}

            {/* 메인 레이아웃 */}
            <div className="flex gap-5" style={{ minHeight: 'calc(100vh - 160px)' }}>
                {/* 좌: 편집 패널 */}
                <div className="w-80 flex-shrink-0 overflow-y-auto p-5 space-y-4 rounded-2xl"
                    style={{ background: '#ffffff', border: '1px solid #e5e7eb', boxShadow: '0 1px 4px rgba(0,0,0,0.06)' }}>
                    <div>
                        <p className="text-xs font-black uppercase tracking-wider mb-3" style={{ color: '#94a3b8' }}>수신 정보</p>
                        <div className="space-y-2 text-sm">
                            <div className="flex items-center gap-2">
                                <User className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#94a3b8' }} />
                                <span style={{ color: '#1e293b' }}>{lead?.contactName}</span>
                                <span style={{ color: '#64748b' }}>({lead?.contactEmail})</span>
                            </div>
                            <div className="flex items-center gap-2">
                                <Mail className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#94a3b8' }} />
                                <span style={{ color: '#475569' }}>{lead?.companyName}</span>
                            </div>
                        </div>
                    </div>

                    <div className="h-px" style={{ background: '#e5e7eb' }} />

                    {/* 제목 편집 */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            이메일 제목
                        </label>
                        <textarea value={subject} onChange={e => setSubject(e.target.value)} rows={3}
                            className="w-full p-3 rounded-lg outline-none text-sm resize-none"
                            style={{ background: '#f8f9fc', border: '1px solid #e5e7eb', color: '#1e293b', lineHeight: 1.5 }} />
                    </div>

                    {/* 변호사 추가 메시지 */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            ✏️ 개인화 메시지 (선택)
                        </label>
                        <textarea value={customMsg} onChange={e => setCustomMsg(e.target.value)} rows={5}
                            placeholder="담당자에게 전할 메시지를 입력하면 이메일 본문에 포함됩니다..."
                            className="w-full p-3 rounded-lg outline-none text-sm resize-none"
                            style={{ background: '#f8f9fc', border: '1px solid #e5e7eb', color: '#1e293b', lineHeight: 1.6 }} />
                    </div>

                    <div className="h-px" style={{ background: '#e5e7eb' }} />

                    {/* 개인화 URL */}
                    <div>
                        <label className="text-xs font-black uppercase tracking-wider mb-2 block" style={{ color: '#94a3b8' }}>
                            개인화 URL
                        </label>
                        <div className="p-3 rounded-lg text-xs break-all"
                            style={{ background: '#fffbeb', border: '1px solid #fde68a', color: '#b8960a' }}>
                            /landing?cid={leadId}
                        </div>
                        <p className="text-xs mt-1" style={{ color: '#94a3b8' }}>클릭 시 해당 기업 분석 결과 랜딩 열림</p>
                    </div>

                    {/* 드립 캠페인 안내 */}
                    <div className="p-3 rounded-lg" style={{ background: '#eff6ff', border: '1px solid #bfdbfe' }}>
                        <p className="text-xs font-black mb-1" style={{ color: '#3b82f6' }}>📅 드립 캠페인 예약</p>
                        <p className="text-xs" style={{ color: '#64748b' }}>미결제 시 D+1·4·8·14·21·30일 법률자료 자동 발송</p>
                    </div>
                </div>

                {/* 우: HTML 미리보기 */}
                <div className="flex-1 overflow-y-auto p-6 rounded-2xl" style={{ background: '#e2e8f0', border: '1px solid #d1d5db' }}>
                    <div className="mb-4 text-center">
                        <span className="text-xs font-bold px-3 py-1.5 rounded-full"
                            style={{ background: '#ffffff', color: '#64748b', border: '1px solid #d1d5db' }}>
                            제목: {subject}
                        </span>
                    </div>
                    <div className={`mx-auto ${viewMode === 'mobile' ? 'max-w-sm' : 'max-w-2xl'} rounded-2xl overflow-hidden shadow-2xl`}>
                        <iframe
                            srcDoc={htmlPreview}
                            className="w-full"
                            style={{ height: viewMode === 'mobile' ? '700px' : '900px', border: 'none' }}
                            title="이메일 미리보기"
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, Phone, Mail, Globe, Building2, AlertTriangle, CheckCircle2, Clock, MessageSquare, Plus, Eye } from 'lucide-react';
import Link from 'next/link';
import { leadStore, calcSubscription, type Lead, type LeadMemo, type LeadStatus } from '@/lib/leadStore';

const STATUS_LABEL: Record<string, string> = {
    pending: '대기', analyzed: '분석완료', sales_confirmed: '영업컨펌',
    lawyer_confirmed: '변호사컨펌', emailed: '발송완료', in_contact: '연락중',
    contracted: '계약완료', failed: '실패',
};

export default function LeadDetailPage({ params }: { params: Promise<{ id: string }> | { id: string } }) {
    const [lead, setLead] = useState<Lead | null>(null);
    const [memoText, setMemoText] = useState('');
    const [storeCount, setStoreCount] = useState(0);
    const [resolvedId, setResolvedId] = useState('');

    useEffect(() => {
        // Next.js 15: params may be a Promise
        Promise.resolve(params).then(p => {
            const id = p.id;
            setResolvedId(id);
            const l = leadStore.getById(id);
            if (l) { setLead(l); setStoreCount(l.storeCount); }
        });
    }, []);

    if (!lead) return (
        <div className="min-h-screen flex items-center justify-center" style={{ background: '#04091a' }}>
            <p style={{ color: 'rgba(240,244,255,0.4)' }}>리드를 찾을 수 없습니다</p>
        </div>
    );

    const sub = calcSubscription(storeCount);

    const addMemo = () => {
        if (!memoText.trim()) return;
        leadStore.addMemo(lead.id, { author: '영업팀', content: memoText });
        setLead(leadStore.getById(lead.id)!);
        setMemoText('');
    };



    return (
        <div className="min-h-screen pt-20 pb-12" style={{ background: '#04091a' }}>
            <div className="max-w-5xl mx-auto px-4">
                {/* 뒤로가기 */}
                <Link href="/admin/leads">
                    <button className="flex items-center gap-2 text-sm mb-6" style={{ color: 'rgba(240,244,255,0.4)' }}>
                        <ArrowLeft className="w-4 h-4" /> 영업 리드 목록
                    </button>
                </Link>

                <div className="grid md:grid-cols-3 gap-6">
                    {/* 회사 정보 */}
                    <div className="md:col-span-2 space-y-4">
                        <div className="p-6 rounded-2xl" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                            <div className="flex items-center justify-between mb-4">
                                <h1 className="text-xl font-black" style={{ color: '#f0f4ff' }}>{lead.companyName}</h1>
                                <span className="text-sm px-3 py-1 rounded-full font-bold"
                                    style={{ background: 'rgba(201,168,76,0.1)', color: '#c9a84c' }}>
                                    {STATUS_LABEL[lead.status]}
                                </span>
                            </div>
                            <div className="grid grid-cols-2 gap-3 text-sm">
                                {[
                                    { icon: Globe, label: '도메인', value: lead.domain },
                                    { icon: Building2, label: '업종', value: lead.bizType },
                                    { icon: Phone, label: '전화', value: lead.contactPhone },
                                    { icon: Mail, label: '이메일', value: lead.contactEmail },
                                    { icon: Building2, label: '담당자', value: lead.contactName },
                                    { icon: Building2, label: '가맹점수', value: `${lead.storeCount}개` },
                                ].map(({ icon: Icon, label, value }) => (
                                    <div key={label} className="flex items-center gap-2">
                                        <Icon className="w-4 h-4 flex-shrink-0" style={{ color: 'rgba(240,244,255,0.3)' }} />
                                        <span style={{ color: 'rgba(240,244,255,0.4)' }}>{label}:</span>
                                        <span style={{ color: '#f0f4ff' }}>{value}</span>
                                    </div>
                                ))}
                            </div>
                            {lead.privacyUrl && (
                                <a href={lead.privacyUrl} target="_blank" rel="noreferrer"
                                    className="flex items-center gap-1.5 mt-3 text-xs" style={{ color: '#c9a84c' }}>
                                    <Globe className="w-3 h-3" /> 개인정보처리방침 원문 →
                                </a>
                            )}
                        </div>

                        {/* 리스크 요약 */}
                        {lead.riskLevel && (
                            <div className="p-5 rounded-2xl" style={{
                                background: lead.riskLevel === 'HIGH' ? 'rgba(248,113,113,0.06)' : 'rgba(251,146,60,0.06)',
                                border: `1px solid ${lead.riskLevel === 'HIGH' ? 'rgba(248,113,113,0.2)' : 'rgba(251,146,60,0.2)'}`
                            }}>
                                <div className="flex items-center gap-2 mb-2">
                                    <AlertTriangle className="w-4 h-4" style={{ color: lead.riskLevel === 'HIGH' ? '#f87171' : '#fb923c' }} />
                                    <span className="font-black text-sm" style={{ color: lead.riskLevel === 'HIGH' ? '#f87171' : '#fb923c' }}>
                                        리스크 {lead.riskScore}점 ({lead.riskLevel}) — {lead.issueCount}건 발견
                                    </span>
                                </div>
                                <Link href={`/lawyer/privacy-review?leadId=${lead.id}&company=${encodeURIComponent(lead.companyName)}`}>
                                    <button className="flex items-center gap-1.5 text-xs font-bold mt-2 px-3 py-1.5 rounded-lg"
                                        style={{ background: 'rgba(129,140,248,0.15)', color: '#818cf8', border: '1px solid rgba(129,140,248,0.25)' }}>
                                        <Eye className="w-3 h-3" /> 변호사 조문 대조표 보기 →
                                    </button>
                                </Link>
                            </div>
                        )}

                        {/* 후속 메모 타임라인 */}
                        <div className="p-5 rounded-2xl" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                            <h3 className="font-black text-sm mb-4" style={{ color: '#f0f4ff' }}>
                                <MessageSquare className="w-4 h-4 inline mr-1.5" style={{ color: '#c9a84c' }} />
                                후속 관리 메모
                            </h3>
                            <div className="space-y-3 mb-4">
                                {lead.memos.length === 0 && (
                                    <p className="text-sm text-center py-4" style={{ color: 'rgba(240,244,255,0.3)' }}>메모가 없습니다</p>
                                )}
                                {lead.memos.map(memo => (
                                    <div key={memo.id} className="flex gap-3">
                                        <div className="w-1.5 h-1.5 rounded-full mt-1.5 flex-shrink-0" style={{ background: '#c9a84c' }} />
                                        <div>
                                            <div className="flex items-center gap-2 mb-0.5">
                                                <span className="text-xs font-bold" style={{ color: '#c9a84c' }}>{memo.author}</span>
                                                <span className="text-xs" style={{ color: 'rgba(240,244,255,0.3)' }}>
                                                    {new Date(memo.createdAt).toLocaleString('ko-KR')}
                                                </span>
                                            </div>
                                            <p className="text-sm" style={{ color: 'rgba(240,244,255,0.7)' }}>{memo.content}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                            <div className="flex gap-2">
                                <input value={memoText} onChange={e => setMemoText(e.target.value)}
                                    onKeyDown={e => e.key === 'Enter' && addMemo()}
                                    placeholder="메모 입력 후 Enter..."
                                    className="flex-1 px-3 py-2 rounded-lg outline-none text-sm"
                                    style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: '#f0f4ff' }} />
                                <button onClick={addMemo} className="px-4 py-2 rounded-lg font-bold text-sm"
                                    style={{ background: 'rgba(201,168,76,0.15)', color: '#c9a84c', border: '1px solid rgba(201,168,76,0.25)' }}>
                                    추가
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* 사이드 — 계산기 + 상태변경 */}
                    <div className="space-y-4">
                        {/* 구독 계산기 */}
                        <div className="p-5 rounded-2xl" style={{ background: 'rgba(201,168,76,0.06)', border: '1px solid rgba(201,168,76,0.2)' }}>
                            <h3 className="font-black text-sm mb-4" style={{ color: '#c9a84c' }}>구독료 계산기</h3>
                            <label className="text-xs mb-1 block" style={{ color: 'rgba(240,244,255,0.5)' }}>가맹점 수</label>
                            <input type="number" value={storeCount} onChange={e => setStoreCount(Number(e.target.value))}
                                className="w-full px-3 py-2 rounded-lg outline-none text-sm mb-3"
                                style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.12)', color: '#f0f4ff' }} />
                            <div className="space-y-2 text-sm">
                                <div className="flex justify-between">
                                    <span style={{ color: 'rgba(240,244,255,0.5)' }}>플랜</span>
                                    <span className="font-bold" style={{ color: '#c9a84c' }}>{sub.plan}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span style={{ color: 'rgba(240,244,255,0.5)' }}>월 구독료</span>
                                    <span className="font-black" style={{ color: '#f0f4ff' }}>{sub.monthly.toLocaleString()}원</span>
                                </div>
                                <div className="flex justify-between">
                                    <span style={{ color: 'rgba(240,244,255,0.5)' }}>연간 합계</span>
                                    <span style={{ color: 'rgba(240,244,255,0.7)' }}>{sub.annual.toLocaleString()}원</span>
                                </div>
                            </div>
                            <button className="w-full py-2.5 rounded-xl font-black text-sm mt-4"
                                style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#0a0e1a' }}>
                                결제 링크 생성 →
                            </button>
                        </div>

                        {/* 현재 상태 */}
                        <div className="p-5 rounded-2xl" style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                            <h3 className="font-black text-sm mb-3" style={{ color: '#f0f4ff' }}>현재 상태</h3>
                            <div className="py-3 px-4 rounded-lg text-sm font-bold text-center"
                                style={{ background: 'rgba(201,168,76,0.15)', color: '#c9a84c', border: '1px solid rgba(201,168,76,0.25)' }}>
                                ✓ {STATUS_LABEL[lead.status]}
                            </div>
                            <p className="text-xs text-center mt-2" style={{ color: 'rgba(240,244,255,0.3)' }}>
                                상태 변경은 CRM에서 관리됩니다
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Search, Plus, CheckSquare, Square, ChevronDown, ChevronUp, X,
    Building2, Phone, Mail, AlertTriangle, TrendingUp,
    Clock, CheckCircle2, Users, Send, Play, RefreshCw,
    User, FileText, Activity, MessageSquare, Upload,
    Calendar, Clipboard, Copy, Edit3, Save, PhoneCall,
    Eye, Scale, CheckCheck, ChevronRight, Gavel, RotateCcw
} from 'lucide-react';
import Link from 'next/link';
import {
    leadStore, type Lead, type LeadStatus, type LeadTimelineEvent, type TimelineEventType
} from '@/lib/leadStore';
import { dripStore, DRIP_SEQUENCE, type DripMember } from '@/lib/dripStore';

// ── 색상 시스템 (employee 페이지와 동일) ─────────────────────────
const T = {
    heading: '#0f172a', body: '#1e293b', sub: '#475569',
    muted: '#64748b', faint: '#94a3b8',
    border: '#d1d5db', borderSub: '#e5e7eb',
    bg: '#f8f9fc', card: '#ffffff', rowHover: '#f1f5f9',
};

// ── 상태 메타 ─────────────────────────────────────────────
const STATUS_META: Record<LeadStatus, { label: string; color: string; bg: string; border: string }> = {
    pending: { label: '대기', color: '#64748b', bg: '#f1f5f9', border: '#cbd5e1' },
    analyzed: { label: '분석완료', color: '#6366f1', bg: '#eef2ff', border: '#c7d2fe' },
    sales_confirmed: { label: '영업컨펌', color: '#d97706', bg: '#fffbeb', border: '#fde68a' },
    lawyer_confirmed: { label: '변호사컨펌', color: '#059669', bg: '#ecfdf5', border: '#a7f3d0' },
    emailed: { label: '발송완료', color: '#b8960a', bg: '#fefce8', border: '#fde047' },
    in_contact: { label: '연락중', color: '#0284c7', bg: '#e0f2fe', border: '#7dd3fc' },
    contracted: { label: '계약완료', color: '#16a34a', bg: '#dcfce7', border: '#86efac' },
    failed: { label: '실패', color: '#dc2626', bg: '#fef2f2', border: '#fca5a5' },
};

const RISK_META = {
    HIGH: { color: '#dc2626', bg: '#fef2f2', border: '#fca5a5', label: '위험' },
    MEDIUM: { color: '#d97706', bg: '#fffbeb', border: '#fde68a', label: '주의' },
    LOW: { color: '#16a34a', bg: '#dcfce7', border: '#86efac', label: '양호' },
    '': { color: '#94a3b8', bg: '#f8fafc', border: '#e2e8f0', label: '-' },
};

const TIMELINE_ICON: Record<TimelineEventType, React.ReactNode> = {
    status_change: <Activity className="w-3.5 h-3.5" />,
    call: <PhoneCall className="w-3.5 h-3.5" />,
    email: <Mail className="w-3.5 h-3.5" />,
    note: <MessageSquare className="w-3.5 h-3.5" />,
    meeting: <Calendar className="w-3.5 h-3.5" />,
};
const TIMELINE_COLOR: Record<TimelineEventType, string> = {
    status_change: '#6366f1', call: '#0284c7', email: '#d97706',
    note: '#64748b', meeting: '#059669',
};

const STATUS_ORDER: LeadStatus[] = ['pending', 'analyzed', 'sales_confirmed', 'lawyer_confirmed', 'emailed', 'in_contact', 'contracted', 'failed'];
const LAWYERS = ['유정훈 변호사', '김수현 변호사', '박민준 변호사', '이지원 변호사'];

// ── 상태 배지 ─────────────────────────────────────────────
function StatusBadge({ status }: { status: LeadStatus }) {
    const m = STATUS_META[status];
    return (
        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold border"
            style={{ color: m.color, background: m.bg, borderColor: m.border }}>
            {m.label}
        </span>
    );
}

// ── 위험도 배지 ───────────────────────────────────────────
function RiskBadge({ level }: { level: string }) {
    const m = RISK_META[level as keyof typeof RISK_META] ?? RISK_META[''];
    return (
        <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-bold border"
            style={{ color: m.color, background: m.bg, borderColor: m.border }}>
            {m.label}
        </span>
    );
}

// ── 일괄 변경 툴바 ────────────────────────────────────────
function BulkToolbar({ count, onClear, onBulkAssign }: {
    count: number; onClear: () => void;
    onBulkAssign: (l: string) => void;
}) {
    const [showAssign, setShowAssign] = useState(false);
    return (
        <div className="flex items-center gap-3 px-4 py-3 rounded-xl mb-4 border"
            style={{ background: '#fffbeb', borderColor: '#fde68a' }}>
            <CheckSquare className="w-5 h-5" style={{ color: '#b8960a' }} />
            <span className="font-bold text-sm" style={{ color: '#b8960a' }}>{count}개 선택됨</span>
            <div className="h-5 w-px bg-slate-200" />
            <div className="relative">
                <button onClick={() => { setShowAssign(v => !v); }}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-semibold border bg-white hover:bg-slate-50 transition-colors"
                    style={{ color: '#475569', borderColor: '#e2e8f0' }}>
                    변호사 배정 <ChevronDown className="w-3.5 h-3.5" />
                </button>
                {showAssign && (
                    <div className="absolute top-full left-0 mt-1 w-44 bg-white rounded-xl shadow-lg border border-slate-200 py-1 z-50">
                        {LAWYERS.map(l => (
                            <button key={l} onClick={() => { onBulkAssign(l); setShowAssign(false); }}
                                className="w-full text-left px-3 py-2 text-sm hover:bg-slate-50 transition-colors"
                                style={{ color: '#475569' }}>
                                {l}
                            </button>
                        ))}
                    </div>
                )}
            </div>
            <button onClick={onClear} className="ml-auto p-1.5 rounded-lg hover:bg-slate-100 transition-colors" style={{ color: '#94a3b8' }}>
                <X className="w-4 h-4" />
            </button>
        </div>
    );
}



