    // 요약 카운트
    const counts = {
        total: leads.length,
        high: leads.filter(l => l.riskLevel === 'HIGH').length,
        contracted: leads.filter(l => l.status === 'contracted').length,
        pending: leads.filter(l => l.status === 'pending').length,
