                                </div>
                            )}
                        </motion.div>
                    ))}
                </div>

                <div className="grid md:grid-cols-3 gap-6">
                    {/* 리드 추이 차트 (CSS) */}
                    <div className="md:col-span-2 p-6 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
