// ── 메인 채팅 페이지 ──────────────────────────────────────────
export default function ChatPage() {
    const { isAuthenticated, loading: authLoading } = useAuth();
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const [consultType, setConsultType] = useState('general');
    const [step, setStep] = useState<'select' | 'chat'>('select');
    const [caseId] = useState(() => `IBS-${new Date().getFullYear()}-${String(Math.random()).slice(2, 8)}`);
    const bottomRef = useRef<HTMLDivElement>(null);

    useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

    // 인증 로딩 중
    if (authLoading) return (
        <div className="min-h-screen flex items-center justify-center" style={{ background: '#04091a' }}>
            <Loader2 className="w-8 h-8 animate-spin" style={{ color: '#c9a84c' }} />
        </div>
    );

    // 미인증 → 로그인 게이트
    if (!isAuthenticated) return <LoginGate />;

    // A5: Streaming helper — reads SSE response and updates message in real-time
    const streamChat = async (chatMessages: Message[], type: string) => {
        setLoading(true);
        // Add empty assistant message that we'll stream into
        setMessages(prev => [...prev, { role: 'assistant', content: '' }]);
        try {
            const res = await fetch('/api/chat-stream', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ messages: chatMessages, consultType: type }),
            });
            if (!res.ok || !res.body) throw new Error('Stream failed');
            const reader = res.body.getReader();
            const decoder = new TextDecoder();
            let buffer = '';
            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                buffer += decoder.decode(value, { stream: true });
                const lines = buffer.split('\n');
                buffer = lines.pop() || '';
                for (const line of lines) {
                    if (!line.startsWith('data: ')) continue;
                    const data = line.slice(6).trim();
                    if (data === '[DONE]') continue;
                    try {
                        const parsed = JSON.parse(data);
                        if (parsed.text) {
                            setMessages(prev => {
                                const updated = [...prev];
                                const last = updated[updated.length - 1];
                                if (last?.role === 'assistant') last.content += parsed.text;
                                return updated;
                            });
                        }
                    } catch { /* skip */ }
                }
            }
        } catch {
            setMessages(prev => {
                const updated = [...prev];
                const last = updated[updated.length - 1];
                if (last?.role === 'assistant' && !last.content) {
                    last.content = '죄송합니다. 일시적 오류가 발생했습니다.';
                }
                return updated;
            });
        }
        setLoading(false);
    };

    const selectType = async (type: string) => {
        setConsultType(type);
        setStep('chat');
        await streamChat([], type);
    };

    const send = async () => {
        if (!input.trim() || loading) return;
        const userMsg: Message = { role: 'user', content: input };
        const newMsgs = [...messages, userMsg];
        setMessages(newMsgs);
        setInput('');
        await streamChat(newMsgs, consultType);
    };

    return (
        <div className="min-h-screen pt-20" style={{ background: '#04091a' }}>
            <div className="max-w-3xl mx-auto px-4 pb-8">
                {/* 헤더 */}
                <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="text-center py-8">
                    <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full mb-4"
                        style={{ background: 'rgba(201,168,76,0.1)', border: '1px solid rgba(201,168,76,0.3)' }}>
                        <Bot className="w-4 h-4" style={{ color: '#c9a84c' }} />
                        <span className="text-xs font-bold" style={{ color: '#c9a84c' }}>AI 상담 어시스턴트</span>
                    </div>
