    const refresh = () => setMembers(dripStore.getAll());
    const pending = dripStore.getPendingEmails();
    const totalSteps = DRIP_SEQUENCE.length;

    const filtered = filter === 'all' ? members : members.filter(m => m.dripStatus === filter);
