                                                </div>
                                            </td>
                                            <td className="py-3 px-4">
                                                <span className="px-2.5 py-1 rounded-full text-[10px] font-bold" style={{ background: statusInfo.bg, color: statusInfo.color }}>
                                                    {statusInfo.label}
