'use client';
import React, { useState, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Upload, FileSpreadsheet, CheckCircle2, X, AlertTriangle,
    ArrowLeft, Trash2, Download, Eye, RefreshCw,
} from 'lucide-react';
import { leadStore, Lead, LeadStatus } from '@/lib/leadStore';

// ── 색상 시스템 ────────────────────────────────────────────────
const T = {
    heading: '#0f172a', body: '#1e293b', sub: '#475569',
    muted: '#64748b', faint: '#94a3b8',
    border: '#d1d5db', borderSub: '#e5e7eb',
    bg: '#f8f9fc', card: '#ffffff',
};

interface ParsedRow {
    companyName: string;
    bizNumber: string;
    contactName: string;
    contactEmail: string;
    contactPhone: string;
    storeCount: number;
    bizType: string;
    bizCategory: string;
    domain: string;
    privacyUrl: string;
    valid: boolean;
    error?: string;
    warning?: string;
}

const REQUIRED_HEADERS = ['회사명', '사업자번호', '담당자명', '이메일', '전화번호', '가맹점수', '업종', '사업형태', '도메인', '개인정보처리방침URL'];
const SAMPLE_CSV = `회사명,사업자번호,담당자명,이메일,전화번호,가맹점수,업종,사업형태,도메인,개인정보처리방침URL
(주)샐러디,123-45-67890,김마케팅,kim@salady.co.kr,010-1234-5678,180,외식,프랜차이즈,salady.co.kr,https://salady.co.kr/privacy
(주)메가커피,234-56-78901,이운영,lee@megacoffee.co.kr,010-2345-6789,2800,카페,프랜차이즈,megacoffee.co.kr,https://megacoffee.co.kr/privacy`;

export default function UploadPage() {
    const router = useRouter();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [isDragging, setIsDragging] = useState(false);
    const [fileName, setFileName] = useState<string | null>(null);
    const [parsedRows, setParsedRows] = useState<ParsedRow[]>([]);
    const [headers, setHeaders] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [step, setStep] = useState<'upload' | 'preview' | 'done'>('upload');
    const [uploadResult, setUploadResult] = useState<{ total: number; valid: number } | null>(null);
    const [selectedRows, setSelectedRows] = useState<Set<number>>(new Set());

    // ── CSV 파싱 ──────────────────────────────────────────────
    const parseCSV = useCallback((text: string) => {
        try {
            const lines = text.split(/\r?\n/).filter(Boolean);
            if (lines.length < 2) {
                setError('데이터가 없습니다. 헤더 행과 최소 1개의 데이터 행이 필요합니다.');
                return;
            }

            const headerLine = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
            setHeaders(headerLine);

            // 1차: 기본 파싱
            const rows: ParsedRow[] = lines.slice(1).map(line => {
                const cols = line.split(',').map(c => c.trim().replace(/^"|"$/g, ''));
                const companyName = cols[0] ?? '';
                const bizNumber = cols[1] ?? '';
                const storeCount = parseInt(cols[5]) || 0;
                const errors: string[] = [];
                if (!companyName) errors.push('회사명 부재');
                if (!bizNumber) errors.push('사업자번호 부재');
                const valid = errors.length === 0;

                return {
                    companyName,
                    bizNumber,
                    contactName: cols[2] ?? '',
                    contactEmail: cols[3] ?? '',
                    contactPhone: cols[4] ?? '',
                    storeCount,
                    bizType: cols[6] ?? '기타',
                    bizCategory: cols[7] ?? '',
                    domain: cols[8] ?? '',
                    privacyUrl: cols[9] ?? '',
                    valid,
                    error: valid ? undefined : errors.join(', '),
                    warning: undefined as string | undefined,
                };
            });

            // 2차: 중복 & 사업형태 경고 체크
            const seenBizNumbers = new Map<string, number>();
            const seenNames = new Map<string, number>();
            rows.forEach((row, i) => {
                if (!row.valid) return;
                const warnings: string[] = [];
                // 사업자번호 중복 체크
                if (row.bizNumber) {
                    const prev = seenBizNumbers.get(row.bizNumber);
                    if (prev !== undefined) {
                        warnings.push(`사업자번호 중복 (#${prev + 1}행)`);
                    } else {
                        seenBizNumbers.set(row.bizNumber, i);
                    }
                }
                // 회사명 중복 체크
                if (row.companyName) {
                    const prev = seenNames.get(row.companyName);
                    if (prev !== undefined) {
                        warnings.push(`회사명 중복 (#${prev + 1}행)`);
                    } else {
                        seenNames.set(row.companyName, i);
                    }
                }
                // 사업형태 비어있거나 공백
                if (!row.bizCategory || !row.bizCategory.trim()) {
                    warnings.push('사업형태 미입력');
                }
                if (warnings.length > 0) {
                    row.warning = warnings.join(', ');
                }
            });

            setParsedRows(rows);
            // valid이고 warning이 없는 행만 기본 선택
            setSelectedRows(new Set(rows.map((_, i) => i).filter(i => rows[i].valid && !rows[i].warning)));
            setStep('preview');
            setError(null);
        } catch {
            setError('파일 파싱 오류. CSV 형식을 확인해주세요.');
        }
    }, []);

    // ── 파일 처리 ──────────────────────────────────────────────
    const handleFile = useCallback((file: File) => {
        if (!file.name.endsWith('.csv') && !file.name.endsWith('.txt')) {
            setError('CSV 또는 TXT 파일만 지원됩니다.');
            return;
        }
        setFileName(file.name);
        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target?.result as string;
            parseCSV(text);
        };
        reader.readAsText(file, 'UTF-8');
    }, [parseCSV]);

    // ── 드래그 앤 드롭 ────────────────────────────────────────
    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    }, []);

    const handleDragLeave = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
    }, []);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files[0];
        if (file) handleFile(file);
    }, [handleFile]);

    const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) handleFile(file);
        e.target.value = '';
    }, [handleFile]);

    // ── 업로드 실행 ──────────────────────────────────────────
    const handleUpload = useCallback(() => {
        const validRows = parsedRows.filter((_, i) => selectedRows.has(i));
        if (validRows.length === 0) {
            setError('업로드할 유효한 데이터가 없습니다.');
            return;
        }

        const now = new Date().toISOString();
        const genId = (p: string) => `${p}_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;

        const newLeads: Lead[] = validRows.map(r => ({
            id: genId('lead'),
            companyName: r.companyName,
            domain: r.domain,
            privacyUrl: r.privacyUrl,
            contactName: r.contactName,
            contactEmail: r.contactEmail,
            contactPhone: r.contactPhone,
            contacts: [],
            storeCount: r.storeCount,
            bizType: r.bizType,
            bizNumber: r.bizNumber,
            bizCategory: r.bizCategory || undefined,
            riskScore: 0,
            riskLevel: '' as const,
            issueCount: 0,
            status: 'pending' as LeadStatus,
            memos: [],
            timeline: [{
                id: genId('t'),
                createdAt: now,
                author: '시스템',
                type: 'status_change' as const,
                content: 'CSV 대량 업로드',
                toStatus: 'pending' as LeadStatus,
            }],
            createdAt: now,
            updatedAt: now,
            source: 'excel' as const,
        }));

        const existing = leadStore.getAll();
        localStorage.setItem('ibs_leads_v1', JSON.stringify([...newLeads, ...existing]));

        setUploadResult({ total: parsedRows.length, valid: validRows.length });
        setStep('done');
    }, [parsedRows, selectedRows]);

    // ── 샘플 다운로드 ────────────────────────────────────────
    const handleSampleDownload = () => {
        const BOM = '\uFEFF';
        const blob = new Blob([BOM + SAMPLE_CSV], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'sample_leads.csv';
        a.click();
        URL.revokeObjectURL(url);
    };

    // ── 초기화 ────────────────────────────────────────────────
    const reset = () => {
        setStep('upload');
        setParsedRows([]);
        setHeaders([]);
        setFileName(null);
        setError(null);
        setUploadResult(null);
        setSelectedRows(new Set());
    };

    const validCount = parsedRows.filter((_, i) => selectedRows.has(i)).length;
    const invalidCount = parsedRows.filter(r => !r.valid).length;
    const warningCount = parsedRows.filter(r => r.valid && !!r.warning).length;
    const problemRows = parsedRows.filter(r => !r.valid || !!r.warning);

    const downloadErrorCSV = () => {
        const bom = '\uFEFF';
        const header = [...REQUIRED_HEADERS, '사유'].join(',');
        const rows = problemRows.map(r => {
            const reason = !r.valid ? `[오류] ${r.error}` : `[경고] ${r.warning}`;
            return [r.companyName, r.bizNumber, r.contactName, r.contactEmail, r.contactPhone, r.storeCount, r.bizType, r.bizCategory, r.domain, r.privacyUrl, reason].join(',');
        });
        const csv = bom + [header, ...rows].join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `upload_errors_${new Date().toISOString().slice(0, 10)}.csv`;
        a.click();
        URL.revokeObjectURL(url);
    };

    return (
        <div className="min-h-screen" style={{ background: T.bg }}>
            <div className="max-w-6xl mx-auto px-6 py-8">
                {/* 헤더 */}
                <div className="flex items-center gap-4 mb-8">
                    <button onClick={() => router.push('/employee')}
                        className="p-2 rounded-xl hover:bg-white transition-colors"
                        style={{ border: `1px solid ${T.border}` }}>
                        <ArrowLeft className="w-5 h-5" style={{ color: T.sub }} />
                    </button>
                    <div>
                        <h1 className="text-2xl font-black" style={{ color: T.heading }}>📊 리드 대량 업로드</h1>
                        <p className="text-sm mt-1" style={{ color: T.muted }}>
                            CSV 파일을 업로드하여 리드를 일괄 등록합니다. 업로드 전 데이터를 미리 확인할 수 있습니다.
                        </p>
                    </div>
                </div>

                {/* 단계 표시 */}
                <div className="flex items-center gap-3 mb-8">
                    {[
                        { key: 'upload', label: '1. 파일 선택', icon: Upload },
                        { key: 'preview', label: '2. 데이터 확인', icon: Eye },
                        { key: 'done', label: '3. 업로드 완료', icon: CheckCircle2 },
                    ].map((s, i) => (
                        <React.Fragment key={s.key}>
                            {i > 0 && <div className="w-12 h-0.5" style={{ background: step === s.key || (s.key === 'done' && step === 'done') || (s.key === 'preview' && step !== 'upload') ? '#c9a84c' : T.borderSub }} />}
                            <div className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold"
                                style={{
                                    background: step === s.key ? '#fffbeb' : T.card,
                                    border: `1px solid ${step === s.key ? '#fde68a' : T.border}`,
                                    color: step === s.key ? '#b8960a' : T.muted,
                                }}>
                                <s.icon className="w-4 h-4" />
                                {s.label}
                            </div>
                        </React.Fragment>
                    ))}
                </div>

                <AnimatePresence mode="wait">
                    {/* STEP 1: 파일 업로드 */}
                    {step === 'upload' && (
                        <motion.div key="upload" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}>
                            <div className="rounded-2xl overflow-hidden" style={{ background: T.card, border: `1px solid ${T.border}`, boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }}>
                                {/* 드래그 앤 드롭 영역 */}
                                <div
                                    onDragOver={handleDragOver}
                                    onDragLeave={handleDragLeave}
                                    onDrop={handleDrop}
                                    onClick={() => fileInputRef.current?.click()}
                                    className="flex flex-col items-center justify-center py-20 px-8 cursor-pointer transition-all duration-300"
                                    style={{
                                        background: isDragging ? '#fffbeb' : 'transparent',
                                        borderBottom: `2px dashed ${isDragging ? '#fde68a' : T.borderSub}`,
                                    }}>
                                    <div className="w-20 h-20 rounded-2xl flex items-center justify-center mb-6"
                                        style={{ background: isDragging ? '#fef3c7' : '#f1f5f9' }}>
                                        <FileSpreadsheet className="w-10 h-10" style={{ color: isDragging ? '#b8960a' : T.faint }} />
                                    </div>
                                    <p className="text-lg font-black mb-2" style={{ color: isDragging ? '#b8960a' : T.heading }}>
                                        {isDragging ? '여기에 파일을 놓으세요' : 'CSV 파일을 드래그하거나 클릭하세요'}
                                    </p>
                                    <p className="text-sm" style={{ color: T.muted }}>
                                        지원 형식: .csv, .txt (UTF-8 인코딩)
                                    </p>
                                    <input ref={fileInputRef} type="file" accept=".csv,.txt" className="hidden" onChange={handleInputChange} />
                                </div>

                                {/* 하단 안내 */}
                                <div className="px-8 py-6">
                                    <div className="flex items-start gap-4">
                                        <div className="flex-1">
                                            <p className="text-sm font-black mb-3" style={{ color: T.heading }}>📋 CSV 파일 형식 안내</p>
                                            <div className="overflow-x-auto rounded-xl" style={{ border: `1px solid ${T.borderSub}` }}>
                                                <table className="w-full text-xs">
                                                    <thead>
                                                        <tr style={{ background: '#f8f9fc' }}>
                                                            {REQUIRED_HEADERS.map(h => (
                                                                <th key={h} className="px-3 py-2 text-left font-bold whitespace-nowrap" style={{ color: '#b8960a', borderBottom: `1px solid ${T.borderSub}` }}>{h}</th>
                                                            ))}
                                                        </tr>
                                                    </thead>
                                                    <tbody>
                                                        <tr>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>(주)샐러디</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>123-45-67890</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>김마케팅</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>kim@salady.co.kr</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>010-1234-5678</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>180</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>외식</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>프랜차이즈</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>salady.co.kr</td>
                                                            <td className="px-3 py-2" style={{ color: T.body, borderBottom: `1px solid ${T.borderSub}` }}>https://...</td>
                                                        </tr>
                                                    </tbody>
                                                </table>
                                            </div>
                                            <div className="flex gap-3 mt-4">
                                                <button onClick={handleSampleDownload}
                                                    className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-bold transition-colors hover:bg-blue-50"
                                                    style={{ background: '#eff6ff', color: '#2563eb', border: '1px solid #bfdbfe' }}>
                                                    <Download className="w-3.5 h-3.5" />
                                                    샘플 CSV 다운로드
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {error && (
                                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                                    className="flex items-center gap-2 mt-4 px-4 py-3 rounded-xl"
                                    style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#dc2626' }}>
                                    <AlertTriangle className="w-4 h-4" />
                                    <span className="text-sm font-bold">{error}</span>
                                </motion.div>
                            )}
                        </motion.div>
                    )}

                    {/* STEP 2: 데이터 미리보기 */}
                    {step === 'preview' && (
                        <motion.div key="preview" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}>
                            {/* 요약 카드 */}
                            <div className="flex gap-4 mb-6">
                                <div className="flex-1 px-5 py-4 rounded-2xl" style={{ background: T.card, border: `1px solid ${T.border}` }}>
                                    <p className="text-xs font-bold mb-1" style={{ color: T.muted }}>파일명</p>
                                    <p className="text-sm font-black flex items-center gap-2" style={{ color: T.heading }}>
                                        <FileSpreadsheet className="w-4 h-4" style={{ color: '#b8960a' }} />
                                        {fileName}
                                    </p>
                                </div>
                                <div className="px-5 py-4 rounded-2xl" style={{ background: '#eff6ff', border: '1px solid #bfdbfe' }}>
                                    <p className="text-xs font-bold mb-1" style={{ color: '#2563eb' }}>전체 행</p>
                                    <p className="text-xl font-black" style={{ color: '#2563eb' }}>{parsedRows.length}</p>
                                </div>
                                <div className="px-5 py-4 rounded-2xl" style={{ background: '#f0fdf4', border: '1px solid #bbf7d0' }}>
                                    <p className="text-xs font-bold mb-1" style={{ color: '#16a34a' }}>유효</p>
                                    <p className="text-xl font-black" style={{ color: '#16a34a' }}>{validCount}</p>
                                </div>
                                {warningCount > 0 && (
                                    <div className="px-5 py-4 rounded-2xl" style={{ background: '#fffbeb', border: '1px solid #fde68a' }}>
                                        <p className="text-xs font-bold mb-1" style={{ color: '#d97706' }}>경고</p>
                                        <p className="text-xl font-black" style={{ color: '#d97706' }}>{warningCount}</p>
                                    </div>
                                )}
                                {invalidCount > 0 && (
                                    <div className="px-5 py-4 rounded-2xl" style={{ background: '#fef2f2', border: '1px solid #fecaca' }}>
                                        <p className="text-xs font-bold mb-1" style={{ color: '#dc2626' }}>오류</p>
                                        <p className="text-xl font-black" style={{ color: '#dc2626' }}>{invalidCount}</p>
                                    </div>
                                )}
                            </div>

                            {/* 데이터 테이블 */}
                            <div className="rounded-2xl overflow-hidden mb-6" style={{ background: T.card, border: `1px solid ${T.border}`, boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }}>
                                <div className="overflow-x-auto" style={{ maxHeight: '500px' }}>
                                    <table className="w-full text-sm">
                                        <thead className="sticky top-0" style={{ zIndex: 1 }}>
                                            <tr style={{ background: '#f8f9fc', borderBottom: `2px solid ${T.border}` }}>
                                                <th className="py-3 px-3 text-left text-xs font-black whitespace-nowrap" style={{ color: '#b8960a' }}>#</th>
                                                <th className="py-3 px-3 text-left text-xs font-black whitespace-nowrap" style={{ color: '#b8960a' }}>상태</th>
                                                {REQUIRED_HEADERS.map(h => (
                                                    <th key={h} className="py-3 px-3 text-left text-xs font-black whitespace-nowrap" style={{ color: '#b8960a' }}>{h}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {parsedRows.map((row, i) => (
                                                <tr key={i} className="transition-colors hover:bg-slate-50"
                                                    style={{
                                                        borderBottom: `1px solid ${T.borderSub}`,
                                                        opacity: selectedRows.has(i) ? 1 : 0.4,
                                                        background: !row.valid ? '#fef2f220' : row.warning ? '#fffbeb40' : 'transparent',
                                                    }}>
                                                    <td className="py-2.5 px-3">
                                                        <input type="checkbox" checked={selectedRows.has(i)} disabled={!row.valid || !!row.warning}
                                                            onChange={() => {
                                                                const s = new Set(selectedRows);
                                                                s.has(i) ? s.delete(i) : s.add(i);
                                                                setSelectedRows(s);
                                                            }}
                                                            className="rounded" />
                                                    </td>
                                                    <td className="py-2.5 px-3">
                                                        {!row.valid
                                                            ? <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-bold" style={{ background: '#fef2f2', color: '#dc2626' }}>
                                                                <AlertTriangle className="w-3 h-3" /> {row.error}
                                                            </span>
                                                            : row.warning
                                                                ? <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-bold" style={{ background: '#fffbeb', color: '#d97706' }}>
                                                                    <AlertTriangle className="w-3 h-3" /> {row.warning}
                                                                </span>
                                                                : <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-bold" style={{ background: '#f0fdf4', color: '#16a34a' }}>
                                                                    <CheckCircle2 className="w-3 h-3" /> 유효
                                                                </span>
                                                        }
                                                    </td>
                                                    <td className="py-2.5 px-3 font-bold" style={{ color: T.body }}>{row.companyName || '—'}</td>
                                                    <td className="py-2.5 px-3 font-mono text-xs" style={{ color: T.sub }}>{row.bizNumber || '—'}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.contactName || '—'}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.contactEmail || '—'}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.contactPhone || '—'}</td>
                                                    <td className="py-2.5 px-3 font-bold" style={{ color: T.body }}>{row.storeCount.toLocaleString()}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.bizType}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.bizCategory || '—'}</td>
                                                    <td className="py-2.5 px-3" style={{ color: T.sub }}>{row.domain || '—'}</td>
                                                    <td className="py-2.5 px-3 text-xs truncate" style={{ color: T.faint, maxWidth: 200 }}>{row.privacyUrl || '—'}</td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>

                            {/* 액션 버튼 */}
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <button onClick={reset}
                                        className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-colors hover:bg-slate-100"
                                        style={{ background: T.card, border: `1px solid ${T.border}`, color: T.sub }}>
                                        <ArrowLeft className="w-4 h-4" /> 다시 선택
                                    </button>
                                    {problemRows.length > 0 && (
                                        <button onClick={downloadErrorCSV}
                                            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-colors hover:bg-red-50"
                                            style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#dc2626' }}>
                                            <Download className="w-4 h-4" /> 오류/경고 목록 CSV
                                        </button>
                                    )}
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="text-sm" style={{ color: T.muted }}>
                                        <strong style={{ color: '#b8960a' }}>{validCount}건</strong> 업로드 예정
                                        {(warningCount + invalidCount) > 0 && (
                                            <span style={{ color: '#dc2626', marginLeft: 8 }}>
                                                ({warningCount + invalidCount}건 제외)
                                            </span>
                                        )}
                                    </span>
                                    <button onClick={handleUpload} disabled={validCount === 0}
                                        className="flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-black transition-all disabled:opacity-40"
                                        style={{
                                            background: 'linear-gradient(135deg, #e8c87a 0%, #c9a84c 60%, #a8872c 100%)',
                                            color: '#04091a',
                                            boxShadow: '0 4px 20px rgba(201,168,76,0.4)',
                                        }}>
                                        <Upload className="w-4 h-4" />
                                        일괄 업로드
                                    </button>
                                </div>
                            </div>

                            {error && (
                                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                                    className="flex items-center gap-2 mt-4 px-4 py-3 rounded-xl"
                                    style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#dc2626' }}>
                                    <AlertTriangle className="w-4 h-4" />
                                    <span className="text-sm font-bold">{error}</span>
                                </motion.div>
                            )}
                        </motion.div>
                    )}

                    {/* STEP 3: 완료 */}
                    {step === 'done' && uploadResult && (
                        <motion.div key="done" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
                            className="rounded-2xl p-12 text-center"
                            style={{ background: T.card, border: `1px solid ${T.border}`, boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }}>
                            <div className="w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6"
                                style={{ background: '#f0fdf4' }}>
                                <CheckCircle2 className="w-10 h-10" style={{ color: '#16a34a' }} />
                            </div>
                            <h2 className="text-2xl font-black mb-2" style={{ color: T.heading }}>업로드 완료! 🎉</h2>
                            <p className="text-sm mb-8" style={{ color: T.muted }}>
                                전체 {uploadResult.total}건 중 <strong style={{ color: '#16a34a' }}>{uploadResult.valid}건</strong>이 성공적으로 등록되었습니다.
                            </p>
                            <div className="flex gap-3 justify-center">
                                <button onClick={reset}
                                    className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-colors hover:bg-slate-100"
                                    style={{ background: T.card, border: `1px solid ${T.border}`, color: T.sub }}>
                                    <RefreshCw className="w-4 h-4" /> 추가 업로드
                                </button>
                                <button onClick={() => router.push('/employee')}
                                    className="flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-black transition-all"
                                    style={{
                                        background: 'linear-gradient(135deg, #e8c87a 0%, #c9a84c 60%, #a8872c 100%)',
                                        color: '#04091a',
                                        boxShadow: '0 4px 20px rgba(201,168,76,0.4)',
                                    }}>
                                    CRM으로 이동 →
                                </button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
}

'use client';
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { HelpCircle, ChevronDown, Search, MessageSquare, FileText, Scale, CreditCard, Shield, Users, Mail } from 'lucide-react';
import Link from 'next/link';

const T = {
    heading: '#0f172a', body: '#1e293b', sub: '#475569',
    muted: '#64748b', faint: '#94a3b8',
    border: '#d1d5db', borderSub: '#e5e7eb',
    bg: '#f8f9fc', card: '#ffffff',
};

interface FAQ {
    q: string;
    a: string;
    category: string;
}

const FAQS: FAQ[] = [
    // 서비스 소개
    { category: '서비스', q: 'IBS 법률사무소는 어떤 서비스를 제공하나요?', a: '프랜차이즈 본부를 위한 종합 법률 자문 서비스를 제공합니다. AI 기반 개인정보처리방침 분석, 전담 변호사 배정, 계약서 검토, 가맹사업법 컴플라이언스 자문, EAP(심리상담) 등을 모두 제공합니다.' },
    { category: '서비스', q: 'AI 분석은 정확한가요?', a: 'AI 분석은 1차 스크리닝 용도로 사용됩니다. 모든 AI 분석 결과는 반드시 전담 변호사가 교차 검증하여 최종 검토합니다. AI + 변호사 이중 검증으로 높은 정확도를 보장합니다.' },
    { category: '서비스', q: '무료 분석은 어떻게 받나요?', a: '홈페이지에서 회사명 또는 사업자번호를 검색하면 즉시 1차 AI 분석을 받으실 수 있습니다. 무료 분석에서는 주요 위험 이슈 2건까지 열람 가능합니다.' },
    // 요금
    { category: '요금', q: '요금제는 어떻게 되나요?', a: 'Basic(월 99만원), Pro(월 249만원), Premium(월 499만원) 3가지 플랜을 제공합니다. Basic은 AI 분석 + 변호사 검토, Pro는 무제한 자문 + EAP, Premium은 전담팀 배정 + 경영자문을 포함합니다.' },
    { category: '요금', q: '결제 방법은 무엇인가요?', a: '신용카드, 무통장입금, 계좌이체를 지원합니다. 월 자동결제 및 연 일시불 결제(10% 할인)가 가능합니다.' },
    { category: '요금', q: '환불 정책은 어떤가요?', a: '서비스 시작 후 7일 이내 100% 환불, 30일 이내 50% 환불이 가능합니다. 단, 이미 제공된 법률 자문 건수에 따라 차감될 수 있습니다.' },
    // 법률
    { category: '법률', q: '개인정보처리방침을 왜 검토해야 하나요?', a: '개인정보 보호법 위반 시 최대 매출액의 3%까지 과징금이 부과될 수 있습니다. 특히 프랜차이즈 본부는 가맹점 직원·고객의 개인정보를 처리하므로 더욱 철저한 관리가 필요합니다.' },
    { category: '법률', q: '가맹사업법 관련 자문도 가능한가요?', a: '네, 가맹사업법 전문 변호사가 정보공개서 검토, 가맹계약서 검토, 분쟁 조정, 공정거래위원회 대응 등 모든 가맹사업법 관련 자문을 제공합니다.' },
    // 기술
    { category: '기술', q: '어떤 AI 기술을 사용하나요?', a: 'Claude, GPT-4o, Gemini 등 최신 AI 모델을 활용합니다. RAG(검색 증강 생성) 기술로 한국 법률 조문을 참조하여 법적 근거가 있는 분석을 제공합니다.' },
    { category: '기술', q: '데이터는 안전하게 관리되나요?', a: '모든 데이터는 암호화 저장되며, AWS 서울 리전에서 운영됩니다. SOC 2 Type II 준수, 개인정보 보호법 제29조에 따른 안전조치 기준을 적용합니다.' },
    // 계정
    { category: '계정', q: '팀원을 추가할 수 있나요?', a: 'Pro 플랜은 최대 5명, Premium 플랜은 무제한 팀원 추가가 가능합니다. 각 팀원에게 역할(HR 담당, 법무 담당 등)을 지정할 수 있습니다.' },
    { category: '계정', q: '비밀번호를 잊어버렸어요', a: '로그인 페이지에서 "비밀번호 찾기"를 클릭하신 후 가입 시 사용한 이메일 주소를 입력하시면 비밀번호 재설정 링크를 보내드립니다.' },
];

const CATEGORIES = ['전체', '서비스', '요금', '법률', '기술', '계정'];

export default function HelpPage() {
    const [search, setSearch] = useState('');
    const [category, setCategory] = useState('전체');
    const [openId, setOpenId] = useState<string | null>(null);

    const filtered = FAQS.filter(faq => {
        const matchCat = category === '전체' || faq.category === category;
        const matchSearch = !search || faq.q.includes(search) || faq.a.includes(search);
        return matchCat && matchSearch;
    });

    return (
        <div className="min-h-screen py-8 px-4" style={{ background: T.bg }}>
            <div className="max-w-3xl mx-auto">

                {/* 헤더 */}
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-black flex items-center justify-center gap-2 mb-2" style={{ color: T.heading }}>
                        <HelpCircle className="w-6 h-6" style={{ color: '#6366f1' }} />
                        도움말 & FAQ
                    </h1>
                    <p className="text-sm" style={{ color: T.muted }}>자주 묻는 질문과 서비스 가이드</p>
                </div>

                {/* 검색 */}
                <div className="relative mb-6">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: T.faint }} />
                    <input value={search} onChange={e => setSearch(e.target.value)}
                        placeholder="질문을 검색하세요..."
                        className="w-full pl-10 pr-4 py-3 rounded-xl text-sm"
                        style={{ background: T.card, border: `1px solid ${T.border}`, color: T.body }} />
                </div>

                {/* 카테고리 필터 */}
                <div className="flex gap-2 mb-6 flex-wrap">
                    {CATEGORIES.map(c => (
                        <button key={c} onClick={() => setCategory(c)}
                            className="px-3 py-1.5 rounded-lg text-xs font-bold transition-all"
                            style={{
                                background: category === c ? '#6366f1' : T.card,
                                color: category === c ? '#fff' : T.muted,
                                border: `1px solid ${category === c ? '#6366f1' : T.border}`,
                            }}>
                            {c}
                        </button>
                    ))}
                </div>

                {/* FAQ 아코디언 */}
                <div className="space-y-2 mb-8">
                    {filtered.map((faq, i) => {
                        const isOpen = openId === `${faq.category}-${i}`;
                        return (
                            <motion.div key={`${faq.category}-${i}`} layout
                                className="rounded-xl overflow-hidden"
                                style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                                <button onClick={() => setOpenId(isOpen ? null : `${faq.category}-${i}`)}
                                    className="w-full flex items-center justify-between p-4 text-left">
                                    <div className="flex items-center gap-3 flex-1 min-w-0">
                                        <span className="text-xs font-bold px-2 py-0.5 rounded flex-shrink-0"
                                            style={{ background: '#eef2ff', color: '#6366f1' }}>{faq.category}</span>
                                        <span className="text-sm font-bold truncate" style={{ color: T.heading }}>{faq.q}</span>
                                    </div>
                                    <ChevronDown className={`w-4 h-4 flex-shrink-0 transition-transform ${isOpen ? 'rotate-180' : ''}`}
                                        style={{ color: T.faint }} />
                                </button>
                                <AnimatePresence>
                                    {isOpen && (
                                        <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }}
                                            exit={{ height: 0, opacity: 0 }} className="overflow-hidden">
                                            <div className="px-4 pb-4 pt-0">
                                                <div className="p-3 rounded-lg text-sm leading-relaxed"
                                                    style={{ background: T.bg, color: T.body }}>
                                                    {faq.a}
                                                </div>
                                            </div>
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </motion.div>
                        );
                    })}
                    {filtered.length === 0 && (
                        <div className="text-center py-12">
                            <HelpCircle className="w-8 h-8 mx-auto mb-2" style={{ color: T.faint }} />
                            <p className="text-sm" style={{ color: T.muted }}>검색 결과가 없습니다</p>
                        </div>
                    )}
                </div>

                {/* 추가 도움말 링크 */}
                <div className="grid sm:grid-cols-3 gap-3">
                    {[
                        { href: '/chat', icon: MessageSquare, label: 'AI 상담', desc: 'AI에게 직접 질문하기', color: '#6366f1' },
                        { href: '/sales', icon: Mail, label: '전문 상담 신청', desc: '변호사 상담 예약', color: '#10b981' },
                        { href: '/pricing', icon: CreditCard, label: '요금제 안내', desc: '플랜 비교 & 구독', color: '#f59e0b' },
                    ].map(({ href, icon: Icon, label, desc, color }) => (
                        <Link key={href} href={href}>
                            <div className="p-4 rounded-xl text-center transition-all hover:shadow-md cursor-pointer"
                                style={{ background: T.card, border: `1px solid ${T.borderSub}` }}>
                                <Icon className="w-6 h-6 mx-auto mb-2" style={{ color }} />
                                <p className="text-sm font-bold" style={{ color: T.heading }}>{label}</p>
                                <p className="text-xs" style={{ color: T.muted }}>{desc}</p>
                            </div>
                        </Link>
                    ))}
                </div>
            </div>
        </div>
    );
}

'use client';
import React, { useState, Suspense } from 'react';
import { useSearchParams } from 'next/navigation';
import { motion } from 'framer-motion';
import { Shield, AlertTriangle, CheckCircle2, Phone, Video, CreditCard, Lock } from 'lucide-react';
import { leadStore, calcSubscription, type Lead } from '@/lib/leadStore';

// ── 개인화 랜딩 페이지 (/landing?cid={leadId}) ───────────────
// 고객이 이메일 클릭 후 처음 보는 페이지
// 분석 결과 티저 공개 → 로그인하면 전체 확인

const RISK_COLOR: Record<string, string> = { HIGH: '#f87171', MEDIUM: '#fb923c', LOW: '#facc15' };

function LandingContent() {
    const searchParams = useSearchParams();
    const leadId = searchParams.get('cid') || '';
    const [lead] = useState<Lead | null>(() => leadStore.getById(leadId) || null);
    const [showLogin, setShowLogin] = useState(false);
    const [bizRegNo, setBizRegNo] = useState('');
    const [logging, setLogging] = useState(false);
    const [loggedIn, setLoggedIn] = useState(false);
    const [loginError, setLoginError] = useState('');

    if (!lead) return (
        <div className="min-h-screen flex items-center justify-center" style={{ background: '#04091a' }}>
            <div className="text-center">
                <Shield className="w-12 h-12 mx-auto mb-3 opacity-30" style={{ color: '#c9a84c' }} />
                <p style={{ color: 'rgba(240,244,255,0.4)' }}>{leadId ? '유효하지 않은 링크입니다' : '로딩 중...'}</p>
            </div>
        </div>
    );

    const handleLogin = async () => {
        if (!bizRegNo.trim()) { setLoginError('사업자번호를 입력하세요'); return; }
        setLogging(true); setLoginError('');
        try {
            // 사업자번호로 회원 등록(또는 기존 회원 확인)
            const res = await fetch('/api/drip', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ leadId, bizRegNo: bizRegNo.replace(/-/g, '') }),
            });
            const data = await res.json();
            if (res.ok) {
                setLoggedIn(true);
            } else {
                setLoginError(data.error || '오류가 발생했습니다');
            }
        } catch {
            setLoginError('서버 오류. 잠시 후 다시 시도하세요.');
        }
        setLogging(false);
    };

    const riskColor = RISK_COLOR[lead.riskLevel] || '#94a3b8';

    return (
        <div className="min-h-screen" style={{ background: '#04091a' }}>
            {/* 헤더 */}
            <div className="px-6 py-4 flex items-center justify-between border-b"
                style={{ borderColor: 'rgba(201,168,76,0.15)', background: 'rgba(13,27,62,0.95)' }}>
                <div className="flex items-center gap-2">
                    <span className="text-xl font-black" style={{ color: '#c9a84c' }}>⚖️ IBS 법률사무소</span>
                </div>
                <button onClick={() => setShowLogin(!showLogin)}
                    className="text-sm px-4 py-2 rounded-lg font-bold"
                    style={{ background: showLogin ? 'rgba(201,168,76,0.15)' : 'rgba(255,255,255,0.05)', color: '#c9a84c', border: '1px solid rgba(201,168,76,0.2)' }}>
                    {loggedIn ? '✓ 로그인됨' : '로그인'}
                </button>
            </div>

            <div className="max-w-3xl mx-auto px-4 py-10">
                {/* 회사명 + 리스크 */}
                <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="text-center mb-10">
                    <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full mb-5"
                        style={{ background: `${riskColor}15`, border: `1px solid ${riskColor}30` }}>
                        <AlertTriangle className="w-4 h-4" style={{ color: riskColor }} />
                        <span className="font-bold text-sm" style={{ color: riskColor }}>
                            {lead.riskLevel} 리스크 — {lead.issueCount}건 위반 가능성 발견
                        </span>
                    </div>
                    <h1 className="text-3xl font-black mb-3" style={{ color: '#f0f4ff' }}>
                        {lead.companyName}
                    </h1>
                    <p className="text-lg" style={{ color: 'rgba(240,244,255,0.6)' }}>
                        개인정보처리방침 AI 분석 결과
                    </p>
                </motion.div>

                {/* 리스크 요약 카드 (공개) */}
                <div className="grid md:grid-cols-3 gap-4 mb-8">
                    {[
                        { label: '리스크 점수', value: `${lead.riskScore}점`, color: riskColor },
                        { label: '위반 가능 건수', value: `${lead.issueCount}건`, color: '#f87171' },
                        { label: '예상 과징금', value: '최대 3,000만원', color: '#fb923c' },
                    ].map(({ label, value, color }) => (
                        <div key={label} className="p-5 rounded-2xl text-center"
                            style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                            <div className="text-2xl font-black mb-1" style={{ color }}>{value}</div>
                            <div className="text-sm" style={{ color: 'rgba(240,244,255,0.5)' }}>{label}</div>
                        </div>
                    ))}
                </div>

                {/* 주요 위반 항목 티저 */}
                <div className="mb-8 rounded-2xl overflow-hidden"
                    style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)' }}>
                    <div className="px-6 py-4" style={{ borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
                        <h2 className="font-black text-sm" style={{ color: '#f0f4ff' }}>주요 발견 항목</h2>
                    </div>
                    <div className="p-6 space-y-3">
                        {[
                            { title: '개인정보 과다수집 의심', level: 'HIGH', law: '개보법 §16', visible: true },
                            { title: '제3자 제공 현황 미명시', level: 'HIGH', law: '개보법 §17', visible: true },
                            { title: '보유기간 일부 항목 누락', level: 'MEDIUM', law: '개보법 §21', visible: loggedIn },
                        ].map((item, i) => (
                            <div key={i} className="flex items-center gap-3">
                                <span className="text-xs px-2 py-0.5 rounded-full font-black flex-shrink-0"
                                    style={{ background: `${RISK_COLOR[item.level]}15`, color: RISK_COLOR[item.level] }}>
                                    {item.level}
                                </span>
                                {item.visible ? (
                                    <>
                                        <span className="text-sm" style={{ color: '#f0f4ff' }}>{item.title}</span>
                                        <span className="text-xs ml-auto" style={{ color: 'rgba(240,244,255,0.3)' }}>{item.law}</span>
                                    </>
                                ) : (
                                    <div className="flex items-center gap-2">
                                        <div className="h-3 rounded" style={{ background: 'rgba(255,255,255,0.1)', width: 160 }} />
                                        <Lock className="w-3 h-3" style={{ color: 'rgba(240,244,255,0.2)' }} />
                                        <span className="text-xs" style={{ color: 'rgba(240,244,255,0.3)' }}>로그인 후 확인</span>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>

                {/* 로그인 박스 or CTA */}
                {!loggedIn ? (
                    <motion.div layout className="rounded-2xl p-6"
                        style={{ background: 'rgba(201,168,76,0.06)', border: '1px solid rgba(201,168,76,0.2)' }}>
                        <h3 className="font-black text-lg mb-2" style={{ color: '#f0f4ff' }}>
                            전체 분석 결과 + 즉시수정안 확인
                        </h3>
                        <p className="text-sm mb-5" style={{ color: 'rgba(240,244,255,0.5)' }}>
                            사업자번호를 입력하면 <strong style={{ color: '#c9a84c' }}>바로 회원 등록</strong>되고 전체 결과를 확인할 수 있습니다.<br />
                            이메일로 임시 비밀번호가 발송됩니다.
                        </p>
                        <div className="space-y-3">
                            <div>
                                <label className="text-xs font-bold mb-1 block" style={{ color: 'rgba(240,244,255,0.4)' }}>사업자번호</label>
                                <input
                                    value={bizRegNo}
                                    onChange={e => setBizRegNo(e.target.value)}
                                    placeholder="000-00-00000"
                                    className="w-full px-4 py-3 rounded-xl outline-none text-sm"
                                    style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.15)', color: '#f0f4ff' }}
                                />
                            </div>
                            {loginError && <p className="text-xs" style={{ color: '#f87171' }}>{loginError}</p>}
                            <button onClick={handleLogin} disabled={logging}
                                className="w-full py-4 rounded-xl font-black text-base"
                                style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#0a0e1a' }}>
                                {logging ? '처리 중...' : '무료 회원 등록 & 전체 결과 확인 →'}
                            </button>
                            <p className="text-xs text-center" style={{ color: 'rgba(240,244,255,0.3)' }}>
                                결제 없이 가입 가능 · 이메일로 임시 비밀번호 발송
                            </p>
                        </div>
                    </motion.div>
                ) : (
                    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                        className="rounded-2xl p-6 space-y-4"
                        style={{ background: 'rgba(74,222,128,0.06)', border: '1px solid rgba(74,222,128,0.2)' }}>
                        <div className="flex items-center gap-3 mb-2">
                            <CheckCircle2 className="w-6 h-6" style={{ color: '#4ade80' }} />
                            <h3 className="font-black text-lg" style={{ color: '#4ade80' }}>회원 등록 완료!</h3>
                        </div>
                        <p className="text-sm" style={{ color: 'rgba(240,244,255,0.6)' }}>
                            임시 비밀번호가 이메일로 발송됐습니다. 이제 전담 변호사와 상담하실 수 있습니다.
                        </p>
                        <div className="grid grid-cols-3 gap-3 mt-4">
                            {[
                                { icon: Phone, label: '전화 상담', sub: '바로 연결', color: '#4ade80' },
                                { icon: Video, label: '줌 미팅', sub: '일정 예약', color: '#818cf8' },
                                { icon: CreditCard, label: '구독 시작', sub: `월 ${calcSubscription(lead.storeCount).monthly.toLocaleString()}원`, color: '#c9a84c' },
                            ].map(({ icon: Icon, label, sub, color }) => (
                                <button key={label} className="p-4 rounded-xl text-center"
                                    style={{ background: `${color}10`, border: `1px solid ${color}25` }}>
                                    <Icon className="w-6 h-6 mx-auto mb-1.5" style={{ color }} />
                                    <p className="font-black text-xs" style={{ color }}>{label}</p>
                                    <p className="text-[10px] mt-0.5" style={{ color: 'rgba(240,244,255,0.4)' }}>{sub}</p>
                                </button>
                            ))}
                        </div>
                    </motion.div>
                )}
            </div>
        </div>
    );
}

