                                    background: '#f8f9fc', color: '#64748b',
                                    border: '1px solid #e5e7eb', borderRadius: 8, padding: '8px 14px',
                                    fontWeight: 700, fontSize: 13, cursor: 'pointer',
                                }}>
                                    <List size={14} />
                                    목록 보기
                                </button>
                            </Link>
                            {/* 컨펌 완료 · 목록 보기 */}
                            <button onClick={handleConfirmAndGoList} disabled={confirming} style={{
