                                border: 'none', borderRadius: 9, padding: '9px 24px',
                                fontWeight: 900, fontSize: 15, cursor: confirming ? 'not-allowed' : 'pointer',
                                boxShadow: '0 2px 12px rgba(22,163,74,0.25)',
                            }}>
                                <CheckCircle2 size={17} />
                                {confirming ? '처리 중...' : '컨펌 완료 · 다음 회사'}
                            </button>
                        </div>
                    </div>
                )}

                {/* ── 컬럼 레이블 ─────────────────────────────────────── */}
