'use client';
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, ChevronLeft, Save, RotateCcw, Users, Lock, Unlock, Eye } from 'lucide-react';
import Link from 'next/link';
import {
  permissionStore,
  PERMISSION_KEYS,
  PERMISSION_LABELS,
  PRESET_LABELS,
  PRESETS,
  type UserPermission,
  type PermissionKey,
  type PermissionLevel,
  type PresetRole,
} from '@/lib/permissions';

const LEVEL_COLORS: Record<PermissionLevel, { bg: string; text: string; border: string; label: string }> = {
  full: { bg: '#ecfdf5', text: '#059669', border: '#a7f3d0', label: '전체' }, // emerald
  own: { bg: '#fffbeb', text: '#d97706', border: '#fde68a', label: '담당건만' }, // amber
  none: { bg: '#fef2f2', text: '#dc2626', border: '#fecaca', label: '제한' }, // red
};

export default function AdminPermissionsPage() {
  const [users, setUsers] = useState<UserPermission[]>([]);
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [toast, setToast] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    setUsers(permissionStore.getAll());
  }, []);

  useEffect(() => {
    if (users.length > 0 && !selectedUserId) setSelectedUserId(users[0].userId);
  }, [users, selectedUserId]);

  const selectedUser = users.find(u => u.userId === selectedUserId);

  const handleLevelChange = (userId: string, key: PermissionKey, level: PermissionLevel) => {
    setUsers(prev => prev.map(u =>
      u.userId === userId ? { ...u, permissions: { ...u.permissions, [key]: level } } : u
    ));
  };

  const applyPreset = (userId: string, preset: PresetRole) => {
    setUsers(prev => prev.map(u =>
      u.userId === userId ? { ...u, permissions: { ...PRESETS[preset] }, role: preset } : u
    ));
    showToast(`✅ ${PRESET_LABELS[preset]} 프리셋이 적용되었습니다`);
  };

  const handleSave = async () => {
    setSaving(true);
    await new Promise(r => setTimeout(r, 500));
    permissionStore.saveAll(users);
    setSaving(false);
    showToast('✅ 권한 설정이 저장되었습니다');
  };

  const handleReset = () => {
    setUsers(permissionStore.getAll());
    showToast('↩️ 변경사항이 초기화되었습니다');
  };

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(''), 2500);
  };

  const cyclePerm = (userId: string, key: PermissionKey) => {
    const current = users.find(u => u.userId === userId)?.permissions[key] || 'none';
    const order: PermissionLevel[] = ['full', 'own', 'none'];
    const idx = order.indexOf(current);
    const next = order[(idx + 1) % order.length];
    handleLevelChange(userId, key, next);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 pb-16">
      {/* 상단 헤더 */}
      <div className="sticky top-0 z-[100] bg-white/90 backdrop-blur-md border-b border-slate-200 px-6 h-[60px] flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-3">
          <Link href="/employee">
            <button className="text-[13px] text-slate-500 hover:text-slate-800 transition-colors bg-transparent border-none cursor-pointer font-medium">← 돌아가기</button>
          </Link>
          <div className="w-px h-4 bg-slate-200" />
          <span className="text-[15px] font-black text-slate-800 flex items-center gap-2">🛡️ 권한 관리</span>
          <span className="text-[11px] font-bold text-amber-600 bg-amber-50 border border-amber-200 py-0.5 px-2 rounded-full">관리자 전용</span>
        </div>
        <div className="flex gap-2">
            <button onClick={handleReset} className="flex items-center gap-1.5 bg-slate-50 hover:bg-slate-100 text-slate-600 border border-slate-200 rounded-lg py-1.5 px-3.5 cursor-pointer text-[13px] font-semibold transition-colors">
                <RotateCcw className="w-3.5 h-3.5" /> 초기화
            </button>
            <button onClick={handleSave} disabled={saving} className={`flex items-center gap-1.5 border-none rounded-lg py-1.5 px-4 cursor-pointer text-[13px] font-bold shadow-sm transition-all ${saving ? 'opacity-60 bg-amber-500' : 'bg-gradient-to-r from-amber-500 to-amber-600 hover:from-amber-600 hover:to-amber-700 text-white'}`}>
                <Save className="w-3.5 h-3.5" /> {saving ? '저장 중...' : '저장'}
            </button>
        </div>
      </div>

      <div className="max-w-[1200px] mx-auto py-8 px-6">
        <div className="flex flex-col md:flex-row gap-6">
          {/* 좌측: 직원 목록 */}
          <div className="w-full md:w-[260px] shrink-0">
            <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="px-4 py-3 border-b border-slate-200 bg-slate-50">
                <div className="flex items-center gap-2">
                  <Users className="w-3.5 h-3.5 text-slate-500" />
                  <span className="text-[12px] font-bold text-slate-600">직원 목록</span>
                  <span className="text-[10px] px-2 py-0.5 rounded-full bg-amber-50 text-amber-600 border border-amber-200 font-bold ml-auto">{users.length}명</span>
                </div>
              </div>
              <div className="divide-y divide-slate-100">
              {users.map(u => (
                <div key={u.userId} onClick={() => setSelectedUserId(u.userId)} className={`px-4 py-3 cursor-pointer transition-all border-l-[3px] ${selectedUserId === u.userId ? 'bg-amber-50/30 border-l-amber-500' : 'bg-transparent border-l-transparent hover:bg-slate-50'}`}>
                  <p className="text-[14px] font-black text-slate-800 m-0">{u.userName}</p>
                  <div className="flex gap-1.5 mt-2">
                    <span className="text-[10px] px-2 py-0.5 rounded-md font-bold" style={{ background: LEVEL_COLORS[u.role === 'partner' ? 'full' : u.role === 'associate' ? 'own' : 'none'].bg, color: LEVEL_COLORS[u.role === 'partner' ? 'full' : u.role === 'associate' ? 'own' : 'none'].text, border: `1px solid ${LEVEL_COLORS[u.role === 'partner' ? 'full' : u.role === 'associate' ? 'own' : 'none'].border}` }}>
                      {PRESET_LABELS[u.role as PresetRole] || u.role}
                    </span>
                  </div>
                </div>
              ))}
              </div>
            </div>
          </div>

          {/* 우측: 권한 매트릭스 */}
          <div className="flex-1 min-w-0">
            {selectedUser ? (
              <motion.div key={selectedUser.userId} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
                {/* 사용자 헤더 */}
                <div className="px-5 py-4 border-b border-slate-200 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                  <div>
                    <h2 className="text-base font-black text-slate-800 m-0 leading-none">{selectedUser.userName}</h2>
                    <p className="text-xs font-medium text-slate-500 m-0 mt-2">11가지 권한을 개별 설정하거나 프리셋을 적용하세요</p>
                  </div>
                  <div className="flex gap-1.5 flex-wrap">
                    {(Object.keys(PRESET_LABELS) as PresetRole[]).map(p => (
                      <button key={p} onClick={() => applyPreset(selectedUser.userId, p)} className={`text-[11px] px-2.5 py-1 rounded-lg font-bold cursor-pointer transition-all border ${selectedUser.role === p ? 'bg-slate-800 text-white border-slate-800' : 'bg-slate-50 text-slate-500 border-slate-200 hover:bg-slate-100 hover:text-slate-700'}`}>
                        {PRESET_LABELS[p]}
                      </button>
                    ))}
                  </div>
                </div>

                {/* 권한 항목 목록 */}
                <div className="divide-y divide-slate-100">
                  {PERMISSION_KEYS.map((key, idx) => {
                    const level = selectedUser.permissions[key];
                    const lc = LEVEL_COLORS[level];
                    return (
                      <div key={key} className="flex flex-col sm:flex-row sm:items-center gap-3 justify-between p-4 sm:px-5 sm:py-3 hover:bg-slate-50 transition-colors">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-xl flex items-center justify-center border shadow-sm shrink-0" style={{ background: lc.bg, borderColor: lc.border }}>
                            {level === 'full' ? <Unlock className="w-4 h-4" style={{ color: lc.text }} /> :
                             level === 'own' ? <Eye className="w-4 h-4" style={{ color: lc.text }} /> :
                             <Lock className="w-4 h-4" style={{ color: lc.text }} />}
                          </div>
                          <div>
                            <p className="text-[13px] font-black text-slate-800 m-0">{idx + 1}. {PERMISSION_LABELS[key]}</p>
                          </div>
                        </div>
                        <div className="flex gap-1.5 shrink-0">
                          {(['full', 'own', 'none'] as PermissionLevel[]).map(l => {
                            const c = LEVEL_COLORS[l];
                            const isActive = level === l;
                            return (
                              <button key={l} onClick={() => handleLevelChange(selectedUser.userId, key, l)} className={`text-[11px] px-2.5 py-1.5 rounded-lg font-bold cursor-pointer transition-all border`} style={{ background: isActive ? c.bg : 'transparent', color: isActive ? c.text : '#94a3b8', borderColor: isActive ? c.border : '#e2e8f0', boxShadow: isActive ? '0 1px 2px rgba(0,0,0,0.05)' : 'none' }}>
                                {c.label}
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </motion.div>
            ) : (
              <div className="text-center p-16 text-slate-400 bg-white rounded-2xl border border-slate-200">
                <Users className="w-12 h-12 mx-auto mb-4 opacity-30" />
                <p className="text-[14px] font-bold">직원을 선택하세요</p>
              </div>
            )}

            {/* 일괄 매트릭스 뷰 (하단) */}
            <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm mt-6">
              <div className="px-5 py-3 border-b border-slate-200 bg-slate-50">
                <span className="text-[12px] font-bold text-slate-600">📊 전체 권한 매트릭스 (클릭하여 변경)</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full border-collapse text-[11px]">
                  <thead>
                    <tr className="bg-slate-50">
                      <th className="p-3 text-left font-bold text-slate-500 border-b border-slate-200 sticky left-0 z-10 min-w-[120px]" style={{ background: '#f8f9fc', WebkitBackdropFilter: 'blur(4px)', backdropFilter: 'blur(4px)' }}>직원</th>
                      {PERMISSION_KEYS.map((key, i) => (
                        <th key={key} className="p-2 text-center font-bold text-slate-400 border-b border-slate-200 whitespace-nowrap min-w-[60px]">{i + 1}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {users.map(u => (
                      <tr key={u.userId} className={`transition-colors ${selectedUserId === u.userId ? 'bg-slate-50' : 'hover:bg-slate-50/50'}`}>
                        <td className="p-3 font-bold text-slate-800 sticky left-0 whitespace-nowrap" style={{ background: selectedUserId === u.userId ? '#f8f9fc' : '#ffffff', WebkitBackdropFilter: 'blur(4px)', backdropFilter: 'blur(4px)' }}>{u.userName}</td>
                        {PERMISSION_KEYS.map(key => {
                          const l = u.permissions[key];
                          const c = LEVEL_COLORS[l];
                          return (
                            <td key={key} onClick={() => cyclePerm(u.userId, key)} className="p-1.5 text-center cursor-pointer">
                              <span className="inline-block px-1.5 py-0.5 rounded-md font-bold text-[10px] border transition-all hover:opacity-80" style={{ background: c.bg, color: c.text, borderColor: c.border }}>{c.label}</span>
                            </td>
                          );
                        })}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              <div className="p-4 bg-slate-50 border-t border-slate-200 flex gap-4 flex-wrap">
                {PERMISSION_KEYS.map((key, i) => (
                  <span key={key} className="text-[10px] font-medium text-slate-500 whitespace-nowrap">{i + 1}. {PERMISSION_LABELS[key]}</span>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Toast */}
      <AnimatePresence>
        {toast && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 20 }} className="fixed bottom-6 left-1/2 -translate-x-1/2 px-5 py-3 rounded-xl text-[13px] font-bold bg-slate-800 text-white shadow-lg border border-slate-700 z-[200] whitespace-nowrap">
            {toast}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';
import React, { useState, useRef, useMemo } from 'react';
import { motion } from 'framer-motion';
import {
    BarChart3, TrendingUp, Users, Phone, Mail,
    FileText, Calendar, DollarSign, Target,
    ArrowUp, ArrowDown, Download, Filter,
    CheckCircle2, Clock, AlertTriangle, Star,
} from 'lucide-react';
import Link from 'next/link';
import { ReportGeneratorFactory } from '@/lib/reportGenerator';
import { useCompanies } from '@/hooks/useDataLayer';

/* ── 기간 탭 ─────────────────────────────────────────────── */
type Period = 'week' | 'month' | 'quarter';

/* ── 공통 유틸 및 매핑 데이터 ────────────────────────────────── */
const PLAN_REVENUE = { premium: 2_990_000, standard: 1_490_000, starter: 490_000, none: 0 };

export default function ReportsPage() {
    const { companies, isLoading } = useCompanies();
    const [period, setPeriod] = useState<Period>('month');
    const [downloading, setDownloading] = useState(false);
    const reportRef = useRef<HTMLDivElement>(null);

    // =========================================================
    // 데이터 집계 (Data Aggregation)
    // =========================================================
    
    // 이번 달 및 지난 달 필터링
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const lastMonth = currentMonth === 0 ? 11 : currentMonth - 1;
    const lastMonthYear = currentMonth === 0 ? currentYear - 1 : currentYear;

    // KPI 카드 동적 계산
    const { currentLeads, lastLeads, currentRevenue, lastRevenue, currentContracts, currentCalls, lastCalls } = useMemo(() => {
        let curLeads = 0, lstLeads = 0;
        let curRev = 0, lstRev = 0;
        let curCont = 0;
        let curCalls = 0, lstCalls = 0;

        companies.forEach(company => {
            const date = new Date(company.createdAt);
            const isCurrentMonth = date.getMonth() === currentMonth && date.getFullYear() === currentYear;
            const isLastMonth = date.getMonth() === lastMonth && date.getFullYear() === lastMonthYear;
            const rev = PLAN_REVENUE[company.plan as keyof typeof PLAN_REVENUE] || 0;

            if (isCurrentMonth) {
                curLeads++;
                curRev += rev;
                if (company.plan !== 'none') curCont++;
                curCalls += (company.callAttempts || 0);
            } else if (isLastMonth) {
                lstLeads++;
                lstRev += rev;
                lstCalls += (company.callAttempts || 0);
            }
        });

        return {
            currentLeads: curLeads,
            lastLeads: lstLeads,
            currentRevenue: curRev,
            lastRevenue: lstRev,
            currentContracts: curCont,
            currentCalls: curCalls,
            lastCalls: lstCalls,
        };
    }, [companies, currentMonth, currentYear, lastMonth, lastMonthYear]);

    // 증감액 및 퍼센트
    const calcChange = (cur: number, last: number) => {
        if (last === 0) return cur > 0 ? '+100%' : '0%';
        const diff = cur - last;
        const pct = (diff / last) * 100;
        return `${pct > 0 ? '+' : ''}${pct.toFixed(1)}%`;
    };

    const leadsChange = calcChange(currentLeads, lastLeads);
    const revChange = calcChange(currentRevenue, lastRevenue);
    const convRate = currentLeads > 0 ? ((currentContracts / currentLeads) * 100).toFixed(1) : '0.0';

    const kpiCards = [
        { icon: Users, label: '신규 리드', value: currentLeads.toString(), change: leadsChange, up: currentLeads >= lastLeads, color: '#2563eb', sub: '전월 대비' },
        { icon: Target, label: '계약 전환율', value: `${convRate}%`, change: '-', up: true, color: '#22c55e', sub: '이번 달 누적' },
        { icon: DollarSign, label: '월 매출', value: `${currentRevenue.toLocaleString()}원`, change: revChange, up: currentRevenue >= lastRevenue, color: '#d97706', sub: '전월 대비' },
        { icon: Phone, label: '전화 완료', value: `${currentCalls}건`, change: `${currentCalls - lastCalls > 0 ? '+' : ''}${currentCalls - lastCalls}건`, up: currentCalls >= lastCalls, color: '#7c3aed', sub: '전월 대비' },
    ];

    // 파이프라인 퍼널 집계
    const FUNNEL_DATA = useMemo(() => {
        let counts = { pending: 0, crawled: 0, sale_conf: 0, law_conf: 0, emailed: 0, reply: 0, contr: 0, sub: 0 };
        companies.forEach(c => {
            // 편의상 파이프라인 진행 상태별 누적 스냅샷 개념 (현 상태 기준)
            switch (c.status) {
                case 'pending': counts.pending++; break;
                case 'crawling': case 'analyzed': counts.crawled++; break;
                case 'reviewing': case 'assigned': counts.sale_conf++; break;
                case 'lawyer_confirmed': counts.law_conf++; break;
                case 'emailed': counts.emailed++; break;
                case 'client_replied': counts.reply++; break;
                case 'contract_sent': case 'contract_signed': counts.contr++; break;
                case 'subscribed': case 'upsell': counts.sub++; break;
            }
        });

        // 좀 더 퍼널(하향식)처럼 보이게, 뒤의 단계 개수를 포함시켜 누적(Threshold)로 만들 수도 있으나,
        // 여기서는 직관적으로 각 파이프라인에 대기 중인 상태를 보여줍니다.
        const funnel = [
            { stage: '신규 리드', count: counts.pending, color: '#94a3b8' },
            { stage: '분석 진행', count: counts.crawled, color: '#60a5fa' },
            { stage: '영업 배정', count: counts.sale_conf, color: '#818cf8' },
            { stage: '변호사 확인', count: counts.law_conf, color: '#c084fc' },
            { stage: '제안 발송', count: counts.emailed, color: '#f472b6' },
            { stage: '고객 응답', count: counts.reply, color: '#fb923c' },
            { stage: '계약 대기', count: counts.contr, color: '#4ade80' },
            { stage: '구독 완료', count: counts.sub, color: '#22c55e' },
        ];
        
        const maxStage = Math.max(...funnel.map(f => f.count), 1);
        return funnel.map(f => ({
            ...f,
            width: Math.min(Math.round((f.count / maxStage) * 100) + 5, 100) // 최소 5% 보장
        }));
    }, [companies]);

    // 월별 트렌드 집계 (최근 6개월)
    const MONTHLY_TRENDS = useMemo(() => {
        const trendsLabel: string[] = [];
        const trendsMap: Record<string, { month: string; leads: number; contracts: number; revenue: number }> = {};
        
        for (let i = 5; i >= 0; i--) {
            const d = new Date(currentYear, currentMonth - i, 1);
            const label = `${d.getMonth() + 1}월`;
            trendsLabel.push(label);
            trendsMap[label] = { month: label, leads: 0, contracts: 0, revenue: 0 };
        }

        companies.forEach(company => {
            const d = new Date(company.createdAt);
            const mLabel = `${d.getMonth() + 1}월`;
            if (trendsMap[mLabel]) {
                trendsMap[mLabel].leads++;
                if (company.plan !== 'none') {
                    trendsMap[mLabel].contracts++;
                    trendsMap[mLabel].revenue += PLAN_REVENUE[company.plan as keyof typeof PLAN_REVENUE] || 0;
                }
            }
        });

        return trendsLabel.map(label => trendsMap[label]);
    }, [companies, currentMonth, currentYear]);

    // 영업 담당자별 성과
    const REP_PERFORMANCE = useMemo(() => {
        const reps: Record<string, any> = {};
        companies.forEach(c => {
            const repName = c.assignedLawyer || c.salesConfirmedBy || '미배정';
            if (!reps[repName]) {
                reps[repName] = { name: repName, leads: 0, calls: 0, emails: 0, contracts: 0, revenue: 0 };
            }
            reps[repName].leads++;
            reps[repName].calls += (c.callAttempts || 0);
            if (c.emailSentAt) reps[repName].emails++;
            
            if (c.plan !== 'none') {
                reps[repName].contracts++;
                reps[repName].revenue += PLAN_REVENUE[c.plan as keyof typeof PLAN_REVENUE] || 0;
            }
        });

        // 배열로 변환 후 정렬 (매출순)
        const list = Object.values(reps).map(r => ({
            ...r,
            rate: r.leads > 0 ? ((r.contracts / r.leads) * 100).toFixed(1) : '0.0'
        }));
        return list.sort((a, b) => b.revenue - a.revenue);
    }, [companies]);


    const handleDownload = async () => {
        if (!reportRef.current || downloading) return;
        try {
            setDownloading(true);
            const generator = ReportGeneratorFactory.create('PDF', `Admin_Report_${period}_${currentYear}.pdf`);
            await generator.generate([reportRef.current]);
            alert('📥 리포트 다운로드가 완료되었습니다.');
        } catch (error) {
            console.error('Report generation failed:', error);
            alert('❌ 다운로드 중 오류가 발생했습니다.');
        } finally {
            setDownloading(false);
        }
    };

    if (isLoading) {
        return <div className="min-h-screen flex items-center justify-center bg-slate-50"><motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}><Clock className="w-8 h-8 text-amber-500" /></motion.div></div>;
    }

    return (
        <div className="min-h-screen bg-slate-50 font-sans text-slate-800 pb-16">

            {/* 상단 헤더 */}
            <div className="sticky top-0 z-[100] bg-white/90 backdrop-blur-md border-b border-slate-200 px-6 h-[60px] flex items-center justify-between shadow-sm">
                <div className="flex items-center gap-3">
                    <Link href="/employee">
                        <button className="text-[13px] text-slate-500 hover:text-slate-800 transition-colors bg-transparent border-none cursor-pointer font-medium">← 돌아가기</button>
                    </Link>
                    <div className="w-px h-4 bg-slate-200" />
                    <span className="text-[15px] font-black text-slate-800 flex items-center gap-2">
                        <BarChart3 className="w-4 h-4 text-amber-600" /> 영업 성과 리포트
                    </span>
                    <span className="text-[11px] font-bold text-amber-600 bg-amber-50 border border-amber-200 py-0.5 px-2 rounded-full">실제 데이터 연동 완료</span>
                    <span className="text-[12px] font-semibold text-slate-400 ml-2 hidden sm:inline-block">{currentYear}년 {currentMonth+1}월 기준 · 실시간 업데이트</span>
                </div>
                <div className="flex items-center gap-2 hidden sm:flex">
                    {/* 기간 필터 */}
                    {(['week', 'month', 'quarter'] as Period[]).map(p => {
                        const labels: Record<Period, string> = { week: '주간', month: '월간', quarter: '분기' };
                        return (
                            <button key={p} onClick={() => setPeriod(p)}
                                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all border cursor-pointer ${period === p ? 'bg-amber-50 text-amber-600 border-amber-200 shadow-sm' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:text-slate-700'}`}>
                                {labels[p]}
                            </button>
                        );
                    })}
                    <div className="w-px h-6 bg-slate-200 mx-1" />
                    <button onClick={handleDownload} disabled={downloading}
                        className={`flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-[13px] font-bold transition-all border-none ${downloading ? 'bg-slate-600 text-white cursor-wait opacity-80' : 'bg-slate-800 hover:bg-slate-900 text-white cursor-pointer shadow-sm'}`}>
                        {downloading ? (
                            <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}>
                                <Clock className="w-3.5 h-3.5" />
                            </motion.div>
                        ) : (
                            <Download className="w-3.5 h-3.5" />
                        )}
                        {downloading ? '생성 중...' : 'PDF 다운로드'}
                    </button>
                </div>
            </div>

            <div className="max-w-[1400px] mx-auto py-8 px-6">
                {/* PDF로 변환될 메인 컨텐츠 영역 */}
                <div ref={reportRef} className="rounded-xl overflow-hidden p-2 bg-slate-50">
                    {/* KPI 카드 */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                        {kpiCards.map((kpi, i) => {
                            const Icon = kpi.icon;
                            return (
                                <motion.div
                                    key={kpi.label}
                                    initial={{ opacity: 0, y: 12 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: 0.05 * i }}
                                    className="bg-white rounded-2xl p-5 border border-slate-200 shadow-sm"
                                >
                                    <div className="flex items-center justify-between mb-3">
                                        <div className="w-10 h-10 rounded-xl flex items-center justify-center opacity-90"
                                            style={{ backgroundColor: `${kpi.color}15` }}>
                                            <Icon className="w-5 h-5" style={{ color: kpi.color }} />
                                        </div>
                                        <span className={`flex items-center gap-0.5 text-[11px] font-bold px-2 py-0.5 rounded-full ${kpi.up ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                                            {kpi.up ? <ArrowUp className="w-3 h-3" /> : <ArrowDown className="w-3 h-3" />}
                                            {kpi.change}
                                        </span>
                                    </div>
                                    <p className="text-xs font-bold text-slate-500 mb-0.5">{kpi.label}</p>
                                    <p className="text-xl font-black text-slate-900">{kpi.value}</p>
                                    <p className="text-[10px] text-slate-400 mt-1 font-medium">{kpi.sub}</p>
                                </motion.div>
                            );
                        })}
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-6">
                        {/* 파이프라인 퍼널 */}
                        <div className="bg-white rounded-2xl p-5 border border-slate-200 shadow-sm">
                            <h2 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2">
                                <Target className="w-4 h-4 text-amber-500" />
                                상태별 스냅샷 퍼널
                            </h2>
                            <div className="space-y-2.5">
                                {FUNNEL_DATA.map((f, i) => (
                                    <div key={f.stage} className="flex items-center gap-3">
                                        <span className="text-[11px] font-bold w-20 text-right shrink-0 text-slate-600">
                                            {f.stage}
                                        </span>
                                        <div className="flex-1 h-7 rounded-lg overflow-hidden bg-slate-100">
                                            <motion.div
                                                initial={{ width: 0 }}
                                                animate={{ width: `${f.width}%` }}
                                                transition={{ delay: 0.1 * i, duration: 0.5 }}
                                                className="h-full rounded-lg flex items-center justify-end px-2 shadow-inner"
                                                style={{ backgroundColor: f.color }}
                                            >
                                                <span className="text-[10px] font-black text-white">{f.count}</span>
                                            </motion.div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* 월별 트렌드 (바 차트 CSS) */}
                        <div className="bg-white rounded-2xl p-5 border border-slate-200 shadow-sm">
                            <h2 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2">
                                <TrendingUp className="w-4 h-4 text-emerald-500" />
                                최근 6개월 매출 트렌드
                            </h2>
                            <div className="flex items-end gap-3 h-44">
                                {MONTHLY_TRENDS.map((m, i) => {
                                    const maxRevenue = Math.max(...MONTHLY_TRENDS.map(t => t.revenue), 1_000_000);
                                    const height = (m.revenue / maxRevenue) * 100;
                                    return (
                                        <div key={m.month} className="flex-1 flex flex-col items-center gap-1">
                                            <span className="text-[9px] font-bold text-amber-600">
                                                {(m.revenue / 1_000_000).toFixed(0)}M
                                            </span>
                                            <motion.div
                                                initial={{ height: 0 }}
                                                animate={{ height: `${height}%` }}
                                                transition={{ delay: 0.1 * i, duration: 0.5 }}
                                                className="w-full rounded-t-lg shadow-sm"
                                                style={{
                                                    background: `linear-gradient(to top, #3b82f6, #93c5fd)`,
                                                    minHeight: 8,
                                                }}
                                            />
                                            <span className="text-[10px] font-bold text-slate-500">{m.month}</span>
                                            <span className="text-[9px] text-slate-400 font-medium">{m.contracts}건</span>
                                        </div>
                                    );
                                })}
                            </div>
                            <div className="flex items-center justify-center gap-4 mt-3 pt-3 border-t border-slate-100">
                                <span className="flex items-center gap-1 text-[10px] text-slate-500 font-medium">
                                    <span className="w-2 h-2 rounded-full bg-blue-500" /> 월 매출
                                </span>
                                <span className="flex items-center gap-1 text-[10px] text-slate-500 font-medium">
                                    <span className="text-[10px] font-black text-amber-500">N</span> 계약 건수
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* 담당자별 성과 테이블 */}
                    <div className="bg-white rounded-2xl overflow-hidden border border-slate-200 shadow-sm mb-8">
                        <div className="px-5 py-4 border-b border-slate-200 bg-white flex items-center justify-between">
                            <h2 className="text-sm font-black text-slate-800 flex items-center gap-2">
                                <Users className="w-4 h-4 text-indigo-500" />
                                실시간 담당자별 성과
                            </h2>
                            <span className="text-[10px] font-bold px-2.5 py-1 rounded-full bg-slate-100 text-slate-600 border border-slate-200">
                                전체 누적 기준
                            </span>
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm">
                                <thead>
                                    <tr className="bg-slate-50">
                                        {['순위', '담당자', '리드', '전화', '이메일', '계약 체결', '누적 매출', '전환율'].map(h => (
                                            <th key={h} className="py-3 px-5 text-left text-[11px] font-extrabold text-slate-500 whitespace-nowrap min-w-[70px]">{h}</th>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {REP_PERFORMANCE.length > 0 ? REP_PERFORMANCE.map((rep, i) => (
                                        <tr key={rep.name} className="transition-colors hover:bg-slate-50/50 bg-white">
                                            <td className="py-3 px-5">
                                                <span className={`w-6 h-6 rounded-full inline-flex items-center justify-center text-[10px] font-black shadow-sm border ${i === 0 ? 'bg-amber-50 text-amber-600 border-amber-200' : i === 1 ? 'bg-slate-100 text-slate-600 border-slate-200' : i === 2 ? 'bg-orange-50 text-orange-600 border-orange-200' : 'bg-white text-slate-400 border-slate-100'}`}>
                                                    {i + 1}
                                                </span>
                                            </td>
                                            <td className="py-3 px-5 font-bold text-slate-800 whitespace-nowrap">{rep.name}</td>
                                            <td className="py-3 px-5 font-bold text-slate-800 text-[13px]">{rep.leads}</td>
                                            <td className="py-3 px-5 text-slate-500 text-[13px] font-medium">{rep.calls}</td>
                                            <td className="py-3 px-5 text-slate-500 text-[13px] font-medium">{rep.emails}</td>
                                            <td className="py-3 px-5">
                                                <span className="font-extrabold text-emerald-600 text-[13px]">{rep.contracts}건</span>
                                            </td>
                                            <td className="py-3 px-5 whitespace-nowrap">
                                                <span className="font-extrabold text-amber-600 text-[13px]">{rep.revenue.toLocaleString()}원</span>
                                            </td>
                                            <td className="py-3 px-5">
                                                <span className={`px-2 py-0.5 rounded-md text-[10px] font-black border ${parseFloat(rep.rate) >= 20 ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-amber-50 text-amber-600 border-amber-200'}`}>
                                                    {rep.rate}%
                                                </span>
                                            </td>
                                        </tr>
                                    )) : (
                                        <tr>
                                            <td colSpan={8} className="py-8 text-center text-slate-400 font-medium text-sm">
                                                연동된 데이터가 없습니다.
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                        <div className="px-5 py-4 bg-slate-50 border-t border-slate-200">
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 text-xs">
                                <span className="text-slate-500 font-bold shrink-0">📈 데이터 총계</span>
                                <div className="flex gap-4 sm:gap-6 flex-wrap font-medium">
                                    <span className="text-slate-600">총 리드 수: <strong className="text-slate-900 ml-1">{REP_PERFORMANCE.reduce((s, r) => s + r.leads, 0)}</strong></span>
                                    <div className="w-px h-4 bg-slate-300 hidden sm:block" />
                                    <span className="text-slate-600">체결 계약: <strong className="text-emerald-600 ml-1">{REP_PERFORMANCE.reduce((s, r) => s + r.contracts, 0)}건</strong></span>
                                    <div className="w-px h-4 bg-slate-300 hidden sm:block" />
                                    <span className="text-slate-600">누적 매출: <strong className="text-amber-600 ml-1 font-black">{REP_PERFORMANCE.reduce((s, r) => s + r.revenue, 0).toLocaleString()}원</strong></span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import {
    Users, Search, Edit3, Trash2, Key, Save, X, ChevronDown,
    Shield, ShieldCheck, Phone, Briefcase, Scale, Gavel,
    Calculator, Heart, UserCheck, User, RotateCcw, CheckCircle2, AlertTriangle
} from 'lucide-react';

// ── 타입 정의 ────────────────────────────────────────────────────
interface ManagedUser {
    id: string;
    email: string;
    name: string;
    role: string;
    companyId: string;
    companyName: string;
    createdAt: string;
    lastSignIn: string | null;
    emailConfirmed: boolean;
}

type EditField = 'name' | 'email' | 'role' | 'companyName' | 'password';

interface EditState {
    userId: string;
    field: EditField;
    value: string;
}

// ── 역할 라벨 매핑 ──────────────────────────────────────────────
const ROLE_MAP: Record<string, { label: string; color: string; icon: React.ReactNode }> = {
    super_admin:     { label: '슈퍼 관리자', color: '#dc2626', icon: <ShieldCheck className="w-3.5 h-3.5" /> },
    admin:           { label: '관리자',      color: '#ea580c', icon: <Shield className="w-3.5 h-3.5" /> },
    sales:           { label: '영업팀',      color: '#2563eb', icon: <Phone className="w-3.5 h-3.5" /> },
    lawyer:          { label: '변호사',      color: '#7c3aed', icon: <Scale className="w-3.5 h-3.5" /> },
    litigation:      { label: '송무팀',      color: '#0891b2', icon: <Gavel className="w-3.5 h-3.5" /> },
    general:         { label: '총무팀',      color: '#4b5563', icon: <Briefcase className="w-3.5 h-3.5" /> },
    hr:              { label: '인사팀',      color: '#059669', icon: <UserCheck className="w-3.5 h-3.5" /> },
    finance:         { label: '회계팀',      color: '#ca8a04', icon: <Calculator className="w-3.5 h-3.5" /> },
    counselor:       { label: '상담사',      color: '#db2777', icon: <Heart className="w-3.5 h-3.5" /> },
    client_hr:       { label: '고객사 HR',   color: '#0d9488', icon: <Users className="w-3.5 h-3.5" /> },
    personal_client: { label: '개인 의뢰인', color: '#64748b', icon: <User className="w-3.5 h-3.5" /> },
};

const ALL_ROLES = Object.keys(ROLE_MAP);

export default function AdminUsersPage() {
    const [users, setUsers] = useState<ManagedUser[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [search, setSearch] = useState('');
    const [roleFilter, setRoleFilter] = useState<string>('all');
    const [editState, setEditState] = useState<EditState | null>(null);
    const [saving, setSaving] = useState(false);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
    const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
    const [showRoleDropdown, setShowRoleDropdown] = useState(false);

    // ── 유저 목록 로드 ──────────────────────────────────────────
    const fetchUsers = useCallback(async () => {
        setLoading(true);
        setError('');
        try {
            const res = await fetch('/api/admin/users');
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || '유저 목록 조회 실패');
            setUsers(data.users || []);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => { fetchUsers(); }, [fetchUsers]);

    // ── 토스트 자동 해제 ────────────────────────────────────────
    useEffect(() => {
        if (!toast) return;
        const t = setTimeout(() => setToast(null), 3000);
        return () => clearTimeout(t);
    }, [toast]);

    // ── 유저 정보 저장 ──────────────────────────────────────────
    const handleSave = async () => {
        if (!editState) return;
        setSaving(true);
        try {
            const body: any = { userId: editState.userId };
            if (editState.field === 'password') {
                if (editState.value.length < 6) {
                    setToast({ message: '비밀번호는 6자 이상이어야 합니다.', type: 'error' });
                    setSaving(false);
                    return;
                }
                body.password = editState.value;
            } else {
                body[editState.field] = editState.value;
            }

            const res = await fetch('/api/admin/users', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || '수정 실패');

            setToast({ message: '✅ 수정 완료', type: 'success' });
            setEditState(null);
            fetchUsers();
        } catch (err: any) {
            setToast({ message: err.message, type: 'error' });
        } finally {
            setSaving(false);
        }
    };

    // ── 유저 삭제 ────────────────────────────────────────────────
    const handleDelete = async (userId: string) => {
        try {
            const res = await fetch('/api/admin/users', {
                method: 'DELETE',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userId }),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || '삭제 실패');

            setToast({ message: '🗑️ 계정이 삭제되었습니다.', type: 'success' });
            setDeleteConfirm(null);
            fetchUsers();
        } catch (err: any) {
            setToast({ message: err.message, type: 'error' });
        }
    };

    // ── 필터링 ───────────────────────────────────────────────────
    const filtered = users.filter(u => {
        const matchSearch = !search ||
            u.name.toLowerCase().includes(search.toLowerCase()) ||
            u.email.toLowerCase().includes(search.toLowerCase());
        const matchRole = roleFilter === 'all' || u.role === roleFilter;
        return matchSearch && matchRole;
    });

    // ── 인라인 편집 셀 ──────────────────────────────────────────
    const EditableCell = ({ user, field, currentValue }: { user: ManagedUser; field: EditField; currentValue: string }) => {
        const isEditing = editState?.userId === user.id && editState?.field === field;

        if (isEditing) {
            if (field === 'role') {
                return (
                    <div className="relative">
                        <button
                            onClick={() => setShowRoleDropdown(!showRoleDropdown)}
                            className="flex items-center gap-1.5 px-2 py-1 border border-amber-400 rounded-lg bg-white text-[12px] font-semibold text-slate-700 cursor-pointer min-w-[120px]"
                        >
                            {ROLE_MAP[editState.value]?.label || editState.value}
                            <ChevronDown className="w-3 h-3 text-slate-400 ml-auto" />
                        </button>
                        {showRoleDropdown && (
                            <div className="absolute z-50 mt-1 bg-white border border-slate-200 rounded-xl shadow-lg py-1 w-[180px] max-h-[260px] overflow-y-auto">
                                {ALL_ROLES.map(r => (
                                    <button
                                        key={r}
                                        onClick={() => {
                                            setEditState({ ...editState, value: r });
                                            setShowRoleDropdown(false);
                                        }}
                                        className={`flex items-center gap-2 w-full px-3 py-2 text-[12px] font-medium text-left border-none cursor-pointer transition-colors ${
                                            editState.value === r ? 'bg-amber-50 text-amber-700 font-bold' : 'bg-white text-slate-600 hover:bg-slate-50'
                                        }`}
                                    >
                                        <span style={{ color: ROLE_MAP[r]?.color }}>{ROLE_MAP[r]?.icon}</span>
                                        {ROLE_MAP[r]?.label}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                );
            }

            return (
                <input
                    autoFocus
                    type={field === 'password' ? 'password' : 'text'}
                    value={editState.value}
                    onChange={e => setEditState({ ...editState, value: e.target.value })}
                    onKeyDown={e => { if (e.key === 'Enter') handleSave(); if (e.key === 'Escape') setEditState(null); }}
                    placeholder={field === 'password' ? '새 비밀번호 (6자 이상)' : ''}
                    className="w-full px-2 py-1 border border-amber-400 rounded-lg text-[12px] font-medium text-slate-700 outline-none focus:ring-2 focus:ring-amber-500/20 bg-white"
                />
            );
        }

        if (field === 'password') {
            return (
                <button
                    onClick={() => setEditState({ userId: user.id, field: 'password', value: '' })}
                    className="flex items-center gap-1 text-[11px] font-bold text-slate-500 hover:text-amber-600 bg-slate-50 hover:bg-amber-50 border border-slate-200 hover:border-amber-300 rounded-lg px-2.5 py-1 cursor-pointer transition-all"
                >
                    <Key className="w-3 h-3" /> 비밀번호 변경
                </button>
            );
        }

        if (field === 'role') {
            const rm = ROLE_MAP[currentValue];
            return (
                <button
                    onClick={() => { setEditState({ userId: user.id, field, value: currentValue }); setShowRoleDropdown(false); }}
                    className="group flex items-center gap-1.5 cursor-pointer bg-transparent border-none p-0"
                >
                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] font-bold border"
                        style={{
                            color: rm?.color || '#64748b',
                            backgroundColor: `${rm?.color || '#64748b'}10`,
                            borderColor: `${rm?.color || '#64748b'}30`,
                        }}
                    >
                        {rm?.icon} {rm?.label || currentValue}
                    </span>
                    <Edit3 className="w-3 h-3 text-slate-300 group-hover:text-amber-500 transition-colors" />
                </button>
            );
        }

        return (
            <button
                onClick={() => setEditState({ userId: user.id, field, value: currentValue })}
                className="group flex items-center gap-1.5 cursor-pointer bg-transparent border-none p-0 text-left"
            >
                <span className="text-[13px] font-medium text-slate-700">{currentValue || '—'}</span>
                <Edit3 className="w-3 h-3 text-slate-300 group-hover:text-amber-500 transition-colors shrink-0" />
            </button>
        );
    };

    // ── 시간 포맷 ────────────────────────────────────────────────
    const formatDate = (d: string | null) => {
        if (!d) return '—';
        return new Date(d).toLocaleDateString('ko-KR', { year: 'numeric', month: '2-digit', day: '2-digit' });
    };

    const formatDateTime = (d: string | null) => {
        if (!d) return '없음';
        const dt = new Date(d);
        return dt.toLocaleDateString('ko-KR', { month: '2-digit', day: '2-digit' }) + ' ' +
               dt.toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' });
    };

    return (
        <div className="min-h-screen bg-slate-50 font-sans text-slate-800">
            {/* 토스트 */}
            {toast && (
                <div className={`fixed top-4 right-4 z-[200] px-4 py-3 rounded-xl shadow-lg text-[13px] font-bold flex items-center gap-2 transition-all animate-in fade-in ${
                    toast.type === 'success' ? 'bg-emerald-50 text-emerald-700 border border-emerald-200' : 'bg-red-50 text-red-700 border border-red-200'
                }`}>
                    {toast.type === 'success' ? <CheckCircle2 className="w-4 h-4" /> : <AlertTriangle className="w-4 h-4" />}
                    {toast.message}
                </div>
            )}

            {/* 헤더 */}
            <div className="sticky top-0 z-[100] bg-white/90 backdrop-blur-md border-b border-slate-200 px-6 h-[60px] flex items-center justify-between shadow-sm">
                <div className="flex items-center gap-3">
                    <Link href="/employee">
                        <button className="text-[13px] text-slate-500 hover:text-slate-800 transition-colors bg-transparent border-none cursor-pointer font-medium">← 돌아가기</button>
                    </Link>
                    <div className="w-px h-4 bg-slate-200" />
                    <span className="text-[15px] font-black text-slate-800 flex items-center gap-2">
                        <Shield className="w-4 h-4 text-red-500" /> 계정 관리
                    </span>
                    <span className="text-[11px] font-bold text-red-600 bg-red-50 border border-red-200 py-0.5 px-2 rounded-full">Super Admin</span>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={fetchUsers}
                        className="flex items-center gap-1.5 bg-slate-50 hover:bg-slate-100 text-slate-600 border border-slate-200 rounded-lg py-1.5 px-3.5 cursor-pointer text-[13px] font-semibold transition-colors">
                        <RotateCcw className="w-3.5 h-3.5" /> 새로고침
                    </button>
                    {editState && (
                        <>
                            <button onClick={() => { setEditState(null); setShowRoleDropdown(false); }}
                                className="flex items-center gap-1.5 bg-slate-50 hover:bg-slate-100 text-slate-600 border border-slate-200 rounded-lg py-1.5 px-3.5 cursor-pointer text-[13px] font-semibold transition-colors">
                                <X className="w-3.5 h-3.5" /> 취소
                            </button>
                            <button onClick={handleSave} disabled={saving}
                                className="flex items-center gap-1.5 bg-gradient-to-r from-amber-500 to-amber-600 hover:from-amber-600 hover:to-amber-700 text-white border-none rounded-lg py-1.5 px-4 cursor-pointer text-[13px] font-bold shadow-sm transition-all disabled:opacity-50">
                                <Save className="w-3.5 h-3.5" /> {saving ? '저장 중...' : '저장'}
                            </button>
                        </>
                    )}
                </div>
            </div>

            {/* 메인 */}
            <div className="max-w-[1400px] mx-auto py-8 px-6">
                {/* 검색 + 탭 필터 */}
                <div className="bg-white border border-slate-200 rounded-2xl shadow-sm mb-6 overflow-hidden">
                    {/* 검색 바 */}
                    <div className="p-4 border-b border-slate-100">
                        <div className="relative max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                value={search}
                                onChange={e => setSearch(e.target.value)}
                                placeholder="이름 또는 이메일로 검색..."
                                className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl text-[13px] font-medium text-slate-700 outline-none focus:ring-2 focus:ring-amber-500/20 focus:border-amber-400 transition-all bg-slate-50"
                            />
                        </div>
                    </div>
                    {/* 역할 탭 */}
                    <div className="flex items-center gap-1 px-4 py-2 overflow-x-auto">
                        {/* 전체 탭 */}
                        <button
                            onClick={() => setRoleFilter('all')}
                            className={`flex items-center gap-1.5 px-3.5 py-2 rounded-lg text-[13px] font-bold border-none cursor-pointer transition-all whitespace-nowrap ${
                                roleFilter === 'all'
                                    ? 'bg-indigo-50 text-indigo-700 ring-1 ring-indigo-200'
                                    : 'bg-transparent text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                            }`}
                        >
                            <Users className="w-3.5 h-3.5" />
                            전체
                            <span className={`text-[11px] font-black px-1.5 py-0.5 rounded-md ${
                                roleFilter === 'all' ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'
                            }`}>{users.filter(u => !search || u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase())).length}</span>
                        </button>

                        <div className="w-px h-5 bg-slate-200 mx-1 shrink-0" />

                        {/* 존재하는 역할별 탭 */}
                        {ALL_ROLES.filter(r => users.some(u => u.role === r)).map(r => {
                            const rm = ROLE_MAP[r];
                            const count = users.filter(u => u.role === r && (!search || u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase()))).length;
                            const isActive = roleFilter === r;
                            return (
                                <button
                                    key={r}
                                    onClick={() => setRoleFilter(r)}
                                    className={`flex items-center gap-1.5 px-3 py-2 rounded-lg text-[13px] font-bold border-none cursor-pointer transition-all whitespace-nowrap ${
                                        isActive
                                            ? 'ring-1 ring-opacity-40'
                                            : 'bg-transparent text-slate-500 hover:bg-slate-50 hover:text-slate-700'
                                    }`}
                                    style={isActive ? {
                                        backgroundColor: `${rm.color}10`,
                                        color: rm.color,
                                        // @ts-ignore
                                        '--tw-ring-color': `${rm.color}60`,
                                    } : undefined}
                                >
                                    <span style={{ color: isActive ? rm.color : undefined }}>{rm.icon}</span>
                                    {rm.label}
                                    <span className={`text-[11px] font-black px-1.5 py-0.5 rounded-md ${
                                        isActive ? 'bg-white/60' : 'bg-slate-100 text-slate-500'
                                    }`} style={isActive ? { color: rm.color } : undefined}>{count}</span>
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* 에러/로딩 */}
                {error && (
                    <div className="bg-red-50 border border-red-200 rounded-xl px-5 py-4 text-[13px] font-bold text-red-700 flex items-center gap-2 mb-6">
                        <AlertTriangle className="w-4 h-4" /> {error}
                    </div>
                )}

                {loading ? (
                    <div className="bg-white border border-slate-200 rounded-2xl p-20 shadow-sm flex flex-col items-center justify-center gap-3">
                        <div className="w-8 h-8 border-3 border-amber-500 border-t-transparent rounded-full animate-spin" />
                        <span className="text-[13px] font-bold text-slate-500">계정 목록을 불러오는 중...</span>
                    </div>
                ) : (
                    /* 유저 테이블 */
                    <div className="bg-white border border-slate-200 rounded-2xl shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-slate-50/80 border-b border-slate-200">
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[180px]">이름</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[220px]">이메일</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[130px]">역할</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[150px]">소속</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[100px]">가입일</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[120px]">최근 로그인</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[130px]">비밀번호</th>
                                        <th className="p-4 text-xs font-bold text-slate-500 w-[60px] text-right">삭제</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {filtered.length === 0 ? (
                                        <tr>
                                            <td colSpan={8} className="p-12 text-center text-[13px] font-medium text-slate-400">
                                                검색 결과가 없습니다.
                                            </td>
                                        </tr>
                                    ) : (
                                        filtered.map(user => (
                                            <tr key={user.id} className="hover:bg-slate-50/60 transition-colors">
                                                <td className="p-4">
                                                    <EditableCell user={user} field="name" currentValue={user.name} />
                                                </td>
                                                <td className="p-4">
                                                    <EditableCell user={user} field="email" currentValue={user.email} />
                                                </td>
                                                <td className="p-4">
                                                    <EditableCell user={user} field="role" currentValue={user.role} />
                                                </td>
                                                <td className="p-4">
                                                    <EditableCell user={user} field="companyName" currentValue={user.companyName} />
                                                </td>
                                                <td className="p-4">
                                                    <span className="text-[12px] font-medium text-slate-500">{formatDate(user.createdAt)}</span>
                                                </td>
                                                <td className="p-4">
                                                    <span className={`text-[12px] font-medium ${user.lastSignIn ? 'text-emerald-600' : 'text-slate-400'}`}>
                                                        {formatDateTime(user.lastSignIn)}
                                                    </span>
                                                </td>
                                                <td className="p-4">
                                                    <EditableCell user={user} field="password" currentValue="" />
                                                </td>
                                                <td className="p-4 text-right">
                                                    {deleteConfirm === user.id ? (
                                                        <div className="flex items-center gap-1 justify-end">
                                                            <button onClick={() => handleDelete(user.id)}
                                                                className="text-[11px] font-bold text-white bg-red-500 hover:bg-red-600 border-none rounded-lg px-2.5 py-1 cursor-pointer transition-colors">
                                                                확인
                                                            </button>
                                                            <button onClick={() => setDeleteConfirm(null)}
                                                                className="text-[11px] font-bold text-slate-500 bg-slate-100 hover:bg-slate-200 border-none rounded-lg px-2.5 py-1 cursor-pointer transition-colors">
                                                                취소
                                                            </button>
                                                        </div>
                                                    ) : (
                                                        <button
                                                            onClick={() => setDeleteConfirm(user.id)}
                                                            className="p-1.5 rounded-lg border-none cursor-pointer bg-transparent hover:bg-red-50 text-slate-300 hover:text-red-500 transition-colors"
                                                            title="계정 삭제"
                                                        >
                                                            <Trash2 className="w-4 h-4" />
                                                        </button>
                                                    )}
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';
import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Bot, User, Loader2, Scale, Brain, Briefcase, ArrowRight } from 'lucide-react';
import { getPromptConfig } from '@/lib/prompts/privacy';

interface Message { role: 'user' | 'assistant'; content: string; }

const CONSULT_TYPES = [
    { id: 'legal', icon: Scale, label: '법률 상담', color: '#b8860b', bg: '#fef3c7', desc: '계약·가맹·노동·형사' },
    // { id: 'eap', icon: Brain, label: '심리/EAP', color: '#7c3aed', bg: '#ede9fe', desc: '스트레스·감정·위기' },
    // { id: 'business', icon: Briefcase, label: '경영 자문', color: '#059669', bg: '#d1fae5', desc: '노무·공정거래·내규' },
];

export default function ChatPage() {
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const [consultType, setConsultType] = useState('general');
    const [step, setStep] = useState<'select' | 'chat'>('select');
    const [caseId] = useState(() => `IBS-${new Date().getFullYear()}-${String(Math.random()).slice(2, 8)}`);
    const bottomRef = useRef<HTMLDivElement>(null);

    useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

    const selectType = async (type: string) => {
        setConsultType(type);
        setStep('chat');
        setLoading(true);
        try {
            const res = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ 
                    messages: [], 
                    consultType: type,
                    systemPrompt: getPromptConfig().chatFullPrompt 
                }),
            });
            const data = await res.json();
            setMessages([{ role: 'assistant', content: data.message }]);
        } catch { setMessages([{ role: 'assistant', content: '안녕하세요. 어떤 도움이 필요하신가요?' }]); }
        setLoading(false);
    };

    const send = async () => {
        if (!input.trim() || loading) return;
        const userMsg: Message = { role: 'user', content: input };
        const newMsgs = [...messages, userMsg];
        setMessages(newMsgs);
        setInput('');
        setLoading(true);
        try {
            const res = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'content-type': 'application/json' },
                body: JSON.stringify({ 
                    messages: newMsgs, 
                    consultType,
                    systemPrompt: getPromptConfig().chatFullPrompt 
                }),
            });
            const data = await res.json();
            setMessages(prev => [...prev, { role: 'assistant', content: data.message }]);
        } catch { setMessages(prev => [...prev, { role: 'assistant', content: '죄송합니다. 일시적 오류가 발생했습니다.' }]); }
        setLoading(false);
    };

    return (
        <div className="min-h-screen pt-20" style={{ background: '#f8f7f4' }}>
            <div className="max-w-3xl mx-auto px-4 pb-8">
                {/* 헤더 */}
                <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="text-center py-8">
                    <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full mb-4"
                        style={{ background: '#fef3c7', border: '1px solid #fde68a' }}>
                        <Bot className="w-4 h-4" style={{ color: '#92400e' }} />
                        <span className="text-xs font-bold" style={{ color: '#92400e' }}>법률 어시스턴트</span>
                    </div>
                    <h1 className="text-3xl font-black mb-2" style={{ color: '#111827' }}>
                        법률 상담
                    </h1>
                    <p className="text-sm" style={{ color: '#6b7280' }}>
                        접수번호: <span className="font-mono font-bold" style={{ color: '#b8860b' }}>{caseId}</span>
                    </p>
                </motion.div>

                {step === 'select' && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="grid gap-4">
                        <p className="text-center text-sm mb-2 font-medium" style={{ color: '#6b7280' }}>상담 분야를 선택해 주세요</p>
                        {CONSULT_TYPES.map(({ id, icon: Icon, label, color, bg, desc }) => (
                            <motion.button key={id} whileHover={{ scale: 1.02, y: -2 }} whileTap={{ scale: 0.98 }}
                                onClick={() => selectType(id)}
                                className="flex items-center gap-5 p-6 rounded-2xl text-left transition-all"
                                style={{ background: '#fff', border: '1px solid #e8e5de', boxShadow: '0 1px 3px rgba(0,0,0,0.04)' }}>
                                <div className="p-3.5 rounded-xl" style={{ background: bg }}>
                                    <Icon className="w-6 h-6" style={{ color }} />
                                </div>
                                <div className="flex-1">
                                    <div className="font-black text-base" style={{ color: '#111827' }}>{label}</div>
                                    <div className="text-sm mt-0.5" style={{ color: '#6b7280' }}>{desc}</div>
                                </div>
                                <ArrowRight className="w-5 h-5" style={{ color: '#d1d5db' }} />
                            </motion.button>
                        ))}
                        <div className="text-center mt-4">
                            <p className="text-xs" style={{ color: '#9ca3af' }}>
                                🔒 모든 상담 내용은 암호화되어 보관됩니다
                            </p>
                        </div>
                    </motion.div>
                )}

                {step === 'chat' && (
                    <div className="rounded-2xl overflow-hidden" style={{ border: '1px solid #e8e5de', background: '#fff' }}>
                        {/* 채팅 헤더 */}
                        <div className="px-6 py-4 flex items-center gap-3" style={{ borderBottom: '1px solid #e8e5de', background: '#fafaf8' }}>
                            <div className="w-8 h-8 rounded-full flex items-center justify-center" style={{ background: '#fef3c7' }}>
                                <Bot className="w-4 h-4" style={{ color: '#92400e' }} />
                            </div>
                            <div>
                                <div className="font-bold text-sm" style={{ color: '#111827' }}>IBS 어시스턴트</div>
                                <div className="text-xs flex items-center gap-1" style={{ color: '#16a34a' }}>
                                    <span className="w-1.5 h-1.5 rounded-full bg-green-500 inline-block" />
                                    온라인
                                </div>
                            </div>
                            <div className="ml-auto text-xs font-medium px-2.5 py-1 rounded-full"
                                style={{ background: '#f3f4f6', color: '#374151' }}>
                                {CONSULT_TYPES.find(t => t.id === consultType)?.label || '일반 상담'}
                            </div>
                        </div>

                        {/* 메시지 목록 */}
                        <div className="h-96 overflow-y-auto p-6 space-y-4" style={{ background: '#fafaf8' }}>
                            <AnimatePresence>
                                {messages.map((msg, i) => (
                                    <motion.div key={i} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                                        className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                                        <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center`}
                                            style={{ background: msg.role === 'user' ? '#fef3c7' : '#ede9fe' }}>
                                            {msg.role === 'user'
                                                ? <User className="w-4 h-4" style={{ color: '#92400e' }} />
                                                : <Bot className="w-4 h-4" style={{ color: '#7c3aed' }} />}
                                        </div>
                                        <div className={`max-w-[80%] px-4 py-3 rounded-2xl text-sm whitespace-pre-line leading-relaxed ${msg.role === 'user' ? 'rounded-tr-sm' : 'rounded-tl-sm'
                                            }`} style={{
                                                background: msg.role === 'user' ? '#111827' : '#fff',
                                                color: msg.role === 'user' ? '#fef3c7' : '#374151',
                                                border: `1px solid ${msg.role === 'user' ? '#111827' : '#e8e5de'}`,
                                            }}>
                                            {msg.content}
                                        </div>
                                    </motion.div>
                                ))}
                                {loading && (
                                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex gap-3">
                                        <div className="w-8 h-8 rounded-full flex items-center justify-center" style={{ background: '#ede9fe' }}>
                                            <Bot className="w-4 h-4" style={{ color: '#7c3aed' }} />
                                        </div>
                                        <div className="px-4 py-3 rounded-2xl rounded-tl-sm" style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                                            <Loader2 className="w-4 h-4 animate-spin" style={{ color: '#7c3aed' }} />
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                            <div ref={bottomRef} />
                        </div>

                        {/* 입력창 */}
                        <div className="p-4" style={{ borderTop: '1px solid #e8e5de' }}>
                            <div className="flex gap-3">
                                <input
                                    value={input}
                                    onChange={e => setInput(e.target.value)}
                                    onKeyDown={e => e.key === 'Enter' && !e.shiftKey && send()}
                                    placeholder="메시지를 입력하세요..."
                                    className="flex-1 px-4 py-3 rounded-xl text-sm outline-none"
                                    style={{ background: '#f3f4f6', border: '1px solid #e8e5de', color: '#111827' }}
                                />
                                <button onClick={send} disabled={loading || !input.trim()}
                                    className="px-4 py-3 rounded-xl transition-all disabled:opacity-30"
                                    style={{ background: '#111827', color: '#fff' }}>
                                    <Send className="w-4 h-4" />
                                </button>
                            </div>
                            <p className="text-center text-xs mt-3" style={{ color: '#9ca3af' }}>
                                자동 답변은 참고용이며, 최종 법률 판단은 담당 변호사가 제공합니다
                            </p>
                        </div>
                    </div>
                )}

                {/* 안내 박스 */}
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1, transition: { delay: 0.4 } }}
                    className="mt-6 p-5 rounded-2xl grid grid-cols-3 gap-4"
                    style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                    {[
                        { icon: '⚡', label: '빠른 접수', desc: '24시간 접수' },
                        { icon: '🔒', label: '보안 보장', desc: '암호화 처리' },
                        { icon: '📞', label: '전문가 연결', desc: '48h 내 답변' },
                    ].map(({ icon, label, desc }) => (
                        <div key={label} className="text-center">
                            <div className="text-2xl mb-1">{icon}</div>
                            <div className="text-xs font-bold" style={{ color: '#111827' }}>{label}</div>
                            <div className="text-xs" style={{ color: '#9ca3af' }}>{desc}</div>
                        </div>
                    ))}
                </motion.div>
            </div>
        </div>
    );
}

import React from 'react';
