        }
        return `해당 조항(${lawRef})의 구체적인 제정 내용은 개인정보보호법 원문을 참고하시기 바랍니다.`;
    };

    useEffect(() => {
        setCategories(getScenarioCategories());
        
        if (leadId) {
            supabaseCompanyStore.getById(leadId).then((data: any) => {
