            ) : (
                <>
                    {clauses.map((c, i) => {
                        const col = R[c.level];
                        const hasIssue = c.level !== 'OK';
                        return (
                            <div key={i} className="print-row" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', borderBottom: '2px solid #d1d5db' }}>
