                                        <div style={{ padding: '14px 16px', fontSize: 12, color: '#44403c', lineHeight: 1.8, whiteSpace: 'pre-line', background: '#fffbeb' }}>
                                            {c.lawText || '법조문 텍스트가 전달되지 않았습니다.'}
                                        </div>
                                    </div>
                                    
                                    {/* 2. 회사 원문 (비교 대상) */}
                                    <div style={{ background: '#ffffff', borderRadius: 8, border: '1px solid #e5e7eb', overflow: 'hidden', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' }}>
                                        <div style={{ background: '#f1f5f9', borderBottom: '1px solid #e2e8f0', padding: '10px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                                <FileText size={15} color="#475569" />
                                                <span style={{ fontWeight: 800, fontSize: 13, color: '#334155' }}>고객사 방침 원문</span>
                                            </div>
                                            <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 10px', borderRadius: 20, background: col.tag, color: col.text, border: `1px solid ${col.border}` }}>
                                                {c.title || c.num}
                                            </span>
                                        </div>
                                        <div style={{ padding: '14px 16px', fontSize: 13, color: '#1e293b', lineHeight: 1.8, whiteSpace: 'pre-line' }}>
                                            {c.original || '회사 방침 원본 데이터가 전달되지 않았습니다.'}
                                        </div>
                                    </div>
                                </div>
                                {/* 우: 수정완본 (의견서 스타일) */}
                                <div style={{ background: '#f9fafb' }}>
                                    {i === 0 && (
                                        <div style={{ background: '#0f172a', padding: '14px 18px', color: '#fff' }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                                <div>
                                                    <div style={{ fontSize: 15, fontWeight: 900, color: '#c9a84c' }}>⚖️ IBS 법률사무소</div>
                                                    <div style={{ fontSize: 10, color: '#94a3b8' }}>개인정보보호 전문 법률 의견서</div>
                                                </div>
                                                <div style={{ textAlign: 'right', fontSize: 10, color: '#94a3b8' }}>
                                                    <div>문서번호: IBS-PR-{new Date().getFullYear()}-{String(Math.floor(Math.random() * 1000)).padStart(3, '0')}</div>
                                                    <div>작성일: {new Date().toLocaleDateString('ko-KR')}</div>
                                                </div>
                                            </div>
                                            <div style={{ marginTop: 8, fontSize: 12, color: '#e2e8f0' }}>
                                                수신: <strong>{company}</strong> 귀중
                                            </div>
                                        </div>
                                    )}
                                    <FullRevisionRow c={c} data={data} onChange={upd} />
                                </div>
                            </div>
                        );
                    })}
                    {/* 서명란 (우측에만) */}
                    <div className="print-row" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr' }}>
                        <div style={{ background: '#fafafa', borderRight: '1px solid #e5e7eb' }} />
                        <div style={{ padding: '20px 18px', background: '#fff', borderTop: '2px solid #e5e7eb' }}>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontSize: 13, color: '#374151', marginBottom: 4 }}>위와 같이 검토 의견을 제출합니다.</div>
                                <div style={{ fontSize: 15, fontWeight: 900, color: '#1e293b', marginBottom: 2 }}>IBS 법률사무소</div>
                                <div style={{ fontSize: 13, fontWeight: 700, color: '#374151' }}>담당 변호사: 김수현</div>
                                <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 4 }}>대한변호사협회 등록 | 개인정보관리사(CPPG)</div>
                            </div>
                        </div>
                    </div>
                </>
            )}

            {/* 추가 자료 요청 모달 */}
            <AnimatePresence>
                {requestModalOpen && (
                    <div className="no-print" style={{ position: 'fixed', inset: 0, zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setRequestModalOpen(false)}
                            style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(2px)' }}
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 10 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 10 }}
                            style={{ position: 'relative', width: 440, background: '#fff', borderRadius: 16, boxShadow: '0 10px 40px rgba(0,0,0,0.2)', overflow: 'hidden' }}
                        >
                            <div style={{ padding: '20px 24px', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#f8fafc' }}>
                                <h3 style={{ margin: 0, fontSize: 16, fontWeight: 800, color: '#0f172a', display: 'flex', alignItems: 'center', gap: 6 }}>
                                    <FilePlus size={18} color="#2563eb" />
                                    추가 자료 요청
                                </h3>
                                <button onClick={() => setRequestModalOpen(false)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: '#64748b' }}>
                                    <X size={20} />
                                </button>
                            </div>
                            <div style={{ padding: 24 }}>
                                <div style={{ fontSize: 13, fontWeight: 700, color: '#334155', marginBottom: 12 }}>요청할 누락 서류 선택 (다중 선택 가능)</div>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 20 }}>
                                    {[
                                        { id: 'contract', label: '근로계약서' },
                                        { id: 'rules', label: '취업규칙' },
                                        { id: 'security', label: '보안서약서' },
                                        { id: 'other', label: '기타 추가 문서' },
                                    ].map(item => (
                                        <label key={item.id} style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 13, color: '#1e293b', cursor: 'pointer' }}>
                                            <input type="checkbox" checked={(docsList as any)[item.id]} onChange={e => setDocsList(p => ({ ...p, [item.id]: e.target.checked }))} style={{ width: 16, height: 16, accentColor: '#2563eb' }} />
                                            {item.label}
                                        </label>
                                    ))}
                                </div>
                                
                                <div style={{ fontSize: 13, fontWeight: 700, color: '#334155', marginBottom: 8 }}>추가 요청 메시지</div>
                                <textarea
                                    value={customReqMsg}
                                    onChange={e => setCustomReqMsg(e.target.value)}
                                    placeholder="고객사에 전달할 상세 요청사항을 입력하세요..."
                                    style={{ width: '100%', height: 100, padding: 12, border: '1px solid #cbd5e1', borderRadius: 8, fontSize: 13, color: '#1e293b', resize: 'none', outline: 'none', fontFamily: 'inherit', boxSizing: 'border-box' }}
                                />
                            </div>
                            <div style={{ padding: '16px 24px', borderTop: '1px solid #e2e8f0', display: 'flex', justifyContent: 'flex-end', gap: 10, background: '#f8fafc' }}>
                                <button onClick={() => setRequestModalOpen(false)} style={{ padding: '8px 16px', border: '1px solid #cbd5e1', background: '#fff', color: '#475569', borderRadius: 6, fontSize: 13, fontWeight: 700, cursor: 'pointer' }}>취소</button>
                                <button
                                    onClick={handleSendRequest}
                                    disabled={requestingFiles}
                                    style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 20px', border: 'none', background: '#2563eb', color: '#fff', borderRadius: 6, fontSize: 13, fontWeight: 700, cursor: requestingFiles ? 'not-allowed' : 'pointer' }}
                                >
                                    {requestingFiles ? <Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> : <FilePlus size={16} />}
                                    {requestingFiles ? '발송 중...' : '요청 발송'}
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            {/* Toast 알림 */}
            <AnimatePresence>
                {toastMsg && (
                    <motion.div
                        className="no-print"
                        initial={{ opacity: 0, y: 50, x: '-50%' }}
                        animate={{ opacity: 1, y: 0, x: '-50%' }}
                        exit={{ opacity: 0, y: 50, x: '-50%' }}
                        style={{ position: 'fixed', bottom: 40, left: '50%', background: '#1e293b', color: '#fff', padding: '14px 24px', borderRadius: 8, fontSize: 14, fontWeight: 700, zIndex: 10000, boxShadow: '0 4px 12px rgba(0,0,0,0.15)', display: 'flex', alignItems: 'center', gap: 8 }}
                    >
                        <CheckCircle2 size={18} color="#4ade80" />
                        {toastMsg}
                    </motion.div>
                )}
            </AnimatePresence>

            {/* 추가 자료 요청 FAB */}
            <button
                className="no-print"
                onClick={() => setRequestModalOpen(true)}
                style={{
                    position: 'fixed', right: 32, bottom: 32, zIndex: 9000,
                    display: 'flex', alignItems: 'center', gap: 8,
                    background: '#0f172a', color: '#fff', border: 'none', borderRadius: 30,
                    padding: '14px 24px', fontSize: 15, fontWeight: 800, cursor: 'pointer',
                    boxShadow: '0 8px 24px rgba(15, 23, 42, 0.3)',
                    transition: 'transform 0.2s',
                }}
                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.05)'}
                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
            >
                <FilePlus size={18} />
                추가 자료 요청
            </button>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/lib/AuthContext';
import { supabaseCompanyStore } from '@/lib/supabaseStore';
import { claimCompany, releaseCompany, getRemainingMinutes } from '@/lib/callQueueService';
import { useTimer, CALLABLE } from '@/lib/callPageUtils';
import type { Company, Issue } from '@/lib/types';
import type { CallLock } from '@/lib/types';
import { useCallLocks } from '@/hooks/useCallLocks';
import ScriptTab from '@/components/sales/call/ScriptTab';
import styles from './sales-queue.module.css';

const GOAL_CALLS = 30;

export default function SalesQueuePage() {
    const { user } = useAuth();
    const { locks } = useCallLocks(); // Get real-time locks
    const [companies, setCompanies] = useState<Company[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeCall, setActiveCall] = useState<Company | null>(null);
    const [queueOpen, setQueueOpen] = useState(true);
    const [memoText, setMemoText] = useState("");
    const [toastMsg, setToastMsg] = useState(""); // Toast Message
    const [isEditingContact, setIsEditingContact] = useState(false);
    const [editContactName, setEditContactName] = useState("");

    // Wrap-up state
    const [callState, setCallState] = useState<'calling' | 'wrapup'>('calling');
    const [selectedResult, setSelectedResult] = useState<'연결-메일'|'연결-콜백'|'연결-거절'|'부재중(24h)'|'사이트이상(패스)' | null>(null);

    // Stats for today
    const [stats, setStats] = useState({ connected: 0, missed: 0, callback: 0, rejected: 0, invalid: 0 });

    const { sec, fmt, start, reset, pause } = useTimer();

    const loadData = useCallback(async () => {
        try {
            const rawComps = await supabaseCompanyStore.getAll();
            const comps = rawComps.filter(c => CALLABLE.includes(c.status));

            // Calc stats for today
            const todayStr = new Date().toISOString().split('T')[0];
            let c = 0, m = 0, cb = 0, rj = 0, inv = 0;
            comps.forEach(comp => {
                if (comp.lastCallAt && comp.lastCallAt.startsWith(todayStr) && comp.lastCalledBy === user?.name) {
                    if (comp.lastCallResult === 'connected') c++;
                    else if (comp.lastCallResult === 'no_answer') m++;
                    else if (comp.lastCallResult === 'callback') cb++;
                    else if (comp.lastCallResult === 'rejected') rj++;
                    else if (comp.lastCallResult === 'invalid_site') inv++;
                }
            });
            setStats({ connected: c, missed: m, callback: cb, rejected: rj, invalid: inv });

            // Sort by not called today first, then riskScore DESC
            const uncalled = comps.filter(comp => {
                const calledToday = comp.lastCallAt && comp.lastCallAt.startsWith(todayStr);
                return !calledToday;
            });

            const sorted = uncalled.sort((a, b) => (b.riskScore || 0) - (a.riskScore || 0));
            setCompanies(sorted);
        } catch (e) {
            console.error('Failed to load queue data', e);
        } finally {
            setLoading(false);
        }
    }, [user?.name]);

    useEffect(() => {
        loadData();
        const int = setInterval(loadData, 30000); // 30s auto refresh back to normal
        return () => clearInterval(int);
    }, [loadData]);

    // 새로고침/재진입 시 본인이 잡고 있는 Lock이 있다면 화면 복구(Auto-resume)
    useEffect(() => {
        if (!user || activeCall || companies.length === 0 || locks.length === 0) return;

        const myLock = locks.find(l => l.userId === user.id);
        if (myLock) {
            const c = companies.find(comp => comp.id === myLock.companyId);
            if (c) {
                supabaseCompanyStore.getById(c.id).then(fullC => {
                    setActiveCall(fullC || c);
                    setCallState('calling');
                    setSelectedResult(null);
                    setToastMsg('기존에 진행 중이던 통화 화면을 복구했습니다.');
                    setTimeout(() => setToastMsg(''), 3000);
                    setEditContactName(c.contactName || '');
                    setIsEditingContact(false);
                    reset();
                    start();
                });
            }
        }
    }, [user, activeCall, companies, locks, reset, start]);

    const handleNextCall = async (retryCount = 0) => {
        if (!user) {
            alert('로그인이 필요합니다.');
            return;
        }
        if (retryCount >= 5) {
            alert('현재 연결 가능한 대기열이 없습니다. 나중에 다시 시도해주세요.');
            return;
        }

        const lockedIds = new Set(locks.map(l => l.companyId));
        const todayStr = new Date().toISOString().split('T')[0];

        // 1. Find best candidate locally
        const candidate = companies.find(c => {
            const calledToday = c.lastCallAt && c.lastCallAt.startsWith(todayStr);
            return !calledToday && !lockedIds.has(c.id);
        });

        if (!candidate) {
            alert('전화할 대기열 회사가 없습니다.');
            return;
        }

        let finalCandidate = candidate;
        // 2. Verify candidate with server to prevent double-calling freshly completed calls
        try {
            const freshCandidate = await supabaseCompanyStore.getById(candidate.id);
            if (freshCandidate) {
                if (freshCandidate.lastCallAt && freshCandidate.lastCallAt.startsWith(todayStr)) {
                    // Someone else just finished calling this company!
                    setCompanies(prev => prev.filter(c => c.id !== freshCandidate.id));
                    return handleNextCall(retryCount + 1);
                }
                finalCandidate = freshCandidate;
            }
        } catch (e) {
            console.error('Candidate verification failed', e);
        }

        try {
            const res = await claimCompany(candidate.id, user.id, user.name || '영업팀');
            if (res.success) {
                setActiveCall(finalCandidate);
                setCallState('calling');
                setSelectedResult(null);
                setMemoText("");
                setEditContactName(candidate.contactName || '');
                setIsEditingContact(false);
                reset(); // Reset timer
                start(); // Start timer
            } else {
                // Already locked, try next
                handleNextCall(retryCount + 1);
            }
        } catch (e) {
            console.error('Claim error', e);
            handleNextCall(retryCount + 1);
        }
    };

    const handleSaveContact = async () => {
        if (!activeCall) return;
        try {
            await supabaseCompanyStore.update(activeCall.id, { contactName: editContactName });
            setActiveCall({ ...activeCall, contactName: editContactName });
            setIsEditingContact(false);

            // Also update the queue state to reflect new contact
            setCompanies(prev => prev.map(c => c.id === activeCall.id ? { ...c, contactName: editContactName } : c));

            setToastMsg('담당자 명이 수정되었습니다.');
            setTimeout(() => setToastMsg(''), 3000);
        } catch (e) {
            console.error(e);
            alert('담당자명 수정 중 오류가 발생했습니다.');
        }
    };

    const cancelCall = async () => {
        if (!activeCall || !user) return;

        try {
            // 통화 결과 저장 없이 단순히 Lock만 해제 (취소)
            await releaseCompany(activeCall.id, user.id).catch(() => {});
            setActiveCall(null);
            setCallState('calling');
            setSelectedResult(null);
            setMemoText("");
            reset();

            setToastMsg('통화가 취소되고 대기열로 복귀했습니다.');
            setTimeout(() => setToastMsg(''), 3000);
            await loadData();
        } catch (e) {
            console.error(e);
            alert('취소 처리 중 오류가 발생했습니다.');
        }
    };

    const handleResult = (result: '연결-메일'|'연결-콜백'|'연결-거절'|'부재중(24h)'|'사이트이상(패스)', nextAction?: 'review'|'memo') => {
        pause(); // Stop timer
        setSelectedResult(result);
        setCallState('wrapup');

        if (nextAction === 'memo') {
            document.getElementById('queue-memo-input')?.focus();
        } else if (result === '연결-메일') {
            setToastMsg('✅ 검토 요청이 등록되었습니다.');
            setMemoText(prev => prev ? prev + '\n[변호사 검토 요청]' : '[변호사 검토 요청]');
        }

        if (result === '사이트이상(패스)') {
            // instant complete can be done by user clicking save, but focus button so user just hits enter!
            document.querySelector<HTMLButtonElement>('.' + styles.saveWrapupBtn)?.focus();
        }
    };

    const finishCall = async () => {
        if (!activeCall || !user || !selectedResult) return;

        try {
            // Un-claim
            await releaseCompany(activeCall.id, user.id).catch(() => {});

            let callRes: 'connected'|'no_answer'|'callback'|'rejected'|'invalid_site' = 'connected';
            if (selectedResult === '부재중(24h)') callRes = 'no_answer';
            else if (selectedResult === '연결-콜백') callRes = 'callback';
            else if (selectedResult === '연결-거절') callRes = 'rejected';
            else if (selectedResult === '사이트이상(패스)') callRes = 'invalid_site';

            const payload: Partial<Company> = {
                lastCallResult: callRes,
                lastCallAt: new Date().toISOString(),
                lastCalledBy: user.name,
                callAttempts: (activeCall.callAttempts || 0) + 1,
            };

            if (selectedResult === '연결-메일' && activeCall.status === 'analyzed') {
                payload.status = 'reviewing';
            }

            // 자동 콜백 24시간 처리
            if (callRes === 'no_answer' || callRes === 'callback') {
                const tomorrow = new Date();
                tomorrow.setHours(tomorrow.getHours() + 24);
                payload.callbackScheduledAt = tomorrow.toISOString();
            }

            // Also append a memo if needed, optional
            if (memoText.trim()) {
                const newMemo = {
                    id: Math.random().toString(36).substring(7),
                    createdAt: new Date().toISOString(),
                    author: user.name,
                    content: memoText.trim()
                };
                payload.memos = [newMemo, ...(activeCall.memos || [])];

                // Add to timeline
                const newTimeEvent = {
                    id: Math.random().toString(36).substring(7),
                    createdAt: new Date().toISOString(),
                    author: user.name,
                    type: 'call' as const,
                    content: `[결과: ${selectedResult}] ${memoText.trim()}`
