                    <div className="flex items-center gap-2 mb-4">
                        <Target className="w-5 h-5" style={{ color: '#c9a84c' }} />
                        <h2 className="font-black text-base">이번달 목표</h2>
                    </div>
                    <div className="grid grid-cols-3 gap-4">
