'use client';
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import type { Company } from '@/lib/types';
import { useCompanies } from '@/hooks/useDataLayer';
import { CallRecordingStore, type CallRecording } from '@/lib/callRecordingService';
import type { Step } from './_constants';
import { getPhoneList } from './_utils/helpers';
import { useRecording } from './_utils/useRecording';
import SidebarNav from './_components/SidebarNav';
import MobileTabBar from './_components/MobileTabBar';
import PageHeader from './_components/PageHeader';
import ToastNotification from './_components/ToastNotification';
import { CompanyList } from './_components/CompanyList';
import RecordPanel from './_components/RecordPanel';
import ResultPanel from './_components/ResultPanel';

export default function VoiceMemoPage() {
  const [step, setStep] = useState<Step>('select');
  const { companies, mutate: mutateCompanies } = useCompanies();
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Company | null>(null);
  const [callResult, setCallResult] = useState<'connected' | 'no_answer' | 'callback'>('connected');
  const [toast, setToast] = useState('');
  const [showHistory, setShowHistory] = useState(false);
  const [quickMemo, setQuickMemo] = useState('');
  const [showQuickMemo, setShowQuickMemo] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [showInstallBanner, setShowInstallBanner] = useState(false);
  const [recentRecordings, setRecentRecordings] = useState<CallRecording[]>([]);

  const refresh = useCallback(async () => {
    await mutateCompanies();
    setRecentRecordings(CallRecordingStore.getRecent(20));
  }, [mutateCompanies]);

  const { isRecording, elapsed, waveformData, sttStatus, lastRecording, startRecording, stopRecording, resetRecording } =
    useRecording(selected, quickMemo, callResult, setToast, setStep, refresh);

  useEffect(() => { refresh(); }, [refresh]);
  useEffect(() => {
    if (!toast) return;
    const t = setTimeout(() => setToast(''), 3000);
    return () => clearTimeout(t);
  }, [toast]);
  useEffect(() => {
    const h = (e: any) => { e.preventDefault(); setInstallPrompt(e); setShowInstallBanner(true); };
    window.addEventListener('beforeinstallprompt', h);
    return () => window.removeEventListener('beforeinstallprompt', h);
  }, []);
  useEffect(() => {
    const h = (e: StorageEvent) => { if (e.key === 'ibs_call_recordings') refresh(); };
    window.addEventListener('storage', h);
    return () => window.removeEventListener('storage', h);
  }, [refresh]);

  const filtered = useMemo(() => {
    if (!search.trim()) return companies.slice(0, 50);
    const q = search.toLowerCase();
    return companies.filter(c =>
      c.name.toLowerCase().includes(q) || c.biz.includes(q) ||
      (c.contactName || '').includes(q) || (c.contactPhone || '').includes(q) || (c.phone || '').includes(q)
    ).slice(0, 50);
  }, [companies, search]);

  const handleSelect = (co: Company) => {
    setSelected(co); setStep('record');
    resetRecording(); setShowHistory(false); setQuickMemo(''); setShowQuickMemo(false);
  };

  const resetToSelect = () => {
    setStep('select'); setSelected(null); resetRecording();
    setShowHistory(false); setQuickMemo(''); setShowQuickMemo(false); refresh();
  };

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') setToast('홈 화면에 설치되었습니다');
    setInstallPrompt(null); setShowInstallBanner(false);
  };

  const companyRecordings = useMemo(
    () => selected ? recentRecordings.filter(r => r.companyId === selected.id) : [],
    [selected, recentRecordings],
  );

  const lastCallMap = useMemo(() => {
    const map: Record<string, string> = {};
    for (const rec of recentRecordings)
      if (!map[rec.companyId])
        map[rec.companyId] = new Date(rec.createdAt).toLocaleDateString('ko-KR', { month: 'short', day: 'numeric' });
    return map;
  }, [recentRecordings]);

  return (
    <div style={{
      minHeight: 'calc(100dvh - 80px)', background: '#F0F2F5',
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', 'Noto Sans KR', -apple-system, sans-serif",
      display: 'flex', color: '#111827',
    }}>
      <SidebarNav />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
        <PageHeader step={step} selectedName={selected?.name} onBack={resetToSelect} />
        <ToastNotification
          toast={toast} showInstallBanner={showInstallBanner}
          onInstall={handleInstall} onDismissBanner={() => setShowInstallBanner(false)}
        />
        <main style={{ flex: 1, padding: '24px', overflowY: 'auto' }}>
          {step === 'select' && (
            <CompanyList
              filtered={filtered} search={search} setSearch={setSearch}
              lastCallMap={lastCallMap} onSelect={handleSelect}
            />
          )}
          {step === 'record' && selected && (
            <RecordPanel
              selected={selected} isRecording={isRecording} elapsed={elapsed}
              waveformData={waveformData} callResult={callResult} setCallResult={setCallResult}
              quickMemo={quickMemo} setQuickMemo={setQuickMemo}
              showQuickMemo={showQuickMemo} setShowQuickMemo={setShowQuickMemo}
              showHistory={showHistory} setShowHistory={setShowHistory}
              companyRecordings={companyRecordings}
              onStart={startRecording} onStop={stopRecording} getPhoneList={getPhoneList}
            />
          )}
          {step === 'result' && selected && (
            <ResultPanel
              selected={selected} sttStatus={sttStatus} lastRecording={lastRecording}
              callResult={callResult}
              onReRecord={() => { setStep('record'); resetRecording(); }}
              onReset={resetToSelect}
            />
          )}
        </main>
        <MobileTabBar />
      </div>
    </div>
  );
}

'use client';
/**
 * 수퍼로이어(SuperLawyer) 메인 페이지
 * 
 * 2컬럼 레이아웃:
 * - 좌측: 사실관계 입력 패널
 * - 우측: BlockNote 에디터 캔버스
 * - 상단: 툴바 (HWPX 다운로드 등)
 */

import { useState, useCallback } from 'react';
import dynamic from 'next/dynamic';
import FactInputPanel, { FactInputData } from '@/components/superlawyer/FactInputPanel';
import ToolbarActions from '@/components/superlawyer/ToolbarActions';
import { getSession } from '@/lib/auth';
import { DUMMY_OPINION_BLOCKS, DUMMY_METADATA } from '@/lib/superlawyer/dummy-opinion';
import { Block, PartialBlock } from '@blocknote/core';
import './superlawyer.css';

// BlockNote는 SSR에서 동작하지 않으므로 dynamic import
const OpinionEditor = dynamic(
  () => import('@/components/superlawyer/OpinionEditor'),
  { ssr: false }
);

export default function SuperLawyerPage() {
  const [editorBlocks, setEditorBlocks] = useState<Block[]>([]);
  const [isGenerated, setIsGenerated] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [initialBlocks, setInitialBlocks] = useState<PartialBlock[]>([]);
  const [metadata, setMetadata] = useState(DUMMY_METADATA);

  /** AI 의견서 생성 (현재는 더미 데이터 로드) */
  const handleGenerate = useCallback(async (facts: FactInputData) => {
    setIsGenerating(true);

    // 실제로는 AI API 호출 → 응답을 BlockNote 블록으로 변환
    // PoC 단계에서는 더미 데이터를 사용
    await new Promise(resolve => setTimeout(resolve, 2000)); // 생성 시뮬레이션

    setMetadata({
      ...DUMMY_METADATA,
      clientName: facts.clientName || DUMMY_METADATA.clientName,
      opponentName: facts.opponentName || DUMMY_METADATA.opponentName,
    });
    
    // Timeline API 로 기록 남기기
    try {
      const session = typeof window !== 'undefined' ? getSession() : null;
      if (session?.companyId) {
        await fetch('/api/timeline', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            companyId: session.companyId,
            author: session.name || '임직원',
            type: 'superlawyer_generated',
            content: `AI 법률 의견서 생성: ${facts.clientName} vs ${facts.opponentName} (${facts.caseType})`
          })
        });
      }
    } catch (e) {
      console.error('Timeline record failed', e);
    }

    setInitialBlocks(DUMMY_OPINION_BLOCKS as unknown as PartialBlock[]);
    setIsGenerated(true);
    setIsGenerating(false);
  }, []);

  /** BlockNote 에디터 변경 핸들러 */
  const handleEditorChange = useCallback((blocks: Block[]) => {
    setEditorBlocks(blocks);
  }, []);

  /** HWPX 다운로드 */
  const handleDownloadHwpx = useCallback(async () => {
    // 에디터 블록을 마크다운으로 변환 → API 호출
    const blocks = editorBlocks.length > 0 ? editorBlocks : DUMMY_OPINION_BLOCKS;
    
    // 블록 → 마크다운 간이 변환
    const markdown = (blocks as any[]).map((block: Record<string, unknown>) => {
      const content = block.content as Array<{ text?: string; styles?: { bold?: boolean; italic?: boolean } }> | undefined;
      const text = content?.map((c) => {
        let t = c.text || '';
        if (c.styles?.bold) t = `**${t}**`;
        if (c.styles?.italic) t = `*${t}*`;
        return t;
      }).join('') || '';

      const props = block.props as { level?: number } | undefined;
      switch (block.type) {
        case 'heading': {
          const hashes = '#'.repeat(props?.level || 1);
          return `${hashes} ${text}`;
        }
        case 'bulletListItem':
          return `- ${text}`;
        case 'numberedListItem':
          return `1. ${text}`;
        default:
          return text;
      }
    }).join('\n');

    const response = await fetch('/api/superlawyer/generate-hwpx', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        content: markdown,
        metadata,
      }),
    });

    if (!response.ok) {
      throw new Error('HWPX 생성 실패');
    }

    // 파일 다운로드
    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `법률의견서_${metadata.caseNumber}_${metadata.date.replace(/\./g, '-')}.hwpx`;
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
  }, [editorBlocks, metadata]);

  /** 새 문서 */
  const handleReset = useCallback(() => {
    setIsGenerated(false);
    setInitialBlocks([]);
    setEditorBlocks([]);
    setMetadata(DUMMY_METADATA);
  }, []);

  return (
    <div className="superlawyer-root">
      {/* 배경 글로우 효과 */}
      <div className="sl-bg-glow sl-bg-glow-1" />
      <div className="sl-bg-glow sl-bg-glow-2" />

      {/* 상단 툴바 */}
      <ToolbarActions
        onDownloadHwpx={handleDownloadHwpx}
        onReset={isGenerated ? handleReset : undefined}
        documentTitle={isGenerated ? `${metadata.caseTitle} — 법률 의견서` : '수퍼로이어 AI'}
      />

      {/* 메인 콘텐츠 */}
      <div className="superlawyer-main">
        {/* 좌측: 사실관계 입력 */}
        <aside className={`fact-panel-container ${isGenerated ? 'fact-panel-collapsed' : ''}`}>
          <FactInputPanel
            onGenerate={handleGenerate}
            isGenerating={isGenerating}
          />
        </aside>

        {/* 우측: 에디터 캔버스 */}
        <main className={`editor-container ${isGenerated ? 'editor-expanded' : 'editor-placeholder'}`}>
          {isGenerated ? (
            <OpinionEditor
              initialBlocks={initialBlocks}
              onChange={handleEditorChange}
              editable={true}
            />
          ) : (
            <div className="editor-empty-state">
              <div className="empty-icon">
                <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <path d="M12 2L2 7l10 5 10-5-10-5z"/>
                  <path d="M2 17l10 5 10-5"/>
                  <path d="M2 12l10 5 10-5"/>
                </svg>
              </div>
              <h3>수퍼로이어 AI</h3>
              <p>사실관계를 입력하면 AI가 법률 의견서 초안을 작성합니다.</p>
              <p className="empty-subtitle">작성된 의견서는 Notion 스타일 에디터에서 자유롭게 수정한 뒤,<br/>완벽한 규격의 HWPX 파일로 다운로드할 수 있습니다.</p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

'use client';
import React, { useState, useRef, useEffect, Suspense } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    CheckCircle2, ArrowLeft, Building2, User, Phone, Mail,
    FileText, Sparkles, ArrowRight, Copy, Check, Pen, RotateCcw,
    Calendar, Shield, Clock,
} from 'lucide-react';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';
import { useCompanies } from '@/hooks/useDataLayer';
import { PRICE_RANGES, CRM_PLAN_MAP, calcPrice } from '@/lib/pricing';

// ── 플랜 데이터 (중앙 관리 모듈에서 가져옴) ─────────────────
const PLANS: Record<string, { name: string; price: number; color: string; features: string[] }> = Object.fromEntries(
    PRICE_RANGES.map(r => [
        r.id,
        { name: r.name, price: calcPrice(r.minStores), color: r.color, features: [`${r.storeRange} 매장`, `${r.priceRange}/월`] },
    ])
);

// ── 서명 캔버스 ─────────────────────────────────────────
function SignatureCanvas({ onSign }: { onSign: (dataUrl: string) => void }) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [drawing, setDrawing] = useState(false);
    const [signed, setSigned] = useState(false);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = canvas.offsetWidth * 2;
        canvas.height = canvas.offsetHeight * 2;
        ctx.scale(2, 2);
        ctx.strokeStyle = '#f0f4ff';
        ctx.lineWidth = 2;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
    }, []);

    const getPos = (e: React.MouseEvent | React.TouchEvent) => {
        const canvas = canvasRef.current!;
        const rect = canvas.getBoundingClientRect();
        if ('touches' in e) {
            return { x: e.touches[0].clientX - rect.left, y: e.touches[0].clientY - rect.top };
        }
        return { x: e.clientX - rect.left, y: e.clientY - rect.top };
    };

    const startDraw = (e: React.MouseEvent | React.TouchEvent) => {
        e.preventDefault();
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.beginPath();
        ctx.moveTo(x, y);
        setDrawing(true);
    };

    const draw = (e: React.MouseEvent | React.TouchEvent) => {
        e.preventDefault();
        if (!drawing) return;
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.lineTo(x, y);
        ctx.stroke();
        if (!signed) setSigned(true);
    };

    const stopDraw = () => {
        setDrawing(false);
        if (signed && canvasRef.current) {
            onSign(canvasRef.current.toDataURL());
        }
    };

    const clear = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        setSigned(false);
        onSign('');
    };

    return (
        <div className="relative">
            <canvas
                ref={canvasRef}
                className="w-full rounded-xl cursor-crosshair touch-none"
                style={{
                    height: 120,
                    background: 'rgba(13,27,62,0.8)',
                    border: `2px dashed ${signed ? 'rgba(34,197,94,0.5)' : 'rgba(201,168,76,0.3)'}`,
                }}
                onMouseDown={startDraw} onMouseMove={draw} onMouseUp={stopDraw} onMouseLeave={stopDraw}
                onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={stopDraw}
            />
            {!signed && (
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <div className="flex items-center gap-2" style={{ color: 'rgba(240,244,255,0.25)' }}>
                        <Pen className="w-5 h-5" />
                        <span className="text-sm font-bold">이곳에 서명해 주세요</span>
                    </div>
                </div>
            )}
            {signed && (
                <button onClick={clear}
                    className="absolute top-2 right-2 flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-lg"
                    style={{ background: 'rgba(255,255,255,0.1)', color: 'rgba(240,244,255,0.5)' }}>
                    <RotateCcw className="w-3 h-3" /> 다시 서명
                </button>
            )}
        </div>
    );
}

// ── 메인 페이지 ─────────────────────────────────────────
function CheckoutContent() {
    const searchParams = useSearchParams();
    const planId = searchParams.get('plan') || 'growth';
    const company = searchParams.get('company') || '';
    const plan = PLANS[planId] || PLANS.growth || Object.values(PLANS)[0];

    const today = new Date();
    const todayStr = `${today.getFullYear()}년 ${today.getMonth() + 1}월 ${today.getDate()}일`;

    const [form, setForm] = useState({
        companyName: company,
        bizNo: '',
        ceoName: '',
        contactName: '',
        contactPhone: '',
        contactEmail: '',
    });
    const [signature, setSignature] = useState('');
    const [agreed, setAgreed] = useState(false);
    const [copied, setCopied] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [done, setDone] = useState(false);

    const bankInfo = { bank: '국민은행', account: '123-456-789012', holder: '법률사무소 IBS' };

    const copyAccount = () => {
        navigator.clipboard.writeText(bankInfo.account);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const canSubmit = form.companyName && form.contactName && form.contactEmail && signature && agreed;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!canSubmit) return;
        setSubmitting(true);
        
        try {
            const res = await fetch('/api/checkout', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...form,
                    bizNumber: form.bizNo,
                    planId,
                    signature
                })
            });

            if (!res.ok) {
                const errorData = await res.json();
                throw new Error(errorData.error || '구독 신청 중 요류가 발생했습니다.');
            }

            setDone(true);
        } catch (err: any) {
            console.error('Checkout error:', err);
            alert(err.message || '오류가 발생했습니다.');
        } finally {
            setSubmitting(false);
        }
    };

    // ── 제출 완료 화면 ─────────────────────────────────
