'use client';
// src/app/intake/[token]/page.tsx
// 신규 고객 전용 접수 페이지 — 로그인 없이 접근 가능
// URL: /intake/[token] (변호사/영업팀이 생성한 전용 링크)

import { useState, useRef, useCallback, useEffect, use } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Mic, StopCircle, Send, ChevronDown, ChevronUp,
    CheckCircle, AlertCircle, Loader2, MessageSquare, Phone
} from 'lucide-react';
import { CallRecorder, AudioVisualizer, STTService, formatDuration } from '@/lib/callRecordingService';
import { IntakeTokenService, registerPendingClient } from '@/lib/pendingClientService';

const CATEGORY_OPTIONS = ['민사', '형사', '가사', '행정', '개인정보', '가맹계약', '노무', '기타'];

export default function IntakePage({ params }: { params: Promise<{ token: string }> }) {
    const { token } = use(params);

    // 토큰 검증
    const [tokenValid, setTokenValid] = useState<boolean | null>(null);
    const [lawyerName, setLawyerName] = useState('');

    useEffect(() => {
        const info = IntakeTokenService.validate(token);
        if (info) {
            setTokenValid(true);
            setLawyerName(info.userName);
        } else {
            setTokenValid(false);
        }
    }, [token]);

    const [inputTab, setInputTab] = useState<'record' | 'text'>('text');
    const [clientName, setClientName] = useState('');
    const [clientPhone, setClientPhone] = useState('');
    const [category, setCategory] = useState('기타');
    const [manualText, setManualText] = useState('');
    const [phase, setPhase] = useState<'form' | 'recording' | 'processing' | 'done' | 'error'>('form');
    const [elapsed, setElapsed] = useState(0);
    const [bars, setBars] = useState<number[]>(new Array(16).fill(2));
    const [recordedTranscript, setRecordedTranscript] = useState('');
    const [errorMsg, setErrorMsg] = useState('');
    const [duration, setDuration] = useState(0);

    const recorder = useRef(new CallRecorder());
    const viz       = useRef(new AudioVisualizer());
    const timerRef  = useRef<ReturnType<typeof setInterval> | null>(null);
    const vizTimer  = useRef<ReturnType<typeof setInterval> | null>(null);

    const stopAll = useCallback(() => {
        if (timerRef.current) clearInterval(timerRef.current);
        if (vizTimer.current) clearInterval(vizTimer.current);
        viz.current.disconnect();
    }, []);

    useEffect(() => () => stopAll(), [stopAll]);

    const handleStartRecording = async () => {
        setErrorMsg('');
        const ok = await recorder.current.start();
        if (!ok) { setErrorMsg('마이크 접근 권한이 필요합니다.'); return; }
        const stream = recorder.current.getStream();
        if (stream) {
            viz.current.connect(stream);
            vizTimer.current = setInterval(() => setBars(viz.current.getFrequencyData()), 80);
        }
        setPhase('recording');
        setElapsed(0);
        timerRef.current = setInterval(() => setElapsed(s => s + 1), 1000);
    };

    const handleStopRecording = async () => {
        stopAll();
        setPhase('processing');
        const result = await recorder.current.stop();
        if (!result) { setPhase('error'); setErrorMsg('녹음 처리 중 오류가 발생했습니다.'); return; }
        setDuration(result.durationSeconds);
        const { transcript } = await STTService.transcribe(result.blob, result.durationSeconds);
        setRecordedTranscript(transcript);
        setPhase('form'); // 녹음 완료 후 다시 폼으로 (확인 후 제출)
    };

    const handleSubmit = async () => {
        if (!clientName.trim()) { setErrorMsg('이름을 입력해주세요.'); return; }
        const finalText = inputTab === 'record' ? recordedTranscript : manualText;
        if (!finalText.trim()) { setErrorMsg('내용을 입력하거나 녹음해주세요.'); return; }

        setPhase('processing');

        // 토큰 정보 가져오기
        const tokenInfo = IntakeTokenService.validate(token);
        await registerPendingClient({
            channel: 'intake_url',
            clientName,
            clientPhone,
            category,
            transcript: finalText,
            recordingDuration: inputTab === 'record' ? duration : undefined,
            sourcePortal: 'intake',
            sourceUserId: tokenInfo?.userId,
            sourceUserName: tokenInfo?.userName,
            token,
        });
        IntakeTokenService.markUsed(token);
        setPhase('done');
    };

    const iS = {
        background: '#f8f9fc',
        border: '1px solid #e2e8f0',
        color: '#1e293b',
        borderRadius: '12px',
        padding: '10px 14px',
        width: '100%',
        fontSize: '14px',
    };

    // ── 로딩 중 ──
    if (tokenValid === null) {
        return (
            <div className="min-h-screen flex items-center justify-center" style={{ background: '#f0f4f8' }}>
                <Loader2 className="w-8 h-8 animate-spin" style={{ color: '#6366f1' }} />
            </div>
        );
    }

    // ── 토큰 무효 ──
    if (tokenValid === false) {
        return (
            <div className="min-h-screen flex items-center justify-center p-4" style={{ background: '#f0f4f8' }}>
                <div className="max-w-sm w-full text-center space-y-4">
                    <AlertCircle className="w-12 h-12 mx-auto" style={{ color: '#ef4444' }} />
                    <h1 className="text-xl font-black" style={{ color: '#1e293b' }}>유효하지 않은 링크</h1>
                    <p className="text-sm" style={{ color: '#64748b' }}>
                        이 접수 링크는 만료되었거나 유효하지 않습니다.<br/>
                        담당 변호사에게 새 링크를 요청해 주세요.
                    </p>
                </div>
            </div>
        );
    }

    // ── 접수 완료 ──
    if (phase === 'done') {
        return (
            <div className="min-h-screen flex items-center justify-center p-4" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' }}>
                <motion.div
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="max-w-sm w-full text-center space-y-5 p-8 rounded-3xl"
                    style={{ background: '#fff' }}
                >
                    <div className="w-20 h-20 rounded-full mx-auto flex items-center justify-center text-4xl"
                        style={{ background: 'linear-gradient(135deg, #84fab0, #8fd3f4)' }}>
                        ✅
                    </div>
                    <h1 className="text-xl font-black" style={{ color: '#1e293b' }}>접수 완료!</h1>
                    <p className="text-sm" style={{ color: '#64748b' }}>
                        <strong>{clientName}</strong>님의 상담 내용이 정상적으로 접수되었습니다.<br/>
                        담당 변호사가 확인 후 곧 연락드립니다.
                    </p>
                    {clientPhone && (
                        <div className="flex items-center gap-2 justify-center text-sm"
                            style={{ color: '#6366f1' }}>
                            <Phone className="w-4 h-4" />
                            <span>{clientPhone}로 연락 예정</span>
                        </div>
                    )}
                    <p className="text-xs" style={{ color: '#94a3b8' }}>
                        법무법인 IBS · 법률 서비스 플랫폼
                    </p>
                </motion.div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col" style={{ background: 'linear-gradient(160deg, #f0f4ff 0%, #faf5ff 100%)' }}>
            {/* 헤더 */}
            <header className="px-5 py-4 flex items-center gap-3"
                style={{ background: '#fff', borderBottom: '1px solid #e5e7eb' }}>
                <div className="w-8 h-8 rounded-full flex items-center justify-center text-lg"
                    style={{ background: 'linear-gradient(135deg, #667eea, #764ba2)' }}>⚖️</div>
                <div>
                    <p className="font-black text-sm" style={{ color: '#1e293b' }}>법률 상담 접수</p>
                    <p className="text-xs" style={{ color: '#94a3b8' }}>담당: {lawyerName}</p>
                </div>
            </header>

            <main className="flex-1 flex items-start justify-center p-4 pt-6">
                <div className="w-full max-w-md space-y-4">
                    {/* 안내 */}
                    <div className="p-4 rounded-2xl" style={{ background: '#fffbeb', border: '1px solid #fde68a' }}>
                        <p className="text-sm font-semibold" style={{ color: '#b8960a' }}>
                            📋 이 페이지에서 상담 내용을 작성하거나 녹음으로 전달하실 수 있습니다.
                        </p>
                    </div>

                    {/* 개인정보 */}
                    <div className="p-4 rounded-2xl space-y-3" style={{ background: '#fff', border: '1px solid #e5e7eb' }}>
                        <p className="text-xs font-black uppercase tracking-wider" style={{ color: '#94a3b8' }}>👤 기본 정보</p>
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#64748b' }}>이름 <span style={{ color: '#ef4444' }}>*</span></label>
                            <input value={clientName} onChange={e => setClientName(e.target.value)}
                                placeholder="홍길동" style={iS} />
                        </div>
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#64748b' }}>연락처</label>
                            <input value={clientPhone} onChange={e => setClientPhone(e.target.value)}
                                placeholder="010-0000-0000" style={iS} />
                        </div>
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#64748b' }}>사건 유형</label>
                            <select value={category} onChange={e => setCategory(e.target.value)} style={iS}>
                                {CATEGORY_OPTIONS.map(c => <option key={c}>{c}</option>)}
                            </select>
                        </div>
                    </div>

                    {/* 내용 입력 */}
                    <div className="p-4 rounded-2xl space-y-3" style={{ background: '#fff', border: '1px solid #e5e7eb' }}>
                        <p className="text-xs font-black uppercase tracking-wider" style={{ color: '#94a3b8' }}>📝 상담 내용</p>
                        {/* 탭 */}
                        <div className="flex gap-1 p-1 rounded-xl" style={{ background: '#f1f5f9' }}>
                            {[{ k: 'text', l: '✍️ 글 작성' }, { k: 'record', l: '🎙️ 녹음' }].map(t => (
                                <button key={t.k} onClick={() => setInputTab(t.k as 'text' | 'record')}
                                    className="flex-1 py-1.5 rounded-lg text-xs font-bold transition-all"
                                    style={inputTab === t.k
                                        ? { background: '#fff', color: '#6366f1', boxShadow: '0 1px 4px rgba(0,0,0,0.1)' }
                                        : { color: '#94a3b8' }}>
                                    {t.l}
                                </button>
                            ))}
                        </div>

                        {/* 글 작성 */}
                        {inputTab === 'text' && (
                            <textarea value={manualText} onChange={e => setManualText(e.target.value)}
                                rows={6} placeholder="어떤 법률 문제로 상담을 원하시나요? 자세히 적어주실수록 정확한 도움을 드릴 수 있습니다."
                                style={{ ...iS, resize: 'none', lineHeight: '1.6' }} />
                        )}

                        {/* 녹음 */}
                        {inputTab === 'record' && (
                            <div className="text-center space-y-3">
                                {phase === 'form' && recordedTranscript && (
                                    <div className="p-3 rounded-xl text-left" style={{ background: '#f0fdf4', border: '1px solid #bbf7d0' }}>
                                        <p className="text-xs font-bold mb-1" style={{ color: '#16a34a' }}>
                                            ✅ 녹음 완료 ({formatDuration(duration)})
                                        </p>
                                        <p className="text-xs" style={{ color: '#64748b' }}>녹음이 완료되었습니다. 아래에서 제출을 눌러주세요.</p>
                                    </div>
                                )}
                                {phase === 'recording' ? (
                                    <>
                                        <div className="flex items-end justify-center gap-0.5 h-10">
                                            {bars.map((h, i) => (
                                                <motion.div key={i}
                                                    animate={{ height: Math.max(4, h / 4) }}
                                                    className="w-1.5 rounded-full"
                                                    style={{ background: '#6366f1', minHeight: 4 }}
                                                    transition={{ duration: 0.08 }} />
                                            ))}
                                        </div>
                                        <p className="text-xl font-black tabular-nums" style={{ color: '#6366f1' }}>
                                            {String(Math.floor(elapsed / 60)).padStart(2, '0')}:{String(elapsed % 60).padStart(2, '0')}
                                        </p>
                                        <button onClick={handleStopRecording}
                                            className="flex items-center gap-2 mx-auto px-6 py-3 rounded-full font-bold text-white"
                                            style={{ background: '#ef4444' }}>
                                            <StopCircle className="w-5 h-5" /> 녹음 완료
                                        </button>
                                    </>
                                ) : phase === 'processing' ? (
                                    <div className="py-4">
                                        <Loader2 className="w-6 h-6 mx-auto animate-spin mb-2" style={{ color: '#6366f1' }} />
                                        <p className="text-xs" style={{ color: '#94a3b8' }}>처리 중...</p>
                                    </div>
                                ) : (
                                    <button onClick={handleStartRecording}
                                        className="flex items-center gap-2 mx-auto px-6 py-3 rounded-full font-bold text-white"
                                        style={{ background: '#6366f1' }}>
                                        <Mic className="w-5 h-5" />
                                        {recordedTranscript ? '다시 녹음' : '녹음 시작'}
                                    </button>
                                )}
                            </div>
                        )}
                    </div>

                    {errorMsg && (
                        <div className="flex items-center gap-2 text-sm" style={{ color: '#ef4444' }}>
                            <AlertCircle className="w-4 h-4" /> {errorMsg}
                        </div>
                    )}

                    {/* 제출 버튼 */}
                    <button
                        onClick={handleSubmit}
                        disabled={phase === 'processing'}
                        className="w-full py-4 rounded-2xl font-black text-white flex items-center justify-center gap-2"
                        style={{ background: 'linear-gradient(135deg, #667eea, #764ba2)', fontSize: '15px' }}>
                        {phase === 'processing' ? (
                            <><Loader2 className="w-5 h-5 animate-spin" /> 접수 중...</>
                        ) : (
                            <><Send className="w-5 h-5" /> 상담 접수하기</>
                        )}
                    </button>

                    <p className="text-xs text-center" style={{ color: '#94a3b8' }}>
                        법무법인 IBS · 개인정보는 법률 상담 목적으로만 사용됩니다.
                    </p>
                </div>
            </main>
        </div>
    );
}

'use client';

import React, { useState, useEffect, Suspense } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    ShieldCheck, Mail, Eye, EyeOff, AlertCircle, ArrowRight,
    Lock, Building2, Users, ChevronRight, Gavel, BarChart3, Heart, KeyRound, UserCircle
} from 'lucide-react';
import { useRouter, useSearchParams } from 'next/navigation';
import { ROLE_HOME, getSession } from '@/lib/auth';
import { useAuth } from '@/lib/AuthContext';

function setCookie(name: string, value: string) {
    if (typeof document !== 'undefined') {
        document.cookie = `${name}=${encodeURIComponent(value)}; path=/`;
    }
}

type LoginMode = 'staff' | 'client' | 'personal';

// 역할별 레이블
const ROLE_ICONS: Record<string, { icon: React.ReactNode; label: string; color: string; dest_label: string }> = {
    super_admin: { icon: <ShieldCheck className="w-4 h-4" />, label: '슈퍼어드민', color: '#b8960a', dest_label: 'CRM 관리' },
    admin: { icon: <BarChart3 className="w-4 h-4" />, label: '관리자', color: '#b8960a', dest_label: 'CRM 관리' },
    sales: { icon: <Users className="w-4 h-4" />, label: '영업팀', color: '#2563eb', dest_label: 'CRM' },
    lawyer: { icon: <Gavel className="w-4 h-4" />, label: '변호사', color: '#7c3aed', dest_label: '검토 대시보드' },
    litigation: { icon: <Gavel className="w-4 h-4" />, label: '송무팀', color: '#db2777', dest_label: '송무 대시보드' },
    counselor: { icon: <Heart className="w-4 h-4" />, label: 'EAP상담사', color: '#059669', dest_label: '상담 현황' },
    client_hr: { icon: <Building2 className="w-4 h-4" />, label: '고객사HR', color: '#ea580c', dest_label: '사용 현황' },
    general: { icon: <Users className="w-4 h-4" />, label: '총무팀(내부)', color: '#64748b', dest_label: '총무' },
    hr: { icon: <Users className="w-4 h-4" />, label: '인사팀(내부)', color: '#64748b', dest_label: '인사' },
};

// 라이트 테마 색상
const L = {
    bg: '#f8f9fc',
    card: '#ffffff',
    heading: '#0f172a',
    body: '#1e293b',
    sub: '#475569',
    muted: '#64748b',
    faint: '#94a3b8',
    border: '#e2e8f0',
    borderLight: '#f1f5f9',
    gold: '#b8960a',
    goldLight: '#fef9e7',
    goldBorder: '#fde68a',
};


function LoginContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const from = searchParams.get('from') || '';
    const claimId = searchParams.get('claim');
    const { login: authLogin, loginWithBizNo: authLoginBiz, loginWithPersonalEmail: authLoginPersonal } = useAuth();

    const [mode, setMode] = useState<LoginMode>('client');
    const [showStaffTab, setShowStaffTab] = useState(false);

    const [claimBizNum, setClaimBizNum] = useState('');
    const [claimPw, setClaimPw] = useState('');
    const [claimPwConfirm, setClaimPwConfirm] = useState('');
    const [showClaimPw, setShowClaimPw] = useState(false);
    const [claimError, setClaimError] = useState('');
    const [claimLoading, setClaimLoading] = useState(false);
    const [agreePrivacy, setAgreePrivacy] = useState(false);
    const [agreeMarketing, setAgreeMarketing] = useState(false);
    const [modalContent, setModalContent] = useState<'privacy' | 'marketing' | null>(null);

    const handleClaimLogin = async () => {
        const cleanBizNum = claimBizNum.replace(/\D/g, '');
        if (!cleanBizNum || cleanBizNum.length < 10) { setClaimError('올바른 개인 사업자 번호(10자리)를 입력해주세요.'); return; }
        if (!claimPw || claimPw !== claimPwConfirm) { setClaimError('비밀번호가 일치하지 않거나 비어있습니다.'); return; }
        if (claimPw.length < 6) { setClaimError('비밀번호는 최소 6자 이상이어야 합니다.'); return; }
        if (!agreePrivacy) { setClaimError('필수 개인정보 수집 및 이용에 동의해주세요.'); return; }
        setClaimLoading(true); setClaimError('');
        try {
            const res = await fetch('/api/auth/claim', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ claimId, bizNum: cleanBizNum, password: claimPw, agreeMarketing })
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || '접근 설정에 실패했습니다.');
            
            const result = await authLoginBiz(cleanBizNum, claimPw);
            if (!result.error) {
                const session = getSession();
                if (session) {
                    // setCookie was moved to inside auth but let's do it safely
                    setCookie('ibs_session', session.id);
                    setCookie('ibs_role', session.role);
                    router.replace(from || '/privacy-analysis');
                } else {
                    router.replace(from || '/privacy-analysis'); // session might be slight delayed
                }
            } else {
                throw new Error(result.error);
            }
        } catch (e: any) {
            setClaimError(e.message);
            setClaimLoading(false);
        }
    };

    // 이미 로그인돼 있으면 홈으로
    useEffect(() => {
        const session = getSession();
        if (session) {
            router.replace(ROLE_HOME[session.role] || '/');
        }
    }, [router]);

    // Staff login state
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPw, setShowPw] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    // Client login state
    const [bizNum, setBizNum] = useState('');
    const [bizPassword, setBizPassword] = useState('');
    const [showBizPw, setShowBizPw] = useState(false);
    const [bizError, setBizError] = useState('');
    const [bizLoading, setBizLoading] = useState(false);

    // Personal login state
    const [personalEmail, setPersonalEmail] = useState('');
    const [personalPassword, setPersonalPassword] = useState('');
    const [showPersonalPw, setShowPersonalPw] = useState(false);
    const [personalError, setPersonalError] = useState('');
    const [personalLoading, setPersonalLoading] = useState(false);

    const formatBizNum = (v: string) => {
        const d = v.replace(/\D/g, '').slice(0, 10);
        if (d.length <= 3) return d;
        if (d.length <= 5) return `${d.slice(0, 3)}-${d.slice(3)}`;
        return `${d.slice(0, 3)}-${d.slice(3, 5)}-${d.slice(5)}`;
    };

    const handleStaffLogin = async () => {
        if (!email || !password) { setError('이메일과 비밀번호를 입력해주세요.'); return; }
        setLoading(true); setError('');
        await new Promise(r => setTimeout(r, 700));
        const result = await authLogin(email, password);
        if (!result.error) {
            const session = getSession();
            if (session) {
                setCookie('ibs_session', session.id);
                setCookie('ibs_role', session.role);
                const dest = from || ROLE_HOME[session.role] || '/';
                setLoading(false);
                router.replace(dest);
            }
        } else {
            setError(result.error);
            setLoading(false);
        }
    };

    const handleClientLogin = async () => {
        if (!bizNum || !bizPassword) { setBizError('사업자번호와 비밀번호를 입력해주세요.'); return; }
        setBizLoading(true); setBizError('');
        await new Promise(r => setTimeout(r, 800));
        const result = await authLoginBiz(bizNum, bizPassword);
        if (!result.error) {
            const session = getSession();
            if (session) {
                setCookie('ibs_session', session.id);
                setCookie('ibs_role', session.role);
                setBizLoading(false);
                router.replace(from || '/dashboard');
            }
        } else {
            setBizError(result.error);
            setBizLoading(false);
        }
    };

    const handlePersonalLogin = async () => {
        if (!personalEmail || !personalPassword) { setPersonalError('이메일과 비밀번호를 입력해주세요.'); return; }
        setPersonalLoading(true); setPersonalError('');
        await new Promise(r => setTimeout(r, 700));
        const result = await authLoginPersonal(personalEmail, personalPassword);
        if (!result.error) {
            const session = getSession();
            if (session) {
                setCookie('ibs_session', session.id);
                setCookie('ibs_role', session.role);
                setPersonalLoading(false);
                router.replace(from || '/personal-litigation');
            }
        } else {
            setPersonalError(result.error);
            setPersonalLoading(false);
        }
    };

    const inputStyle: React.CSSProperties = {
        width: '100%', padding: '10px 14px 10px 38px',
        background: L.borderLight, border: `1px solid ${L.border}`,
        borderRadius: 12, fontSize: 14, color: L.body, outline: 'none',
    };

    return (
        <div
            className="min-h-screen flex items-center justify-center px-4 py-12 relative"
            style={{ background: `linear-gradient(135deg, ${L.bg} 0%, #eef2ff 50%, #fef9e7 100%)` }}
        >
            {/* Subtle decorative circles */}
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <div style={{ position: 'absolute', top: '-10%', right: '-5%', width: 500, height: 500, borderRadius: '50%', background: 'radial-gradient(circle, rgba(184,150,10,0.06) 0%, transparent 70%)' }} />
                <div style={{ position: 'absolute', bottom: '-15%', left: '-10%', width: 600, height: 600, borderRadius: '50%', background: 'radial-gradient(circle, rgba(37,99,235,0.04) 0%, transparent 70%)' }} />
            </div>

            <div className="w-full max-w-md relative z-10">
                <h1 className="sr-only">IBS 법률사무소 로그인</h1>
                {/* Logo removed per user request */}

                {/* Mode Toggle (Hidden if claimId exists) */}
                {!claimId && (
                    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>
                        <div className="flex rounded-xl p-1 mb-6" style={{ background: L.borderLight, border: `1px solid ${L.border}` }}>
                            {([
                                { key: 'personal', label: '개인', icon: <UserCircle className="w-4 h-4" /> },
                                { key: 'client',   label: '기업',     icon: <Building2 className="w-4 h-4" /> },
                                ...(showStaffTab ? [{ key: 'staff', label: '내부 직원', icon: <Users className="w-4 h-4" /> }] : []),
                            ] as { key: LoginMode; label: string; icon: React.ReactNode }[]).map((tab) => (
                                <button
                                    key={tab.key}
                                    onClick={() => { setMode(tab.key); setError(''); setBizError(''); setPersonalError(''); }}
                                    className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-sm font-semibold transition-all"
                                    style={{
                                        background: mode === tab.key ? 'linear-gradient(135deg,#e8c87a,#c9a84c)' : 'transparent',
                                        color: mode === tab.key ? '#0f172a' : L.muted,
                                        boxShadow: mode === tab.key ? '0 2px 8px rgba(184,150,10,0.2)' : 'none',
                                    }}
                                >
                                    {tab.icon}{tab.label}
                                </button>
                            ))}
                        </div>
                    </motion.div>
                )}

                {/* Card */}
                <AnimatePresence mode="wait">
                    <motion.div
                        key={claimId ? 'claim' : mode}
                        initial={{ opacity: 0, x: mode === 'staff' ? -20 : 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: mode === 'staff' ? 20 : -20 }}
                        transition={{ duration: 0.25 }}
                    >
                        <div style={{
                            background: L.card, border: `1px solid ${L.border}`, borderRadius: 16, padding: 28,
                            boxShadow: '0 4px 24px rgba(0,0,0,0.06)',
                        }}>

                                {/* ── Claim Flow ── */}
                            {claimId && (
                                <div className="space-y-5">
                                    <div>
                                        <h2 className="text-lg font-black mb-0.5" style={{ color: L.heading }}>초기 비밀번호 및 아이디 설정</h2>
                                        <p className="text-xs" style={{ color: L.muted }}>보안을 위해 본인이 사용할 아이디(사업자 번호)와 비밀번호를 등록해주세요.</p>
                                    </div>
                                    
                                    {/* BizNum ID */}
                                    <div>
                                        <label className="block text-sm font-semibold mb-1.5" style={{ color: L.sub }}>개인 사업자 번호 (아이디)</label>
                                        <div className="relative">
                                            <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: L.faint }} />
                                            <input
                                                style={inputStyle}
                                                type="text"
                                                placeholder="숫자만 입력 (예: 1234567890)"
                                                autoComplete="off"
                                                value={claimBizNum}
                                                onChange={(e) => { setClaimBizNum(e.target.value.replace(/\D/g, '')); setClaimError(''); }}
                                                onKeyDown={(e) => e.key === 'Enter' && handleClaimLogin()}
                                            />
                                        </div>
                                    </div>

                                    {/* Password */}
                                    <div>
                                        <label className="block text-sm font-semibold mb-1.5" style={{ color: L.sub }}>새 비밀번호</label>
                                        <div className="relative">
                                            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: L.faint }} />
                                            <input
                                                style={{ ...inputStyle, paddingRight: '2.75rem' }}
                                                type={showClaimPw ? 'text' : 'password'}
                                                placeholder="6자리 이상 입력"
                                                autoComplete="off"
                                                value={claimPw}
                                                onChange={(e) => { setClaimPw(e.target.value); setClaimError(''); }}
                                                onKeyDown={(e) => e.key === 'Enter' && handleClaimLogin()}
                                            />
                                            <button onClick={() => setShowClaimPw(!showClaimPw)} className="absolute right-3 top-1/2 -translate-y-1/2" style={{ color: L.faint }}>
                                                {showClaimPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>

                                    {/* Password Confirm */}
                                    <div>
                                        <label className="block text-sm font-semibold mb-1.5" style={{ color: L.sub }}>새 비밀번호 확인</label>
                                        <div className="relative">
                                            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: L.faint }} />
                                            <input
                                                style={{ ...inputStyle, paddingRight: '2.75rem' }}
                                                type={showClaimPw ? 'text' : 'password'}
                                                placeholder="비밀번호 재입력"
                                                autoComplete="off"
                                                value={claimPwConfirm}
                                                onChange={(e) => { setClaimPwConfirm(e.target.value); setClaimError(''); }}
                                                onKeyDown={(e) => e.key === 'Enter' && handleClaimLogin()}
                                            />
                                        </div>
                                    </div>

                                    {/* 약관 동의 */}
                                    <div className="space-y-0 pt-1">
                                        <div className="flex items-center justify-between">
                                            <label className="flex items-center gap-2 text-sm font-medium cursor-pointer select-none" style={{ color: L.body }}>
                                                <input 
                                                    type="checkbox" 
                                                    checked={agreePrivacy}
                                                    onChange={(e) => setAgreePrivacy(e.target.checked)}
                                                    className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" 
                                                />
                                                [필수] 개인정보 수집 및 이용 동의
                                            </label>
                                            <button 
                                                onClick={() => setModalContent('privacy')}
                                                className="text-xs font-semibold hover:underline" 
                                                style={{ color: L.gold }}>보기</button>
                                        </div>
                                        <div className="flex items-center justify-between">
                                            <label className="flex items-center gap-2 text-sm font-medium cursor-pointer select-none" style={{ color: L.body }}>
                                                <input 
                                                    type="checkbox" 
                                                    checked={agreeMarketing}
                                                    onChange={(e) => setAgreeMarketing(e.target.checked)}
                                                    className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" 
                                                />
                                                [선택] 마케팅 정보 수신 동의
                                            </label>
                                            <button 
                                                onClick={() => setModalContent('marketing')}
                                                className="text-xs font-semibold hover:underline" 
                                                style={{ color: L.gold }}>보기</button>
                                        </div>
                                    </div>

                                    {claimError && (
                                        <div className="flex items-center gap-2 text-sm" style={{ color: '#dc2626' }}>
                                            <AlertCircle className="w-4 h-4 flex-shrink-0" />{claimError}
                                        </div>
                                    )}

                                    <button
                                        onClick={handleClaimLogin}
                                        disabled={claimLoading}
                                        className="w-full flex items-center justify-center gap-2 py-3 rounded-xl font-bold text-sm transition-all"
                                        style={{
                                            background: claimLoading ? 'rgba(201,168,76,0.3)' : 'linear-gradient(135deg,#e8c87a,#c9a84c)',
                                            color: '#0f172a',
                                            opacity: claimLoading ? 0.8 : 1,
                                            boxShadow: claimLoading ? 'none' : '0 2px 12px rgba(184,150,10,0.25)',
                                        }}
                                    >
                                        {claimLoading ? (
                                            <span className="flex items-center gap-2">
                                                <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
