                                {!method && (
                                    <div className="space-y-2 mb-5">
                                        {[
                                            { key: 'code', icon: <Ticket className="w-4 h-4" />, title: '초대코드 입력', desc: '본사에서 받은 코드를 입력', color: '#c9a84c' },
