                                                className="w-full px-4 py-2.5 rounded-xl outline-none text-sm"
                                                style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(52,211,153,0.2)', color: reqCompany ? '#f0f4ff' : 'rgba(240,244,255,0.3)' }}>
