'use client';
import React, { useEffect, Suspense } from 'react';
import { motion } from 'framer-motion';
import { CheckCircle2, ArrowRight, Home, Sparkles, Calendar, Shield, Phone } from 'lucide-react';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';

const NEXT_STEPS = [
    { num: 1, text: '신청 확인 이메일 발송 (5분 내)', done: true },
    { num: 2, text: '입금 확인 후 계정 활성화', done: false },
    { num: 3, text: '전담 변호사 배정 (48시간 내)', done: false },
    { num: 4, text: '온보딩 가이드 발송 및 서비스 시작', done: false },
];

function SuccessContent() {
    const searchParams = useSearchParams();
    const plan = searchParams.get('plan') || 'Pro';
    const company = searchParams.get('company') || '';

    return (
        <div className="min-h-screen flex items-center justify-center px-4 py-16"
            style={{ background: 'radial-gradient(ellipse 80% 60% at 50% 0%, rgba(74,222,128,0.06), #04091a 60%)' }}>

            {/* 배경 파티클 효과 */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none">
                {[...Array(12)].map((_, i) => (
                    <motion.div key={i}
                        initial={{ opacity: 0, y: 0, x: `${Math.random() * 100}%` }}
                        animate={{ opacity: [0, 0.6, 0], y: -300 + Math.random() * -200 }}
                        transition={{ delay: i * 0.3, duration: 3 + Math.random() * 2, repeat: Infinity, repeatDelay: Math.random() * 4 }}
                        className="absolute bottom-0 w-1 h-1 rounded-full"
                        style={{ background: '#4ade80', left: `${Math.random() * 100}%` }}
                    />
                ))}
            </div>

            <div className="max-w-lg w-full relative z-10">
                {/* 성공 아이콘 */}
                <motion.div initial={{ scale: 0, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    transition={{ type: 'spring', stiffness: 200, delay: 0.1 }}
                    className="text-center mb-8">
                    <div className="inline-flex items-center justify-center w-24 h-24 rounded-full mb-4"
                        style={{ background: 'radial-gradient(circle, rgba(74,222,128,0.25), rgba(74,222,128,0.05))', border: '2px solid rgba(74,222,128,0.4)' }}>
                        <CheckCircle2 className="w-12 h-12" style={{ color: '#4ade80' }} />
                    </div>

                    <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}>
                        <h1 className="text-4xl font-black mb-2" style={{ color: '#4ade80' }}>구독 완료!</h1>
                        {company && (
                            <p className="text-base mb-1" style={{ color: '#f0f4ff' }}>
                                <span style={{ color: '#c9a84c' }}>{company}</span>님,
                            </p>
                        )}
                        <p className="text-base" style={{ color: 'rgba(240,244,255,0.7)' }}>
                            <strong style={{ color: '#c9a84c' }}>{plan} 플랜</strong> 구독 신청이 완료되었습니다
                        </p>
                    </motion.div>
                </motion.div>

                {/* 다음 단계 */}
                <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}
                    className="rounded-2xl p-6 mb-5"
                    style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.08)' }}>
                    <h2 className="font-black text-sm mb-4 flex items-center gap-2">
                        <Calendar className="w-4 h-4" style={{ color: '#818cf8' }} />
                        다음 단계
                    </h2>
                    <div className="space-y-3">
                        {NEXT_STEPS.map(({ num, text, done }) => (
                            <div key={num} className="flex items-center gap-3">
                                <div className="w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 text-xs font-black"
                                    style={{
                                        background: done ? 'rgba(74,222,128,0.15)' : 'rgba(255,255,255,0.06)',
                                        color: done ? '#4ade80' : 'rgba(240,244,255,0.4)',
                                        border: `1px solid ${done ? 'rgba(74,222,128,0.3)' : 'rgba(255,255,255,0.1)'}`,
                                    }}>
                                    {done ? <CheckCircle2 className="w-3.5 h-3.5" /> : num}
                                </div>
                                <span className="text-sm" style={{ color: done ? '#f0f4ff' : 'rgba(240,244,255,0.55)' }}>{text}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>

                {/* 입금 계좌 */}
                <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }}
                    className="rounded-2xl p-5 mb-5"
                    style={{ background: 'rgba(201,168,76,0.06)', border: '1px solid rgba(201,168,76,0.25)' }}>
                    <p className="text-xs font-black mb-3 flex items-center gap-1.5" style={{ color: '#c9a84c' }}>
                        <Sparkles className="w-3.5 h-3.5" /> 입금 안내
                    </p>
                    <div className="space-y-1.5 text-sm">
                        {[
                            ['은행', '국민은행'],
                            ['계좌번호', '123-456-789012'],
                            ['예금주', '법률사무소 IBS'],
                        ].map(([k, v]) => (
                            <div key={k} className="flex justify-between">
                                <span style={{ color: 'rgba(240,244,255,0.4)' }}>{k}</span>
                                <span className="font-bold" style={{ color: '#e8c87a' }}>{v}</span>
                            </div>
                        ))}
                    </div>
                </motion.div>

                {/* 보안 & 고객지원 */}
                <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.6 }}
                    className="flex items-center justify-center gap-4 mb-6 text-xs"
                    style={{ color: 'rgba(240,244,255,0.4)' }}>
                    <span className="flex items-center gap-1"><Shield className="w-3.5 h-3.5" style={{ color: '#4ade80' }} /> SSL 보안</span>
                    <span>·</span>
                    <span className="flex items-center gap-1"><Phone className="w-3.5 h-3.5" style={{ color: '#3b82f6' }} /> 02-1234-5678</span>
                </motion.div>

                {/* CTA 버튼 */}
                <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.7 }}
                    className="flex flex-col gap-3">
                    <Link href="/dashboard">
                        <button className="w-full py-4 rounded-2xl font-black text-base flex items-center justify-center gap-2"
                            style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#04091a', boxShadow: '0 6px 24px rgba(201,168,76,0.3)' }}>
                            고객 포털 바로가기 <ArrowRight className="w-5 h-5" />
                        </button>
                    </Link>
                    <Link href="/login">
                        <button className="w-full py-3.5 rounded-2xl font-bold text-sm flex items-center justify-center gap-2"
                            style={{ background: 'rgba(255,255,255,0.04)', color: 'rgba(240,244,255,0.7)', border: '1px solid rgba(255,255,255,0.1)' }}>
                            로그인 페이지로
                        </button>
                    </Link>
                    <Link href="/">
                        <button className="w-full py-3 rounded-2xl font-bold text-sm flex items-center justify-center gap-1.5"
                            style={{ color: 'rgba(240,244,255,0.35)' }}>
                            <Home className="w-3.5 h-3.5" /> 홈으로
                        </button>
                    </Link>
                </motion.div>
            </div>
        </div>
    );
}

export default function SubscribeSuccessPage() {
    return (
        <Suspense fallback={
            <div className="min-h-screen flex items-center justify-center" style={{ background: '#04091a' }}>
                <div className="text-sm" style={{ color: '#4ade80' }}>로딩 중...</div>
            </div>
        }>
            <SuccessContent />
        </Suspense>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Coins, RefreshCw, Download, FileText, CheckCircle2,
    Clock, Search, X, Receipt
} from 'lucide-react';
import { PaymentRecord, PLAN_PRICE, PLAN_LABEL, PAY_STATUS_STYLE, T } from '../types';
import { useCompanies } from '@/hooks/useDataLayer';

import { BillingKPIs } from './internal/BillingKPIs';
import { SubscribedCompanyList } from './internal/SubscribedCompanyList';
import { PlanRevenueCharts } from './internal/PlanRevenueCharts';
import { exportToExcel } from '@/lib/exportUtils';

export function InternalBillingMain() {
    const { companies: allCompanies } = useCompanies();
    const companies = allCompanies || [];
    const [payments, setPayments] = useState<PaymentRecord[]>([]);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [selectedCompany, setSelectedCompany] = useState<any | null>(null);
    const [toast, setToast] = useState('');

    // ── 데이터 로드 (store 연동) ─────────────────────────
    const refresh = useCallback(() => {
        const all = companies;

        // 구독 완료된 기업에서 결제 내역 생성
        const subscribedCompaniesList = all.filter(c => c.status === 'subscribed' || c.plan !== 'none');
        const records: PaymentRecord[] = [];
        subscribedCompaniesList.forEach(c => {
            const price = PLAN_PRICE[c.plan] || 0;
            if (price === 0) return;
            // 최근 6개월 결제 기록 생성
            for (let i = 0; i < 6; i++) {
                const d = new Date();
                d.setMonth(d.getMonth() - i);
                records.push({
                    id: `pay-${c.id}-${i}`,
                    companyId: c.id,
                    companyName: c.name,
                    plan: c.plan,
                    amount: price,
                    date: `${d.getFullYear()}.${String(d.getMonth() + 1).padStart(2, '0')}.15`,
                    status: i === 0 ? 'pending' : 'paid',
                    method: '신한카드 ****4852',
                    invoiceNo: `INV-${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, '0')}-${c.id.slice(-3)}`,
                });
            }
        });

        // 파이프라인에서 contract_signed / contract_sent 기업은 결제 대기
        const pendingCompaniesList = all.filter(c =>
            ['contract_signed', 'contract_sent'].includes(c.status)
        );
        pendingCompaniesList.forEach(c => {
            const price = PLAN_PRICE['standard']; // 예상 구독료
            records.push({
                id: `pay-pending-${c.id}`,
                companyId: c.id,
                companyName: c.name,
                plan: 'standard',
                amount: price,
                date: new Date().toISOString().slice(0, 10).replace(/-/g, '.'),
                status: 'pending',
                method: '-',
                invoiceNo: `INV-PENDING-${c.id.slice(-3)}`,
            });
        });

        records.sort((a, b) => b.date.localeCompare(a.date));
        setPayments(records);
    }, [companies]);

    useEffect(() => { refresh(); }, [refresh]);
    useEffect(() => { if (toast) { const t = setTimeout(() => setToast(''), 3000); return () => clearTimeout(t); } }, [toast]);

    // ── 통계 계산 ───────────────────────────────────────────
    const subscribedCompanies = companies.filter(c => c.status === 'subscribed' && c.plan !== 'none');
    const totalMRR = subscribedCompanies.reduce((s, c) => s + (PLAN_PRICE[c.plan] || 0), 0);
    const totalARR = totalMRR * 12;
    const paidPayments = payments.filter(p => p.status === 'paid');
    const pendingPayments = payments.filter(p => p.status === 'pending');
    const overduePayments = payments.filter(p => p.status === 'overdue');
    const totalRevenue = paidPayments.reduce((s, p) => s + p.amount, 0);
    const pendingAmount = pendingPayments.reduce((s, p) => s + p.amount, 0);

    // ── 필터링 (결제 테이블에 사용됨) ─────────────────────────
    /*
    const filteredPayments = payments.filter(p => {
        const matchSearch = p.companyName.includes(search) || p.invoiceNo.includes(search);
        const matchStatus = statusFilter === 'all' || p.status === statusFilter;
        return matchSearch && matchStatus;
    });
    */

    // ── 플랜별 기업 수 ──────────────────────────────────────
    const planCounts = {
        starter: subscribedCompanies.filter(c => c.plan === 'starter').length,
        standard: subscribedCompanies.filter(c => c.plan === 'standard').length,
        premium: subscribedCompanies.filter(c => c.plan === 'premium').length,
    };

    const contractSentCount = companies.filter(c => c.status === 'contract_sent').length;
    const contractSignedCount = companies.filter(c => c.status === 'contract_signed').length;

    const handleExportExcel = () => {
        if (payments.length === 0) {
            setToast('다운로드할 데이터가 없습니다.');
            return;
        }
        exportToExcel(
            payments,
            [
                { header: '결제일', key: 'date' },
                { header: '청구번호', key: 'invoiceNo' },
                { header: '기업명', key: 'companyName' },
                { header: '플랜', key: p => PLAN_LABEL[p.plan] || p.plan },
                { header: '결제금액', key: 'amount' },
                { header: '상태', key: p => p.status === 'paid' ? '결제완료' : p.status === 'pending' ? '결제대기' : '연체' },
                { header: '결제수단', key: 'method' },
            ],
            `매출리포트_${new Date().toISOString().slice(0, 10).replace(/-/g, '')}`
        );
    };

    return (
        <div className="min-h-screen pt-20 pb-16" style={{ background: T.bg }}>
            <div className="max-w-7xl mx-auto px-4">
                {/* 헤더 */}
                <div className="py-6 flex items-center justify-between">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <Coins className="w-5 h-5" style={{ color: T.gold }} />
                            <h1 className="text-2xl font-black" style={{ color: T.heading }}>
                                회계팀 · 결제 관리
                            </h1>
                            <span className="text-[10px] px-2 py-0.5 rounded-full font-black"
                                style={{ background: T.goldBg, color: T.gold, border: `1px solid ${T.gold}30` }}>
                                FINANCE
                            </span>
                        </div>
                        <p className="text-sm" style={{ color: T.muted }}>
                            구독 매출, 결제 현황, 미수금을 실시간으로 추적합니다
                        </p>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={refresh}
                            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-bold transition-all hover:scale-105"
                            style={{ background: T.card, color: T.muted, border: `1px solid ${T.border}` }}>
                            <RefreshCw className="w-3.5 h-3.5" /> 새로고침
                        </button>
                        <button
                            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-bold transition-all hover:scale-105"
                            style={{ background: '#f0fdf4', color: '#16a34a', border: '1px solid #86efac' }}
                            onClick={handleExportExcel}>
                            <Download className="w-3.5 h-3.5" /> 매출 리포트 Excel 다운로드
                        </button>
                    </div>
                </div>

                {/* KPI 부문 */}
                <BillingKPIs 
                    totalMRR={totalMRR}
                    totalARR={totalARR}
                    subscribedCompaniesCount={subscribedCompanies.length}
                    planCounts={planCounts}
                    totalRevenue={totalRevenue}
                    paidPaymentsCount={paidPayments.length}
                    pendingAmount={pendingAmount}
                    pendingPaymentsCount={pendingPayments.length}
                    overduePaymentsCount={overduePayments.length}
                />

                <div className="grid lg:grid-cols-3 gap-5 mb-6">
                    {/* 구독 기업 리스트 */}
                    <SubscribedCompanyList 
                        subscribedCompanies={subscribedCompanies}
                        onSelectCompany={setSelectedCompany}
                    />

                    {/* 매출 차트 / 파이프라인 */}
                    <PlanRevenueCharts 
                        planCounts={planCounts}
                        totalMRR={totalMRR}
                        contractSentCount={contractSentCount}
                        contractSignedCount={contractSignedCount}
                        pendingPaymentsCount={pendingPayments.length}
                    />
                </div>

                {/* 하단 결제 테이블 및 시스템 로그 영역 
                    (향후 PaymentTable.tsx 및 ActivityLog.tsx로 분리 예정)
                */}
                
            </div>

            {/* 기업 상세 사이드패널 */}
            <AnimatePresence>
                {selectedCompany && (
                    <motion.div className="fixed inset-0 z-50 flex justify-end"
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                        <div className="absolute inset-0 bg-black/30" onClick={() => setSelectedCompany(null)} />
                        <motion.div initial={{ x: 400 }} animate={{ x: 0 }} exit={{ x: 400 }}
                            className="relative w-full max-w-md h-full overflow-y-auto"
                            style={{ background: T.card, borderLeft: `1px solid ${T.border}` }}>
                            <div className="sticky top-0 z-10 flex items-center justify-between px-6 py-4"
                                style={{ background: T.card, borderBottom: `1px solid ${T.borderSub}` }}>
                                <h3 className="font-black" style={{ color: T.heading }}>결제 상세</h3>
                                <button onClick={() => setSelectedCompany(null)} className="p-1 rounded hover:bg-gray-100">
                                    <X className="w-5 h-5" style={{ color: T.muted }} />
                                </button>
                            </div>
                            <div className="p-6 space-y-5">
                                {/* 기업 정보 */}
                                <div>
                                    <h4 className="text-lg font-black mb-1" style={{ color: T.heading }}>{selectedCompany.name}</h4>
                                    <p className="text-xs" style={{ color: T.muted }}>{selectedCompany.biz}</p>
                                </div>
                                {/* 구독 정보 */}
                                <div className="p-4 rounded-xl" style={{ background: T.bg, border: `1px solid ${T.border}` }}>
                                    <p className="text-[10px] font-bold mb-2" style={{ color: T.gold }}>구독 정보</p>
                                    <div className="grid grid-cols-2 gap-3 text-xs">
                                        <div>
                                            <p style={{ color: T.faint }}>플랜</p>
                                            <p className="font-bold" style={{ color: T.heading }}>{PLAN_LABEL[selectedCompany.plan]}</p>
                                        </div>
                                        <div>
                                            <p style={{ color: T.faint }}>월 구독료</p>
                                            <p className="font-bold" style={{ color: T.heading }}>₩{(PLAN_PRICE[selectedCompany.plan] || 0).toLocaleString()}</p>
                                        </div>
                                        <div>
                                            <p style={{ color: T.faint }}>가맹점수</p>
                                            <p className="font-bold" style={{ color: T.heading }}>{selectedCompany.storeCount.toLocaleString()}개</p>
                                        </div>
                                        <div>
                                            <p style={{ color: T.faint }}>담당 변호사</p>
                                            <p className="font-bold" style={{ color: T.heading }}>{selectedCompany.assignedLawyer || '-'}</p>
                                        </div>
                                        <div>
                                            <p style={{ color: T.faint }}>이메일</p>
                                            <p className="font-bold" style={{ color: '#2563eb' }}>{selectedCompany.email}</p>
                                        </div>
                                        <div>
                                            <p style={{ color: T.faint }}>전화</p>
                                            <p className="font-bold" style={{ color: T.heading }}>{selectedCompany.phone}</p>
                                        </div>
                                    </div>
                                </div>
                                {/* 이 기업의 결제 내역 */}
                                <div>
                                    <p className="text-xs font-black mb-2" style={{ color: T.heading }}>결제 이력</p>
                                    {payments.filter(p => p.companyId === selectedCompany.id).map(p => {
                                        const s = PAY_STATUS_STYLE[p.status];
                                        return (
                                            <div key={p.id} className="flex items-center justify-between py-2"
                                                style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                                <div>
                                                    <p className="text-xs font-bold" style={{ color: T.body }}>{p.date}</p>
                                                    <p className="text-[10px]" style={{ color: T.faint }}>{p.invoiceNo}</p>
                                                </div>
                                                <div className="text-right">
                                                    <p className="text-xs font-bold" style={{ color: T.heading }}>₩{p.amount.toLocaleString()}</p>
                                                    <span className="text-[10px] px-1.5 py-0.5 rounded-full font-bold"
                                                        style={{ color: s.color, background: s.bg }}>{s.label}</span>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Toast */}
            <AnimatePresence>
                {toast && (
                    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 20 }}
                        className="fixed bottom-6 left-1/2 -translate-x-1/2 px-5 py-3 rounded-xl text-sm font-bold z-50"
                        style={{ background: '#111827', color: '#f0f4ff', border: '1px solid rgba(201,168,76,0.3)' }}>
                        {toast}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

import React from 'react';
import { Search, Receipt } from 'lucide-react';
import { PaymentRecord, PLAN_LABEL, PAY_STATUS_STYLE, T } from '../../types';

interface InternalPaymentTableProps {
    filteredPayments: PaymentRecord[];
    search: string;
    setSearch: (val: string) => void;
    statusFilter: string;
    setStatusFilter: (val: string) => void;
    setToast: (msg: string) => void;
}

export default function InternalPaymentTable({
    filteredPayments,
    search,
    setSearch,
    statusFilter,
    setStatusFilter,
    setToast,
}: InternalPaymentTableProps) {
    return (
        <div className="rounded-2xl" style={{ background: T.card, border: `1px solid ${T.border}` }}>
            <div className="flex items-center justify-between px-6 py-4" style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                <h3 className="font-black flex items-center gap-2" style={{ color: T.heading }}>
                    <Receipt className="w-4 h-4" style={{ color: '#2563eb' }} />
                    결제 내역
                </h3>
                <div className="flex items-center gap-2">
                    {/* 검색 */}
                    <div className="relative">
                        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5" style={{ color: T.faint }} />
                        <input value={search} onChange={e => setSearch(e.target.value)}
                            placeholder="기업명 또는 청구서 번호"
                            className="pl-8 pr-3 py-1.5 rounded-lg text-xs w-48 outline-none"
                            style={{ background: T.bg, color: T.body, border: `1px solid ${T.border}` }} />
                    </div>
                    {/* 필터 */}
                    <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}
                        className="px-3 py-1.5 rounded-lg text-xs font-bold outline-none cursor-pointer"
                        style={{ background: T.bg, color: T.body, border: `1px solid ${T.border}` }}>
                        <option value="all">전체</option>
                        <option value="paid">결제 완료</option>
                        <option value="pending">결제 대기</option>
                        <option value="overdue">연체</option>
                    </select>
                </div>
            </div>
            <div className="overflow-x-auto">
                <table className="w-full">
                    <thead>
                        <tr style={{ background: '#fafaf8', borderBottom: `1px solid ${T.borderSub}` }}>
                            {['날짜', '기업명', '청구서 번호', '플랜', '금액', '결제수단', '상태', ''].map(h => (
                                <th key={h} className="text-left text-xs font-black py-3 px-3" style={{ color: T.gold }}>{h}</th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {filteredPayments.length === 0 ? (
                            <tr>
                                <td colSpan={8} className="text-center py-12 text-sm" style={{ color: T.muted }}>
                                    결제 내역이 없습니다
                                </td>
                            </tr>
                        ) : filteredPayments.map(p => {
                            const s = PAY_STATUS_STYLE[p.status];
                            return (
                                <tr key={p.id} className="hover:bg-gray-50/50 transition-colors"
                                    style={{ borderBottom: `1px solid ${T.borderSub}` }}>
                                    <td className="py-3 px-3 text-xs" style={{ color: T.body }}>{p.date}</td>
                                    <td className="py-3 px-3 text-xs font-bold" style={{ color: T.heading }}>{p.companyName}</td>
                                    <td className="py-3 px-3 text-xs font-mono" style={{ color: T.faint }}>{p.invoiceNo}</td>
                                    <td className="py-3 px-3">
                                        <span className="text-[10px] px-2 py-0.5 rounded-full font-bold"
                                            style={{ background: '#eff6ff', color: '#2563eb' }}>
                                            {PLAN_LABEL[p.plan] || p.plan}
                                        </span>
                                    </td>
                                    <td className="py-3 px-3 text-xs font-bold" style={{ color: T.heading }}>
                                        ₩{p.amount.toLocaleString()}
                                    </td>
                                    <td className="py-3 px-3 text-xs" style={{ color: T.muted }}>{p.method}</td>
                                    <td className="py-3 px-3">
                                        <span className="text-[10px] px-2 py-0.5 rounded-full font-bold"
                                            style={{ color: s.color, background: s.bg }}>
                                            {s.label}
                                        </span>
                                    </td>
                                    <td className="py-3 px-3">
                                        <button className="flex items-center gap-1 text-[10px] font-bold"
                                            style={{ color: '#2563eb' }}
                                            onClick={() => setToast(`📄 ${p.invoiceNo} 영수증 다운로드`)}>
                                            <Receipt className="w-3 h-3" /> 영수증
                                        </button>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
            {filteredPayments.length > 0 && (
                <div className="flex items-center justify-between px-6 py-3" style={{ borderTop: `1px solid ${T.borderSub}`, background: '#fafaf8' }}>
                    <span className="text-[10px]" style={{ color: T.faint }}>
                        총 {filteredPayments.length}건
                    </span>
                    <span className="text-xs font-bold" style={{ color: T.heading }}>
                        합계: ₩{filteredPayments.reduce((s, p) => s + p.amount, 0).toLocaleString()}
                    </span>
                </div>
            )}
        </div>
    );
}

