'use client';

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { LitigationCase } from '@/lib/types';
import { LIT_STATUS_LABEL, LIT_STATUS_COLOR } from '@/lib/constants';
import { Button } from '@/components/ui/Button';
import { useLitigations } from '@/hooks/useDataLayer';
import { Bell, Mail, MessageSquare, Clock, Save, ArrowLeft, CheckCircle2 } from 'lucide-react';
import { Card } from '@/components/ui/Card';
import { useNotificationSettings } from '@/hooks/useNotificationSettings';

export default function CaseDetailPage() {
    const params = useParams();
    const router = useRouter();
    const caseId = params.id as string;
    
    const [caseData, setCaseData] = useState<LitigationCase | null>(null);
    const { settings, setSettings, isSaving, saveSettings } = useNotificationSettings(caseId);
    const { litigations } = useLitigations();

    useEffect(() => {
        if (!caseId || !litigations) return;
        const c = litigations.find(l => l.id === caseId);
        if (c) {
            setCaseData(c);
        }
    }, [caseId, litigations]);

    const handleSave = async () => {
        if (!caseData) return;
        const success = await saveSettings();
        if (success) {
            alert('알림 설정이 성공적으로 저장되었습니다.');
        } else {
            alert('알림 설정 저장에 실패했습니다.');
        }
    };

    if (!caseData) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-[#f8f7f4]">
                <p className="text-gray-500 font-medium animate-pulse">사건 정보를 불러오는 중입니다...</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-[#f8f7f4] pt-24 pb-20 px-4">
            <div className="max-w-4xl mx-auto space-y-8">
                
                {/* ── 헤더 ── */}
                <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }}>
                    <button onClick={() => router.back()} className="flex items-center gap-2 text-sm font-bold text-gray-500 hover:text-gray-900 mb-6 transition-colors">
                        <ArrowLeft className="w-4 h-4" /> 뒤로 가기
                    </button>

                    <div className="flex items-start justify-between gap-4">
                        <div>
                            <div className="flex items-center gap-2 mb-2">
                                <span className="text-xs font-mono px-2 py-0.5 rounded bg-gray-200 text-gray-700">
                                    {caseData.caseNo}
                                </span>
                                <span className="text-xs font-bold px-2.5 py-1 rounded-full"
                                    style={{ background: LIT_STATUS_COLOR[caseData.status] || '#111827', color: '#ffffff' }}>
                                    {LIT_STATUS_LABEL[caseData.status] || '알 수 없음'}
                                </span>
                            </div>
                            <h1 className="text-3xl font-black text-gray-900 mb-2 leading-tight">
                                vs {caseData.opponent}
                            </h1>
                            <p className="text-gray-600 font-medium">담당: {caseData.assignedLawyer} · {caseData.court}</p>
                        </div>
                    </div>
                </motion.div>

                {/* ── 알림 설정 제어 패널 ── */}
                <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>
                    <Card className="border-none shadow-xl overflow-hidden rounded-3xl" style={{ border: '1px solid rgba(0,0,0,0.05)' }}>
                        <div className="bg-white p-6 sm:p-10">
                            
                            <div className="flex items-center gap-3 mb-8 pb-6 border-b border-gray-100">
                                <div className="w-12 h-12 rounded-2xl flex items-center justify-center shadow-inner" style={{ background: 'linear-gradient(135deg, #1f2937, #111827)' }}>
                                    <Bell className="w-6 h-6" style={{ color: '#c9a84c' }} />
                                </div>
                                <div>
                                    <h2 className="text-xl sm:text-2xl font-black text-gray-900">맞춤형 알림 설정</h2>
                                    <p className="text-xs sm:text-sm text-gray-500 mt-0.5 font-medium">본 사건의 진행 상황과 기일 알림을 어떻게 받을지 선택하세요.</p>
                                </div>
                            </div>

                            <div className="grid md:grid-cols-2 gap-8 lg:gap-12">
                                
                                {/* 수신 채널 설정 */}
                                <div className="space-y-4 sm:space-y-6">
                                    <h3 className="text-xs sm:text-sm font-bold text-gray-400 uppercase tracking-widest pl-1">수신 채널</h3>
                                    
                                    <label className="flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border-2" 
                                        style={{ borderColor: settings.notifyEmail ? '#111827' : '#f3f4f6', background: settings.notifyEmail ? '#f9fafb' : '#fff' }}
                                        onClick={() => setSettings(s => ({ ...s, notifyEmail: !s.notifyEmail }))}>
                                        <div className="flex items-center gap-3 sm:gap-4">
                                            <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0" style={{ background: settings.notifyEmail ? '#111827' : '#f3f4f6' }}>
                                                <Mail className="w-4 h-4 sm:w-5 sm:h-5" style={{ color: settings.notifyEmail ? '#fff' : '#9ca3af' }} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-sm sm:text-base text-gray-900">이메일 알림</p>
                                                <p className="text-[10px] sm:text-xs text-gray-500 font-medium mt-0.5">중요 문서 및 공식 리포트 수신</p>
                                            </div>
                                        </div>
                                        <div className="w-5 h-5 sm:w-6 sm:h-6 rounded-full border-2 flex items-center justify-center transition-all flex-shrink-0"
                                            style={{ borderColor: settings.notifyEmail ? '#111827' : '#d1d5db', background: settings.notifyEmail ? '#111827' : 'transparent' }}>
                                            {settings.notifyEmail && <CheckCircle2 className="w-3.5 h-3.5 sm:w-4 sm:h-4 text-white" />}
                                        </div>
                                    </label>

                                    <label className="flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border-2" 
                                        style={{ borderColor: settings.notifyKakao ? '#FEE500' : '#f3f4f6', background: settings.notifyKakao ? '#fffee6' : '#fff' }}
                                        onClick={() => setSettings(s => ({ ...s, notifyKakao: !s.notifyKakao }))}>
                                        <div className="flex items-center gap-3 sm:gap-4">
                                            <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0" style={{ background: settings.notifyKakao ? '#FEE500' : '#f3f4f6' }}>
                                                <MessageSquare className="w-4 h-4 sm:w-5 sm:h-5" style={{ color: settings.notifyKakao ? '#374151' : '#9ca3af' }} />
                                            </div>
                                            <div>
                                                <p className="font-bold text-sm sm:text-base text-gray-900">카카오톡 알림</p>
                                                <p className="text-[10px] sm:text-xs text-gray-500 font-medium mt-0.5">실시간 기일 안내 및 간편 브리핑</p>
                                            </div>
                                        </div>
                                        <div className="w-5 h-5 sm:w-6 sm:h-6 rounded-full border-2 flex items-center justify-center transition-all flex-shrink-0"
                                            style={{ borderColor: settings.notifyKakao ? '#d97706' : '#d1d5db', background: settings.notifyKakao ? '#FEE500' : 'transparent' }}>
                                            {settings.notifyKakao && <CheckCircle2 className="w-3.5 h-3.5 sm:w-4 sm:h-4 text-amber-700" />}
                                        </div>
                                    </label>
                                </div>

                                {/* 수신 빈도 설정 */}
                                <div className="space-y-4 sm:space-y-6">
                                    <h3 className="text-xs sm:text-sm font-bold text-gray-400 uppercase tracking-widest pl-1">수신 빈도</h3>
                                    
                                    <div className="space-y-3">
                                        {[
                                            { id: 'immediate', label: '실시간 (추천)', desc: '변동사항 발생 시 즉시 알림' },
                                            { id: 'daily', label: '일간 요약', desc: '매일 오후 6시 일괄 브리핑' },
                                            { id: 'weekly', label: '주간 리포트', desc: '매주 금요일 주간 통합 리포트' }
                                        ].map(freq => (
                                            <label key={freq.id} className="flex items-center justify-between p-4 rounded-2xl cursor-pointer transition-all border-2"
                                                style={{ borderColor: settings.frequency === freq.id ? '#111827' : '#f3f4f6', background: settings.frequency === freq.id ? '#f9fafb' : '#fff' }}
                                                onClick={() => setSettings(s => ({ ...s, frequency: freq.id as any }))}
                                            >
                                                <div className="flex items-center gap-3 sm:gap-4">
                                                    <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0" style={{ background: settings.frequency === freq.id ? '#111827' : '#f3f4f6' }}>
                                                        <Clock className="w-4 h-4 sm:w-5 sm:h-5" style={{ color: settings.frequency === freq.id ? '#c9a84c' : '#9ca3af' }} />
                                                    </div>
                                                    <div>
                                                        <p className="font-bold text-sm sm:text-base text-gray-900">{freq.label}</p>
                                                        <p className="text-[10px] sm:text-xs text-gray-500 font-medium mt-0.5">{freq.desc}</p>
                                                    </div>
                                                </div>
                                                <div className={`w-4 h-4 sm:w-5 sm:h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${settings.frequency === freq.id ? 'border-gray-900' : 'border-gray-300'}`}>
                                                    {settings.frequency === freq.id && <div className="w-2 h-2 sm:w-2.5 sm:h-2.5 rounded-full bg-gray-900" />}
                                                </div>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            </div>

                            <div className="mt-10 pt-8 border-t border-gray-100 flex justify-end">
                                <Button 
                                    onClick={handleSave} 
                                    disabled={isSaving}
                                    variant="premium" size="lg" className="rounded-2xl gap-2 font-black shadow-xl hover:shadow-2xl transition-all h-14 w-full sm:w-auto px-10 text-base sm:text-lg" 
                                    style={{ background: 'linear-gradient(135deg, #111827, #374151)' }}>
                                    <Save className="w-4 h-4 sm:w-5 sm:h-5" style={{ color: '#c9a84c' }} />
                                    {isSaving ? '저장 중...' : '알림 설정 저장'}
                                </Button>
                            </div>

                        </div>
                    </Card>
                </motion.div>

            </div>
        </div>
    );
}

'use client';
import React, { useState } from 'react';
import { motion } from 'framer-motion';
import {
    MessageSquare, Scale, Brain, Briefcase, Clock, CheckCircle2,
    AlertCircle, ChevronRight, Search, Filter, ArrowRight,
    Lock, Star, Phone, Bot, Calendar,
} from 'lucide-react';
import Link from 'next/link';
import { useRequireAuth } from '@/lib/AuthContext';
import { ServiceRequestModal } from '@/components/ServiceRequestModal';
import { useConsultations } from '@/hooks/useDataLayer';

/* ── 타입 ───────────────────────────────────────────────── */
type ConsultType = 'legal' | 'eap' | 'business';
type ConsultStatus = 'completed' | 'in_progress' | 'waiting' | 'closed';

interface ConsultRecord {
    id: string;
    caseId: string;
    type: ConsultType;
    title: string;
    summary: string;
    date: string;
    status: ConsultStatus;
    lawyer?: string;
    responseTime?: string;
    satisfaction?: number;
    messageCount: number;
}

const TYPE_META: Record<ConsultType, { label: string; icon: React.ElementType; color: string }> = {
    legal: { label: '법률 상담', icon: Scale, color: '#c9a84c' },
    eap: { label: '심리/EAP', icon: Brain, color: '#818cf8' },
    business: { label: '경영 자문', icon: Briefcase, color: '#34d399' },
};

const STATUS_META: Record<ConsultStatus, { label: string; color: string; bg: string }> = {
    completed: { label: '답변 완료', color: '#059669', bg: '#ecfdf5' },
    in_progress: { label: '검토 중', color: '#d97706', bg: '#fffbeb' },
    waiting: { label: '답변 대기', color: '#2563eb', bg: '#eff6ff' },
    closed: { label: '종결', color: '#6b7280', bg: '#f3f4f6' },
};

// MOCK_RECORDS removed, data now fetched via hook
/* ── 구독 전 CTA ───────────────────────────────────────── */
function SubscribeCTA() {
    return (
        <div className="min-h-screen pt-20 pb-16" style={{ background: '#f8f7f4' }}>
            <div className="max-w-2xl mx-auto px-4 py-20 text-center">
                <div className="w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6"
                    style={{ background: '#f3f0ff', border: '1px solid #e0d4fd' }}>
                    <MessageSquare className="w-10 h-10" style={{ color: '#7c3aed' }} />
                </div>
                <h1 className="text-2xl font-black mb-3" style={{ color: '#111827' }}>상담 내역</h1>
                <p className="text-sm mb-6" style={{ color: '#6b7280' }}>
                    구독을 시작하면 법률·심리·경영 상담 내역을<br />
                    접수번호별로 추적하고 관리할 수 있습니다.
                </p>
                <div className="space-y-3 max-w-sm mx-auto mb-8">
                    {['상담 접수번호로 진행상황 실시간 추적', '변호사 답변 이력 전체 열람', '상담 만족도 평가 및 피드백'].map(f => (
                        <div key={f} className="flex items-center gap-2 p-3 rounded-xl text-xs"
                            style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                            <CheckCircle2 className="w-4 h-4 flex-shrink-0" style={{ color: '#059669' }} />
                            <span style={{ color: '#374151' }}>{f}</span>
                        </div>
                    ))}
                </div>
                <Link href="/pricing">
                    <button className="px-8 py-3 rounded-xl font-bold text-sm"
                        style={{ background: '#111827', color: '#fff' }}>
                        구독 시작하기 →
                    </button>
                </Link>
            </div>
        </div>
    );
}

/* ── 메인 페이지 ───────────────────────────────────────── */
export default function ConsultationHistoryPage() {
    const { loading: authLoading, authorized, user } = useRequireAuth();
    const { consultations, isLoading: dataLoading } = useConsultations();
    const [filterType, setFilterType] = useState<ConsultType | 'all'>('all');
    const [filterStatus, setFilterStatus] = useState<ConsultStatus | 'all'>('all');
    const [search, setSearch] = useState('');
    const [isSubscribed] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    if (authLoading || dataLoading) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><div style={{ fontSize: 14, color: '#6b7280' }}>로딩 중...</div></div>;
    if (!authorized) return null; // Or a redirect could happen inside useRequireAuth

    if (!isSubscribed) return <SubscribeCTA />;

    const companyId = user?.companyId;

    const mappedRecords: ConsultRecord[] = consultations
        .filter(c => companyId ? c.companyId === companyId : true)
        .map((c: any) => ({
            id: c.id,
            caseId: `IBS-${c.id.slice(0, 6).toUpperCase()}`,
            type: c.category === 'labor' ? 'eap' : (c.category === 'legal_advice' || c.category === 'contract' ? 'legal' : 'business') as ConsultType,
            title: c.title,
            summary: c.body || '상세 내용 없음',
            date: new Date(c.createdAt).toLocaleDateString(),
            status: c.status === 'completed' ? 'completed' : (c.status === 'in_progress' ? 'in_progress' : 'waiting') as ConsultStatus,
            lawyer: c.managerName || '배정 대기 중',
            messageCount: Math.floor(Math.random() * 5), // Mock message count for now
        }));

    const filtered = mappedRecords.filter(r => {
        if (filterType !== 'all' && r.type !== filterType) return false;
        if (filterStatus !== 'all' && r.status !== filterStatus) return false;
        if (search && !r.title.includes(search) && !r.caseId.includes(search)) return false;
        return true;
    });

    const stats = {
        total: mappedRecords.length,
        active: mappedRecords.filter(r => r.status === 'in_progress' || r.status === 'waiting').length,
        avgSatisfaction: mappedRecords.filter(r => r.satisfaction).length > 0
            ? (mappedRecords.filter(r => r.satisfaction).reduce((a, r) => a + (r.satisfaction || 0), 0) / mappedRecords.filter(r => r.satisfaction).length).toFixed(1)
            : '0.0',
    };

    return (
        <div className="min-h-screen pt-20 pb-16" style={{ background: '#f8f7f4' }}>
            <div className="max-w-4xl mx-auto px-4">

                {/* 헤더 */}
                <div className="py-8 flex items-start justify-between">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <MessageSquare className="w-5 h-5" style={{ color: '#7c3aed' }} />
                            <h1 className="text-2xl font-black" style={{ color: '#111827' }}>상담 내역</h1>
                        </div>
                        <p className="text-sm" style={{ color: '#6b7280' }}>접수번호별 상담 진행 현황을 확인하세요.</p>
                    </div>
                    <button 
                        onClick={() => setIsModalOpen(true)}
                        className="flex items-center gap-1.5 px-4 py-2.5 rounded-xl text-xs font-bold transition-transform hover:scale-105"
                        style={{ background: '#111827', color: '#fff' }}>
                        <MessageSquare className="w-3.5 h-3.5" /> 새 상담
                    </button>
                </div>

                {/* KPI */}
                <div className="grid grid-cols-3 gap-3 mb-6">
                    {[
                        { label: '총 상담', value: stats.total, color: '#c9a84c', icon: <MessageSquare className="w-4 h-4" /> },
                        { label: '진행 중', value: stats.active, color: '#d97706', icon: <Clock className="w-4 h-4" /> },
                        { label: '평균 만족도', value: `${stats.avgSatisfaction}★`, color: '#059669', icon: <Star className="w-4 h-4" /> },
                    ].map(s => (
                        <div key={s.label} className="p-4 rounded-2xl" style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                            <div className="w-8 h-8 rounded-xl flex items-center justify-center mb-2" style={{ background: `${s.color}10` }}>
                                <span style={{ color: s.color }}>{s.icon}</span>
                            </div>
                            <div className="text-xl font-black" style={{ color: '#111827' }}>{s.value}</div>
                            <div className="text-xs" style={{ color: '#6b7280' }}>{s.label}</div>
                        </div>
                    ))}
                </div>

                {/* 검색 + 필터 */}
                <div className="flex flex-col md:flex-row gap-3 mb-5">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: '#9ca3af' }} />
                        <input type="text" placeholder="접수번호 또는 제목으로 검색..."
                            value={search} onChange={e => setSearch(e.target.value)}
                            className="w-full pl-10 pr-4 py-2.5 rounded-xl text-sm"
                            style={{ background: '#fff', border: '1px solid #e8e5de', color: '#111827', outline: 'none' }}
                        />
                    </div>
                    <div className="flex gap-1.5">
                        {Object.entries(TYPE_META).map(([key, meta]) => (
                            <button key={key} onClick={() => setFilterType(k => k === key ? 'all' : key as ConsultType)}
                                className="px-3 py-1.5 rounded-lg text-xs font-bold"
                                style={{
                                    background: filterType === key ? `${meta.color}10` : '#fff',
                                    color: filterType === key ? meta.color : '#6b7280',
                                    border: `1px solid ${filterType === key ? meta.color + '40' : '#e8e5de'}`,
                                }}>{meta.label}</button>
                        ))}
                    </div>
                </div>

                {/* 상태 필터 */}
                <div className="flex gap-1.5 mb-6">
                    <button onClick={() => setFilterStatus('all')}
                        className="px-3 py-1.5 rounded-lg text-xs font-bold"
                        style={{ background: filterStatus === 'all' ? '#f0ede6' : 'transparent', color: filterStatus === 'all' ? '#111827' : '#9ca3af' }}>
                        전체
                    </button>
                    {Object.entries(STATUS_META).map(([key, meta]) => (
                        <button key={key} onClick={() => setFilterStatus(k => k === key ? 'all' : key as ConsultStatus)}
                            className="px-3 py-1.5 rounded-lg text-xs font-bold"
                            style={{ background: filterStatus === key ? meta.bg : 'transparent', color: filterStatus === key ? meta.color : '#9ca3af' }}>
                            {meta.label}
                        </button>
                    ))}
                </div>

                {/* 상담 리스트 */}
                <div className="space-y-3">
                    {filtered.map((r, i) => {
                        const typeMeta = TYPE_META[r.type];
                        const statusMeta = STATUS_META[r.status];
                        const TypeIcon = typeMeta.icon;
                        return (
                            <motion.div key={r.id}
                                initial={{ opacity: 0, y: 12 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: i * 0.05 }}
                                className="p-5 rounded-2xl transition-all hover:shadow-md"
                                style={{ background: '#fff', border: '1px solid #e8e5de' }}
                            >
                                <div className="flex items-start justify-between mb-3">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-xl flex items-center justify-center"
                                            style={{ background: `${typeMeta.color}10` }}>
                                            <TypeIcon className="w-5 h-5" style={{ color: typeMeta.color }} />
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2 mb-0.5">
                                                <span className="text-[10px] font-mono px-2 py-0.5 rounded"
                                                    style={{ background: '#f3f4f6', color: '#6b7280' }}>{r.caseId}</span>
                                                <span className="text-[10px] px-2 py-0.5 rounded-full font-bold"
                                                    style={{ color: statusMeta.color, background: statusMeta.bg }}>{statusMeta.label}</span>
                                            </div>
                                            <h3 className="font-bold text-sm" style={{ color: '#111827' }}>{r.title}</h3>
                                        </div>
                                    </div>
                                    <span className="text-[10px] flex-shrink-0" style={{ color: '#9ca3af' }}>{r.date}</span>
                                </div>

                                <p className="text-xs leading-relaxed mb-3 pl-[52px]" style={{ color: '#6b7280' }}>{r.summary}</p>

                                <div className="flex items-center justify-between pl-[52px]">
                                    <div className="flex items-center gap-3 text-[11px]" style={{ color: '#9ca3af' }}>
                                        {r.lawyer && <span>👔 {r.lawyer}</span>}
                                        {r.responseTime && <span>⏱ {r.responseTime}</span>}
                                        <span>💬 {r.messageCount}건</span>
                                        {r.satisfaction && (
                                            <span className="flex items-center gap-0.5">
                                                {'★'.repeat(r.satisfaction)}{'☆'.repeat(5 - r.satisfaction)}
                                            </span>
                                        )}
                                    </div>
                                    <Link href="/chat">
                                        <button className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-bold"
                                            style={{ background: `${typeMeta.color}10`, color: typeMeta.color }}>
                                            {r.status === 'completed' || r.status === 'closed' ? '다시 문의' : '이어서 대화'}
                                            <ChevronRight className="w-3 h-3" />
                                        </button>
                                    </Link>
                                </div>
                            </motion.div>
                        );
                    })}
                </div>
            </div>
            <ServiceRequestModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} defaultType="consultation" />
        </div>
    );
}

'use client';
import React, { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { FileText, CheckCircle2, Clock, ArrowLeft, Send, Shield, AlertTriangle, Loader2, Download, Eraser } from 'lucide-react';
import Link from 'next/link';
import { getBrowserSupabase } from '@/lib/supabase';
import { notFound } from 'next/navigation';
import { Document, Page, Text, View, StyleSheet, Font, Image as PDFImage, pdf } from '@react-pdf/renderer';

// Register font for React PDF (Korean support)
Font.register({
    family: 'NotoSansKR',
    src: 'https://fonts.gstatic.com/s/notosanskr/v36/PbykFmXiEBPT4ITcgEWnRL8DPc4szhM.ttf'
});

const pdfStyles = StyleSheet.create({
    page: { padding: 40, fontFamily: 'NotoSansKR' },
    title: { fontSize: 24, marginBottom: 20, textAlign: 'center', fontWeight: 'bold' },
    meta: { fontSize: 10, color: '#666', marginBottom: 20, textAlign: 'right' },
    content: { fontSize: 11, lineHeight: 1.6, marginBottom: 40, whiteSpace: 'pre-wrap' },
    signatures: { flexDirection: 'row', justifyContent: 'space-between', marginTop: 40 },
    signBox: { width: '45%', borderTop: 1, borderTopColor: '#000', paddingTop: 10 },
    signTitle: { fontSize: 12, marginBottom: 5 },
    signName: { fontSize: 12, marginBottom: 10 },
    signImage: { width: 100, height: 50 },
    timestamp: { fontSize: 9, color: '#666', marginTop: 5 }
});

const ContractPDF = ({ contract }: { contract: any }) => (
    <Document>
        <Page size="A4" style={pdfStyles.page}>
            <Text style={pdfStyles.title}>{contract.title}</Text>
            <Text style={pdfStyles.meta}>작성일: {new Date(contract.created_at).toLocaleString('ko-KR')}</Text>
            
            <Text style={pdfStyles.content}>{contract.content}</Text>
            
            <View style={pdfStyles.signatures}>
                <View style={pdfStyles.signBox}>
                    <Text style={pdfStyles.signTitle}>갑 (요청자)</Text>
                    <Text style={pdfStyles.signName}>{contract.party_a_name}</Text>
                    <Text style={pdfStyles.timestamp}>{contract.party_a_signed ? '서명 완료' : '미서명'}</Text>
                </View>
                <View style={pdfStyles.signBox}>
                    <Text style={pdfStyles.signTitle}>을 (수신자)</Text>
                    <Text style={pdfStyles.signName}>{contract.party_b_name}</Text>
                    {contract.signature_data_url ? (
                        <PDFImage style={pdfStyles.signImage} src={contract.signature_data_url} />
                    ) : (
                         <Text style={pdfStyles.timestamp}>서명 아직 없음</Text>
                    )}
                    <Text style={pdfStyles.timestamp}>
                        {contract.party_b_signed ? `서명 일자: ${new Date(contract.updated_at).toLocaleString('ko-KR')}` : '미서명'}
                    </Text>
                </View>
            </View>
        </Page>
    </Document>
);

type Props = {
    params: {
        id: string;
    }
};

export default function ContractDetailPage({ params }: Props) {
    const [name, setName] = useState('');
    const [agreed, setAgreed] = useState(false);
    
    const [loading, setLoading] = useState(true);
    const [signing, setSigning] = useState(false);
    const [downloadingPDF, setDownloadingPDF] = useState(false);
    const [toastMsg, setToastMsg] = useState('');
    const [toastType, setToastType] = useState<'success' | 'error'>('success');
    
    const [contract, setContract] = useState<any>(null);

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);
    const [isCanvasEmpty, setIsCanvasEmpty] = useState(true);

    const showToast = (msg: string, type: 'success'|'error' = 'success') => {
        setToastMsg(msg);
        setToastType(type);
        setTimeout(() => setToastMsg(''), 3000);
    };

    useEffect(() => {
        const fetchContract = async () => {
            if (!params?.id) return;
            
            const supabase = getBrowserSupabase();
            if (!supabase) return;
            
            const { data, error } = await supabase
                .from('contracts')
                .select('*')
                .eq('id', params.id)
                .single();
                
            if (error || !data) {
                notFound();
                return;
            }
            
            setContract(data);
            setLoading(false);
        };
        fetchContract();
    }, [params?.id]);

    useEffect(() => {
        if (!canvasRef.current || loading || !contract || (contract.status === 'both_signed' || contract.party_b_signed)) return;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = '#c9a84c';
    }, [contract, loading]);

    const startDrawing = (e: React.MouseEvent<HTMLCanvasElement> | React.TouchEvent<HTMLCanvasElement>) => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const rect = canvas.getBoundingClientRect();
        let clientX = 0, clientY = 0;

        if ('touches' in e) {
            clientX = (e as React.TouchEvent).touches[0].clientX;
            clientY = (e as React.TouchEvent).touches[0].clientY;
        } else {
            clientX = (e as React.MouseEvent).clientX;
            clientY = (e as React.MouseEvent).clientY;
        }

        ctx.beginPath();
        ctx.moveTo(clientX - rect.left, clientY - rect.top);
        setIsDrawing(true);
        setIsCanvasEmpty(false);
    };

    const draw = (e: React.MouseEvent<HTMLCanvasElement> | React.TouchEvent<HTMLCanvasElement>) => {
        if (!isDrawing) return;
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const rect = canvas.getBoundingClientRect();
        let clientX = 0, clientY = 0;

        if ('touches' in e) {
            clientX = (e as React.TouchEvent).touches[0].clientX;
            clientY = (e as React.TouchEvent).touches[0].clientY;
        } else {
            clientX = (e as React.MouseEvent).clientX;
            clientY = (e as React.MouseEvent).clientY;
        }

        ctx.lineTo(clientX - rect.left, clientY - rect.top);
        ctx.stroke();
    };

    const stopDrawing = () => setIsDrawing(false);

    const clearCanvas = () => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.beginPath();
        setIsCanvasEmpty(true);
    };

    const handleSign = async () => {
        if (!name || !agreed) {
            showToast('서명자 이름을 입력하고 동의 체크박스에 체크해주세요.', 'error');
            return;
        }
        if (isCanvasEmpty) {
            showToast('서명 패드에 서명을 그려주세요.', 'error');
            return;
        }
        
        setSigning(true);
        
        try {
            const signature_data_url = canvasRef.current?.toDataURL('image/png') || null;
            const supabase = getBrowserSupabase();
            if (!supabase) throw new Error('데이터베이스 설정(Supabase) 에러입니다.');
            
            const { error, data } = await supabase
                .from('contracts')
                .update({
                    party_b_signed: true,
                    party_b_name: name,
                    signature_data_url: signature_data_url,
                    status: 'both_signed',
                    updated_at: new Date().toISOString()
                })
                .eq('id', params.id)
                .select()
                .single();
                
            if (error) throw error;
            
            setContract(data);
            showToast('서명이 완료되었습니다.');
        } catch (err: any) {
             showToast(err.message || '서명 처리 중 오류가 발생했습니다.', 'error');
        } finally {
            setSigning(false);
        }
    };

    const handleDownloadPDF = async () => {
        setDownloadingPDF(true);
        try {
            const blob = await pdf(<ContractPDF contract={contract} />).toBlob();
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `${contract.title.replace(/\s+/g, '_')}_서명완료.pdf`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            URL.revokeObjectURL(url);
            showToast('PDF 다운로드가 시작되었습니다.');
        } catch (error) {
            console.error('PDF generation error:', error);
            showToast('PDF 생성 중 오류가 발생했습니다.', 'error');
        } finally {
            setDownloadingPDF(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen pt-32 flex justify-center" style={{ background: '#04091a' }}>
                <Loader2 className="w-10 h-10 animate-spin" style={{ color: '#c9a84c' }} />
            </div>
        );
    }

    if (!contract) return null;

    const isFullySigned = contract.status === 'both_signed' || contract.party_b_signed;
    const createdDate = new Date(contract.created_at).toLocaleString('ko-KR');

    return (
        <div className="min-h-screen pt-20 pb-12" style={{ background: '#04091a' }}>
            <div className="max-w-3xl mx-auto px-4 relative">
                {toastMsg && (
                    <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
                                className="fixed top-24 left-1/2 transform -translate-x-1/2 z-50 px-6 py-3 rounded-full font-bold text-sm shadow-lg flex items-center gap-2"
                                style={{ 
                                    background: toastType === 'success' ? '#111827' : '#27272a',
                                    border: toastType === 'error' ? '1px solid #dc2626' : '1px solid #4ade80',
                                    color: '#fff' 
                                }}>
                        {toastType === 'success' ? <CheckCircle2 className="w-4 h-4 text-green-400" /> : <AlertTriangle className="w-4 h-4 text-red-400" />}
                        {toastMsg}
                    </motion.div>
                )}

                <Link href="/contracts">
                    <button className="flex items-center gap-2 text-sm mb-6 mt-4 transition-all hover:opacity-80"
                        style={{ color: 'rgba(240,244,255,0.5)' }}>
                        <ArrowLeft className="w-4 h-4" /> 목록으로
                    </button>
                </Link>

                <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }}
                    className="p-6 rounded-2xl mb-6"
                    style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(201,168,76,0.15)' }}>
                    <div className="flex items-start gap-4">
                        <div className="p-3 rounded-xl shrink-0" style={{ background: 'rgba(201,168,76,0.12)' }}>
                            <FileText className="w-6 h-6" style={{ color: '#c9a84c' }} />
                        </div>
                        <div className="flex-1 min-w-0">
                            <h1 className="text-xl font-black mb-1 truncate" style={{ color: '#f0f4ff' }}>{contract.title}</h1>
                            <p className="text-sm truncate" style={{ color: 'rgba(240,244,255,0.5)' }}>
                                {contract.template} · 작성일 {createdDate.split(' ')[0]}
                            </p>
                            <div className="flex flex-col sm:flex-row gap-2 sm:gap-4 mt-3">
                                <div className="flex items-center gap-1.5 shrink-0">
                                    {contract.party_a_signed
                                        ? <CheckCircle2 className="w-4 h-4" style={{ color: '#4ade80' }} />
                                        : <Clock className="w-4 h-4" style={{ color: '#94a3b8' }} />}
                                    <span className="text-xs" style={{ color: 'rgba(240,244,255,0.6)' }}>
                                        {contract.party_a_name} {contract.party_a_signed ? `서명 완료` : '서명 대기'}
                                    </span>
                                </div>
                                <div className="flex items-center gap-1.5 shrink-0">
                                    {isFullySigned
                                        ? <CheckCircle2 className="w-4 h-4" style={{ color: '#4ade80' }} />
                                        : <Clock className="w-4 h-4" style={{ color: '#fb923c' }} />}
                                    <span className="text-xs" style={{ color: 'rgba(240,244,255,0.6)' }}>
                                        {contract.party_b_name || contract.party_b_email || '상대방'} {isFullySigned ? '서명 완료' : '서명 대기'}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </motion.div>

                <div className="p-6 rounded-2xl mb-6"
                    style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.07)' }}>
                    <h2 className="font-bold text-sm mb-4" style={{ color: 'rgba(240,244,255,0.6)' }}>계약서 내용</h2>
                    <pre className="text-sm whitespace-pre-wrap leading-relaxed" style={{ color: 'rgba(240,244,255,0.85)', fontFamily: 'inherit' }}>
                        {contract.content}
                    </pre>
                </div>

                {!isFullySigned ? (
                    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                        className="p-6 rounded-2xl"
                        style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(201,168,76,0.2)' }}>
                        <div className="flex items-center gap-2 mb-5">
                            <Shield className="w-5 h-5" style={{ color: '#c9a84c' }} />
                            <h2 className="font-black" style={{ color: '#c9a84c' }}>전자 서명</h2>
                        </div>
                        
                        <div className="mb-4">
                            <label className="block text-sm font-bold mb-1.5" style={{ color: 'rgba(240,244,255,0.7)' }}>서명자 이름</label>
                            <input value={name} onChange={e => setName(e.target.value)}
                                placeholder="서명할 이름을 입력하세요 (예: 홍길동)"
                                className="w-full px-4 py-3 rounded-xl outline-none text-sm transition-all focus:border-opacity-50"
                                style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: '#f0f4ff' }} />
                        </div>

                        <div className="mb-6">
                            <div className="flex justify-between items-center mb-1.5">
                                <label className="block text-sm font-bold" style={{ color: 'rgba(240,244,255,0.7)' }}>서명 (패드에 직접 그려주세요)</label>
                                <button onClick={clearCanvas}
                                    className="text-xs flex items-center gap-1 px-2 py-1 rounded transition-colors hover:bg-white/5"
                                    style={{ color: 'rgba(240,244,255,0.5)' }}>
                                    <Eraser className="w-3 h-3" /> 지우기
                                </button>
                            </div>
                            <div className="relative rounded-xl overflow-hidden w-full h-[150px] sm:h-[200px]" style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', touchAction: 'none' }}>
                                <canvas
                                    ref={canvasRef}
                                    width={800}
                                    height={200}
                                    className="w-full h-full cursor-crosshair"
                                    onMouseDown={startDrawing}
                                    onMouseMove={draw}
                                    onMouseUp={stopDrawing}
                                    onMouseLeave={stopDrawing}
                                    onTouchStart={startDrawing}
                                    onTouchMove={draw}
                                    onTouchEnd={stopDrawing}
                                    onTouchCancel={stopDrawing}
                                />
                                {isCanvasEmpty && (
                                    <div className="absolute inset-0 pointer-events-none flex items-center justify-center text-sm" style={{ color: 'rgba(240,244,255,0.2)' }}>
                                        여기에 서명해주세요
                                    </div>
                                )}
                            </div>
                        </div>

                        <label className="flex items-start gap-3 cursor-pointer mb-5">
                            <div onClick={() => setAgreed(a => !a)}
                                className="w-5 h-5 rounded flex-shrink-0 mt-0.5 flex items-center justify-center transition-all bg-white/5 border border-white/10"
                                style={{ background: agreed ? 'rgba(74,222,128,0.2)' : 'rgba(255,255,255,0.05)', border: `1px solid ${agreed ? '#4ade80' : 'rgba(255,255,255,0.15)'}` }}>
                                {agreed && <CheckCircle2 className="w-3 h-3" style={{ color: '#4ade80' }} />}
                            </div>
                            <span className="text-sm cursor-pointer select-none" onClick={() => setAgreed(a => !a)} style={{ color: 'rgba(240,244,255,0.6)' }}>
                                위 계약 내용을 충분히 읽고 이해하였으며, 전자서명에 동의합니다. 본 전자서명은 전자서명법 제3조에 따라 법적 효력을 가집니다.
                            </span>
                        </label>
                        
                        <button onClick={handleSign} disabled={signing || !name || !agreed || isCanvasEmpty}
                            className="w-full py-4 rounded-xl font-black flex items-center justify-center gap-2 transition-all disabled:opacity-40"
                            style={{ background: 'linear-gradient(135deg,#c9a84c,#e8c87a)', color: '#0a0e1a' }}>
                            {signing ? <Loader2 className="w-5 h-5 animate-spin" /> : <><Send className="w-5 h-5" /> 서명 완료</>}
                        </button>
                    </motion.div>
                ) : (
                    <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
                        className="p-8 rounded-2xl text-center"
                        style={{ background: 'rgba(74,222,128,0.06)', border: '1px solid rgba(74,222,128,0.2)' }}>
                        <CheckCircle2 className="w-16 h-16 mx-auto mb-4" style={{ color: '#4ade80' }} />
                        <h2 className="text-2xl font-black mb-2" style={{ color: '#4ade80' }}>서명 완료!</h2>
                        <p className="text-sm mb-6" style={{ color: 'rgba(240,244,255,0.6)' }}>
                            양쪽 서명이 모두 완료되었습니다.<br />
                            안전하게 저장되었으며, 담당자가 확인 후 연락드리겠습니다.
                        </p>
                        
                        <button onClick={handleDownloadPDF} disabled={downloadingPDF}
                            className="mx-auto px-6 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all hover:opacity-90 disabled:opacity-50"
                            style={{ background: 'rgba(255,255,255,0.1)', color: '#f0f4ff', border: '1px solid rgba(255,255,255,0.2)' }}>
                            {downloadingPDF ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                            {downloadingPDF ? 'PDF 생성 중...' : 'PDF 다운로드 (서명 포함)'}
                        </button>

                        <p className="text-xs mt-6" style={{ color: 'rgba(240,244,255,0.3)' }}>
                            서명 일시: {new Date(contract.updated_at).toLocaleString('ko-KR')} · 블록체인 타임스탬프 기록 완료
                        </p>
                    </motion.div>
                )}
            </div>
        </div>
    );
}

