import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Gavel } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { COURTS, LITIGATION_TYPES, LAWYERS } from '@/lib/constants';
import { useCompanies, useLitigations } from '@/hooks/useDataLayer';

export const INSTANCE_TYPES = ['1심', '2심(항소)', '3심(상고)', '헌법', '가처분', '가압류', '조정'];
export const CASE_CATEGORIES = ['민사', '형사', '가사', '행정', '헌법', '회생/파산', '국제중재'];

export default function AddCaseModal({ onClose, onAdd }: { onClose: () => void; onAdd: () => void }) {
    const { companies } = useCompanies();
    const { addLitigation } = useLitigations();
    const [form, setForm] = useState({
        companyId: companies?.[0]?.id ?? '', caseNo: '', court: COURTS[0], type: LITIGATION_TYPES[0],
        category: '민사', instance: '1심', opponent: '', opponentCounsel: '', claimAmount: '',
        assignedLawyer: LAWYERS[0], coLawyer: '', assistLawyer: '', notes: '', filingDate: '',
    });
    const [deadlines, setDeadlines] = useState<{ label: string; dueDate: string }[]>([{ label: '소장 접수', dueDate: '' }]);
    const [aiSuggestion, setAiSuggestion] = useState<any>(null);

    useEffect(() => {
        const stored = sessionStorage.getItem('ibs_ocr_suggestion');
        if (stored) {
            try {
                setAiSuggestion(JSON.parse(stored));
            } catch (e) {}
        }
    }, []);

    const handleApplySuggestion = () => {
        if (!aiSuggestion) return;
        setForm(p => ({
            ...p,
            opponent: aiSuggestion.parties?.[1] || p.opponent,
            claimAmount: aiSuggestion.amounts?.[0] ? aiSuggestion.amounts[0].replace(/[^0-9]/g, '') : p.claimAmount,
        }));
    };

    const handleAdd = () => {
        const company = companies.find(c => c.id === form.companyId);
        addLitigation({
            companyId: form.companyId, companyName: company?.name ?? '',
            caseNo: form.caseNo, court: form.court, type: form.type,
            opponent: form.opponent, claimAmount: parseInt(form.claimAmount.replace(/,/g, '')) || 0,
            status: 'preparing', assignedLawyer: form.assignedLawyer,
            deadlines: deadlines.filter(d => d.label && d.dueDate).map((d, i) => ({ id: `d${Date.now()}-${i}`, ...d, completed: false, completedAt: '' })),
            notes: form.notes, result: '', resultNote: '',
        });
        sessionStorage.removeItem('ibs_ocr_suggestion');
        onAdd(); onClose();
    };
    const F = ({ label, reqd, children }: { label: string; reqd?: boolean; children: React.ReactNode }) => (
        <div><label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>{reqd && <span style={{ color: '#dc2626' }}>★ </span>}{label}</label>{children}</div>
    );
    const inputCls = "w-full px-3 py-2 rounded-lg text-sm";
    const inputStyle = { background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' };
    return (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            style={{ background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' }}
            onClick={e => e.target === e.currentTarget && onClose()}>
            <motion.div initial={{ scale: 0.95 }} animate={{ scale: 1 }} exit={{ scale: 0.95 }}
                className="w-full max-w-2xl rounded-2xl p-6 overflow-y-auto max-h-[90vh]"
                style={{ background: '#ffffff', border: '1px solid #e5e7eb', boxShadow: '0 20px 60px rgba(0,0,0,0.15)' }}>
                <div className="flex items-center justify-between mb-5">
                    <h2 className="font-black text-lg" style={{ color: '#1e293b' }}>⚖️ 신규 사건 등록</h2>
                    <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-slate-100" style={{ color: '#94a3b8' }}><X className="w-5 h-5" /></button>
                </div>
                {aiSuggestion && (
                    <div className="mb-4 p-3 rounded-lg flex items-center justify-between" style={{ background: '#f0fdf4', border: '1px solid #bbf7d0' }}>
                        <div>
                            <p className="text-sm font-bold" style={{ color: '#16a34a' }}>🤖 AI가 문서에서 추출한 정보</p>
                            <p className="text-xs" style={{ color: '#15803d' }}>
                                당사자: {aiSuggestion.parties?.join(', ')} / 
                                청구액: {aiSuggestion.amounts?.[0]}
                            </p>
                        </div>
                        <Button variant="outline" size="sm" onClick={handleApplySuggestion} className="border-green-300 text-green-700 hover:bg-green-100">
                            적용
                        </Button>
                    </div>
                )}
                <div className="mb-4"><p className="text-[10px] font-black uppercase tracking-wider mb-3 pb-1" style={{ color: '#94a3b8', borderBottom: '1px solid #f1f5f9' }}>📋 기초사항</p>
                    <div className="grid grid-cols-2 gap-3">
                        <F label="의뢰인" reqd><select value={form.companyId} onChange={e => setForm(p => ({ ...p, companyId: e.target.value }))} className={inputCls} style={inputStyle}>{companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></F>
                        <F label="대분류"><select value={form.category} onChange={e => setForm(p => ({ ...p, category: e.target.value }))} className={inputCls} style={inputStyle}>{CASE_CATEGORIES.map(c => <option key={c}>{c}</option>)}</select></F>
                        <F label="소송 유형"><select value={form.type} onChange={e => setForm(p => ({ ...p, type: e.target.value }))} className={inputCls} style={inputStyle}>{LITIGATION_TYPES.map(t => <option key={t}>{t}</option>)}</select></F>
                        <F label="심급"><select value={form.instance} onChange={e => setForm(p => ({ ...p, instance: e.target.value }))} className={inputCls} style={inputStyle}>{INSTANCE_TYPES.map(t => <option key={t}>{t}</option>)}</select></F>
                        <F label="수임일"><input type="date" value={form.filingDate} onChange={e => setForm(p => ({ ...p, filingDate: e.target.value }))} className={inputCls} style={inputStyle} /></F>
                        <F label="사건번호" reqd><input value={form.caseNo} onChange={e => setForm(p => ({ ...p, caseNo: e.target.value }))} placeholder="2026가합12345" className={inputCls} style={inputStyle} /></F>
                    </div>
                </div>
                <div className="mb-4"><p className="text-[10px] font-black uppercase tracking-wider mb-3 pb-1" style={{ color: '#94a3b8', borderBottom: '1px solid #f1f5f9' }}>🏛️ 계속기관</p>
                    <div className="grid grid-cols-2 gap-3">
                        <F label="법원(가관)"><select value={form.court} onChange={e => setForm(p => ({ ...p, court: e.target.value }))} className={inputCls} style={inputStyle}>{COURTS.map(c => <option key={c}>{c}</option>)}</select></F>
                        <F label="청구금액 (원)"><input value={form.claimAmount} onChange={e => setForm(p => ({ ...p, claimAmount: e.target.value }))} placeholder="50000000" className={inputCls} style={inputStyle} /></F>
                    </div>
                </div>
                <div className="mb-4"><p className="text-[10px] font-black uppercase tracking-wider mb-3 pb-1" style={{ color: '#94a3b8', borderBottom: '1px solid #f1f5f9' }}>👥 당사자</p>
                    <div className="grid grid-cols-2 gap-3">
                        <F label="상대방" reqd><input value={form.opponent} onChange={e => setForm(p => ({ ...p, opponent: e.target.value }))} placeholder="김○○ / ○○연합회" className={inputCls} style={inputStyle} /></F>
                        <F label="상대방 소송대리인"><input value={form.opponentCounsel} onChange={e => setForm(p => ({ ...p, opponentCounsel: e.target.value }))} placeholder="○○법무법인" className={inputCls} style={inputStyle} /></F>
                    </div>
                </div>
                <div className="mb-4"><p className="text-[10px] font-black uppercase tracking-wider mb-3 pb-1" style={{ color: '#94a3b8', borderBottom: '1px solid #f1f5f9' }}>⚖️ 수임 / 수행 / 보조</p>
                    <div className="grid grid-cols-3 gap-3">
                        <F label="수임 변호사" reqd><select value={form.assignedLawyer} onChange={e => setForm(p => ({ ...p, assignedLawyer: e.target.value }))} className={inputCls} style={inputStyle}>{LAWYERS.map(l => <option key={l}>{l}</option>)}</select></F>
                        <F label="수행 변호사"><select value={form.coLawyer} onChange={e => setForm(p => ({ ...p, coLawyer: e.target.value }))} className={inputCls} style={inputStyle}><option value="">없음</option>{LAWYERS.map(l => <option key={l}>{l}</option>)}</select></F>
                        <F label="보조 변호사"><select value={form.assistLawyer} onChange={e => setForm(p => ({ ...p, assistLawyer: e.target.value }))} className={inputCls} style={inputStyle}><option value="">없음</option>{LAWYERS.map(l => <option key={l}>{l}</option>)}</select></F>
                    </div>
                </div>
                <div className="mb-4"><label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>사건 메모</label>
                    <textarea value={form.notes} onChange={e => setForm(p => ({ ...p, notes: e.target.value }))} rows={2} className="w-full px-3 py-2 rounded-lg text-sm resize-none" style={inputStyle} /></div>
                <div className="mb-5"><div className="flex items-center justify-between mb-2">
                    <p className="text-xs font-bold" style={{ color: '#64748b' }}>📅 기한·일정</p>
                    <button onClick={() => setDeadlines(p => [...p, { label: '', dueDate: '' }])} className="text-xs px-2 py-1 rounded-lg font-semibold" style={{ background: '#fffbeb', color: '#b8960a', border: '1px solid #fde68a' }}>+ 추가</button>
                </div>
                <div className="space-y-2">{deadlines.map((d, i) => (
                    <div key={i} className="flex gap-2">
                        <input value={d.label} onChange={e => setDeadlines(p => p.map((x, j) => j === i ? { ...x, label: e.target.value } : x))} placeholder="기한명" className="flex-1 px-2 py-1.5 rounded-lg text-xs" style={inputStyle} />
                        <input type="date" value={d.dueDate} onChange={e => setDeadlines(p => p.map((x, j) => j === i ? { ...x, dueDate: e.target.value } : x))} className="px-2 py-1.5 rounded-lg text-xs" style={inputStyle} />
                        {deadlines.length > 1 && <button onClick={() => setDeadlines(p => p.filter((_, j) => j !== i))} className="p-1"><X className="w-3.5 h-3.5" style={{ color: '#94a3b8' }} /></button>}
                    </div>
                ))}</div></div>
                <div className="flex gap-2">
                    <Button variant="ghost" className="flex-1" onClick={onClose}>취소</Button>
                    <Button variant="premium" className="flex-1" onClick={handleAdd}><Gavel className="w-4 h-4 mr-1" /> 사건 등록</Button>
                </div>
            </motion.div>
        </motion.div>
    );
}

// @ts-nocheck
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, CheckCircle2, Clock, AlertTriangle, Calendar, Archive, RotateCcw } from 'lucide-react';
import { LitigationCase, LitigationDeadline } from '@/lib/types';
import { LIT_STATUS_COLOR, LIT_STATUS_LABEL } from '@/lib/constants';
import { getAiSummary, generateAiMemoSummary } from '@/lib/automationEngine';
import { useLitigations } from '@/hooks/useDataLayer';

import CloseModal from './CloseModal';
import { STATUS_TEXT_MAP, STATUSES, daysUntil } from '../constants';

export default function DetailPanel({ lit, onClose, onUpdate }: { lit: LitigationCase; onClose: () => void; onUpdate: () => void }) {
    const [editNote, setEditNote] = useState(lit.notes);
    const [editResult, setEditResult] = useState(lit.result);
    const [editResultNote, setEditResultNote] = useState(lit.resultNote);
    const [saving, setSaving] = useState(false);
    const [showCloseModal, setShowCloseModal] = useState(false);
    const { updateLitigation } = useLitigations();

    const saveNotes = () => {
        setSaving(true);
        updateLitigation(lit.id, { notes: editNote, result: editResult as LitigationCase['result'], resultNote: editResultNote });
        if (editNote.trim()) generateAiMemoSummary(lit.id, editNote);
        setTimeout(() => { setSaving(false); onUpdate(); }, 400);
    };
    const toggleDeadline = (d: LitigationDeadline) => {
        const now = new Date().toLocaleString('ko-KR', { hour12: false });
        const updatedDeadlines = lit.deadlines.map(x => x.id === d.id ? { ...x, completed: !x.completed, completedAt: !x.completed ? now : '' } : x);
        updateLitigation(lit.id, { deadlines: updatedDeadlines });
        onUpdate();
    };

    return (
        <>
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-40" style={{ background: 'rgba(0,0,0,0.3)' }} onClick={onClose} />
        <motion.div initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }} transition={{ type: 'spring', damping: 30, stiffness: 300 }}
            className="fixed top-0 right-0 bottom-0 z-50 w-full sm:w-[520px] overflow-y-auto"
            style={{ background: '#ffffff', boxShadow: '-8px 0 30px rgba(0,0,0,0.1)' }}>
            {/* Header */}
            <div className="sticky top-0 z-10 px-5 py-4 flex items-center justify-between"
                style={{ background: '#ffffff', borderBottom: '1px solid #e5e7eb' }}>
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                        <span className="text-xs font-mono px-2 py-0.5 rounded" style={{ background: '#f1f5f9', color: '#64748b' }}>{lit.caseNo}</span>
                        <span className="text-xs font-bold px-2.5 py-1 rounded-full"
                            style={{ background: LIT_STATUS_COLOR[lit.status], color: STATUS_TEXT_MAP[lit.status] }}>
                            {LIT_STATUS_LABEL[lit.status]}
                        </span>
                    </div>
                    <h2 className="font-black text-lg truncate" style={{ color: '#1e293b' }}>{lit.companyName}</h2>
                </div>
                <button onClick={onClose} className="p-2 rounded-xl hover:bg-slate-100"><X className="w-5 h-5" style={{ color: '#94a3b8' }} /></button>
            </div>

            <div className="p-5 space-y-5">
                {/* Basic Info */}
                <div className="grid grid-cols-2 gap-3">
                    {[
                        { l: '소송유형', v: lit.type }, { l: '법원', v: lit.court },
                        { l: '상대방', v: lit.opponent || '—' }, { l: '담당변호사', v: lit.assignedLawyer },
                        { l: '청구금액', v: lit.claimAmount > 0 ? `${(lit.claimAmount / 100000000).toFixed(1)}억원` : '—' },
                        { l: '등록일', v: lit.createdAt?.split('T')[0] || '—' },
                    ].map(({ l, v }) => (
                        <div key={l} className="p-3 rounded-xl" style={{ background: '#f8f9fc', border: '1px solid #f1f5f9' }}>
                            <p className="text-[10px] font-bold mb-0.5" style={{ color: '#94a3b8' }}>{l}</p>
                            <p className="text-sm font-bold" style={{ color: '#1e293b' }}>{v}</p>
                        </div>
                    ))}
                </div>

                {/* Status Change */}
                <div>
                    <p className="text-xs font-bold mb-2" style={{ color: '#64748b' }}>⚡ 사건 상태</p>
                    <div className="flex flex-wrap gap-1">
                        {STATUSES.map(s => (
                            <button key={s} onClick={() => { updateLitigation(lit.id, { status: s }); onUpdate(); }}
                                className="text-[10px] px-2 py-1 rounded-full font-bold transition-all"
                                style={{
                                    background: lit.status === s ? LIT_STATUS_COLOR[s] : '#f1f5f9',
                                    color: lit.status === s ? STATUS_TEXT_MAP[s] : '#64748b',
                                    border: `1px solid ${lit.status === s ? STATUS_TEXT_MAP[s] + '40' : '#e2e8f0'}`,
                                }}>{LIT_STATUS_LABEL[s]}</button>
                        ))}
                    </div>
                </div>

                {/* Deadlines */}
                <div>
                    <p className="text-xs font-bold mb-2" style={{ color: '#94a3b8' }}>📅 기한·일정 ({lit.deadlines.filter(d => d.completed).length}/{lit.deadlines.length})</p>
                    <div className="space-y-2">
                        {lit.deadlines.map(d => {
                            const days = daysUntil(d.dueDate);
                            const urgent = !d.completed && days <= 7;
                            const overdue = !d.completed && days < 0;
                            return (
                                <button key={d.id} onClick={() => toggleDeadline(d)}
                                    className="flex items-center gap-2 px-3 py-2 rounded-lg w-full text-left transition-all hover:scale-[1.01]"
                                    style={{
                                        background: d.completed ? '#f0fdf4' : overdue ? '#fef2f2' : urgent ? '#fffbeb' : '#f8fafc',
                                        border: `1px solid ${d.completed ? '#86efac' : overdue ? '#fca5a5' : urgent ? '#fde68a' : '#e2e8f0'}`,
                                    }}>
                                    {d.completed ? <CheckCircle2 className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#16a34a' }} />
                                        : overdue ? <AlertTriangle className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#dc2626' }} />
                                        : urgent ? <Clock className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#d97706' }} />
                                        : <Calendar className="w-3.5 h-3.5 flex-shrink-0" style={{ color: '#94a3b8' }} />}
                                    <div className="flex-1">
                                        <p className="text-xs font-bold" style={{ color: d.completed ? '#16a34a' : overdue ? '#dc2626' : urgent ? '#d97706' : '#1e293b' }}>{d.label}</p>
                                        <p className="text-[10px]" style={{ color: '#94a3b8' }}>
                                            {d.dueDate}
                                            {!d.completed && !overdue && <span style={{ color: urgent ? '#d97706' : '#94a3b8' }}> ({days}일 남음)</span>}
                                            {overdue && <span style={{ color: '#dc2626' }}> (D+{Math.abs(days)} 초과)</span>}
                                            {d.completed && d.completedAt && <span> · 완료 {d.completedAt}</span>}
                                        </p>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Notes */}
                <div>
                    <p className="text-xs font-bold mb-1" style={{ color: '#64748b' }}>📝 사건 메모</p>
                    <textarea value={editNote} onChange={e => setEditNote(e.target.value)} rows={4}
                        className="w-full text-xs p-2.5 rounded-lg resize-none"
                        style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                </div>

                {/* Result */}
                <div>
                    <p className="text-xs font-bold mb-1" style={{ color: '#64748b' }}>🏆 결과</p>
                    <div className="flex gap-1 mb-2">
                        {(['', '승소', '패소', '합의', '취하'] as const).map(r => (
                            <button key={r} onClick={() => setEditResult(r)}
                                className="text-[11px] px-2.5 py-1 rounded-lg font-bold transition-all"
                                style={{
                                    background: editResult === r ? (r === '승소' ? '#dcfce7' : r === '패소' ? '#fef2f2' : '#fffbeb') : '#f1f5f9',
                                    color: editResult === r ? (r === '승소' ? '#16a34a' : r === '패소' ? '#dc2626' : '#b8960a') : '#64748b',
                                    border: `1px solid ${editResult === r ? '#d1d5db' : '#e2e8f0'}`,
                                }}>{r || '미정'}</button>
                        ))}
                    </div>
                    <textarea value={editResultNote} onChange={e => setEditResultNote(e.target.value)} rows={2}
                        placeholder="결과 메모..." className="w-full text-xs p-2.5 rounded-lg resize-none"
                        style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                </div>

                {/* AI Summary */}
                {(() => {
                    const aiSummary = getAiSummary(lit.id);
                    return aiSummary ? (
                        <div className="p-3 rounded-lg" style={{ background: '#f0f9ff', border: '1px solid #bae6fd' }}>
                            <p className="text-[10px] font-bold mb-1" style={{ color: '#0284c7' }}>🤖 AI 자동 요약</p>
                            <pre className="text-xs whitespace-pre-wrap" style={{ color: '#0369a1', fontFamily: 'inherit' }}>{aiSummary}</pre>
                        </div>
                    ) : null;
                })()}

                {/* Save + Close buttons */}
                <div className="flex gap-2">
                    <button onClick={saveNotes} className="flex-1 text-sm py-2.5 rounded-xl font-bold"
                        style={{ background: saving ? '#dcfce7' : '#fffbeb', color: saving ? '#16a34a' : '#b8960a', border: `1px solid ${saving ? '#86efac' : '#fde68a'}` }}>
                        {saving ? '✓ 저장됨' : '💾 저장'}
                    </button>
                    {lit.status !== 'closed' && (
                        <button onClick={() => setShowCloseModal(true)} className="text-sm px-4 py-2.5 rounded-xl font-bold"
                            style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fca5a5' }}>
                            <Archive className="w-3.5 h-3.5 inline mr-1" />종결
                        </button>
                    )}
                    {lit.status === 'closed' && (
                        <button onClick={() => { updateLitigation(lit.id, { status: 'preparing' }); onUpdate(); }}
                            className="text-sm px-4 py-2.5 rounded-xl font-bold"
                            style={{ background: '#eff6ff', color: '#2563eb', border: '1px solid #93c5fd' }}>
                            <RotateCcw className="w-3.5 h-3.5 inline mr-1" />복원
                        </button>
                    )}
                </div>
            </div>
        </motion.div>
        <AnimatePresence>
            {showCloseModal && <CloseModal ids={[lit.id]} onClose={() => setShowCloseModal(false)}
                onConfirm={(reason) => { updateLitigation(lit.id, { status: 'closed', resultNote: reason }); setShowCloseModal(false); onUpdate(); }} />}
        </AnimatePresence>
        </>
    );
}

'use client';
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Bell, FileText, CreditCard, MessageSquare, UserCheck,
    CheckCircle2, Clock, AlertTriangle, Shield, Scale,
    ChevronRight, Trash2, Check, Filter, X, Lock,
    ArrowRight, Star,
} from 'lucide-react';
import Link from 'next/link';
import { useRequireAuth } from '@/lib/AuthContext';
import { useNotifications } from '@/hooks/useDataLayer';

/* ── 타입 ───────────────────────────────────────────────── */
type NotiType = 'document' | 'payment' | 'consultation' | 'member' | 'system';
type NotiStatus = 'unread' | 'read';

interface Notification {
    id: string;
    type: NotiType;
    title: string;
    message: string;
    date: string;
    status: NotiStatus;
    href?: string;
    actionLabel?: string;
}

const TYPE_META: Record<NotiType, { icon: React.ElementType; color: string; label: string }> = {
    document: { icon: FileText, color: '#2563eb', label: '문서' },
    payment: { icon: CreditCard, color: '#059669', label: '결제' },
    consultation: { icon: MessageSquare, color: '#7c3aed', label: '상담' },
    member: { icon: UserCheck, color: '#d97706', label: '멤버' },
    system: { icon: Bell, color: '#6b7280', label: '시스템' },
};

// MOCK_NOTIFICATIONS removed, data now fetched via useNotifications hook

/* ── 구독 전 CTA ───────────────────────────────────────── */
function SubscribeCTA() {
    return (
        <div className="min-h-screen pt-20 pb-16" style={{ background: '#f8f7f4' }}>
            <div className="max-w-2xl mx-auto px-4 py-20 text-center">
                <div className="w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6"
                    style={{ background: '#fff3cd', border: '1px solid #ffeaa7' }}>
                    <Bell className="w-10 h-10" style={{ color: '#c9a84c' }} />
                </div>
                <h1 className="text-2xl font-black mb-3" style={{ color: '#111827' }}>알림 센터</h1>
                <p className="text-sm mb-6" style={{ color: '#6b7280' }}>
                    구독을 시작하면 문서 검토 완료, 변호사 답변, 결제 알림 등<br />
                    중요한 알림을 실시간으로 받을 수 있습니다.
                </p>
                <div className="grid grid-cols-2 gap-3 max-w-sm mx-auto mb-8">
                    {[
                        { icon: <FileText className="w-4 h-4" />, label: '문서 완료 알림' },
                        { icon: <MessageSquare className="w-4 h-4" />, label: '변호사 답변 알림' },
                        { icon: <CreditCard className="w-4 h-4" />, label: '결제 알림' },
                        { icon: <UserCheck className="w-4 h-4" />, label: '멤버 승인 알림' },
                    ].map(f => (
                        <div key={f.label} className="flex items-center gap-2 p-3 rounded-xl text-xs"
                            style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                            <span style={{ color: '#c9a84c' }}>{f.icon}</span>
                            <span style={{ color: '#374151' }}>{f.label}</span>
                        </div>
                    ))}
                </div>
                <Link href="/pricing">
                    <button className="px-8 py-3 rounded-xl font-bold text-sm"
                        style={{ background: '#111827', color: '#fff' }}>
                        구독 시작하기 →
                    </button>
                </Link>
            </div>
        </div>
    );
}

/* ── 메인 페이지 ───────────────────────────────────────── */
export default function NotificationsPage() {
    const { loading: authLoading, authorized, user } = useRequireAuth();
    const { notifications, isLoading: dataLoading, markAsRead, markAllAsRead, deleteNotification } = useNotifications();
    const [filterType, setFilterType] = useState<NotiType | 'all'>('all');
    const [isSubscribed] = useState(true); // TODO: 세션에서 구독 상태 가져오기

    if (authLoading || dataLoading) return <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><div style={{ fontSize: 14, color: '#6b7280' }}>로딩 중...</div></div>;
    if (!authorized || !user) return null;

    if (!isSubscribed) return <SubscribeCTA />;

    const typedNotifications = notifications.map(n => ({
        ...n,
        type: n.type as NotiType,
        status: n.status as NotiStatus,
        date: new Date(n.created_at).toLocaleDateString(),
        actionLabel: n.action_label,
    }));

    const filtered = filterType === 'all' ? typedNotifications : typedNotifications.filter(n => n.type === filterType);
    const unreadCount = typedNotifications.filter(n => n.status === 'unread').length;

    return (
        <div className="min-h-screen pt-20 pb-16" style={{ background: '#f8f7f4' }}>
            <div className="max-w-3xl mx-auto px-4">

                {/* 헤더 */}
                <div className="py-8 flex items-start justify-between">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <Bell className="w-5 h-5" style={{ color: '#c9a84c' }} />
                            <h1 className="text-2xl font-black" style={{ color: '#111827' }}>알림</h1>
                            {unreadCount > 0 && (
                                <span className="px-2 py-0.5 rounded-full text-xs font-bold"
                                    style={{ background: '#dc2626', color: '#fff' }}>{unreadCount}</span>
                            )}
                        </div>
                        <p className="text-sm" style={{ color: '#6b7280' }}>문서, 결제, 상담 관련 알림을 확인하세요.</p>
                    </div>
                    {unreadCount > 0 && (
                        <button onClick={markAllAsRead}
                            className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-bold"
                            style={{ background: '#fff', color: '#374151', border: '1px solid #e8e5de' }}>
                            <Check className="w-3.5 h-3.5" /> 모두 읽음
                        </button>
                    )}
                </div>

                {/* 필터 */}
                <div className="flex gap-1.5 mb-5 overflow-x-auto pb-1">
                    <button onClick={() => setFilterType('all')}
                        className="px-3 py-1.5 rounded-lg text-xs font-bold whitespace-nowrap"
                        style={{
                            background: filterType === 'all' ? '#111827' : '#fff',
                            color: filterType === 'all' ? '#fff' : '#6b7280',
                            border: `1px solid ${filterType === 'all' ? '#111827' : '#e8e5de'}`,
                        }}>전체</button>
                    {Object.entries(TYPE_META).map(([key, meta]) => (
                        <button key={key} onClick={() => setFilterType(key as NotiType)}
                            className="px-3 py-1.5 rounded-lg text-xs font-bold whitespace-nowrap"
                            style={{
                                background: filterType === key ? `${meta.color}10` : '#fff',
                                color: filterType === key ? meta.color : '#6b7280',
                                border: `1px solid ${filterType === key ? meta.color + '40' : '#e8e5de'}`,
                            }}>{meta.label}</button>
                    ))}
                </div>

                {/* 알림 리스트 */}
                <div className="space-y-2">
                    <AnimatePresence>
                        {filtered.map((n, i) => {
                            const meta = TYPE_META[n.type];
                            const Icon = meta.icon;
                            return (
                                <motion.div key={n.id}
                                    initial={{ opacity: 0, y: 8 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, x: -100 }}
                                    transition={{ delay: i * 0.03 }}
                                    className="group relative p-4 rounded-2xl transition-all"
                                    style={{
                                        background: n.status === 'unread' ? '#fff' : '#fafaf8',
                                        border: `1px solid ${n.status === 'unread' ? meta.color + '30' : '#e8e5de'}`,
                                        boxShadow: n.status === 'unread' ? '0 2px 8px rgba(0,0,0,0.04)' : 'none',
                                    }}
                                    onClick={() => markAsRead(n.id)}
                                >
                                    <div className="flex gap-3">
                                        <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0"
                                            style={{ background: `${meta.color}10` }}>
                                            <Icon className="w-5 h-5" style={{ color: meta.color }} />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-start justify-between gap-2">
                                                <div className="flex-1">
                                                    <div className="flex items-center gap-2 mb-0.5">
                                                        {n.status === 'unread' && (
                                                            <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: meta.color }} />
                                                        )}
                                                        <h3 className="font-bold text-sm" style={{ color: '#111827' }}>{n.title}</h3>
                                                    </div>
                                                    <p className="text-xs leading-relaxed" style={{ color: '#6b7280' }}>{n.message}</p>
                                                </div>
                                                <div className="flex items-center gap-1 flex-shrink-0">
                                                    <span className="text-[10px]" style={{ color: '#9ca3af' }}>{n.date.split(' ')[0]}</span>
                                                    <button onClick={(e) => { e.stopPropagation(); deleteNotification(n.id); }}
                                                        className="opacity-0 group-hover:opacity-100 p-1 rounded-lg transition-all hover:bg-red-50">
                                                        <Trash2 className="w-3.5 h-3.5" style={{ color: '#dc2626' }} />
                                                    </button>
                                                </div>
                                            </div>
                                            {n.actionLabel && n.href && (
                                                <Link href={n.href}>
                                                    <button className="mt-2 flex items-center gap-1 px-3 py-1.5 rounded-lg text-[11px] font-bold transition-all hover:opacity-80"
                                                        style={{ background: `${meta.color}10`, color: meta.color }}>
                                                        {n.actionLabel} <ChevronRight className="w-3 h-3" />
                                                    </button>
                                                </Link>
                                            )}
                                        </div>
                                    </div>
                                </motion.div>
                            );
                        })}
                    </AnimatePresence>

                    {filtered.length === 0 && (
                        <div className="text-center py-16 rounded-2xl" style={{ background: '#fff', border: '1px solid #e8e5de' }}>
                            <Bell className="w-10 h-10 mx-auto mb-3" style={{ color: '#d1d5db' }} />
                            <p className="font-bold text-sm" style={{ color: '#6b7280' }}>알림이 없습니다</p>
                            <p className="text-xs mt-1" style={{ color: '#9ca3af' }}>새로운 알림이 오면 여기에 표시됩니다.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

