                    <div><label className="text-xs font-bold mb-1 block" style={{ color: '#1e40af' }}>다음 기일</label>
                        <input type="date" value={form.nextHearingDate} onChange={e => setForm(p => ({ ...p, nextHearingDate: e.target.value }))}
