/* ── 메인 페이지 ─────────────────────────────────────────── */
export default function WelcomePage() {
    const [completed, setCompleted] = useState<Record<string, boolean>>({});

    const toggleComplete = (id: string) => {
        setCompleted(p => ({ ...p, [id]: !p[id] }));
