                >
                    <Link href="/dashboard">
                        <button className="w-full py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3"
                            style={{
                                background: 'linear-gradient(135deg,#e8c87a,#c9a84c)',
                                color: '#04091a',
