  company?: string;
  clauseData?: Record<string, string>;
  highRiskCount?: number;
  medRiskCount?: number;
  summaryOpinion?: string;
  // full_revision_to_client
  revisionData?: Record<string, string>;
  documentTitle?: string;
  documentNo?: string;
}

