'use client';

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Scale, ChevronLeft, MapPin, Calendar, Clock, Bell, CheckCircle2, User } from 'lucide-react';
import { personalStore, PersonalLitigation } from '@/lib/store';

const formatMoney = (n: number) => n >= 100000000 ? `${(n / 100000000).toFixed(1)}억` : n >= 10000 ? `${(n / 10000).toFixed(0)}만원` : `${n.toLocaleString()}원`;

export default function ClientPortalMyCasesPage() {
    const [caseData, setCaseData] = useState<PersonalLitigation | null>(null);

    useEffect(() => {
        const allCases = personalStore.getAll();
        const activeCase = allCases.find((c: any) => c.status !== 'closed') || allCases[0];
        setCaseData(activeCase);
    }, []);

    if (!caseData) return <div className="min-h-screen flex items-center justify-center bg-indigo-50"><div className="w-8 h-8 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div></div>;

    const stages = [
        { key: 'filed', label: '소장접수' },
        { key: 'hearing', label: '1차변론' },
        { key: 'judgment', label: '판결' }
    ];

    const currentStageIndex = caseData.status === 'preparing' || caseData.status === 'consulting' ? -1 : 
                              caseData.status === 'filed' ? 0 : 
                              caseData.status === 'judgment' || caseData.status === 'appeal' || caseData.status === 'enforcing' || caseData.status === 'closed' ? 2 : 1;

    const upcomingDeadlines = caseData.deadlines?.filter(d => !d.completed).sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime()) || [];
    const nextDeadline = upcomingDeadlines.length > 0 ? upcomingDeadlines[0] : null;

    return (
        <div className="min-h-screen bg-[#f8faff] text-slate-800 font-sans pb-20 sm:pb-8">
            <header className="bg-indigo-600 text-white rounded-b-3xl shadow-lg shadow-indigo-200 px-5 pt-12 pb-6 sticky top-0 z-40">
                <div className="max-w-md mx-auto relative">
                    <button className="absolute left-0 top-1/2 -translate-y-1/2 p-2 rounded-full bg-white/10 hover:bg-white/20 transition-all">
                        <ChevronLeft className="w-5 h-5 text-white" />
                    </button>
                    <div className="text-center">
                        <p className="text-indigo-100 text-xs font-bold tracking-widest uppercase mb-1">{caseData.caseNo}</p>
                        <h1 className="text-xl font-black">{caseData.clientName} 의뢰인님,</h1>
                        <p className="text-indigo-100 text-sm mt-0.5 font-medium">{caseData.assignedLawyer}가 사건을 전담하고 있습니다.</p>
                    </div>
                </div>
            </header>

            <main className="max-w-md mx-auto px-5 pt-6 space-y-6">
                
                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="bg-white rounded-2xl p-5 shadow-sm border border-indigo-50">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <span className="inline-block px-2.5 py-1 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold mb-2">{caseData.type}</span>
                            <h2 className="text-lg font-black text-slate-900 leading-tight">상대방: {caseData.opponent}</h2>
                            <p className="text-xs text-slate-500 mt-1">{caseData.court} 관할</p>
                        </div>
                        <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 shadow-inner">
                            <Scale className="w-5 h-5" />
                        </div>
                    </div>
                    {caseData.claimAmount > 0 && (
                        <div className="bg-slate-50 rounded-xl p-3 flex justify-between items-center border border-slate-100">
                            <span className="text-xs font-bold text-slate-500">청구금액</span>
                            <span className="text-sm font-black text-indigo-700">{formatMoney(caseData.claimAmount)}</span>
                        </div>
                    )}
                </motion.div>

                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }} className="bg-white rounded-2xl p-6 shadow-sm border border-indigo-50 relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 to-purple-500 opacity-20"></div>
                    <h3 className="text-sm font-black text-slate-800 mb-6 flex items-center gap-2">
                        <span className="w-1.5 h-4 bg-indigo-600 rounded-full"></span>사건 진행 현황
                    </h3>
                    
                    <div className="relative">
                        <div className="absolute top-4 left-4 right-4 h-1 bg-slate-100 rounded-full">
                            <motion.div 
                                className="absolute top-0 left-0 h-full bg-indigo-600 rounded-full"
                                initial={{ width: "0%" }}
                                animate={{ width: currentStageIndex <= 0 ? "0%" : currentStageIndex === 1 ? "50%" : "100%" }}
                                transition={{ duration: 1, delay: 0.2, ease: "easeOut" }}
                            />
                        </div>

                        <div className="flex justify-between relative z-10 px-2">
                            {stages.map((stage, idx) => {
                                const isCompleted = idx < currentStageIndex;
                                const isCurrent = idx === currentStageIndex;
                                const stageColor = isCompleted ? 'bg-indigo-600 text-white' : isCurrent ? 'bg-white border-2 border-indigo-600 text-indigo-600' : 'bg-white border-2 border-slate-200 text-slate-300';
                                return (
                                    <div key={stage.key} className="flex flex-col items-center bg-white z-10">
                                        <div className={`w-9 h-9 rounded-full flex items-center justify-center transition-all duration-500 ${stageColor} shadow-sm`}>
                                            {isCompleted ? <CheckCircle2 className="w-5 h-5" /> : <span className="text-xs font-bold">{idx + 1}</span>}
                                        </div>
                                        <span className={`text-[10px] font-bold mt-2 transition-colors ${isCurrent ? 'text-indigo-700' : isCompleted ? 'text-slate-700' : 'text-slate-400'}`}>{stage.label}</span>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                    {caseData.status === 'hearing' && (
                        <div className="mt-6 p-3 rounded-xl bg-indigo-50 border border-indigo-100 flex items-start gap-2">
                            <div className="mt-0.5"><div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" /></div>
                            <p className="text-xs font-medium text-indigo-900 leading-relaxed">
                                현재 변론이 진행 중입니다. 법원 일정에 맞추어 서면을 준비하고 있습니다.
                            </p>
                        </div>
                    )}
                </motion.div>

                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}>
                    <h3 className="text-sm font-black text-slate-800 mb-3 ml-1 flex items-center gap-2">
                        <span className="w-1.5 h-4 bg-purple-500 rounded-full"></span>다음 기일 안내
                    </h3>
                    {nextDeadline ? (
                        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 rounded-2xl p-5 text-white shadow-lg shadow-indigo-200/50 relative overflow-hidden">
                            <div className="absolute -right-6 -top-6 w-24 h-24 bg-white opacity-5 rounded-full blur-xl"></div>
                            <div className="absolute -left-6 -bottom-6 w-20 h-20 bg-indigo-400 opacity-20 rounded-full blur-lg"></div>
                            
                            <div className="relative z-10">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-2 bg-white/10 px-2.5 py-1 rounded-full backdrop-blur-sm border border-white/10">
                                        <Calendar className="w-3.5 h-3.5 text-indigo-200" />
                                        <span className="text-[10px] font-bold text-indigo-100">{nextDeadline.label}</span>
                                        {nextDeadline.isFixed && <span className="ml-1 text-[9px] px-1 py-0.5 bg-red-500/80 text-white rounded font-bold">불변</span>}
                                    </div>
                                    <div className="bg-white/20 p-1.5 rounded-lg backdrop-blur-sm"><Bell className="w-4 h-4 text-white" /></div>
                                </div>
                                
                                <h4 className="text-3xl font-black mb-1">{nextDeadline.dueDate ? new Date(nextDeadline.dueDate).toLocaleDateString('ko-KR', { month: 'long', day: 'numeric' }) : '일정 미정'}</h4>
                                <p className="text-indigo-200 text-xs font-medium mb-5">{nextDeadline.dueDate ? new Date(nextDeadline.dueDate).toLocaleDateString('ko-KR', { weekday: 'short' }) + '요일, ' : ''}{caseData.court}</p>
                                
                                <div className="grid grid-cols-2 gap-2">
                                    <button className="bg-white text-indigo-600 hover:bg-slate-50 transition-colors py-2.5 rounded-xl text-xs font-bold w-full flex items-center justify-center shadow-sm">
                                        <MapPin className="w-3.5 h-3.5 mr-1" /> 길찾기
                                    </button>
                                    <button className="bg-indigo-700/50 hover:bg-indigo-700 transition-colors text-white border border-indigo-400/30 py-2.5 rounded-xl text-xs font-bold w-full flex items-center justify-center">
                                        <Calendar className="w-3.5 h-3.5 mr-1" /> 캘린더 추가
                                    </button>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-white rounded-2xl p-6 text-center shadow-sm border border-indigo-50">
                            <Clock className="w-8 h-8 text-indigo-200 mx-auto mb-2" />
                            <p className="text-sm font-bold text-slate-600">예정된 기일이 없습니다.</p>
                            <p className="text-xs text-slate-400 mt-1">일정이 업데이트되면 안내해 드립니다.</p>
                        </div>
                    )}
                </motion.div>

                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }} className="bg-white rounded-2xl p-5 shadow-sm border border-indigo-50">
                    <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">전담 법률팀</h3>
                    <div className="flex items-center gap-3">
                        <div className="w-12 h-12 rounded-full bg-gradient-to-br from-indigo-100 to-purple-100 border-2 border-white shadow-sm flex items-center justify-center overflow-hidden">
                            <User className="w-6 h-6 text-indigo-400" />
                        </div>
                        <div className="flex-1">
                            <p className="text-sm font-black text-slate-800">{caseData.assignedLawyer}</p>
                            <p className="text-[10px] text-slate-500 font-medium">IBS 법률사무소 담당 변호사</p>
                        </div>
                        <button className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-100 transition-colors">
                            <svg className="w-4 h-4 fill-current" viewBox="0 0 24 24"><path d="M20 22.621l-3.521-6.795c-.008.004-1.974.97-2.064 1.011-2.24 1.086-6.799-7.82-4.609-8.994l2.083-1.022-3.498-6.82-2.106 1.039c-1.684.83-3.346 6.836 2.396 11.623 5.34 4.492 11.234 1.487 13.564-.326l-2.245-1.111v-.005zm-6.68-19.167c2.618.36 4.706 2.457 5.056 5.086l2.164-.298c-.46-3.66-3.266-6.476-6.922-6.953l-.298 2.165zm-2.091 2.22c1.472.248 2.657 1.442 2.895 2.923l2.09-.344c-.347-2.39-2.222-4.275-4.641-4.669l-.344 2.09z"/></svg>
                        </button>
                    </div>
                </motion.div>

            </main>
        </div>
    );
}

// @ts-nocheck
'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    CalendarDays, Plus, X, Clock, CheckCircle2, XCircle,
    MapPin, ChevronLeft, ChevronRight, AlertTriangle,
} from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { ATTENDANCE_TYPES, ATTENDANCE_TYPE_COLOR, ATTENDANCE_STATUS_LABEL } from '@/lib/constants';
import { attendanceStore, type AttendanceRecord, type AttendanceType, type AttendanceStatus } from '@/lib/store';

// ── Apply Modal ──
function ApplyModal({ onClose, onSubmit, initial }: {
    onClose: () => void; onSubmit: (data: Omit<AttendanceRecord, 'id' | 'createdAt'>) => void;
    initial?: { startDate: string; type?: AttendanceType };
}) {
    const [form, setForm] = useState({
        type: initial?.type ?? '연차' as AttendanceType,
        startDate: initial?.startDate ?? new Date().toISOString().slice(0, 10),
        endDate: initial?.startDate ?? new Date().toISOString().slice(0, 10),
        memo: '',
        destination: '',
    });
    const needsDestination = ['출장', '외출', '법원출석'].includes(form.type);
    return (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            style={{ background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' }}
            onClick={e => e.target === e.currentTarget && onClose()}>
            <motion.div initial={{ scale: 0.95 }} animate={{ scale: 1 }} className="w-full max-w-md rounded-2xl p-6"
                style={{ background: '#ffffff', border: '1px solid #e5e7eb', boxShadow: '0 20px 60px rgba(0,0,0,0.15)' }}>
                <div className="flex items-center justify-between mb-5">
                    <h3 className="font-black text-lg" style={{ color: '#1e293b' }}>📋 근태 신청</h3>
                    <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-slate-100"><X className="w-5 h-5" style={{ color: '#94a3b8' }} /></button>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold mb-1.5 block" style={{ color: '#b8960a' }}>유형</label>
                        <div className="flex flex-wrap gap-1.5">
                            {ATTENDANCE_TYPES.map(t => (
                                <button key={t} onClick={() => setForm(p => ({ ...p, type: t }))}
                                    className="text-xs px-3 py-1.5 rounded-xl font-bold transition-all"
                                    style={{
                                        background: form.type === t ? ATTENDANCE_TYPE_COLOR[t] + '20' : '#f1f5f9',
                                        color: form.type === t ? ATTENDANCE_TYPE_COLOR[t] : '#64748b',
                                        border: `1px solid ${form.type === t ? ATTENDANCE_TYPE_COLOR[t] + '60' : '#e2e8f0'}`,
                                    }}>{t}</button>
                            ))}
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>시작일</label>
                            <input type="date" value={form.startDate} onChange={e => setForm(p => ({ ...p, startDate: e.target.value }))}
                                className="w-full px-3 py-2 rounded-lg text-sm" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                        </div>
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>종료일</label>
                            <input type="date" value={form.endDate} onChange={e => setForm(p => ({ ...p, endDate: e.target.value }))}
                                className="w-full px-3 py-2 rounded-lg text-sm" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                        </div>
                    </div>
                    {needsDestination && (
                        <div>
                            <label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>🗺️ 행선지</label>
                            <input value={form.destination} onChange={e => setForm(p => ({ ...p, destination: e.target.value }))}
                                placeholder="예: 수원지방법원, 의뢰인 사무실"
                                className="w-full px-3 py-2 rounded-lg text-sm" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                        </div>
                    )}
                    <div>
                        <label className="text-xs font-bold mb-1 block" style={{ color: '#b8960a' }}>메모</label>
                        <textarea value={form.memo} onChange={e => setForm(p => ({ ...p, memo: e.target.value }))} rows={3}
                            placeholder="상세 사유를 입력하세요..."
                            className="w-full px-3 py-2 rounded-lg text-sm resize-none" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                    </div>
                </div>
                <div className="flex gap-2 mt-5">
                    <button onClick={onClose} className="flex-1 py-2.5 rounded-xl text-sm font-bold" style={{ background: '#f1f5f9', color: '#64748b' }}>취소</button>
                    <button onClick={() => { onSubmit({ userId: 'lawyer1', userName: '김수현 변호사', type: form.type, startDate: form.startDate, endDate: form.endDate, memo: form.memo, destination: form.destination || undefined, status: 'pending' }); onClose(); }}
                        className="flex-1 py-2.5 rounded-xl text-sm font-bold text-white" style={{ background: '#c9a84c' }}>신청하기</button>
                </div>
            </motion.div>
        </motion.div>
    );
}

// ── Quick Destination ──
function QuickDestModal({ onClose, onSubmit }: { onClose: () => void; onSubmit: (data: Omit<AttendanceRecord, 'id' | 'createdAt'>) => void }) {
    const today = new Date().toISOString().slice(0, 10);
    const [type, setType] = useState<AttendanceType>('외출');
    const [dest, setDest] = useState('');
    const [memo, setMemo] = useState('');
    const quickTypes: AttendanceType[] = ['외출', '법원출석', '출장'];
    return (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            style={{ background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' }}
            onClick={e => e.target === e.currentTarget && onClose()}>
            <motion.div initial={{ scale: 0.95 }} animate={{ scale: 1 }} className="w-full max-w-sm rounded-2xl p-5"
                style={{ background: '#ffffff', border: '1px solid #e5e7eb', boxShadow: '0 20px 60px rgba(0,0,0,0.15)' }}>
                <h3 className="font-black text-base mb-4" style={{ color: '#1e293b' }}>📍 행선지 빠른 등록</h3>
                <div className="flex gap-1.5 mb-3">
                    {quickTypes.map(t => (
                        <button key={t} onClick={() => setType(t)} className="text-xs px-3 py-1.5 rounded-xl font-bold flex-1"
                            style={{ background: type === t ? ATTENDANCE_TYPE_COLOR[t] + '20' : '#f1f5f9', color: type === t ? ATTENDANCE_TYPE_COLOR[t] : '#64748b',
                                border: `1px solid ${type === t ? ATTENDANCE_TYPE_COLOR[t] + '60' : '#e2e8f0'}` }}>{t}</button>
                    ))}
                </div>
                <input value={dest} onChange={e => setDest(e.target.value)} placeholder="행선지 (예: 수원지방법원)"
                    className="w-full px-3 py-2 rounded-lg text-sm mb-3" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                <input value={memo} onChange={e => setMemo(e.target.value)} placeholder="메모 (선택)"
                    className="w-full px-3 py-2 rounded-lg text-sm mb-4" style={{ background: '#f8f9fc', border: '1px solid #e2e8f0', color: '#1e293b' }} />
                <div className="flex gap-2">
                    <button onClick={onClose} className="flex-1 py-2 rounded-xl text-sm font-bold" style={{ background: '#f1f5f9', color: '#64748b' }}>취소</button>
                    <button onClick={() => { if (!dest.trim()) return; onSubmit({ userId: 'lawyer1', userName: '김수현 변호사', type, startDate: today, endDate: today, memo, destination: dest, status: 'pending' }); onClose(); }}
                        className="flex-1 py-2 rounded-xl text-sm font-bold text-white" style={{ background: dest.trim() ? '#c9a84c' : '#94a3b8' }}>등록</button>
                </div>
            </motion.div>
        </motion.div>
    );
}

// ── Main AttendanceTab Component ──
export default function AttendanceTab() {
    const [records, setRecords] = useState<AttendanceRecord[]>([]);
    const [showApply, setShowApply] = useState(false);
    const [showQuickDest, setShowQuickDest] = useState(false);
    const [calMonth, setCalMonth] = useState(new Date());
    const [applyInitial, setApplyInitial] = useState<{ startDate: string; type?: AttendanceType } | undefined>();

    const refresh = useCallback(() => { setRecords([...attendanceStore.getAll()]); }, []);
    useEffect(() => { refresh(); }, [refresh]);

    // Calendar helpers
    const year = calMonth.getFullYear();
    const month = calMonth.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().toISOString().slice(0, 10);

    const dayRecords = (d: number) => {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        return records.filter(r => r.startDate <= dateStr && r.endDate >= dateStr);
    };

    const prevMonth = () => setCalMonth(new Date(year, month - 1, 1));
    const nextMonth = () => setCalMonth(new Date(year, month + 1, 1));

    const handleSubmit = (data: Omit<AttendanceRecord, 'id' | 'createdAt'>) => { attendanceStore.add(data); refresh(); };

    const pendingCount = records.filter(r => r.status === 'pending').length;
    const thisMonthRecords = records.filter(r => { const d = new Date(r.startDate); return d.getFullYear() === year && d.getMonth() === month; });
    const leaveCount = thisMonthRecords.filter(r => ['연차', '반차(오전)', '반차(오후)'].includes(r.type)).length;
    const outCount = thisMonthRecords.filter(r => ['외출', '법원출석', '출장'].includes(r.type)).length;

    const statusIcon = (s: AttendanceStatus) => s === 'approved' ? <CheckCircle2 className="w-3.5 h-3.5" style={{ color: '#16a34a' }} />
        : s === 'rejected' ? <XCircle className="w-3.5 h-3.5" style={{ color: '#dc2626' }} />
        : <Clock className="w-3.5 h-3.5" style={{ color: '#d97706' }} />;
    const statusColor = (s: AttendanceStatus) => s === 'approved' ? '#16a34a' : s === 'rejected' ? '#dc2626' : '#d97706';
    const statusBg = (s: AttendanceStatus) => s === 'approved' ? '#f0fdf4' : s === 'rejected' ? '#fef2f2' : '#fffbeb';

    return (
        <div className="pb-16 max-w-5xl mx-auto">
            {/* Header */}
            <div className="mb-5 flex items-center justify-between flex-wrap gap-3">
                <div>
                    <h1 className="text-2xl font-black flex items-center gap-2" style={{ color: '#1e293b' }}>
                        <CalendarDays className="w-6 h-6" style={{ color: '#c9a84c' }} />
                        근태 / 행선지 관리
                    </h1>
                    <p className="text-sm mt-0.5 font-medium" style={{ color: '#475569' }}>
                        대기 {pendingCount}건 · 이달 휴가 {leaveCount}건 · 외근 {outCount}건
                    </p>
                </div>
                <div className="flex gap-2">
                    <button onClick={() => { setApplyInitial(undefined); setShowQuickDest(true); }}
                        className="text-xs px-3.5 py-2 rounded-xl font-bold flex items-center gap-1.5"
                        style={{ background: '#ffffff', border: '1px solid #e2e8f0', color: '#64748b' }}>
                        <MapPin className="w-3.5 h-3.5" />행선지 등록
                    </button>
                    <Button variant="premium" size="sm" onClick={() => { setApplyInitial(undefined); setShowApply(true); }}>
                        <Plus className="w-4 h-4 mr-1" /> 근태 신청
                    </Button>
                </div>
            </div>

            {/* KPI */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-5">
                {[
                    { label: '대기 중', value: pendingCount, accent: '#d97706', icon: Clock },
                    { label: '이달 휴가', value: leaveCount, accent: '#2563eb', icon: CalendarDays },
                    { label: '이달 외근', value: outCount, accent: '#7c3aed', icon: MapPin },
                    { label: '총 신청', value: records.length, accent: '#16a34a', icon: CheckCircle2 },
                ].map(({ label, value, accent, icon: Icon }) => (
                    <motion.div key={label} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                        className="p-4 rounded-xl" style={{ background: '#ffffff', border: '1px solid #e5e7eb' }}>
                        <div className="flex items-center gap-2 mb-2">
                            <div className="w-7 h-7 rounded-lg flex items-center justify-center" style={{ background: accent + '18' }}>
                                <Icon className="w-3.5 h-3.5" style={{ color: accent }} /></div>
                            <span className="text-[10px] font-bold uppercase" style={{ color: '#94a3b8' }}>{label}</span>
                        </div>
                        <p className="text-xl font-black" style={{ color: accent }}>{value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Calendar + List layout */}
            <div className="grid grid-cols-1 lg:grid-cols-5 gap-5">
                {/* Calendar */}
                <div className="lg:col-span-3">
                    <div className="rounded-2xl p-5" style={{ background: '#ffffff', border: '1px solid #e5e7eb' }}>
                        {/* Month nav */}
                        <div className="flex items-center justify-between mb-4">
                            <button onClick={prevMonth} className="p-1.5 rounded-lg hover:bg-slate-100"><ChevronLeft className="w-4 h-4" style={{ color: '#64748b' }} /></button>
                            <h2 className="text-base font-black" style={{ color: '#1e293b' }}>{year}년 {month + 1}월</h2>
                            <button onClick={nextMonth} className="p-1.5 rounded-lg hover:bg-slate-100"><ChevronRight className="w-4 h-4" style={{ color: '#64748b' }} /></button>
                        </div>
                        {/* DOW header */}
                        <div className="grid grid-cols-7 gap-1 mb-1">
                            {['일', '월', '화', '수', '목', '금', '토'].map((d, i) => (
                                <div key={d} className="text-center text-[10px] font-bold py-1" style={{ color: i === 0 ? '#dc2626' : i === 6 ? '#2563eb' : '#94a3b8' }}>{d}</div>
                            ))}
                        </div>
                        {/* Days grid */}
                        <div className="grid grid-cols-7 gap-1">
                            {Array.from({ length: firstDay }).map((_, i) => <div key={`e${i}`} />)}
                            {Array.from({ length: daysInMonth }).map((_, i) => {
                                const d = i + 1;
                                const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
                                const recs = dayRecords(d);
                                const isToday = dateStr === today;
                                const dayOfWeek = new Date(year, month, d).getDay();
                                return (
                                    <button key={d} onClick={() => { setApplyInitial({ startDate: dateStr }); setShowApply(true); }}
                                        className="relative p-1 rounded-lg text-center transition-all hover:bg-slate-50"
                                        style={{
                                            minHeight: 48,
                                            background: isToday ? '#fffbeb' : 'transparent',
                                            border: isToday ? '1.5px solid #c9a84c' : '1px solid transparent',
                                        }}>
                                        <span className="text-xs font-bold block"
                                            style={{ color: dayOfWeek === 0 ? '#dc2626' : dayOfWeek === 6 ? '#2563eb' : '#1e293b' }}>{d}</span>
                                        <div className="flex justify-center gap-0.5 mt-0.5 flex-wrap">
                                            {recs.slice(0, 3).map(r => (
                                                <span key={r.id} className="w-1.5 h-1.5 rounded-full" style={{ background: ATTENDANCE_TYPE_COLOR[r.type] }} />
                                            ))}
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                        {/* Legend */}
                        <div className="mt-4 flex flex-wrap gap-2 pt-3" style={{ borderTop: '1px solid #f1f5f9' }}>
                            {ATTENDANCE_TYPES.map(t => (
                                <span key={t} className="flex items-center gap-1 text-[10px] font-bold" style={{ color: '#64748b' }}>
                                    <span className="w-2 h-2 rounded-full" style={{ background: ATTENDANCE_TYPE_COLOR[t] }} />{t}
                                </span>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Records List */}
                <div className="lg:col-span-2">
                    <div className="rounded-2xl p-5" style={{ background: '#ffffff', border: '1px solid #e5e7eb' }}>
                        <h3 className="font-black text-sm mb-3" style={{ color: '#1e293b' }}>📋 신청 내역</h3>
                        <div className="space-y-2 max-h-[500px] overflow-y-auto">
                            {records.map(r => (
                                <motion.div key={r.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                                    className="p-3 rounded-xl transition-all hover:shadow-sm"
                                    style={{ background: statusBg(r.status), border: `1px solid ${statusColor(r.status)}20` }}>
                                    <div className="flex items-center justify-between mb-1.5">
                                        <div className="flex items-center gap-1.5">
                                            <span className="text-xs font-bold px-2 py-0.5 rounded-full"
                                                style={{ background: ATTENDANCE_TYPE_COLOR[r.type] + '20', color: ATTENDANCE_TYPE_COLOR[r.type] }}>{r.type}</span>
                                            <span className="flex items-center gap-0.5 text-[10px] font-bold px-1.5 py-0.5 rounded-full"
                                                style={{ background: statusBg(r.status), color: statusColor(r.status), border: `1px solid ${statusColor(r.status)}30` }}>
                                                {statusIcon(r.status)} {ATTENDANCE_STATUS_LABEL[r.status]}
                                            </span>
                                        </div>
                                        {r.status === 'pending' && (
                                            <button onClick={() => { attendanceStore.remove(r.id); refresh(); }}
                                                className="p-1 rounded hover:bg-white"><X className="w-3 h-3" style={{ color: '#94a3b8' }} /></button>
                                        )}
                                    </div>
                                    <p className="text-xs font-bold" style={{ color: '#1e293b' }}>
                                        {r.startDate === r.endDate ? r.startDate : `${r.startDate} ~ ${r.endDate}`}
                                    </p>
                                    {r.destination && (
                                        <p className="text-[10px] flex items-center gap-1 mt-0.5" style={{ color: '#7c3aed' }}>
                                            <MapPin className="w-2.5 h-2.5" />{r.destination}
                                        </p>
                                    )}
                                    {r.memo && <p className="text-[10px] mt-0.5" style={{ color: '#64748b' }}>{r.memo}</p>}
                                </motion.div>
                            ))}
                            {records.length === 0 && (
                                <div className="text-center py-8" style={{ color: '#94a3b8' }}>
                                    <CalendarDays className="w-8 h-8 mx-auto mb-2 opacity-30" />
                                    <p className="text-xs">근태 기록이 없습니다</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Modals */}
            <AnimatePresence>
                {showApply && <ApplyModal onClose={() => setShowApply(false)} onSubmit={handleSubmit} initial={applyInitial} />}
            </AnimatePresence>
            <AnimatePresence>
                {showQuickDest && <QuickDestModal onClose={() => setShowQuickDest(false)} onSubmit={handleSubmit} />}
            </AnimatePresence>
        </div>
    );
}

// @ts-nocheck
'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { FileText, UploadCloud } from 'lucide-react';
import type { Document, DocumentCategory, DocumentStatus } from '@/lib/types';

import { OcrResultData, OcrResultPanel } from './documents/OcrResultPanel';
import { DocumentList } from './documents/DocumentList';

const CATEGORIES: DocumentCategory[] = ['계약서', '의견서', '리포트', '소장', '영수증', '기타'];

interface DocumentWidgetProps {
    companyId: string;
    currentUserRole: 'lawyer' | 'admin';
}

export function DocumentWidget({ companyId, currentUserRole }: DocumentWidgetProps) {
    const [docs, setDocs] = useState<Document[]>([]);
    const [selectedCategory, setSelectedCategory] = useState<DocumentCategory | '전체'>('전체');
    const [isDragging, setIsDragging] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // ── OCR State ──
    const [ocrLoading, setOcrLoading] = useState<string | null>(null);
    const [ocrProgress, setOcrProgress] = useState(0);
    const [ocrResult, setOcrResult] = useState<OcrResultData | null>(null);
    const [ocrError, setOcrError] = useState<string | null>(null);
    const [ocrEngine, setOcrEngine] = useState<'auto'|'cloud_vision'|'tesseract'>('auto');
    const [ocrMode, setOcrMode] = useState<'document'|'text'|'handwriting'>('document');

    // load docs
    useEffect(() => {
        // TODO: Replace with SWR-based fetching from Supabase Storage & DB
        const load = () => setDocs([]);
        load();
        window.addEventListener('ibs-docs-updated', load);
        return () => window.removeEventListener('ibs-docs-updated', load);
    }, [companyId]);

    const handleFileUpload = (files: FileList | null) => {
        if (!files || files.length === 0) return;
        
        Array.from(files).forEach(file => {
            if (file.size > 10 * 1024 * 1024) {
                alert(`${file.name} 10MB 이하의 파일만 업로드 가능합니다.`);
                return;
            }
            
            // TODO: Implement Supabase Storage upload
            const fileDoc: Document = {
                id: Math.random().toString(),
                companyId,
                authorRole: currentUserRole,
                name: file.name,
                size: file.size,
                type: file.type || 'application/octet-stream',
                category: '의견서', // Default for lawyers
                status: '검토 완료',
                url: URL.createObjectURL(file),
                isNewForClient: true,
                isNewForLawyer: false,
                createdAt: new Date().toISOString()
            };
            setDocs(prev => [fileDoc, ...prev]);
            console.log('Document upload pending Supabase Integration:', file.name);
        });
    };

    const handleStatusChange = (docId: string, newStatus: DocumentStatus) => {
        // TODO: Update via Supabase DB mutation
        setDocs(prev => prev.map(d => d.id === docId ? { ...d, status: newStatus } : d));
    };

    const handleDocClick = (doc: Document) => {
        if (doc.isNewForLawyer) {
            // TODO: Mark as read via Supabase DB mutation
            setDocs(prev => prev.map(d => d.id === doc.id ? { ...d, isNewForLawyer: false } : d));
        }
        window.open(doc.url, '_blank');
    };

    // ── OCR Handler ──
    const handleOcr = useCallback(async (doc: Document) => {
        setOcrLoading(doc.id);
        setOcrProgress(0);
        setOcrResult(null);
        setOcrError(null);

        try {
            // Lazy import to avoid loading Tesseract on every page
            const { extractText, isOcrSupported } = await import('@/lib/ocr');

            // 실제 File 객체를 URL에서 fetch로 가져오거나, 더미 파일 생성
            let file: globalThis.File;
            if (doc.url.startsWith('blob:') || doc.url.startsWith('http')) {
                const res = await fetch(doc.url);
                const blob = await res.blob();
                file = new globalThis.File([blob], doc.name, { type: doc.type });
            } else {
                // URL이 '#'인 경우 (mock 데이터) — 데모용 OCR 시뮬레이션
                setOcrProgress(50);
                await new Promise(r => setTimeout(r, 800));
                setOcrProgress(100);
                setOcrResult({
                    id: `ocr_demo_${Date.now()}`,
                    fileName: doc.name,
                    extractedText: `[데모] "${doc.name}" 파일의 OCR 텍스트 추출 결과입니다.\n\n이 문서는 실제 파일이 아닌 시스템 생성 문서이므로,\n실제 업로드된 이미지/PDF 파일에서 OCR을 실행하면\n한국어/영어 텍스트가 정확히 추출됩니다.\n\n원고: 김민수\n피고: (주)프랜차이즈코리아\n2024년 3월 15일\n손해배상금 50,000,000원\n사건번호: 2024가합12345`,
                    confidence: 85,
                    language: 'ko',
                    processedAt: new Date().toISOString(),
                    pageCount: 1,
                    structuredData: {
                        parties: ['김민수', '(주)프랜차이즈코리아'],
                        dates: ['2024-03-15'],
                        amounts: ['50,000,000원'],
                        caseNumbers: ['2024가합12345'],
                        keyPhrases: ['손해배상'],
                    }
                });
                setOcrLoading(null);
                return;
            }

            if (!isOcrSupported(file)) {
                setOcrError('지원하지 않는 파일 형식입니다.');
                setOcrLoading(null);
                return;
            }

            const result = await extractText(file, {
                engine: ocrEngine,
                mode: ocrMode,
                language: 'kor+eng',
                extractStructured: true,
                onProgress: (pct) => setOcrProgress(pct),
            });

            setOcrResult(result);
        } catch (err: any) {
            console.error('OCR Error:', err);
            setOcrError(err.message || 'OCR 처리 중 오류가 발생했습니다.');
        } finally {
            setOcrLoading(null);
        }
    }, [ocrEngine, ocrMode]);

    // Check if a doc is OCR-compatible by extension
    const isOcrCompatible = (doc: Document) => {
        const ext = doc.name.split('.').pop()?.toLowerCase() || '';
        return ['jpg', 'jpeg', 'png', 'webp', 'bmp', 'tiff', 'tif', 'pdf', 'docx', 'hwp', 'hwpx'].includes(ext)
            || doc.type.includes('image') || doc.type.includes('pdf');
    };

    const filteredDocs = docs.filter(doc => selectedCategory === '전체' || doc.category === selectedCategory)
        .sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

    return (
        <div className="flex flex-col h-full bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
                <div>
                    <h3 className="font-bold text-gray-900 flex items-center gap-2">
                        <FileText className="w-4 h-4 text-blue-500" />
                        의뢰인 문서함
                    </h3>
                    <p className="text-[11px] text-gray-500 mt-0.5">고객이 업로드한 문서와 수임 결과를 관리합니다.</p>
                </div>
                <div className="flex items-center gap-2">
                    <select 
                        value={ocrEngine}
                        onChange={(e) => setOcrEngine(e.target.value as any)}
                        className="text-[10px] border border-gray-200 rounded-md bg-white px-2 py-1 outline-none text-gray-600 font-medium"
                    >
                        <option value="auto">Auto (Cloud 우선)</option>
                        <option value="cloud_vision">Cloud Vision</option>
                        <option value="tesseract">Tesseract (로컬)</option>
                    </select>
                    <select 
                        value={ocrMode}
                        onChange={(e) => setOcrMode(e.target.value as any)}
                        className="text-[10px] border border-gray-200 rounded-md bg-white px-2 py-1 outline-none text-gray-600 font-medium"
                    >
                        <option value="document">일반 문서</option>
                        <option value="text">텍스트 위주</option>
                        <option value="handwriting">필기체 포함</option>
                    </select>
                    <select 
                        value={selectedCategory} 
                        onChange={(e) => setSelectedCategory(e.target.value as any)}
                        className="text-xs border-gray-200 rounded-md bg-white pr-7 py-1 outline-none"
                    >
                        <option value="전체">모든 분류</option>
                        {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>
            </div>

            {/* List */}
            <DocumentList 
                filteredDocs={filteredDocs}
                ocrLoading={ocrLoading}
                ocrProgress={ocrProgress}
                handleDocClick={handleDocClick}
                isOcrCompatible={isOcrCompatible}
                handleOcr={handleOcr}
                handleStatusChange={handleStatusChange}
            />

            {/* OCR Result Panel */}
            <OcrResultPanel 
                ocrResult={ocrResult}
                setOcrResult={setOcrResult}
                ocrError={ocrError}
                setOcrError={setOcrError}
            />

            {/* Upload Area */}
            <div className="p-3 border-t border-gray-100 bg-gray-50">
                <input type="file" ref={fileInputRef} className="hidden" multiple onChange={(e) => handleFileUpload(e.target.files)} />
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    onDragOver={e => { e.preventDefault(); setIsDragging(true); }}
                    onDragLeave={e => { e.preventDefault(); setIsDragging(false); }}
                    onDrop={e => { e.preventDefault(); setIsDragging(false); handleFileUpload(e.dataTransfer.files); }}
                    className={`flex items-center justify-center gap-2 py-3 rounded-xl border-2 border-dashed text-sm font-bold cursor-pointer transition-colors ${
                        isDragging ? 'border-blue-500 bg-blue-50 text-blue-600' : 'border-gray-200 bg-white text-gray-500 hover:border-gray-300 hover:bg-gray-50'
                    }`}
                >
                    <UploadCloud className="w-4 h-4" />
                    결과물 / 참고 서류 업로드 (HWP, Word, PDF, 이미지 등)
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
// import { supabase } from "@/lib/supabase";

export type BriefingVariant = 'logout' | '1330' | '1500' | '1730';

interface EveningBriefingModalProps {
  isOpen: boolean;
  variant: BriefingVariant;
  onConfirm: () => void;
  onCancel: () => void;
}

export function EveningBriefingModal({ isOpen, variant, onConfirm, onCancel }: EveningBriefingModalProps) {
  const [actualCalls, setActualCalls] = useState(0);
  const targetCalls = 80;
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (isOpen) {
      const fetchCallData = async () => {
        setIsLoading(true);
        try {
          const { supabase } = await import('@/lib/supabase');
          
          // Get start of today
          const startOfToday = new Date();
          startOfToday.setHours(0, 0, 0, 0);
          
          if (!supabase) return;
          
          const { count, error } = await supabase
            .from('companies')
            .select('*', { count: 'exact', head: true })
            .gte('lastCallAt', startOfToday.toISOString());
            
          if (error) throw error;
          
          setActualCalls(count || 0);
        } catch (error) {
          console.error('Failed to fetch call stats:', error);
          setActualCalls(0);
        } finally {
          setIsLoading(false);
        }
      };
      fetchCallData();
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const progressPercentage = Math.min(100, (actualCalls / targetCalls) * 100);
  const isGoalMet = actualCalls >= targetCalls;
  const remainingCalls = targetCalls - actualCalls;
  
  const isSmall = variant === '1330' || variant === '1500';
  
  // Custom texts depending on variant
  let title, description, buttonText;
  
  if (variant === 'logout') {
    title = "업무 종료 최종 스코어";
    description = "오늘의 최종 시스템 통계입니다. 목표 달성률을 확인 후 퇴근을 눌러주세요.";
    buttonText = isGoalMet ? '✨ 기분 좋게 퇴근하기' : '확인 후 퇴근하기';
  } else if (variant === '1330') {
    title = "중간점검 스코어 (1:30 PM)";
    description = "현재 시점 누적 유효 통화 데이터입니다.";
