  } else if (variant === '1500') {
    title = "중간점검 스코어 (3:00 PM)";
    description = "현재 시점 누적 유효 통화 데이터입니다.";
    buttonText = isGoalMet ? '💪 현재 페이스 완벽하게 유지하기' : '📞 즉시 전화기 들기 (수치 채우기)';
  } else { // 1730
