  const isMidday = variant === '1330' || variant === '1500';

  // Wrapper classes for non-blocking vs full-screen overlay
  const wrapperClass = isMidday 
    ? "fixed bottom-8 right-8 z-[100] w-full max-w-[420px] pointer-events-none" 
