  return (
    <div className={wrapperClass}>
      <div className={cardClass}>
        
        {/* Dynamic header colored based on goal met */}
        <div className={`absolute top-0 left-0 w-full h-2 ${isGoalMet ? 'bg-green-500' : 'bg-red-500'}`}></div>

