}

// ── 스크립트 탭 ──
function ScriptTab({ company, onUpdate }: { company: Company; onUpdate: () => void }) {
    const defaultCall = `안녕하세요, ${company.contactName || '담당자'}님. IBS 법률사무소 영업팀입니다.\n\n${company.name}의 개인정보처리방침을 검토한 결과, ${company.issues?.length || 0}건의 법적 리스크를 발견했습니다.\n\n10분 정도 통화 가능하신가요?`;
    const defaultEmail = `제목: [IBS 법률] ${company.name} 개인정보처리방침 리스크 진단 결과\n\n${company.contactName || '담당자'} 님께,\n\n안녕하세요. IBS 법률사무소입니다.\n\n${company.name}의 홈페이지를 검토한 결과, ${company.issues?.length || 0}건의 이슈를 발견했습니다.\n\n무료 상세 진단 리포트를 제공해 드리겠습니다.\n\nIBS 법률사무소 드림`;

    const [callScript, setCallScript] = useState(company.customScript?.call ?? defaultCall);
    const [emailScript, setEmailScript] = useState(company.customScript?.email ?? defaultEmail);
    const [activeScript, setActiveScript] = useState<'call' | 'email'>('call');
    const [saved, setSaved] = useState(false);

    const { updateCompany } = useCompanies();
    const handleSave = () => {
        updateCompany(company.id, { customScript: { call: callScript, email: emailScript } });
        onUpdate(); setSaved(true); setTimeout(() => setSaved(false), 2000);
    };

    return (
        <div>
            <div className="flex gap-1 mb-4">
                {([['call', '📞 콜 스크립트'], ['email', '📧 이메일']] as const).map(([k, label]) => (
                    <button key={k} onClick={() => setActiveScript(k)}
                        className="px-3 py-1.5 rounded-lg text-sm font-semibold transition-colors"
                        style={{ background: activeScript === k ? '#eef2ff' : 'transparent', color: activeScript === k ? '#4f46e5' : '#94a3b8', border: activeScript === k ? '1px solid #c7d2fe' : '1px solid transparent' }}>
                        {label}
                    </button>
                ))}
            </div>
            <textarea
                value={activeScript === 'call' ? callScript : emailScript}
                onChange={e => activeScript === 'call' ? setCallScript(e.target.value) : setEmailScript(e.target.value)}
                rows={12}
                className="w-full px-4 py-3 rounded-xl border text-sm resize-none outline-none transition-colors"
                style={{ borderColor: '#e2e8f0', color: '#1e293b', lineHeight: '1.7', fontFamily: 'inherit' }}
                onFocus={e => e.target.style.borderColor = '#c7d2fe'}
                onBlur={e => e.target.style.borderColor = '#e2e8f0'}
            />
            <div className="flex gap-2 mt-2">
                <button onClick={() => navigator.clipboard.writeText(activeScript === 'call' ? callScript : emailScript)}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold border bg-white hover:bg-slate-50 transition-colors"
                    style={{ color: '#475569', borderColor: '#e2e8f0' }}>
                    <Copy className="w-3.5 h-3.5" /> 복사
                </button>
                <button onClick={handleSave}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-colors"
                    style={{ background: saved ? '#dcfce7' : '#eef2ff', color: saved ? '#16a34a' : '#4f46e5', border: `1px solid ${saved ? '#86efac' : '#c7d2fe'}` }}>
                    {saved ? <><CheckCircle2 className="w-3.5 h-3.5" /> 저장됨</> : <><Save className="w-3.5 h-3.5" /> 저장</>}
                </button>
            </div>
        </div>
    );
}

// ── 타임라인 탭 ──
function TimelineTab({ company, onUpdate }: { company: Company; onUpdate: () => void }) {
    const [newContent, setNewContent] = useState('');
    const [newType, setNewType] = useState<TimelineEventType>('call');
    const sorted = [...(company.timeline || [])].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

    const { updateCompany } = useCompanies();
    const handleAdd = () => {
        if (!newContent.trim()) return;
        updateCompany(company.id, { 
            timeline: [...(company.timeline || []), { 
                id: crypto.randomUUID(), 
                createdAt: new Date().toISOString(), 
                author: '영업팀', 
                type: newType, 
                content: newContent 
            }] 
        });
        onUpdate(); setNewContent('');
    };

    return (
        <div>
            <div className="p-3 rounded-xl border border-slate-200 bg-slate-50 mb-4 space-y-2">
                <div className="flex gap-1">
                    {([['call', '통화'], ['email', '이메일'], ['meeting', '미팅'], ['note', '메모']] as const).map(([t, label]) => (
                        <button key={t} onClick={() => setNewType(t)}
                            className="px-2.5 py-1 rounded-lg text-xs font-semibold transition-colors"
                            style={{ background: newType === t ? TIMELINE_COLOR[t] : 'white', color: newType === t ? 'white' : '#64748b', border: `1px solid ${newType === t ? TIMELINE_COLOR[t] : '#e2e8f0'}` }}>
                            {label}
                        </button>
                    ))}
                </div>
                <div className="flex gap-2">
                    <input value={newContent} onChange={e => setNewContent(e.target.value)}
                        placeholder="활동 내용 입력..." onKeyDown={e => e.key === 'Enter' && handleAdd()}
                        className="flex-1 px-3 py-2 rounded-lg border text-sm outline-none"
                        style={{ borderColor: '#e2e8f0', color: '#1e293b' }} />
                    <button onClick={handleAdd}
                        className="px-3 py-2 rounded-lg text-sm font-bold transition-colors"
                        style={{ background: '#eef2ff', color: '#4f46e5', border: '1px solid #c7d2fe' }}>
                        기록
                    </button>
                </div>
            </div>
            <div className="space-y-3">
                {sorted.map(event => {
                    const color = TIMELINE_COLOR[event.type];
                    return (
                        <div key={event.id} className="flex gap-3">
                            <div className="flex flex-col items-center">
                                <div className="w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0"
                                    style={{ background: `${color}18`, color }}>
                                    {TIMELINE_ICON[event.type]}
                                </div>
                                <div className="w-px flex-1 mt-1" style={{ background: '#e2e8f0', minHeight: 12 }} />
                            </div>
                            <div className="pb-3 min-w-0 flex-1">
                                <div className="flex items-center gap-2 mb-0.5">
                                    <span className="text-xs font-bold" style={{ color }}>{event.author}</span>
                                    <span className="text-[10px]" style={{ color: '#94a3b8' }}>
                                        {new Date(event.createdAt).toLocaleDateString('ko-KR', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                </div>
                                <p className="text-sm" style={{ color: '#475569' }}>{event.content}</p>
                            </div>
                        </div>
                    );
                })}
                {sorted.length === 0 && (
                    <div className="text-center py-8" style={{ color: '#94a3b8' }}>
                        <Activity className="w-8 h-8 mx-auto mb-2 opacity-40" />
                        <p className="text-sm">아직 활동 기록이 없습니다</p>
                    </div>
                )}
            </div>
        </div>
    );
}

// ── 메모 탭 ──
function MemoTab({ company, onUpdate }: { company: Company; onUpdate: () => void }) {
    const [text, setText] = useState('');
    const { updateCompany } = useCompanies();
    const handleSave = () => {
        if (!text.trim()) return;
        updateCompany(company.id, { 
            memos: [...(company.memos || []), { 
                id: crypto.randomUUID(), 
                createdAt: new Date().toISOString(), 
                author: '영업팀', 
                content: text 
            }] 
        });
        onUpdate(); setText('');
    };
    return (
        <div className="space-y-3">
            {(!company.memos || company.memos.length === 0) && (
                <div className="text-center py-8" style={{ color: '#94a3b8' }}>
                    <MessageSquare className="w-8 h-8 mx-auto mb-2 opacity-40" />
                    <p className="text-sm">아직 메모가 없습니다</p>
                </div>
            )}
            {[...(company.memos || [])].reverse().map(memo => (
                <div key={memo.id} className="p-3 rounded-xl border" style={{ borderColor: '#e2e8f0', background: '#f8fafc' }}>
                    <div className="flex items-center gap-2 mb-1.5">
                        <span className="text-xs font-bold" style={{ color: '#4f46e5' }}>{memo.author}</span>
                        <span className="text-[10px]" style={{ color: '#94a3b8' }}>
                            {new Date(memo.createdAt).toLocaleDateString('ko-KR', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                        </span>
                    </div>
                    <p className="text-sm" style={{ color: '#475569', lineHeight: '1.6' }}>{memo.content}</p>
                </div>
            ))}
            <div className="border-t pt-3" style={{ borderColor: '#e2e8f0' }}>
                <textarea value={text} onChange={e => setText(e.target.value)}
                    placeholder="새 메모 입력..." rows={3}
                    className="w-full px-3 py-2.5 rounded-xl border text-sm resize-none outline-none mb-2"
                    style={{ borderColor: '#e2e8f0', color: '#1e293b', fontFamily: 'inherit' }}
                    onFocus={e => e.target.style.borderColor = '#c7d2fe'}
                    onBlur={e => e.target.style.borderColor = '#e2e8f0'} />
                <button onClick={handleSave} disabled={!text.trim()}
                    className="w-full py-2 rounded-lg text-sm font-bold transition-colors"
                    style={{ background: text.trim() ? '#eef2ff' : '#f8fafc', color: text.trim() ? '#4f46e5' : '#cbd5e1', border: `1px solid ${text.trim() ? '#c7d2fe' : '#e2e8f0'}` }}>
                    메모 저장
                </button>
            </div>
        </div>
    );
}

// ── 개인정보방침 탭 ──
function PrivacyTab({ company, onUpdate }: { company: Company; onUpdate: () => void }) {
    const [privacyUrl, setPrivacyUrl] = useState(company.privacyUrl || '');
    const [privacyText, setPrivacyText] = useState(company.privacyPolicyText || '');
    const [saved, setSaved] = useState(false);
    const { updateCompany } = useCompanies();

    const handleSave = () => {
        updateCompany(company.id, { privacyUrl, privacyPolicyText: privacyText });
        onUpdate(); 
        setSaved(true); 
        setTimeout(() => setSaved(false), 2000);
    };

    return (
        <div className="space-y-4">
            <div>
                <label className="text-xs font-bold mb-1 block" style={{ color: '#64748b' }}>개인정보처리방침 URL</label>
                <input value={privacyUrl} onChange={e => setPrivacyUrl(e.target.value)}
                    placeholder="https://example.com/privacy (없으면 비워두세요)"
                    className="w-full px-3 py-2.5 rounded-xl border text-sm outline-none transition-colors"
                    style={{ background: '#f8fafc', borderColor: '#e2e8f0', color: '#1e293b', boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.02)' }}
                    onFocus={e => e.target.style.borderColor = '#c7d2fe'}
                    onBlur={e => e.target.style.borderColor = '#e2e8f0'} />
            </div>
            <div>
                <label className="text-xs font-bold mb-1 block" style={{ color: '#64748b' }}>방침 원문 텍스트 (옵션)</label>
                <textarea value={privacyText} onChange={e => setPrivacyText(e.target.value)}
                    placeholder="방침 전문 텍스트를 붙여넣으세요..." rows={9}
                    className="w-full px-4 py-3 rounded-xl border text-sm resize-none outline-none transition-colors"
                    style={{ background: '#f8fafc', borderColor: '#e2e8f0', color: '#1e293b', lineHeight: '1.7', fontFamily: 'inherit', boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.02)' }}
                    onFocus={e => e.target.style.borderColor = '#c7d2fe'}
                    onBlur={e => e.target.style.borderColor = '#e2e8f0'} />
            </div>
            <button onClick={handleSave}
                className="w-full py-2.5 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-1.5"
                style={{ background: saved ? '#dcfce7' : '#eef2ff', color: saved ? '#16a34a' : '#4f46e5', border: `1px solid ${saved ? '#86efac' : '#c7d2fe'}` }}>
                {saved ? <><CheckCircle2 className="w-4 h-4" /> 저장됨</> : <><Save className="w-4 h-4" /> 저장 및 동기화</>}
            </button>
        </div>
    );
}

// ── 패널 탭 정의 ──
const PANEL_TABS = [
    { key: 'contact', label: '연락처', icon: <User className="w-3.5 h-3.5" /> },
    { key: 'script', label: '스크립트', icon: <Mail className="w-3.5 h-3.5" /> },
    { key: 'timeline', label: '진행', icon: <Activity className="w-3.5 h-3.5" /> },
    { key: 'memo', label: '메모', icon: <MessageSquare className="w-3.5 h-3.5" /> },
    { key: 'privacy', label: '개인정보', icon: <Shield className="w-3.5 h-3.5" /> },
] as const;

// ── 슬라이드 패널 메인 ──
export default function SlidePanel({ company, onClose, onUpdate }: { company: Company; onClose: () => void; onUpdate: () => void }) {
    const [tab, setTab] = useState<'contact' | 'script' | 'timeline' | 'memo' | 'privacy'>('contact');
    const risk = RISK_META[company.riskLevel as keyof typeof RISK_META] ?? RISK_META[''];

    return (
        <motion.div
            initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
            transition={{ type: 'spring', stiffness: 320, damping: 32 }}
            className="fixed top-0 right-0 h-full w-[520px] shadow-2xl z-50 flex flex-col"
            style={{ background: '#ffffff', borderLeft: '1px solid #e2e8f0' }}>

            {/* 헤더 */}
            <div className="border-b" style={{ borderColor: '#e2e8f0' }}>
                <div className="px-5 pt-4 pb-3 flex items-start justify-between">
                    <div>
                        <h2 className="font-black text-lg leading-tight" style={{ color: '#1e293b' }}>{company.name}</h2>
                        <p className="text-xs mt-0.5" style={{ color: '#94a3b8' }}>{company.bizType || company.biz}</p>
                    </div>
                    <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-slate-100 transition-colors flex-shrink-0 mt-0.5" style={{ color: '#94a3b8' }}>
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* 요약 그리드 */}
                <div className="grid grid-cols-4 border-t" style={{ borderColor: '#f1f5f9' }}>
                    {[
                        { label: '위험도', value: <RiskBadge level={company.riskLevel} /> },
                        { label: '가맹점', value: <span className="text-sm font-bold" style={{ color: '#1e293b' }}>{company.storeCount.toLocaleString()}개</span> },
                        { label: '이슈', value: <span className="text-sm font-black" style={{ color: (company.issueCount || company.issues?.length || 0) >= 4 ? '#dc2626' : '#d97706' }}>{company.issueCount || company.issues?.length || 0}건</span> },
                        { label: '상태', value: <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold" style={{ background: STATUS_COLOR[company.status], color: STATUS_TEXT[company.status] }}>{STATUS_LABEL[company.status]}</span> },
                    ].map((col, i) => (
                        <div key={i} className="flex flex-col items-center justify-center py-2.5 gap-1"
                            style={{ borderRight: i < 3 ? '1px solid #f1f5f9' : undefined }}>
                            <span className="text-[10px] font-bold uppercase tracking-wide" style={{ color: '#94a3b8' }}>{col.label}</span>
                            {col.value}
                        </div>
                    ))}
                </div>
            </div>

            {/* 탭 네비 */}
            <div className="flex border-b" style={{ borderColor: '#e2e8f0' }}>
                {PANEL_TABS.map(t => (
                    <button key={t.key} onClick={() => setTab(t.key)}
                        className="flex-1 flex items-center justify-center gap-1.5 py-2.5 text-xs font-bold transition-colors"
                        style={{
                            color: tab === t.key ? '#4f46e5' : '#94a3b8',
                            borderBottom: `2px solid ${tab === t.key ? '#4f46e5' : 'transparent'}`,
                            background: tab === t.key ? '#eef2ff' : 'transparent',
                        }}>
                        {t.icon} {t.label}
                    </button>
                ))}
            </div>

            {/* 탭 콘텐츠 */}
            <div className="flex-1 overflow-y-auto p-5">
                {tab === 'contact' && <ContactTab company={company} onUpdate={onUpdate} />}
                {tab === 'script' && <ScriptTab company={company} onUpdate={onUpdate} />}
                {tab === 'timeline' && <TimelineTab company={company} onUpdate={onUpdate} />}
                {tab === 'memo' && <MemoTab company={company} onUpdate={onUpdate} />}
                {tab === 'privacy' && <PrivacyTab company={company} onUpdate={onUpdate} />}
            </div>
        </motion.div>
    );
}

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FileText, FileImage, File, CheckCircle2, Clock, MessageSquare, Eye, ScanSearch, Loader2 } from 'lucide-react';
import { Document, DocumentStatus } from '@/lib/types';

export const STATUS_CONFIG: Record<DocumentStatus, { color: string, bg: string, icon: any }> = {
    '검토 대기': { color: '#dc2626', bg: '#fef2f2', icon: Clock },
    '변호사 열람 완료': { color: '#d97706', bg: '#fffbeb', icon: Eye },
    '검토 중': { color: '#2563eb', bg: '#eff6ff', icon: MessageSquare },
    '검토 완료': { color: '#16a34a', bg: '#f0fdf4', icon: CheckCircle2 }
};

interface Props {
    filteredDocs: Document[];
    ocrLoading: string | null;
    ocrProgress: number;
    handleDocClick: (doc: Document) => void;
    isOcrCompatible: (doc: Document) => boolean;
    handleOcr: (doc: Document) => void;
    handleStatusChange: (docId: string, newStatus: DocumentStatus) => void;
}

export function DocumentList({
    filteredDocs, ocrLoading, ocrProgress,
    handleDocClick, isOcrCompatible, handleOcr, handleStatusChange
}: Props) {
    return (
        <div className="flex-1 overflow-y-auto p-2 space-y-2 min-h-[300px]">
            <AnimatePresence>
                {filteredDocs.length === 0 ? (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="py-12 text-center text-gray-400">
                        <File className="w-8 h-8 mx-auto mb-2 opacity-50" />
                        <p className="text-xs">문서가 없습니다.</p>
                    </motion.div>
                ) : (
                    filteredDocs.map((doc, i) => {
                        const StatusIcon = STATUS_CONFIG[doc.status].icon;
                        const isProcessing = ocrLoading === doc.id;
                        return (
                            <motion.div 
                                key={doc.id}
                                initial={{ opacity: 0, y: 5 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="p-3 rounded-xl border border-gray-100 hover:border-gray-200 bg-white group transition-all"
                            >
                                <div className="flex items-start gap-3">
                                    <div 
                                        className="w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 bg-blue-50 text-blue-500 cursor-pointer hover:bg-blue-100"
                                        onClick={() => handleDocClick(doc)}
                                    >
                                        {doc.type.includes('pdf') ? <FileText className="w-5 h-5"/> : 
                                         doc.type.includes('image') ? <FileImage className="w-5 h-5"/> : 
                                         <File className="w-5 h-5"/>}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2 mb-1">
                                            <h4 
                                                className="text-sm font-bold text-gray-800 truncate cursor-pointer hover:text-blue-600"
                                                onClick={() => handleDocClick(doc)}
                                            >
                                                {doc.name}
                                            </h4>
                                            {doc.isNewForLawyer && (
                                                <span className="text-[9px] font-black bg-red-100 text-red-600 px-1 py-0.5 rounded leading-none">
                                                    NEW
                                                </span>
                                            )}
                                        </div>
                                        <div className="flex items-center gap-2 text-[10px] text-gray-500 font-medium flex-wrap">
                                            <span className="bg-gray-100 px-1.5 py-0.5 rounded">{doc.category}</span>
                                            <span>{new Date(doc.createdAt).toLocaleDateString()}</span>
                                            <span>{(doc.size / 1024 / 1024).toFixed(1)} MB</span>
                                            <span className={doc.authorRole === 'client' ? 'text-orange-500' : 'text-blue-500'}>
                                                {doc.authorRole === 'client' ? '고객 업로드' : '변호사 등록'}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                                
                                {/* OCR Progress Bar */}
                                {isProcessing && (
                                    <motion.div
                                        initial={{ opacity: 0, height: 0 }}
                                        animate={{ opacity: 1, height: 'auto' }}
                                        className="mt-2"
                                    >
                                        <div className="flex items-center gap-2 text-[10px] text-blue-600 font-bold mb-1">
                                            <Loader2 className="w-3 h-3 animate-spin" />
                                            OCR 텍스트 추출 중... {ocrProgress}%
                                        </div>
                                        <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
                                            <motion.div
                                                className="h-full bg-gradient-to-r from-blue-500 to-violet-500 rounded-full"
                                                initial={{ width: 0 }}
                                                animate={{ width: `${ocrProgress}%` }}
                                                transition={{ duration: 0.3 }}
                                            />
                                        </div>
                                    </motion.div>
                                )}

                                <div className="mt-3 pt-3 border-t border-gray-50 flex items-center justify-between">
                                    <div className="flex items-center gap-1.5 px-2 py-1 rounded border text-[10px] font-bold" 
                                         style={{ 
                                             background: STATUS_CONFIG[doc.status].bg, 
                                             borderColor: STATUS_CONFIG[doc.status].color + '30', 
                                             color: STATUS_CONFIG[doc.status].color 
                                         }}>
                                        <StatusIcon className="w-3 h-3" />
                                        {doc.status}
                                    </div>
                                    
                                    <div className="flex items-center gap-2">
                                        {/* OCR Button */}
                                        {isOcrCompatible(doc) && (
                                            <button
                                                onClick={() => handleOcr(doc)}
                                                disabled={!!ocrLoading}
                                                className="flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md border border-violet-200 bg-violet-50 text-violet-600 hover:bg-violet-100 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                                title="OCR 텍스트 추출"
                                            >
                                                <ScanSearch className="w-3 h-3" />
                                                OCR
                                            </button>
                                        )}
                                        <select 
                                            value={doc.status}
                                            onChange={(e) => handleStatusChange(doc.id, e.target.value as DocumentStatus)}
                                            className="text-[10px] bg-gray-50 border border-gray-200 rounded px-1.5 py-1 outline-none font-medium cursor-pointer flex-shrink-0 max-w-[100px]"
                                        >
                                            {Object.keys(STATUS_CONFIG).map(s => <option key={s} value={s}>{s} 상태로 변경</option>)}
                                        </select>
                                    </div>
                                </div>
                            </motion.div>
                        );
                    })
                )}
            </AnimatePresence>
        </div>
    );
}

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ScanSearch, X, Users, Calendar, DollarSign, Hash, Tag, LayoutGrid } from 'lucide-react';

export interface OcrResultData {
    id: string;
    fileName: string;
    extractedText: string;
    confidence: number;
    language: 'ko' | 'en' | 'mixed';
    processedAt: string;
    pageCount: number;
    structuredData?: {
        parties?: string[];
        dates?: string[];
        amounts?: string[];
        caseNumbers?: string[];
        keyPhrases?: string[];
        tables?: Array<{ headers: string[]; rows: string[][]; rawText: string }>;
    };
}

interface Props {
    ocrResult: OcrResultData | null;
    setOcrResult: (val: OcrResultData | null) => void;
    ocrError: string | null;
    setOcrError: (val: string | null) => void;
}

export function OcrResultPanel({ ocrResult, setOcrResult, ocrError, setOcrError }: Props) {
    return (
        <>
            <AnimatePresence>
                {ocrResult && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="border-t border-violet-200 bg-gradient-to-br from-violet-50 to-blue-50 overflow-hidden"
                    >
                        <div className="p-4">
                            <div className="flex items-center justify-between mb-3">
                                <div className="flex items-center gap-2">
                                    <ScanSearch className="w-4 h-4 text-violet-600" />
                                    <h4 className="text-sm font-black text-violet-800">OCR 추출 결과</h4>
                                    <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-violet-200 text-violet-700 font-bold">
                                        신뢰도 {ocrResult.confidence}%
                                    </span>
                                    <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-blue-200 text-blue-700 font-bold">
                                        {ocrResult.language === 'ko' ? '한국어' : ocrResult.language === 'en' ? '영어' : '혼합'}
                                    </span>
                                    {ocrResult.pageCount > 1 && (
                                        <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-gray-200 text-gray-700 font-bold">
                                            {ocrResult.pageCount}페이지
                                        </span>
                                    )}
                                </div>
                                <button
                                    onClick={() => setOcrResult(null)}
                                    className="p-1 rounded-md hover:bg-violet-200 text-violet-500 transition-colors"
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            </div>

                            {/* Structured Data Tags */}
                            {ocrResult.structuredData && (
                                <div className="mb-3 space-y-1.5">
                                    {ocrResult.structuredData.parties && ocrResult.structuredData.parties.length > 0 && (
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <Users className="w-3 h-3 text-blue-500 flex-shrink-0" />
                                            <span className="text-[9px] font-bold text-blue-600 flex-shrink-0">당사자</span>
                                            {ocrResult.structuredData.parties.map((p, i) => (
                                                <span key={i} className="text-[9px] px-1.5 py-0.5 rounded bg-blue-100 text-blue-700 font-medium">{p}</span>
                                            ))}
                                        </div>
                                    )}
                                    {ocrResult.structuredData.dates && ocrResult.structuredData.dates.length > 0 && (
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <Calendar className="w-3 h-3 text-green-500 flex-shrink-0" />
                                            <span className="text-[9px] font-bold text-green-600 flex-shrink-0">날짜</span>
                                            {ocrResult.structuredData.dates.map((d, i) => (
                                                <span key={i} className="text-[9px] px-1.5 py-0.5 rounded bg-green-100 text-green-700 font-medium">{d}</span>
                                            ))}
                                        </div>
                                    )}
                                    {ocrResult.structuredData.amounts && ocrResult.structuredData.amounts.length > 0 && (
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <DollarSign className="w-3 h-3 text-amber-500 flex-shrink-0" />
                                            <span className="text-[9px] font-bold text-amber-600 flex-shrink-0">금액</span>
                                            {ocrResult.structuredData.amounts.map((a, i) => (
                                                <span key={i} className="text-[9px] px-1.5 py-0.5 rounded bg-amber-100 text-amber-700 font-medium">{a}</span>
                                            ))}
                                        </div>
                                    )}
                                    {ocrResult.structuredData.caseNumbers && ocrResult.structuredData.caseNumbers.length > 0 && (
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <Hash className="w-3 h-3 text-purple-500 flex-shrink-0" />
                                            <span className="text-[9px] font-bold text-purple-600 flex-shrink-0">사건번호</span>
                                            {ocrResult.structuredData.caseNumbers.map((c, i) => (
                                                <span key={i} className="text-[9px] px-1.5 py-0.5 rounded bg-purple-100 text-purple-700 font-medium">{c}</span>
                                            ))}
                                        </div>
                                    )}
                                    {ocrResult.structuredData.keyPhrases && ocrResult.structuredData.keyPhrases.length > 0 && (
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <Tag className="w-3 h-3 text-rose-500 flex-shrink-0" />
                                            <span className="text-[9px] font-bold text-rose-600 flex-shrink-0">핵심</span>
                                            {ocrResult.structuredData.keyPhrases.slice(0, 10).map((k, i) => (
                                                <span key={i} className="text-[9px] px-1.5 py-0.5 rounded bg-rose-100 text-rose-700 font-medium">{k}</span>
                                            ))}
                                        </div>
                                    )}
                                    {ocrResult.structuredData.tables && ocrResult.structuredData.tables.length > 0 && (
                                        <div className="mt-2 pt-2 border-t border-violet-100 flex flex-col gap-2">
                                            <div className="flex items-center gap-1.5 mb-1">
                                                <LayoutGrid className="w-3 h-3 text-emerald-500" />
                                                <span className="text-[9px] font-bold text-emerald-600">표/양식 인식 결과</span>
                                            </div>
                                            {ocrResult.structuredData.tables.map((table, tIdx) => (
                                                <div key={tIdx} className="border border-emerald-100 rounded-md overflow-hidden bg-white shadow-sm">
                                                    <table className="w-full text-left text-[10px]">
                                                        {table.headers && table.headers.length > 0 && (
                                                            <thead className="bg-emerald-50 text-emerald-800 font-bold">
                                                                <tr>
                                                                    {table.headers.map((h, i) => <th key={i} className="p-1 px-1.5 border-b border-r border-emerald-100 last:border-r-0 whitespace-nowrap">{h}</th>)}
                                                                </tr>
                                                            </thead>
                                                        )}
                                                        <tbody>
                                                            {table.rows.map((row, rIdx) => (
                                                                <tr key={rIdx} className="border-b border-emerald-50 last:border-b-0 hover:bg-gray-50 transition-colors">
                                                                    {row.map((cell, cIdx) => <td key={cIdx} className="p-1 px-1.5 border-r border-emerald-50 last:border-r-0">{cell}</td>)}
                                                                </tr>
                                                            ))}
                                                        </tbody>
                                                    </table>
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )}

                            {/* Extracted Text */}
                            <div className="max-h-[200px] overflow-y-auto p-3 bg-white rounded-lg border border-violet-100 text-xs text-gray-700 font-mono whitespace-pre-wrap leading-relaxed">
                                {ocrResult.extractedText || '(텍스트 없음)'}
                            </div>

                            <div className="flex items-center justify-between mt-2">
                                <span className="text-[9px] text-gray-400">
                                    {ocrResult.fileName} · {new Date(ocrResult.processedAt).toLocaleString('ko-KR')}
                                </span>
                                <button
                                    onClick={() => {
                                        navigator.clipboard.writeText(ocrResult.extractedText);
                                        alert('클립보드에 복사되었습니다.');
                                    }}
                                    className="text-[10px] font-bold px-2 py-1 rounded bg-violet-600 text-white hover:bg-violet-700 transition-colors"
                                >
                                    텍스트 복사
                                </button>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            <AnimatePresence>
                {ocrError && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="border-t border-red-200 bg-red-50 p-3"
                    >
                        <div className="flex items-center justify-between">
                            <span className="text-xs text-red-600 font-bold">⚠ OCR 오류: {ocrError}</span>
                            <button onClick={() => setOcrError(null)} className="text-red-400 hover:text-red-600">
                                <X className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </>
    );
}

// @ts-nocheck
import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { X, Zap } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { T } from './shared';
import { useCompanies, useAutoSettings } from '@/hooks/useDataLayer';
import { getPromptConfig } from '@/lib/prompts/privacy';
import dataLayer from '@/lib/dataLayer';
import { mutate as globalMutate } from 'swr';

interface AddCompanyModalProps {
    onClose: () => void;
    refresh: () => void;
}

export default function AddCompanyModal({ onClose, refresh }: AddCompanyModalProps) {
    const { addCompany, updateCompany, mutate } = useCompanies();
    const { settings: autoSettings } = useAutoSettings();
    const [addForm, setAddForm] = useState({ name: '', biz: '', url: '', email: '', phone: '', storeCount: '', contactName: '', contactPhone: '', bizType: '', franchiseType: '' });
    const [isSubmitting, setIsSubmitting] = useState(false);

    return (
        <motion.div className="fixed inset-0 z-50 flex items-center justify-center p-4"
            style={{ background: 'rgba(15,23,42,0.5)', backdropFilter: 'blur(4px)' }}
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            <motion.div initial={{ scale: 0.96 }} animate={{ scale: 1 }} exit={{ scale: 0.96 }}
                className="w-full max-w-lg rounded-2xl p-6"
                style={{ background: T.card, border: `1px solid ${T.border}`, boxShadow: '0 24px 64px rgba(0,0,0,0.18)' }}>
                <div className="flex items-center justify-between mb-5">
                    <h2 className="text-base font-black" style={{ color: T.heading }}>기업 등록</h2>
                    <button onClick={onClose} disabled={isSubmitting} className="p-1.5 rounded-lg hover:bg-slate-100 transition-colors cursor-pointer disabled:opacity-50" style={{ color: T.muted }}>
                        <X className="w-5 h-5" />
                    </button>
                </div>
                <div className="space-y-3">
                    {[
                        { k: 'name', l: '기업명 *', ph: '(주)교촌에프앤비' },
                        { k: 'franchiseType', l: '구분 (프랜차이즈/그외) *', type: 'select', options: [{label: '선택 안함', value: ''}, {label: '프랜차이즈', value: '프랜차이즈'}, {label: '그외', value: '그외'}] },
                        { k: 'bizType', l: '업종 (예: 식음료, IT)', ph: '식음료' },
                        { k: 'biz', l: '사업자번호', ph: '123-45-67890' },
                        { k: 'url', l: '홈페이지 URL (등록 시 방침 자동 분석)', ph: 'https://kyochon.com' },
                        { k: 'email', l: '이메일 *', ph: 'legal@kyochon.com' },
                        { k: 'phone', l: '전화번호', ph: '02-1234-5678' },
                        { k: 'storeCount', l: '가맹점수', ph: '100' },
                    ].map(f => (
                        <div key={f.k}>
                            <label className="text-xs font-bold mb-1 block" style={{ color: T.sub }}>{f.l}</label>
                            {f.type === 'select' ? (
                                <select 
                                    value={addForm[f.k as keyof typeof addForm]}
                                    onChange={e => setAddForm((p: typeof addForm) => ({ ...p, [f.k]: e.target.value }))}
                                    disabled={isSubmitting}
                                    className="w-full px-3 py-2 rounded-lg text-sm font-medium disabled:opacity-60"
                                    style={{ background: '#f8f9fc', border: `1px solid ${T.border}`, color: T.body, outline: 'none' }}
                                >
                                    {f.options?.map(opt => (
                                        <option key={opt.value} value={opt.value}>{opt.label}</option>
                                    ))}
                                </select>
                            ) : (
                                <input value={addForm[f.k as keyof typeof addForm]}
                                    onChange={e => setAddForm((p: typeof addForm) => ({ ...p, [f.k]: e.target.value }))}
                                    placeholder={f.ph}
                                    disabled={isSubmitting}
                                    className="w-full px-3 py-2 rounded-lg text-sm font-medium disabled:opacity-60"
                                    style={{ background: '#f8f9fc', border: `1px solid ${T.border}`, color: T.body, outline: 'none' }} />
                            )}
                        </div>
                    ))}
                </div>
                <div className="flex gap-2 mt-5">
                    <Button variant="ghost" className="flex-1" onClick={onClose} disabled={isSubmitting}>취소</Button>
                    <Button variant="premium" className="flex-1" disabled={isSubmitting} onClick={async () => {
                        if (!addForm.name || !addForm.email || !addForm.franchiseType) {
                            alert('기업명, 이메일, 구분(프랜차이즈/그외)은 필수 항목입니다.');
                            return;
                        }
                        if (addForm.franchiseType !== '프랜차이즈' && addForm.franchiseType !== '그외') {
                            alert('구분(프랜차이즈/그외)을 정확히 선택해주세요.');
                            return;
                        }

                        setIsSubmitting(true);
                        const newId = crypto.randomUUID();
                        
                        try {
                            const initialStatus = addForm.url ? 'crawling' : 'pending';
                            
                            await addCompany({
                                id: newId,
                                name: addForm.name, biz: addForm.biz, url: addForm.url,
                                email: addForm.email, phone: addForm.phone,
                                storeCount: parseInt(addForm.storeCount) || 0,
                                status: initialStatus, assignedLawyer: '', issues: [],
                                salesConfirmed: false, salesConfirmedAt: '', salesConfirmedBy: '',
                                lawyerConfirmed: false, lawyerConfirmedAt: '',
                                emailSentAt: '', emailSubject: '',
                                clientReplied: false, clientRepliedAt: '', clientReplyNote: '',
                                loginCount: 0, callNote: '', plan: 'none',
                                autoMode: true, aiDraftReady: false, source: 'manual' as const,
                                riskScore: 0, riskLevel: '', issueCount: 0,
                                bizType: addForm.bizType || '', 
                                franchiseType: addForm.franchiseType as '프랜차이즈' | '그외',
                                domain: addForm.url || '', privacyUrl: addForm.url || '',
                                contactName: addForm.contactName || '', contactEmail: addForm.email || '',
                                contactPhone: addForm.contactPhone || addForm.phone || '',
                                contacts: [], memos: [], timeline: [],
                            });

                            setAddForm({ name: '', biz: '', url: '', email: '', phone: '', storeCount: '', contactName: '', contactPhone: '', bizType: '', franchiseType: '' });
                            onClose();
                            refresh();

                            // 등록 후 URL이 있으면 백그라운드로 분석 요청 (fire-and-forget)
                            if (addForm.url) {
                                (async () => {
                                    try {
                                        const promptConfig = getPromptConfig();
                                        const res = await fetch('/api/analyze', {
                                            method: 'POST',
                                            headers: { 'Content-Type': 'application/json' },
                                            body: JSON.stringify({ 
                                                companyId: newId, 
                                                url: addForm.url, 
                                                systemPrompt: promptConfig.analyzePrompt,
                                                model: promptConfig.model
                                            })
                                        });
                                        const data = await res.json();
                                        if (!res.ok || !data.success) {
                                            await updateCompany(newId, { status: 'pending' });
                                            await dataLayer.auto.addLog({
                                                type: 'ai_analysis',
                                                label: '분석 실패',
                                                companyName: addForm.name,
                                                detail: data?.error || '알 수 없는 오류'
                                            });
                                        } else {
                                            const payload: any = { 
                                                status: 'analyzed',
                                                issues: data.issues || [],
                                                issueCount: data.issueCount || 0,
                                                riskLevel: data.riskLevel || 'MEDIUM',
                                                aiDraftReady: autoSettings?.autoGenerateDraft ?? false
                                            };
                                            if (data.rawText) {
                                                payload.privacyPolicyText = data.rawText;
                                            }
                                            await updateCompany(newId, payload);
                                            await dataLayer.auto.addLog({
                                                type: 'ai_analysis',
                                                label: '분석 완료',
                                                companyName: addForm.name,
                                                detail: `발견된 이슈 ${data.issueCount || 0}건 (${data.riskLevel || 'MEDIUM'})`
                                            });
                                        }
                                    } catch (err: any) {
                                        console.error('Auto analysis error:', err);
                                        await updateCompany(newId, { status: 'pending' });
                                        await dataLayer.auto.addLog({
                                            type: 'ai_analysis',
                                            label: '분석 중단됨',
                                            companyName: addForm.name,
                                            detail: err.message || '네트워크 에러 발생'
                                        });
                                    } finally {
                                        mutate(); // 전체 리프레시
                                        globalMutate('auto-logs');
                                    }
                                })();
                            }
                        } catch (error) {
                            console.error('Failed to add company:', error);
                            alert('기업 등록에 실패했습니다. 관리자에게 문의하세요.');
                            setIsSubmitting(false);
                        }
                    }}>
                        {isSubmitting ? '처리 중...' : <><Zap className="w-4 h-4 mr-1" /> 등록 + 분석 예약</>}
                    </Button>
                </div>
            </motion.div>
        </motion.div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Phone, CheckCircle2, Mail, FileText, Star, Activity, MessageSquare } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Company, CaseStatus, AutoSettings } from '@/lib/types';
