                            <span style={{ color: 'rgba(0,0,0,0.2)' }}>|</span>
                            {isAdmin ? <EditableField value={c.biz || ''} onChange={v => updateCompany(c.id, { biz: v })} placeholder="사업자번호" /> : c.biz || ''}
                            <span style={{ color: 'rgba(0,0,0,0.2)' }}>|</span>
                            <span>가맹점</span>
                            {isAdmin ? <EditableField value={String(c.storeCount || 0)} onChange={v => updateCompany(c.id, { storeCount: parseInt(v, 10) || 0 })} placeholder="매장수" /> : c.storeCount}
                            <span>개</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <StatusBadge status={c.status} />
                    <RiskBadge level={c.riskLevel} />
                    <span className="text-xs font-bold" style={{ color: T.muted }}>
                        {(phoneIdx % filtered.length) + 1} / {filtered.length}
                    </span>
                </div>
            </div>

            <div className="p-6 grid grid-cols-2 gap-6">
                {/* 왼쪽: 통화 스크립트 */}
                <div>
                    <p className="text-xs font-black mb-2 flex items-center gap-1.5" style={{ color: '#2563eb' }}>
                        📋 통화 스크립트
                    </p>
                    <div className="rounded-xl p-4 text-sm whitespace-pre-line leading-relaxed"
                        style={{ background: '#f8fafc', border: `1px solid ${T.border}`, color: T.body, minHeight: 200 }}>
                        {script}
                    </div>
                </div>

                {/* 오른쪽: 핵심 이슈 + 연락처 + 메모 */}
                <div className="space-y-4">
                    {/* 연락처 */}
                    <div className="rounded-xl p-4" style={{ background: '#fffbeb', border: '1px solid #fde68a' }}>
                        <p className="text-xs font-black mb-2 flex justify-between" style={{ color: '#b8960a' }}>
                            <span>📞 연락처 (클릭하여 텍스트 수정)</span>
                        </p>
                        <div className="grid grid-cols-2 gap-3 text-xs">
                            <div className="flex items-center gap-1.5"><span style={{ color: T.muted, width: 44 }}>담당자:</span> <strong style={{ color: T.body, flex: 1, minWidth:0 }}><EditableField value={c.contactName || ''} onChange={v => updateCompany(c.id, { contactName: v })} placeholder="이름 입력" /></strong></div>
                            <div className="flex items-center gap-1.5"><span style={{ color: T.muted, width: 44 }}>전화:</span> <strong style={{ color: '#2563eb', flex: 1, minWidth:0 }}><EditableField value={c.contactPhone || c.phone || ''} onChange={v => updateCompany(c.id, { contactPhone: v })} placeholder="전화번호 입력" /></strong></div>
                            <div className="flex items-center gap-1.5"><span style={{ color: T.muted, width: 44 }}>이메일:</span> <strong style={{ color: T.body, flex: 1, minWidth:0 }}><EditableField value={c.contactEmail || c.email || ''} onChange={v => updateCompany(c.id, { contactEmail: v })} placeholder="이메일 입력" /></strong></div>
                            <div className="flex items-center gap-1.5"><span style={{ color: T.muted, width: 44 }}>웹:</span> <strong style={{ color: T.body, flex: 1, minWidth:0 }}><EditableField value={c.domain || c.url || ''} onChange={v => updateCompany(c.id, { domain: v })} placeholder="홈페이지 주소" /></strong></div>
                        </div>
                    </div>

                    {/* 핵심 이슈 */}
                    <div className="rounded-xl p-4" style={{ background: '#fef2f2', border: '1px solid #fecaca' }}>
                        <p className="text-xs font-black mb-2" style={{ color: '#dc2626' }}>⚠️ 핵심 이슈 ({c.issues?.length || c.issueCount || 0}건)</p>
                        <div className="space-y-1.5">
                            {(c.issues || []).slice(0, 4).map((iss, i) => (
                                <div key={i} className="flex items-center gap-2 text-xs">
                                    <span className="px-1.5 py-0.5 rounded text-[10px] font-bold whitespace-nowrap"
                                        style={{ background: iss.level === 'HIGH' ? '#fecaca' : '#fef3c7', color: iss.level === 'HIGH' ? '#dc2626' : '#d97706' }}>
                                        {iss.level === 'HIGH' ? '고위험' : iss.level === 'MEDIUM' ? '주의' : iss.level}
                                    </span>
                                    <span style={{ color: T.body }} className="truncate">{iss.title}</span>
                                </div>
                            ))}
                            {(!c.issues || c.issues.length === 0) && (
                                <span className="text-xs text-gray-400">발견된 주요 이슈가 없습니다.</span>
                            )}
                        </div>
                    </div>

                    {/* 통합 통화 메모 및 AI 분석 (MemoTab) */}
                    <div className="rounded-xl p-4" style={{ background: '#f8fafc', border: `1px solid ${T.border}` }}>
                        <p className="text-xs font-black mb-2 flex items-center gap-1.5" style={{ color: T.sub }}>
                            <MessageSquare className="w-3.5 h-3.5" /> 통화 메모 & AI 분석 저장
                        </p>
                        <MemoTab co={c} onRefresh={refresh} setToast={showToast} />
                    </div>

                    {/* 과거 이력 (타임라인 / 이전 메모) */}
                    {((c.timeline && c.timeline.length > 0) || (c.memos && c.memos.length > 0)) && (
                        <div className="rounded-xl p-4 bg-white border border-slate-200 shadow-sm mt-4">
                            <p className="text-xs font-black mb-3 flex items-center gap-1.5" style={{ color: T.sub }}>
                                <Activity className="w-3.5 h-3.5 text-blue-500" /> 🔄 최근 기록 (통화/메세지/메모 등)
                            </p>
                            <div className="space-y-3 max-h-48 overflow-y-auto pr-1">
                                {[...(c.timeline || []).map(t => ({...t, _k: 't'})), ...(c.memos || []).map(m => ({...m, _k: 'm'}))]
                                    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
                                    .slice(0, 8)
                                    .map(env => (
                                        <div key={env.id} className="text-xs pb-3 border-b last:border-0 border-slate-100">
                                            <div className="flex items-center justify-between mb-1">
                                                <span className="font-bold flex items-center gap-1 text-[10.5px]" style={{ color: env._k === 't' ? '#6366f1' : '#10b981' }}>
                                                    {env._k === 't' ? <Activity className="w-3 h-3"/> : <MessageSquare className="w-3 h-3"/>}
                                                    {env.author || '시스템'}
                                                </span>
                                                <span className="text-[10px]" style={{ color: '#94a3b8' }}>
                                                    {new Date(env.createdAt).toLocaleDateString('ko-KR', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                                                </span>
                                            </div>
                                            <p style={{ color: T.sub, lineHeight: 1.4 }} className="whitespace-pre-wrap">{env.content}</p>
                                        </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* 어드민 상태 강제 변경 */}
                    {(user?.role === 'super_admin' || user?.role === 'admin') && (
                        <div className="rounded-xl p-4" style={{ background: '#fef2f2', border: '1px solid #fca5a5' }}>
                            <p className="text-xs font-black mb-2" style={{ color: '#dc2626' }}>🔧 상태 강제 변경 (Admin)</p>
                            <select
                                value={c.status}
                                onChange={(e) => {
                                    updateCompany(c.id, { status: e.target.value as CaseStatus });
                                    refresh();
                                    showToast('슈퍼 관리자 권한으로 상태가 변경되었습니다.');
                                }}
                                className="w-full text-xs px-3 py-2 rounded-lg border outline-none font-bold bg-white"
                                style={{ color: '#dc2626', borderColor: '#fca5a5' }}
                            >
                                {Object.entries(STATUS_LABEL).map(([val, label]) => (
                                    <option key={val} value={val}>{label}</option>
                                ))}
                            </select>
                        </div>
                    )}
                </div>
            </div>

            {/* 하단 액션 바 */}
            <div className="flex items-center justify-between px-6 py-4" style={{ background: '#f8f9fc', borderTop: `1px solid ${T.border}` }}>
                <div className="flex gap-2">
                    <button onClick={() => setPhoneIdx(p => Math.max(0, p - 1))}
                        className="px-4 py-2 rounded-lg text-xs font-bold"
                        style={{ background: T.card, border: `1px solid ${T.border}`, color: T.body }}>
                        ← 이전
                    </button>
                    <button onClick={() => setPhoneIdx(p => p + 1)}
                        className="px-4 py-2 rounded-lg text-xs font-bold"
                        style={{ background: '#2563eb', color: '#fff' }}>
                        다음 →
                    </button>
                </div>
                <div className="flex gap-2">
                    {callableStatuses.includes(c.status) && c.status !== 'emailed' && (
                        <Button variant="outline" size="sm" onClick={() => {
                            updateCompany(c.id, { 
                                salesConfirmed: true, 
                                salesConfirmedBy: autoSettings.updatedBy || '영업팀',
                                salesConfirmedAt: new Date().toISOString()
                            });
                            // AI 분석을 아직 수행하지 않은 경우, 통화 완료 시 Timeline(히스토리) 노드를 강제로 하나 생성하여 남깁니다.
                            updateCompany(c.id, {
                                timeline: [...(c.timeline || []), { id: crypto.randomUUID(), createdAt: new Date().toISOString(), author: autoSettings.updatedBy || '영업팀', type: 'call', content: '통화 완료 (AI분석 미진행)' }] 
                            });
                            refresh();
                            const nextIdx = phoneIdx + 1;
                            if (nextIdx < filtered.length) {
                                showToast(`✅ ${c.name} 통화 완료 → 다음 기업으로 이동`);
                                setTimeout(() => setPhoneIdx(nextIdx), 800);
                            } else {
                                showToast(`✅ ${c.name} 통화 완료 — 마지막 기업입니다`);
                            }
                        }}>
                            <CheckCircle2 className="w-3.5 h-3.5 mr-1" /> 통화 완료
                        </Button>
                    )}
                    {c.status === 'lawyer_confirmed' && (
                        <a href={`/admin/email-preview?leadId=${c.id}`}>
                            <Button variant="premium" size="sm">
                                <Mail className="w-3.5 h-3.5 mr-1" /> 이메일 미리보기
                            </Button>
                        </a>
                    )}
                    {(c.status === 'client_replied' || c.status === 'client_viewed') && (
                        <Button variant="premium" size="sm" onClick={() => setContractModal(c)}>
                            <FileText className="w-3.5 h-3.5 mr-1" /> 계약서 발송
                        </Button>
                    )}
                    {c.status === 'contract_sent' && (
                        <Button variant="outline" size="sm" onClick={() => { updateCompany(c.id, { status: 'contract_signed' }); refresh(); }}>
                            <CheckCircle2 className="w-3.5 h-3.5 mr-1" /> 서명 확인
                        </Button>
                    )}
                    {c.status === 'contract_signed' && (
                        <Button variant="premium" size="sm" onClick={() => { updateCompany(c.id, { plan: 'standard' }); refresh(); }}>
                            <Star className="w-3.5 h-3.5 mr-1" /> 구독 확정 + 이관
                        </Button>
                    )}
                </div>
            </div>
        </motion.div>
    );
}

import React, { useState, useMemo } from 'react';
import { Search, ChevronDown, ChevronUp } from 'lucide-react';
import { Company } from '@/lib/types';
import { PIPELINE, SALES_REPS, LAWYERS } from '@/lib/constants';
import { RiskBadge } from '@/components/crm/SlidePanel';
import { T, StatusBadge, StepCell, ActionButton, ExpandedRow } from './shared';

interface TableViewProps {
    filtered: Company[];
    refresh: () => void;
}

export default function TableView({ filtered, refresh }: TableViewProps) {
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [confirmingId, setConfirmingId] = useState<string | null>(null);
    const [confirmRep, setConfirmRep] = useState(SALES_REPS[0]);
    const [loading, setLoading] = useState<string | null>(null);
    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);

    const run = async (key: string, fn: () => Promise<void> | void) => {
        setLoading(key);
        try {
            await fn();
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(null);
            refresh();
        }
    };

    const handleSort = (title: string) => {
        if (title === '액션') return;
        let direction: 'asc' | 'desc' = 'desc';
        if (sortConfig && sortConfig.key === title && sortConfig.direction === 'desc') {
            direction = 'asc';
        }
        setSortConfig({ key: title, direction });
    };

    const sortedData = useMemo(() => {
        let sortableItems = [...filtered];
        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                let aValue: any = a[sortConfig.key as keyof Company];
                let bValue: any = b[sortConfig.key as keyof Company];

                if (sortConfig.key === '위험도') {
                    const riskOrder: Record<string, number> = { 'High': 3, 'Medium': 2, 'Low': 1 };
                    aValue = riskOrder[a.riskLevel as string] || 0;
                    bValue = riskOrder[b.riskLevel as string] || 0;
                } else if (sortConfig.key === '기업명') {
                    aValue = a.name;
                    bValue = b.name;
                } else if (sortConfig.key === '가맹점수') {
                    aValue = a.storeCount;
                    bValue = b.storeCount;
                } else if (sortConfig.key === '상태') {
                    aValue = PIPELINE.indexOf(a.status);
                    bValue = PIPELINE.indexOf(b.status);
                } else if (sortConfig.key === '법률분석') {
                    aValue = PIPELINE.indexOf(a.status) >= PIPELINE.indexOf('analyzed') ? 1 : 0;
                    bValue = PIPELINE.indexOf(b.status) >= PIPELINE.indexOf('analyzed') ? 1 : 0;
                } else if (sortConfig.key === '영업컨펌') {
                    aValue = a.salesConfirmed ? 1 : 0;
                    bValue = b.salesConfirmed ? 1 : 0;
                } else if (sortConfig.key === '변호사배정') {
                     aValue = a.assignedLawyer ? 1 : 0;
                     bValue = b.assignedLawyer ? 1 : 0;
                } else if (sortConfig.key === '변호사컨펌') {
                    aValue = a.lawyerConfirmed ? 1 : 0;
                    bValue = b.lawyerConfirmed ? 1 : 0;
                } else if (sortConfig.key === '이메일') {
                    aValue = a.emailSentAt ? 1 : 0;
                    bValue = b.emailSentAt ? 1 : 0;
                } else if (sortConfig.key === '답장') {
                    aValue = a.clientReplied ? 1 : 0;
                    bValue = b.clientReplied ? 1 : 0;
                }

                if (aValue < bValue) {
                    return sortConfig.direction === 'asc' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        }
        return sortableItems;
    }, [filtered, sortConfig]);

    return (
        <div className="rounded-2xl overflow-hidden" style={{ background: T.card, border: `1px solid ${T.border}`, boxShadow: '0 2px 12px rgba(0,0,0,0.07)' }}>
            <div className="overflow-x-auto">
                <table className="w-full text-sm">
                    <thead>
                        <tr style={{ background: '#f8f9fc', borderBottom: `2px solid ${T.border}` }}>
                            {['기업명', '위험도', '가맹점수', '상태', '법률분석', '영업컨펌', '변호사배정', '변호사컨펌', '이메일', '답장', '액션'].map(h => (
                                <th key={h} 
                                    className={`py-3 px-3 text-left text-xs font-black whitespace-nowrap tracking-wide ${h !== '액션' ? 'cursor-pointer select-none hover:bg-slate-100 transition-colors' : ''}`}
                                    style={{ color: '#b8960a' }}
                                    onClick={() => h !== '액션' && handleSort(h)}>
                                    <div className="flex items-center gap-1">
                                        {h}
                                        {h !== '액션' && (
                                            <div className="flex flex-col opacity-50 ml-0.5">
                                                <ChevronUp className={`w-2.5 h-2.5 -mb-1 ${sortConfig?.key === h && sortConfig.direction === 'asc' ? 'opacity-100 text-black' : 'opacity-30'}`} strokeWidth={3} />
                                                <ChevronDown className={`w-2.5 h-2.5 ${sortConfig?.key === h && sortConfig.direction === 'desc' ? 'opacity-100 text-black' : 'opacity-30'}`} strokeWidth={3} />
                                            </div>
                                        )}
                                    </div>
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {sortedData.map((c: Company) => (
                            <React.Fragment key={c.id}>
                                <tr
                                    className="transition-colors cursor-pointer"
                                    style={{ borderBottom: `1px solid ${T.borderSub}` }}
                                    onClick={(e) => {
                                        const target = e.target as HTMLElement;
                                        if (target.closest('button') || target.closest('a') || target.closest('select')) {
                                            return;
                                        }
                                        setExpandedId(expandedId === c.id ? null : c.id);
                                    }}
                                    onMouseEnter={e => (e.currentTarget.style.background = T.rowHover)}
                                    onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}>

                                    <td className="py-3.5 px-3">
                                        <div className="flex items-center gap-2">
                                            <button onClick={() => setExpandedId(expandedId === c.id ? null : c.id)} className="p-0.5 rounded hover:bg-slate-200 transition-colors">
                                                {expandedId === c.id
                                                    ? <ChevronUp className="w-3.5 h-3.5" style={{ color: T.muted }} />
                                                    : <ChevronDown className="w-3.5 h-3.5" style={{ color: T.muted }} />}
                                            </button>
                                            <div className="cursor-pointer" onClick={() => setExpandedId(expandedId === c.id ? null : c.id)}>
                                                <p className="font-bold text-xs hover:underline" style={{ color: T.body }}>{c.name}</p>
                                                <p className="text-[10px] mt-0.5" style={{ color: T.muted }}>{c.bizType || c.biz}</p>
                                            </div>
                                            {c.source === 'crawler' && (
                                                <span className="text-[9px] px-1.5 py-0.5 rounded-full font-bold" style={{ background: '#fffbeb', color: '#b8960a', border: '1px solid #fde68a' }}>
                                                    자동수집
                                                </span>
                                            )}
                                        </div>
                                    </td>

                                    <td className="py-3.5 px-3"><RiskBadge level={c.riskLevel} /></td>
                                    <td className="py-3.5 px-3"><span className="text-xs font-black" style={{ color: T.body }}>{c.storeCount.toLocaleString()}</span></td>
                                    <td className="py-3.5 px-3"><StatusBadge status={c.status} /></td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={PIPELINE.indexOf(c.status) >= PIPELINE.indexOf('analyzed')}
                                            label={`이슈 ${c.issues.length}건`} active={c.status === 'crawling'} />
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={c.salesConfirmed} label={c.salesConfirmedBy || '컨펌'} active={c.status === 'analyzed'} />
                                        {c.salesConfirmedAt && <p className="text-[9px] mt-0.5 font-medium" style={{ color: T.faint }}>{c.salesConfirmedAt}</p>}
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={!!c.assignedLawyer} label={c.assignedLawyer || '배정 대기'} active={c.status === 'analyzed'} />
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={c.lawyerConfirmed} label="컨펌 완료" active={['assigned', 'reviewing'].includes(c.status)} />
                                        {c.lawyerConfirmedAt && <p className="text-[9px] mt-0.5 font-medium" style={{ color: T.faint }}>{c.lawyerConfirmedAt}</p>}
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={!!c.emailSentAt} label="발송완료" active={c.status === 'lawyer_confirmed'} />
                                        {c.emailSentAt && <p className="text-[9px] mt-0.5 font-medium" style={{ color: T.faint }}>{c.emailSentAt}</p>}
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <StepCell done={c.clientReplied} label="답장 수신" active={c.status === 'emailed'} />
                                    </td>
                                    <td className="py-3.5 px-3">
                                        <ActionButton c={c} run={run}
                                            confirmingId={confirmingId} setConfirmingId={setConfirmingId}
                                            confirmRep={confirmRep} setConfirmRep={setConfirmRep}
                                            loading={loading} refresh={refresh}
                                            onRequireExpansion={() => setExpandedId(c.id)} />
                                    </td>
                                </tr>
                                {expandedId === c.id && <ExpandedRow key={`exp-${c.id}`} c={c} refresh={refresh} />}
                            </React.Fragment>
                        ))}
                        {sortedData.length === 0 && (
                            <tr>
                                <td colSpan={11} className="text-center py-16" style={{ color: T.faint }}>
                                    <Search className="w-8 h-8 mx-auto mb-2 opacity-30" />
                                    <p className="font-medium">검색 결과가 없습니다</p>
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

// @ts-nocheck
import React, { useState } from 'react';
import { RefreshCw, CheckCircle2, Clock, Eye, Mail, Star, FileText, Zap, Save, AlertTriangle, RotateCcw } from 'lucide-react';
import { Company, CaseStatus } from '@/lib/types';
import { STATUS_COLOR, STATUS_TEXT, STATUS_LABEL, LAWYERS } from '@/lib/constants';
import { useCompanies, useUsers } from '@/hooks/useDataLayer';
import { useAuth } from '@/lib/AuthContext';
import { Button } from '@/components/ui/Button';
import { getPromptConfig } from '@/lib/prompts/privacy';
import dataLayer from '@/lib/dataLayer';
import { mutate as globalMutate } from 'swr';

export const T = {
    heading: '#0f172a',
    body: '#1e293b',
    sub: '#475569',
    muted: '#64748b',
    faint: '#94a3b8',
    border: '#d1d5db',
    borderSub: '#e5e7eb',
    bg: '#f8f9fc',
    card: '#ffffff',
    rowHover: '#f1f5f9',
};

export function StatusBadge({ status }: { status: CaseStatus }) {
    return (
        <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold"
            style={{ background: STATUS_COLOR[status], color: STATUS_TEXT[status] }}>
            {status === 'crawling' && <RefreshCw className="w-3 h-3 animate-spin" />}
            {STATUS_LABEL[status]}
        </span>
    );
}

export function StepCell({ done, label, active }: { done: boolean; label: string; active?: boolean }) {
    if (done) return (
        <span className="flex items-center gap-1 text-[10px] font-bold" style={{ color: '#16a34a' }}>
            <CheckCircle2 className="w-3 h-3" /> {label}
        </span>
    );
    if (active) return (
        <span className="flex items-center gap-1 text-[10px] font-bold" style={{ color: '#d97706' }}>
            <Clock className="w-3 h-3 animate-pulse" /> {label}
        </span>
    );
    return <span className="text-[10px] font-medium" style={{ color: T.faint }}>—</span>;
}

// ==========================================
// 공통 AI 통합 분석 함수
// ==========================================
export async function executeAiAnalysis({
    c, 
    updateCompany, 
    mutate, 
    setErrorMsg, 
    setAnalyzing,
    privacyUrl,
    privacyText,
    additionalPayload = {},
    onSuccess
}: {
    c: Company;
    updateCompany: any;
    mutate: any;
    setErrorMsg: (msg: string | null) => void;
    setAnalyzing: (val: boolean) => void;
    privacyUrl: string;
    privacyText: string;
    additionalPayload?: Partial<Company>;
    onSuccess?: (data: any) => void;
}) {
    setErrorMsg(null);
    setAnalyzing(true);

    // 클라이언트 fetch 타임아웃 — 서버 무응답 시 무한 대기 방지 (120초)
    const clientAbort = new AbortController();
    const clientTimeout = setTimeout(() => clientAbort.abort(), 120_000);

    try {
        await updateCompany(c.id, { 
            privacyUrl,
            privacyPolicyText: privacyText,
            ...additionalPayload,
            status: 'crawling' 
        });
        await mutate();

        const promptConfig = getPromptConfig();
        const res = await fetch('/api/analyze', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                companyId: c.id, 
                homepageUrl: c.url,
                privacyUrl: privacyUrl, 
                manualText: privacyText,
                systemPrompt: promptConfig.analyzePrompt,
                model: promptConfig.model
            }),
            signal: clientAbort.signal
        });

        // 서버 에러 응답(502, 504 등)일 때 JSON 파싱 실패 방어
        let data: any;
        try {
            data = await res.json();
        } catch {
            throw new Error(`서버 응답 파싱 실패 (HTTP ${res.status}). Vercel 서버 로그를 확인하세요.`);
        }
        
        if (!res.ok || !data.success) {
            setErrorMsg(data.error || '알 수 없는 오류');
            try { await updateCompany(c.id, { status: 'pending' }); } catch {}
            try {
                await dataLayer.auto.addLog({
                    type: 'ai_analysis',
                    label: '분석 실패',
                    companyName: c.name,
                    detail: data?.error || '알 수 없는 오류'
                });
            } catch {}
        } else {
            const payload: any = { 
                status: 'analyzed',
                issues: data.issues || [],
                issueCount: data.issueCount || 0,
                riskLevel: data.riskLevel || 'MEDIUM'
            };
            if (data.rawText) {
                payload.privacyPolicyText = data.rawText;
            }
            if (data.extractedDetails) {
                if (data.extractedDetails.businessNumber) payload.businessRegNumber = data.extractedDetails.businessNumber;
                if (data.extractedDetails.phoneNumber) payload.supportPhone = data.extractedDetails.phoneNumber;
                if (data.extractedDetails.privacyUrl) payload.privacyUrl = data.extractedDetails.privacyUrl;
            }
            await updateCompany(c.id, payload);
            try {
                await dataLayer.auto.addLog({
                    type: 'ai_analysis',
                    label: '분석 완료',
                    companyName: c.name,
                    detail: `발견된 이슈 ${data.issueCount || 0}건 (${data.riskLevel || 'MEDIUM'})`
                });
            } catch {}
            
            if (onSuccess) onSuccess(data);
        }
    } catch (err: any) {
        const isTimeout = err.name === 'AbortError';
        const msg = isTimeout 
            ? '서버 응답 시간 초과 (2분). 네트워크 상태를 확인하거나 잠시 후 재시도해 주세요.'
            : `분석 중 에러 발생: ${err.message}`;
        setErrorMsg(msg);
        try { await updateCompany(c.id, { status: 'pending' }); } catch {}
        try {
            await dataLayer.auto.addLog({
                type: 'ai_analysis',
                label: isTimeout ? '분석 시간 초과' : '분석 중단됨',
                companyName: c.name,
                detail: err.message || '네트워크 에러 발생'
            });
        } catch {}
    } finally {
        clearTimeout(clientTimeout);
        setAnalyzing(false);
        try { await mutate(); } catch {}
        globalMutate('auto-logs');
    }
}

export function ActionButton({
    c, run, confirmingId, setConfirmingId, confirmRep, setConfirmRep,
    loading, refresh, onRequireExpansion
}: {
    c: Company; run: (k: string, fn: () => Promise<void> | void) => void;
    confirmingId: string | null; setConfirmingId: (v: string | null) => void;
    confirmRep: string; setConfirmRep: (v: string) => void;
    loading: string | null; refresh: () => void;
    onRequireExpansion?: () => void;
}) {
    const s = c.status;
    const selectStyle = { background: T.card, border: `1px solid ${T.border}`, color: T.body, borderRadius: 6, padding: '2px 6px', fontSize: 12 };
    const { updateCompany, mutate } = useCompanies();
    const { users } = useUsers();
    const lawyerList = users?.filter(u => u.role === 'lawyer').map(u => u.name);
    const finalLawyers = lawyerList && lawyerList.length > 0 ? lawyerList : LAWYERS;
    const [analyzing, setAnalyzing] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);

    // 공통 로직으로 추출된 분석 함수 호출
    const triggerAnalysis = async () => {
        if (analyzing) return;

        if (!c.privacyUrl && !c.privacyPolicyText) {
            alert('개인정보처리방침 URL이나 전문 텍스트를 기입해야 합니다. 상세 보기에서 직접 입력해주세요.');
            if (onRequireExpansion) onRequireExpansion();
            return;
        }

        await executeAiAnalysis({
            c,
            updateCompany,
            mutate,
            setErrorMsg,
            setAnalyzing,
            privacyUrl: c.privacyUrl || '',
            privacyText: c.privacyPolicyText || ''
        });
    };

    if (s === 'pending' || s === 'crawling') {
        if (s === 'pending' && errorMsg) {
            return (
                <div className="flex flex-col items-center gap-1.5">
                    <span 
                        className="text-[11px] font-bold flex text-center flex-col items-center max-w-[120px]" 
                        style={{ color: '#dc2626' }}
                        title={errorMsg}
                    >
                        <div className="flex items-center"><AlertTriangle className="w-3.5 h-3.5 mr-1" />분석 실패</div>
                        <span className="text-[9px] font-normal mt-0.5 truncate w-full" title={errorMsg}>{errorMsg}</span>
                    </span>
                    <button
                        onClick={() => setErrorMsg(null)}
                        className="text-[10px] px-2 py-0.5 rounded font-bold transition-colors w-full"
                        style={{ color: '#dc2626', background: '#fef2f2', border: '1px solid #fecaca' }}
                    >
                        <RotateCcw className="w-3 h-3 inline mr-0.5" />초기화
                    </button>
                </div>
            );
        }
        
        const isAnalyzing = analyzing || s === 'crawling';
        
        return (
            <div className="flex flex-col items-center gap-1">
                <Button 
                    variant="premium" 
                    size="sm" 
                    onClick={triggerAnalysis} 
                    disabled={isAnalyzing}
                >
                    {isAnalyzing ? (
                        <><RefreshCw className="w-3.5 h-3.5 mr-1 animate-spin" /> 분석 중...</>
                    ) : (
                        <><Zap className="w-3.5 h-3.5 mr-1" /> 법률 분석</>
                    )}
                </Button>
                
                {/* crawling 상태가 너무 오래 지속될 경우 강제 초기화할 수 있는 작은 버튼 */}
                {s === 'crawling' && (
                    <button
                        onClick={async () => {
                            await updateCompany(c.id, { status: 'pending' });
                            await mutate();
                        }}
                        className="text-[9px] px-1.5 py-0.5 rounded font-medium mt-1 hover:underline"
                        style={{ color: T.faint }}
                        title="분석이 멈춘 경우 상태를 초기화합니다"
                    >
                        상태 강제 초기화
                    </button>
                )}
            </div>
        );
    }
    if (s === 'analyzed') return (
        <Button 
            variant="outline" 
            size="sm" 
            onClick={() => run(c.id, () => updateCompany(c.id, { status: 'reviewing', assignedLawyer: '공통' }))}
            disabled={loading === c.id}
        >
            공통 배정
        </Button>
    );
    if (s === 'assigned' || s === 'reviewing') return (
        <span className="text-xs flex items-center gap-1 font-semibold" style={{ color: '#d97706' }}>
            <Eye className="w-3.5 h-3.5" /> 변호사 검토 중
        </span>
    );
    if (s === 'lawyer_confirmed') return (
        <div className="flex items-center gap-1.5">
            <Button variant="premium" size="sm" onClick={() => run(c.id, () => updateCompany(c.id, { status: 'emailed' }))} disabled={loading === c.id}>
                <Mail className="w-3.5 h-3.5 mr-1" />
                {loading === c.id ? '발송 중...' : '이메일 발송'}
            </Button>
            <button onClick={() => window.open(`/privacy-report?company=${encodeURIComponent(c.name)}`, '_blank')}
                className="text-[10px] font-bold px-2 py-1 rounded"
                style={{ color: '#c9a84c', background: 'rgba(201,168,76,0.1)', border: '1px solid rgba(201,168,76,0.2)' }}>
                미리보기
            </button>
        </div>
    );
    if (s === 'emailed') return (
        <span className="text-xs flex items-center gap-1 font-semibold" style={{ color: '#16a34a' }}>
            <Mail className="w-3.5 h-3.5" /> 발송 완료
        </span>
    );
    if (s === 'client_replied' || s === 'client_viewed') return (
        <Button variant="premium" size="sm" onClick={() => run(c.id, () => updateCompany(c.id, { status: 'contract_sent' }))} disabled={loading === c.id}>
            <FileText className="w-3.5 h-3.5 mr-1" />
            {loading === c.id ? '발송 중...' : '계약서 발송'}
        </Button>
    );
    if (s === 'contract_sent') return (
        <Button variant="outline" size="sm" onClick={() => run(c.id, () => updateCompany(c.id, { status: 'contract_signed', currentStage: '가입/온보딩' }))} disabled={loading === c.id}>
            <CheckCircle2 className="w-3.5 h-3.5 mr-1" />
            {loading === c.id ? '처리 중...' : '서명 확인'}
        </Button>
    );
    if (s === 'contract_signed') return (
        <Button variant="premium" size="sm" onClick={() => run(c.id, () => updateCompany(c.id, { plan: 'standard' }))} disabled={loading === c.id}>
            <Star className="w-3.5 h-3.5 mr-1" />
            {loading === c.id ? '처리 중...' : '구독 확정'}
        </Button>
    );
    return <span className="text-xs font-medium" style={{ color: T.faint }}>—</span>;
}

export function ExpandedRow({ c, refresh }: { c: Company; refresh: () => void }) {
    const { updateCompany, mutate } = useCompanies();
    const { user } = useAuth();
    const [name, setName] = useState(c.name || '');
    const [url, setUrl] = useState(c.url || c.domain || '');
    const [biz, setBiz] = useState(c.biz || '');
    const [contactName, setContactName] = useState(c.contactName || '');
    const [contactPhone, setContactPhone] = useState(c.contactPhone || c.phone || '');
    const [privacyUrl, setPrivacyUrl] = useState(c.privacyUrl || '');
    const [privacyText, setPrivacyText] = useState(c.privacyPolicyText || '');
    const [callNote, setCallNote] = useState(c.callNote || '');
    const [clientReplyNote, setClientReplyNote] = useState(c.clientReplyNote || '');
    const [saving, setSaving] = useState(false);
    const [analyzing, setAnalyzing] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);

    // 정보 저장만 (분석 트리거 없음)
    const handleSave = async () => {
        setSaving(true);
        try {
            await updateCompany(c.id, {
                name,
                url,
                biz,
                contactName,
                contactPhone,
                privacyUrl,
                privacyPolicyText: privacyText,
                callNote,
                clientReplyNote,
            });
            await mutate();
        } catch (e: any) {
            alert(`저장 실패: ${e.message}`);
        } finally {
            setSaving(false);
        }
    };

    // 분석 트리거 (공통 로직 사용)
    const handleAnalyze = async () => {
        if (analyzing) return;
        await executeAiAnalysis({
            c,
            updateCompany,
            mutate,
            setErrorMsg,
            setAnalyzing,
            privacyUrl,
            privacyText,
            additionalPayload: {
                callNote,
                clientReplyNote,
                // 현재 ExpandedRow 폼의 기본 정보도 같이 저장하려면 여기서 추가할 수 있습니다.
            },
            onSuccess: (data) => {
                if (data.rawText) {
                    setPrivacyText(data.rawText); // 화면 즉시 업데이트
                }
            }
        });
    };

    const inputStyle = {
        background: T.card, border: `1px solid ${T.border}`, color: T.body,
        outline: 'none', borderRadius: 8, padding: '8px 12px', fontSize: 12, width: '100%'
    };
    const taStyle = { ...inputStyle, resize: 'none' as const, lineHeight: '1.6' };

    return (
        <tr>
            <td colSpan={11}>
                <div className="px-6 py-4" style={{ background: '#f8fafc', borderTop: `1px solid ${T.border}` }}>
                    <div className="grid grid-cols-2 gap-6">
                        
                        {/* 기업 기본 정보 영역 */}
