                                <select
                                    value={c.status}
                                    onChange={async (e) => {
                                        await updateCompany(c.id, { status: e.target.value as CaseStatus });
                                        await mutate();
                                    }}
                                    className="w-full text-xs px-3 py-2 rounded-lg border outline-none font-bold bg-white"
                                    style={{ color: '#dc2626', borderColor: '#fca5a5' }}
                                >
