                        )}
                        {(!privacyUrl && !privacyText) && !errorMsg && (
                            <div className="col-span-2 flex items-center gap-2 text-[11px] px-3 py-2 rounded-lg" style={{ background: '#fef3c7', color: '#92400e', border: '1px solid #fde68a' }}>
