import { useZeroTrust } from '@/components/ZeroTrustBriefingProvider';
import { startAutomationEngine } from '@/lib/automationEngine';

// ── 역할 레이블·색상 ──────────────────────────────────────
const ROLE_META: Record<string, { label: string; color: string }> = {
