                    <motion.div key={i}
                      className="w-1.5 h-1.5 rounded-full"
                      style={{ background: '#c9a84c' }}
                      animate={{ y: [0, -4, 0] }}
                      transition={{ duration: 0.6, repeat: Infinity, delay: d }}
