                  ))}
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          {/* [개선 2위] FAQ Chips — initial + asked_free 단계 모두 노출 */}
          {(step === 'initial' || step === 'asked_free') && (
            <div className="px-5 pb-4 flex flex-wrap gap-2" role="group" aria-label="자주 묻는 질문">
