import React from 'react';
import { useAuth } from '@/lib/AuthContext';
import { AnimatePresence } from 'framer-motion';
import { ChevronUp, ChevronDown, Phone, Mail, Globe, MessageCircle, FileSignature, Eye } from 'lucide-react';
import Link from 'next/link';

import InlinePanel from './InlinePanel';
import { C, Badge, riskColor, useTimer } from '@/lib/callPageUtils';
import { Company } from '@/lib/types';
import {
  AutoSignatureService,
  EmailTrackingService,
  FollowUpService,
  ConversionPredictionService,
  KakaoScheduleItem
} from '@/lib/salesAutomation';
import { CallRecordingStore } from '@/lib/callRecordingService';

interface CompanyTableRowProps {
  c: Company;
  lockInfo?: { userId: string; userName: string; lockedUntil: string } | null;
  myUserId?: string;
  index: number;
  selectedId: string | null;
  activeCallId: string | null;
  kakaoStatuses: Record<string, KakaoScheduleItem>;
  callResult: string;
  timer: ReturnType<typeof useTimer>;
  isRecording: boolean;
  sttStatus: string;
  waveformData: number[];
  onSelect: (id: string) => void;
  onStartCall: () => void;
  onEndCall: () => Promise<void>;
  onCallResult: (r: 'connected' | 'no_answer' | 'callback' | 'rejected' | 'invalid_site') => void;
  onRefresh: () => void;
  setToast: (s: string) => void;
  onOpenKakao: (c: Company) => void;
  onOpenContract: (c: Company) => void;
  onPass?: () => void;
}

export default function CompanyTableRow({
  c, lockInfo, myUserId, index, selectedId, activeCallId, kakaoStatuses, callResult, timer, 
  isRecording, sttStatus, waveformData, onSelect, onStartCall, onEndCall, 
  onCallResult, onRefresh, setToast, onOpenKakao, onOpenContract, onPass
}: CompanyTableRowProps) {
  const isSel = selectedId === c.id;
  const isCall = activeCallId === c.id;
  const isLockedByMe = lockInfo?.userId === myUserId;
  const isLockedByOther = !!(lockInfo && lockInfo.userId !== myUserId);
  const remainingMin = lockInfo ? Math.max(0, Math.round((new Date(lockInfo.lockedUntil).getTime() - Date.now()) / 60000)) : 0;
  const rc = riskColor(c.riskScore);
  const { user } = useAuth();
  const authorName = user?.name || '알 수 없음';

  // 최신 메모: co.memos가 있으면 바로 사용, 없으면 API에서 로드
  const [apiMemos, setApiMemos] = React.useState<{content: string; createdAt: string; author: string}[]>([]);
  
  React.useEffect(() => {
      // co.memos가 RLS로 비어있을 수 있으므로 API에서도 로드
      if (!c.memos || c.memos.length === 0) {
          fetch(`/api/memos?companyId=${c.id}`)
              .then(r => r.ok ? r.json() : { memos: [] })
              .then(data => setApiMemos(data.memos || []))
              .catch(() => {});
      }
  }, [c.id, c.memos]);

  const latestMemo = React.useMemo(() => {
      const allMemos = (c.memos && c.memos.length > 0) ? c.memos : apiMemos;
      if (!allMemos || allMemos.length === 0) return null;
      const sorted = [...allMemos].sort(
          (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
      const m = sorted[0];
      const d = new Date(m.createdAt);
      const pad = (n: number) => n.toString().padStart(2, '0');
      return {
          content: m.content,
          date: `${d.getFullYear()}.${pad(d.getMonth() + 1)}.${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`,
      };
  }, [c.memos, apiMemos]);

  const [isEditingMemo, setIsEditingMemo] = React.useState(false);
  const [memoValue, setMemoValue] = React.useState('');

  const handleMemoSave = async () => {
      setIsEditingMemo(false);
      if (memoValue.trim()) {
          setToast('메모 저장 중...');
          try {
              const res = await fetch('/api/memos', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({
                      companyId: c.id,
                      author: authorName,
                      content: memoValue.trim(),
                  }),
              });
              if (res.ok) {
                  setToast('메모가 저장되었습니다.');
                  setMemoValue('');
                  // API에서 메모 다시 로드
                  fetch(`/api/memos?companyId=${c.id}`)
                      .then(r => r.ok ? r.json() : { memos: [] })
                      .then(data => setApiMemos(data.memos || []))
                      .catch(() => {});
                  onRefresh();
              } else {
                  const err = await res.json();
                  setToast(`메모 저장 실패: ${err.error}`);
              }
          } catch (e) {
              setToast('메모 저장에 실패했습니다.');
          }
      }
  };

  return (
    <React.Fragment>
      <tr onClick={() => onSelect(c.id)} className="cursor-pointer transition-all"
          style={{
            background: (c.lastCallResult === 'rejected' || c.lastCallResult === 'invalid_site') ? '#f1f5f9' : isLockedByMe ? '#f0fdf4' : isLockedByOther ? '#fef2f2' : isCall ? '#f0fdf4' : isSel ? '#eef2ff' : C.surface,
            borderBottom: `1px solid ${C.borderLight}`,
            borderLeft: isLockedByMe ? '3px solid #10b981' : isLockedByOther ? '3px solid #ef4444' : isCall ? '3px solid #059669' : isSel ? '3px solid #4f46e5' : '3px solid transparent',
            opacity: isLockedByOther ? 0.7 : (c.lastCallResult === 'rejected' || c.lastCallResult === 'invalid_site') ? 0.5 : 1
          }}
          onMouseEnter={e => { if (!isSel && !isCall && !isLockedByMe && !isLockedByOther) (e.currentTarget as HTMLElement).style.background = C.rowHover; }}
          onMouseLeave={e => { if (!isSel && !isCall && !isLockedByMe && !isLockedByOther) (e.currentTarget as HTMLElement).style.background = (c.lastCallResult === 'rejected' || c.lastCallResult === 'invalid_site') ? '#f1f5f9' : C.surface; }}>
          <td className="py-2.5 px-3 text-[12px] font-mono" style={{color:C.faint}}>{index + 1}</td>
          <td className="py-2.5 px-3">
              <div className="flex items-center gap-1.5 flex-wrap">
                  <span className="text-[14px] font-bold" style={{color:C.heading}}>{c.name}</span>
                  {isLockedByMe && <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[11px] font-bold" style={{background:'#d1fae5',color:'#065f46',border:'1px solid #a7f3d0'}}>📞 내가 통화중</span>}
                  {isLockedByOther && lockInfo && <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[11px] font-bold" style={{background:'#fee2e2',color:'#991b1b',border:'1px solid #fecaca'}}>🔴 {lockInfo.userName} 통화중 ({remainingMin}분 남음)</span>}
                  {isSel ? <ChevronUp className="w-3 h-3 flex-shrink-0" style={{color:C.accent}}/> : <ChevronDown className="w-3 h-3 flex-shrink-0" style={{color:C.faint}}/>}
              </div>
          </td>
          <td className="py-2.5 px-3">
              <span className={`inline-flex items-center px-2 py-0.5 rounded text-[11px] font-bold ${c.franchiseType?.trim() === '프랜차이즈' ? 'bg-indigo-50 text-indigo-700 border border-indigo-200' : 'bg-slate-100 text-slate-600 border border-slate-200'}`}>
                  {c.franchiseType?.trim() || '그외'}
              </span>
          </td>
          <td className="py-2.5 px-3">
                  <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-1 flex-wrap">
                          <Badge status={c.status}/>
                          {c.lastCallResult && c.lastCallAt && new Date(c.lastCallAt).toDateString() === new Date().toDateString() && (
                              <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold cursor-default" 
                                    style={{
                                        background: c.lastCallResult === 'connected' ? '#ecfdf5' : c.lastCallResult === 'no_answer' ? '#fef2f2' : c.lastCallResult === 'callback' ? '#fffbeb' : '#f1f5f9',
                                        color: c.lastCallResult === 'connected' ? '#059669' : c.lastCallResult === 'no_answer' ? '#dc2626' : c.lastCallResult === 'callback' ? '#d97706' : '#475569',
                                        border: `1px solid ${c.lastCallResult === 'connected' ? '#a7f3d0' : c.lastCallResult === 'no_answer' ? '#fecaca' : c.lastCallResult === 'callback' ? '#fde68a' : '#cbd5e1'}`
                                    }}>
                                  {c.lastCallResult === 'connected' ? '✅연결됨' : c.lastCallResult === 'no_answer' ? '📵부재중' : c.lastCallResult === 'callback' ? '🔄콜백' : c.lastCallResult === 'rejected' ? '❌거절' : '⚠️패스'}
                              </span>
                          )}
                          {kakaoStatuses[c.id]?.status === 'sent' && <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold cursor-default" style={{background:'#FFFDE7',color:'#2E7D32',border:'1px solid #C8E6C9'}} title="카카오 알림톡 발송 완료">💬</span>}
                          {(() => {
                              const sig = AutoSignatureService.getStatus(c.id);
                          if (!sig) return null;
                          return sig.status === 'watching' ? <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold animate-pulse cursor-default" style={{background:'#fef3c7',color:'#92400e',border:'1px solid #fde68a'}} title="계약서 발송됨 → 고객 전자서명 대기 중 (자동 감지)">✍️대기</span> : <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold cursor-default" style={{background:'#d1fae5',color:'#065f46',border:'1px solid #a7f3d0'}} title="고객이 전자서명 완료! → 구독 자동 전환 진행">✅서명</span>;
                      })()}
                      {(() => {
                          const et = EmailTrackingService.getAll().find(e=>e.companyId===c.id);
                          if (!et) return null;
                          return et.openedAt ? <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold cursor-default" style={{background:'#ede9fe',color:'#5b21b6',border:'1px solid #c4b5fd'}} title="고객이 이메일을 열어봤습니다! 지금 전화하면 효과적">👁️열람</span> : <span className="inline-flex items-center px-1 py-0.5 rounded text-[10px] font-bold cursor-default" style={{background:'#dbeafe',color:'#1d4ed8',border:'1px solid #bfdbfe'}} title="이메일 열람 여부 자동 추적 중 (SendGrid 연동)">📧추적중</span>;
                      })()}
                  </div>
                  {c.emailSentAt && (() => {
                      const step = FollowUpService.getCurrentStep(c);
                      const next = FollowUpService.getNextStep(c);
                      if (step === 0 && !next) return null;
                      return <div className="flex items-center gap-1 cursor-default" title={`자동 팔로업 이메일: ${step}/3단계 완료${next ? ` · 다음 D+${next.dayOffset} 자동 발송 예정` : ' · 전체 완료'}`}>{[1, 2, 3].map(s=><div key={s} className="w-3 h-1.5 rounded-full" style={{background:s<=step?'#4f46e5':'#e2e8f0'}}/>)}<span className="text-[10px] font-bold" style={{color:step>=3?'#059669':'#4f46e5'}}>{step>=3?'완료':`D+${next?.dayOffset||'?'}`}</span></div>;
                  })()}
              </div>
          </td>
          <td className="py-2.5 px-3">{c.riskScore > 0 && <div className="flex items-center gap-1.5"><div className="w-14 h-2 rounded-full overflow-hidden" style={{background:'#e5e7eb'}}><div className="h-full rounded-full" style={{width:`${c.riskScore}%`,background:rc.bar}}/></div><span className="text-[12px] font-bold" style={{color:rc.text}}>{c.riskScore}</span></div>}</td>
          <td className="py-2.5 px-3"><span className="text-[13px]" style={{color:c.contactName?C.body:C.amber}}>{c.contactName||'미등록'}</span></td>
          <td className="py-2.5 px-3">
              {c.lastCalledBy ? (
                  <span className="text-[13px] font-bold text-slate-700 bg-slate-100 px-1.5 py-0.5 rounded-md">{c.lastCalledBy}</span>
              ) : (
                  <span className="text-[13px]" style={{color:C.faint}}>—</span>
              )}
          </td>
          <td className="py-2.5 px-3 whitespace-nowrap" onClick={e=>e.stopPropagation()}><a href={`tel:${(c.contactPhone||c.phone).replace(/[^0-9+]/g,'')}`} className="text-[13px] font-mono inline-flex items-center gap-1 hover:text-indigo-600" style={{color:C.sub, opacity: isLockedByOther ? 0.5 : 1}} title={isLockedByOther ? "다른 담당자가 통화중입니다" : "클릭하여 전화걸기"} onClick={(e) => { if(isLockedByOther && lockInfo) { e.preventDefault(); alert(`현재 ${lockInfo.userName}님이 통화중입니다 (${remainingMin}분 남음)`); } }}><Phone className="w-3 h-3" style={{color:C.accent}}/>{c.contactPhone||c.phone}</a></td>
          <td className="py-2.5 px-3">{(() => {
              const p = ConversionPredictionService.predict(c);
              const colors = { HOT: { bg: '#fef2f2', c: '#dc2626', icon: '🔥' }, WARM: { bg: '#fffbeb', c: '#d97706', icon: '🌡️' }, COLD: { bg: '#f0f9ff', c: '#0284c7', icon: '❄️' } };
              const cl = colors[p.level];
              return <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[12px] font-bold" style={{background:cl.bg,color:cl.c}} title={p.factors.join(' · ')}>{cl.icon}{p.score}%</span>;
          })()}</td>
          <td className="py-2.5 px-3">{c.issues && c.issues.length > 0 ? <span className="text-[12px] font-bold" style={{color:'#dc2626'}}>{c.issues.filter(ii=>ii.level==='HIGH').length}H/{c.issues.length}건</span> : <span className="text-[12px]" style={{color:C.faint}}>—</span>}</td>
          <td className="py-2.5 px-3 max-w-[250px]" onClick={e => e.stopPropagation()}>
              {isEditingMemo ? (
                  <div className="flex flex-col gap-1">
                      <textarea 
                          autoFocus
                          className="w-full text-[12px] p-1.5 border rounded-md resize-none shadow-sm focus:outline-none focus:ring-1 focus:ring-indigo-500 bg-white"
                          style={{ borderColor: C.borderLight, color: C.body }}
                          rows={2}
                          value={memoValue}
                          onChange={e => setMemoValue(e.target.value)}
                          placeholder="새 메모 입력..."
                          onKeyDown={e => {
                              if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
                                  e.preventDefault();
                                  handleMemoSave();
                              }
                              if (e.key === 'Escape') {
                                  setIsEditingMemo(false);
                                  setMemoValue('');
                              }
                          }}
                      />
                      <div className="flex gap-1">
                          <button onClick={handleMemoSave} className="text-[11px] px-2 py-0.5 rounded bg-indigo-50 text-indigo-600 font-bold hover:bg-indigo-100 transition-colors">저장</button>
                          <button onClick={() => { setIsEditingMemo(false); setMemoValue(''); }} className="text-[11px] px-2 py-0.5 rounded bg-gray-50 text-gray-500 font-bold hover:bg-gray-100 transition-colors">취소</button>
                      </div>
                  </div>
              ) : (
                  <div 
                      onClick={() => setIsEditingMemo(true)}
                      className="text-[12px] truncate cursor-pointer hover:bg-slate-50 p-1.5 rounded-md transition-colors border border-transparent hover:border-slate-200"
                      style={{ color: latestMemo ? C.body : C.faint }}
                      title={latestMemo ? `최근 메모 (${latestMemo.date})\n---\n${latestMemo.content}${c.memos?.length > 1 ? `\n\n📝 총 ${c.memos.length}개 메모` : ''}` : '클릭하여 메모 입력'}
                  >
                      {latestMemo ? (
                          <div className="flex flex-col gap-0.5">
                              <span className="text-[10px] font-bold" style={{ color: C.faint }}>{latestMemo.date}</span>
                              <span className="truncate">{latestMemo.content}</span>
                          </div>
                      ) : <span className="italic">메모 없음</span>}
                  </div>
              )}
          </td>
          <td className="py-2.5 px-3" onClick={e=>e.stopPropagation()}>
              <div className="flex items-center gap-1">
                  {(() => {
                      const link = c.domain || c.url;
                      const finalLink = link ? (link.startsWith('http') ? link : `http://${link}`) : '#';
                      return (
                          <a href={finalLink} target={link ? "_blank" : "_self"} rel="noopener noreferrer" title="홈페이지"
                              onClick={(e) => {
                                  if (!link) {
                                      e.preventDefault();
                                      alert('등록된 홈페이지 주소가 없습니다.');
                                  }
                              }}
                          >
                              <button className="p-1.5 rounded-lg flex items-center justify-center hover:bg-cyan-50 transition-colors" style={{border:`1px solid ${C.borderLight}`}} title="홈페이지"><Globe className="w-3.5 h-3.5" style={{color:'#0891b2'}}/></button>
                          </a>
                      );
                  })()}
                  <Link href={`/lawyer/privacy-review?company=${encodeURIComponent(c.name)}&leadId=${c.id}&preview=1`} target="_blank" title="1차 조문검토 미리보기">
                      <button className="p-1.5 rounded-lg flex items-center justify-center hover:bg-purple-50 transition-colors" style={{border:`1px solid ${C.borderLight}`}} title="1차 조문검토 미리보기"><Eye className="w-3.5 h-3.5" style={{color:'#7c3aed'}}/></button>
                  </Link>
                  {(() => {
                      const isMailKakaoDisabled = user?.role === 'sales' && !c.lawyerConfirmed;
                      const isContractDisabled = !c.clientReplied;
                      return (
                          <>
                              {isMailKakaoDisabled ? (
                                  <button onClick={(e) => { e.stopPropagation(); alert('변호사 검토가 완료된 후에만 메일 발송이 가능합니다.'); }} className="p-1.5 rounded-lg flex items-center justify-center opacity-50 cursor-not-allowed" style={{border:`1px solid ${C.borderLight}`, background: C.surface}} title="메일 발송 (변호사 검토 대기중)">
                                      <Mail className="w-3.5 h-3.5" style={{color:'#2563eb'}}/>
                                  </button>
                              ) : (
                                  <Link href={`/admin/email-preview?company=${encodeURIComponent(c.name)}&leadId=${c.id}`} target="_blank" title="이메일 미리보기">
                                      <button className="p-1.5 rounded-lg flex items-center justify-center hover:bg-blue-50 transition-colors" style={{border:`1px solid ${C.borderLight}`}} title="이메일 미리보기"><Mail className="w-3.5 h-3.5" style={{color:'#2563eb'}}/></button>
                                  </Link>
                              )}
                              <button onClick={(e) => { 
                                  e.stopPropagation(); 
                                  if (isMailKakaoDisabled) {
                                      alert('변호사 검토가 완료된 후에만 카카오톡 발송이 가능합니다.');
                                      return;
                                  }
                                  onOpenKakao(c); 
                              }} className={`p-1.5 rounded-lg flex items-center justify-center transition-colors ${isMailKakaoDisabled ? 'opacity-50 cursor-not-allowed bg-transparent' : 'hover:bg-yellow-50'}`} style={{border:`1px solid ${C.borderLight}`}} title={isMailKakaoDisabled ? "카카오톡 발송 (변호사 검토 대기중)" : "카카오톡 발송"}>
                                  <MessageCircle className="w-3.5 h-3.5" style={{color:'#FAE100',fill:'#FAE100',stroke:'#3C1E1E'}}/>
                              </button>
                              <button onClick={(e) => { 
                                  e.stopPropagation(); 
                                  if (isContractDisabled) {
                                      alert('해당 기업의 요청(회신)이 확인된 후에만 계약서를 발송할 수 있습니다.');
                                      return;
                                  }
                                  onOpenContract(c); 
                              }} className={`p-1.5 rounded-lg flex items-center justify-center transition-colors ${isContractDisabled ? 'opacity-50 cursor-not-allowed bg-transparent' : 'hover:bg-amber-50'}`} style={{border:`1px solid ${C.borderLight}`}} title={isContractDisabled ? "계약서 발송 (기업 요청 필요)" : "계약서 발송 미리보기"}>
                                  <FileSignature className="w-3.5 h-3.5" style={{color:'#d97706'}}/>
                              </button>
                          </>
                      );
                  })()}
              </div>
          </td>
      </tr>
      <AnimatePresence>
          {isSel && <InlinePanel
              co={c} isOnCall={isCall} onStartCall={onStartCall}
              onEndCall={onEndCall} onClose={() => onSelect('')} onPass={onPass}
              timer={timer} callResult={callResult as any}
              onCallResult={onCallResult} onRefresh={onRefresh} setToast={setToast}
              isRecording={isRecording} sttStatus={sttStatus} waveformData={waveformData}
              companyRecordings={CallRecordingStore.getByCompany(c.id)} />}
      </AnimatePresence>
    </React.Fragment>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
    Phone, PhoneOff, Building2, Headphones,
    Pause, Play, RefreshCw, X,
} from 'lucide-react';
import { Company, type CaseStatus } from '@/lib/types';
import { STATUS_COLOR, STATUS_TEXT, STATUS_LABEL } from '@/lib/constants';
import { type CallRecording } from '@/lib/callRecordingService';
import ScriptTab from './ScriptTab';
import InfoTab from './InfoTab';
import MemoTab from './MemoTab';
import { useAuth } from '@/lib/AuthContext';
import { supabaseCompanyStore } from '@/lib/supabaseStore';

/* ── shared constants (local copy until callPageUtils is extracted) ── */
const C = {
    bg: '#f8f9fc', surface: '#ffffff', card: '#ffffff', cardHover: '#f1f5f9',
    elevated: '#f8fafc', border: '#d1d5db', borderLight: '#e5e7eb',
    heading: '#0f172a', body: '#1e293b', sub: '#475569', muted: '#64748b', faint: '#94a3b8',
    accent: '#4f46e5', accentSoft: '#6366f1', green: '#059669', greenSoft: '#10b981',
    red: '#dc2626', amber: '#d97706', blue: '#2563eb', purple: '#7c3aed',
    cyan: '#0891b2', rowHover: '#f1f5f9',
};

function Badge({ status }: { status: CaseStatus }) {
    return (
        <span
            className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold whitespace-nowrap"
            style={{ background: STATUS_COLOR[status], color: STATUS_TEXT[status] }}
        >
            {STATUS_LABEL[status]}
        </span>
    );
}

/* ── useTimer return type helper ── */
type UseTimerReturn = {
    sec: number;
    fmt: string;
    running: boolean;
    start: () => void;
    pause: () => void;
    resume: () => void;
    reset: () => void;
};

/* ── Props ── */
export interface InlinePanelProps {
    co: Company;
    isOnCall: boolean;
    onStartCall: () => void;
    onEndCall: () => void;
    onClose: () => void;
    onPass?: () => void;
    timer: UseTimerReturn;
    callResult: string;
    onCallResult: (r: 'connected' | 'no_answer' | 'callback' | 'rejected' | 'invalid_site') => void;
    onRefresh: () => void;
    setToast: (s: string) => void;
    isRecording: boolean;
    sttStatus: string;
    waveformData: number[];
    companyRecordings: CallRecording[];
}

/* ── Component ── */
export default function InlinePanel({
    co, isOnCall, onStartCall, onEndCall, onClose, onPass,
    timer, callResult, onCallResult, onRefresh, setToast,
    isRecording, sttStatus, waveformData, companyRecordings,
}: InlinePanelProps) {
    const { user } = useAuth();
    const [tab, setTab] = useState<'script' | 'info' | 'memo' | 'recordings'>('script');
    const [manualCaller, setManualCaller] = useState(user?.name || '영업담당자');
    const [localResult, setLocalResult] = useState<string | null>(null);

    useEffect(() => {
        if (user?.name && manualCaller === '영업담당자') {
            setManualCaller(user.name);
        }
    }, [user]);

    const handleManualLog = async (res: 'connected' | 'no_answer' | 'callback' | 'rejected' | 'invalid_site', nextAction?: 'review' | 'memo' | 'alarm' | 'pass') => {
        try {
            setLocalResult(res);
            
            // --- 즉각적인 UI 반영 (Optimistic UI) ---
            co.lastCallResult = res;
            co.lastCallAt = new Date().toISOString();
            co.lastCalledBy = manualCaller;
            
            let extraUpdate: any = {};
            if (nextAction === 'review' && co.status === 'analyzed') {
                extraUpdate = { status: 'reviewing' };
                co.status = 'reviewing';
            }
            
            // --- 백그라운드 DB 저장 (UI 딜레이 제거) ---
            supabaseCompanyStore.update(co.id, {
                lastCallResult: res,
                lastCallAt: co.lastCallAt,
                lastCalledBy: manualCaller,
                callAttempts: (co.callAttempts || 0) + 1,
                ...extraUpdate
            }).catch(e => {
                console.error('Manual log failed:', e);
                setToast('❌ 기록 저장 실패');
                setLocalResult(null); // 실패 시 원복
            });

            // --- 통화 내역(RecordingsTab)에도 수동 이력 추가 ---
            import('@/lib/callRecordingService').then(({ CallRecordingStore }) => {
                CallRecordingStore.save({
                    companyId: co.id,
                    companyName: co.name,
                    salesUserName: manualCaller,
                    fileSizeBytes: 0,
                    durationSeconds: 0,
                    transcript: `수동 상태 변경: ${res === 'connected' ? '연결됨' : res === 'no_answer' ? '부재중' : res === 'callback' ? '콜백요청' : res === 'rejected' ? '거절' : '사이트 이상'}`,
                    transcriptSummary: '수동 통화 기록',
                    callResult: res as 'connected'|'no_answer'|'callback', // DB type may still need to be compatible, but keeping as res for now.
                    sttStatus: 'completed',
                    sttProvider: 'mock',
                    contactName: co.contactName || '',
                    contactPhone: co.contactPhone || co.phone,
                });
            });
            
            setToast(`✅ 수동 기록됨: ${res === 'connected' ? '연결됨' : res === 'no_answer' ? '부재중' : res === 'callback' ? '콜백' : res === 'rejected' ? '거절' : '사이트 이상'}`);
            onRefresh(); // 부모 컴포넌트에 즉시 리렌더링 트리거
        } catch(e) {
            setToast('❌ 기록 처리 오류');
            setLocalResult(null);
        }
    };

    const handleResetCallData = async () => {
        if (!confirm('정말로 이 기업의 통화 기록(상태, 시도 횟수)을 초기화하시겠습니까?')) return;
        try {
            await supabaseCompanyStore.update(co.id, {
                lastCallResult: null,
                lastCallAt: null,
                lastCalledBy: null,
                callAttempts: 0,
            } as any);
            
            // UI optimistic update
            co.lastCallResult = undefined;
            co.lastCallAt = undefined;
            co.lastCalledBy = undefined;
            co.callAttempts = 0;
            
            setLocalResult(null);
            setToast('✅ 통화 기록이 초기화되었습니다.');
            onRefresh();
        } catch (e) {
            console.error('Reset log failed:', e);
            setToast('❌ 초기화 오류');
        }
    };

    const handleResultAction = (res: 'connected' | 'no_answer' | 'callback' | 'rejected' | 'invalid_site', nextAction?: 'review' | 'memo' | 'alarm' | 'pass') => {
        // 1. 콜 이력 로깅
        if (isOnCall) {
            onCallResult(res);
        } else {
            handleManualLog(res, nextAction);
        }
        
        // 2. 후속 액션 진행 
        if (nextAction === 'memo') {
            setTab('memo');
        } else if (nextAction === 'review') {
            setToast('✅ 변호사 검토 요청이 접수되었습니다. (자동 메일 발송 준비)');
        } else if (nextAction === 'alarm') {
            setToast('⏰ 24시간 후 재연락 알람이 설정되었습니다.');
        } else if (nextAction === 'pass') {
            setToast('⏭️ 다음 기업으로 넘어갑니다.');
            if (onPass) onPass();
            else onClose();
        }
    };

    // Reset local result when company changes
    useEffect(() => { setLocalResult(null); }, [co.id]);

    // Reset tab when company changes
    useEffect(() => { setTab('script'); }, [co.id]);

    return (
        <motion.tr
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.25 }}
        >
            <td colSpan={12} className="p-0">
                <div style={{
                    background: isOnCall ? '#f0fdf4' : '#f8fafc',
                    borderTop: `2px solid ${isOnCall ? '#059669' : '#4f46e5'}`,
                    borderBottom: `2px solid ${isOnCall ? '#a7f3d0' : '#c7d2fe'}`,
                }}>


                    {/* ── 통합 콘텐츠 대시보드 ── */}
                    <div className="px-5 py-4" style={{ maxHeight: 800, overflowY: 'auto', background: C.bg }}>
                        <div className="grid grid-cols-3 gap-6 items-stretch">
                            {/* Col 1: 스마트 기업 상세정보, 위험도, 주요 이슈 */}
                            <div className="flex flex-col gap-4 h-full min-w-0">
                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 shrink-0">
                                    <h3 className="text-sm font-bold text-gray-800 mb-3">📊 스마트 기업 상세정보</h3>
                                    <InfoTab co={co} onRefresh={onRefresh} setToast={setToast} />
                                </div>
                                
                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-3 shrink-0">
                                    <p className="text-[10px] font-bold mb-1" style={{ color: C.heading }}>위험도</p>
                                    <div className="flex items-center gap-2">
                                        <div className="flex-1 h-3 rounded-full overflow-hidden" style={{ background: '#e5e7eb' }}>
                                            <div
                                                className="h-full rounded-full"
                                                style={{
                                                    width: `${co.riskScore}%`,
                                                    background: co.riskScore >= 70 ? '#dc2626' : co.riskScore >= 40 ? '#d97706' : '#059669'
                                                }}
                                            />
                                        </div>
                                        <span className="text-sm font-black" style={{ color: co.riskScore >= 70 ? '#dc2626' : co.riskScore >= 40 ? '#92400e' : '#065f46' }}>
                                            {co.riskScore}
                                        </span>
                                    </div>
                                </div>

                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 shrink-0">
                                    <h3 className="text-[10px] font-bold text-red-600 mb-2">🚨 발생 이슈</h3>
                                    {co.issues && co.issues.length > 0 ? (
                                        <div className="grid grid-cols-[56px_1fr] gap-x-2 gap-y-2 items-start mt-1">
                                            {co.issues.map((iss, j) => (
                                                <React.Fragment key={j}>
                                                    <div className="text-center pt-[1px]">
                                                        <span
                                                            className="inline-block text-[8px] px-1.5 py-0.5 rounded font-bold whitespace-nowrap w-full"
                                                            style={{
                                                                background: iss.level === 'HIGH' ? '#fef2f2' : '#fffbeb',
                                                                color: iss.level === 'HIGH' ? '#dc2626' : '#92400e',
                                                            }}
                                                        >
                                                            {iss.level}
                                                        </span>
                                                    </div>
                                                    <span className="text-[11px] leading-relaxed break-words" style={{ color: C.body }}>
                                                        {iss.title}
                                                    </span>
                                                </React.Fragment>
                                            ))}
                                        </div>
                                    ) : (
                                        <div className="text-xs text-gray-500">발견된 이슈가 없습니다.</div>
                                    )}
                                </div>
                            </div>

                            {/* Col 2: 스크립트 & 통화 제어 (원래 Col 3) */}
                            <div className="flex flex-col gap-4 h-full min-w-0">

                                {/* 통화 제어 내역 및 수동 기록 */}
                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col shrink-0 min-h-[150px]">
                                    <div className="flex flex-col gap-3 mb-3 border-b border-gray-100 pb-3">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-2">
                                                <h3 className="text-[11px] font-bold text-gray-800">🎙️ 통화 제어 ({companyRecordings.length})</h3>
                                                {user?.role === 'super_admin' && (
                                                    <button onClick={handleResetCallData}
                                                        className="px-1.5 py-0.5 rounded text-[10px] font-bold border bg-white text-gray-500 border-gray-200 hover:bg-gray-50 hover:text-gray-700 transition-colors"
                                                        title="통화 상태 초기화"
                                                    >
                                                        <RefreshCw className="w-2.5 h-2.5 inline mr-0.5" />초기화
                                                    </button>
                                                )}
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {!isOnCall ? (
                                                    <button onClick={onStartCall}
                                                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black hover:scale-105 transition-transform"
                                                        style={{ background: '#ecfdf5', color: '#059669', border: '1px solid #a7f3d0' }}>
                                                        <Phone className="w-3 h-3" />통화 시작
                                                    </button>
                                                ) : <>
                                                    <button onClick={timer.running ? timer.pause : timer.resume}
                                                        className="p-1.5 rounded-lg"
                                                        style={{ background: '#f8f9fc', border: `1px solid ${C.borderLight}` }}>
                                                        {timer.running
                                                            ? <Pause className="w-3 h-3" style={{ color: C.sub }} />
                                                            : <Play className="w-3 h-3" style={{ color: '#059669' }} />}
                                                    </button>
                                                    <button onClick={onEndCall}
                                                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black animate-pulse"
                                                        style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fca5a5' }}>
                                                        <PhoneOff className="w-3 h-3" />녹음 종료
                                                    </button>
                                                </>}
                                            </div>
                                        </div>

                                        {/* 연락 기록(수동/자동 겸용) */}
                                        <div className="flex flex-col bg-slate-50 p-2 rounded-lg border border-slate-100 gap-2">
                                            <div className="flex items-center gap-2">
                                                <span className="text-[10px] font-bold text-slate-500">담당자:</span>
                                                <input 
                                                    value={manualCaller} 
                                                    onChange={e => setManualCaller(e.target.value)}
                                                    className="text-[10px] border border-slate-200 rounded px-1.5 py-0.5 w-[80px] bg-white text-slate-700 outline-none focus:border-indigo-400"
                                                />
                                            </div>
                                            
                                            {/* 5버튼 레이아웃 */}
                                            <div className="flex flex-col gap-1.5 mt-1">
                                                <div className="flex gap-1.5">
                                                    <button 
                                                        onClick={() => handleResultAction('connected', 'review')}
                                                        className={`flex-1 px-1 py-1 rounded text-[10px] font-bold transition-all border
                                                            ${(isOnCall ? callResult : (localResult || co.lastCallResult)) === 'connected' ? 'bg-indigo-600 text-white border-indigo-700 shadow-sm' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50'}`}
                                                    >
                                                        ✅ 연결-메일
                                                    </button>
                                                    <button 
                                                        onClick={() => handleResultAction('callback', 'alarm')}
                                                        className={`flex-1 px-1 py-1 rounded text-[10px] font-bold transition-all border
                                                            ${(isOnCall ? callResult : (localResult || co.lastCallResult)) === 'callback' ? 'bg-amber-600 text-white border-amber-700 shadow-sm' : 'bg-white text-amber-600 border-amber-200 hover:bg-amber-50'}`}
                                                    >
                                                        🔄 연결-콜백
                                                    </button>
                                                    <button 
                                                        onClick={() => handleResultAction('rejected')}
                                                        className={`flex-1 px-1 py-1 rounded text-[10px] font-bold transition-all border
                                                            ${(isOnCall ? callResult : (localResult || co.lastCallResult)) === 'rejected' ? 'bg-slate-700 text-white border-slate-800 shadow-sm' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'}`}
                                                    >
                                                        ❌ 연결-거절
                                                    </button>
                                                </div>
                                                <div className="flex gap-1.5">
                                                    <button 
                                                        onClick={() => handleResultAction('no_answer', 'alarm')}
                                                        className={`flex-1 px-1 py-1 rounded text-[10px] font-bold transition-all border
                                                            ${(isOnCall ? callResult : (localResult || co.lastCallResult)) === 'no_answer' ? 'bg-rose-600 text-white border-rose-700 shadow-sm' : 'bg-white text-rose-600 border-rose-200 hover:bg-rose-50'}`}
                                                    >
                                                        📵 부재(24h)
                                                    </button>
                                                    <button 
                                                        onClick={() => handleResultAction('invalid_site', 'pass')}
                                                        className={`flex-1 px-1 py-1 rounded text-[10px] font-bold transition-all border
                                                            ${(isOnCall ? callResult : (localResult || co.lastCallResult)) === 'invalid_site' ? 'bg-gray-400 text-white border-gray-500 shadow-sm' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-100'}`}
                                                    >
                                                        ⚠️ 사이트이상(패스)
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col flex-1">
                                    <h3 className="text-sm font-bold text-gray-800 mb-3">📞 통화 스크립트</h3>
                                    <ScriptTab co={co} setToast={setToast} />
                                </div>
                            </div>

                            {/* Col 3: 메모 & AI 분석 (원래 Col 2) */}
                            <div className="flex flex-col gap-4 h-full min-w-0">
                                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col flex-1">
                                    <h3 className="text-sm font-bold text-gray-800 mb-3">📝 메모&요약</h3>
                                    <MemoTab co={co} onRefresh={onRefresh} setToast={setToast} />
                                </div>
                            </div>


                                                        </div>
                        </div>
                    </div>
            </td>
        </motion.tr>
    );
}

'use client';

import { AnimatePresence, motion } from 'framer-motion';
import { MessageCircle, X, Check, Send, RefreshCw } from 'lucide-react';
import { C } from '@/lib/callPageUtils';
import { Company } from '@/lib/types';

export interface KakaoModalProps {
  kakaoTarget: Company | null;
  kakaoTemplate: number;
  setKakaoTemplate: (i: number) => void;
  kakaoSending: boolean;
  setKakaoSending: (v: boolean) => void;
  setKakaoTarget: (v: Company | null) => void;
  setToast: (s: string) => void;
}

const getTemplates = (co: Company) => [
  {
    title: '📊 분석 보고서 안내',
    desc: '개인정보 진단 보고서 발송 알림',
    msg: `[IBS 법률사무소]\n\n${co.contactName || '담당자'}님, 안녕하세요.\n${co.name}의 개인정보처리방침 진단 보고서가 준비되었습니다.\n\n▶ 보고서 확인하기\nhttps://ibs-law.co.kr/report/${co.id}\n\n문의: 02-1234-5678`,
  },
  {
    title: '📞 통화 팔로업',
    desc: '통화 후 추가 자료 안내',
    msg: `[IBS 법률사무소]\n\n${co.contactName || '담당자'}님, 오늘 통화 감사드립니다.\n말씀드린 ${co.name} 관련 상세 검토 의견서를 첨부드립니다.\n\n▶ 검토 의견서 확인\nhttps://ibs-law.co.kr/opinion/${co.id}\n\n추가 문의사항이 있으시면 편하게 연락주세요.`,
  },
  {
    title: '🔔 리마인드 안내',
    desc: '계약/회신 리마인드',
    msg: `[IBS 법률사무소]\n\n${co.contactName || '담당자'}님, 안녕하세요.\n${co.name} 건 관련 회신 부탁드립니다.\n\n미조치 시 법적 리스크가 발생할 수 있어 사전 대응을 권고드리며,\n편하신 시간에 연락 주시면 상세 안내 도와드리겠습니다.\n\n📞 02-1234-5678`,
  },
];

export default function KakaoModal({
  kakaoTarget,
  kakaoTemplate,
  setKakaoTemplate,
  kakaoSending,
  setKakaoSending,
  setKakaoTarget,
  setToast,
}: KakaoModalProps) {
  return (
    <AnimatePresence>
      {kakaoTarget && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center"
          style={{ background: 'rgba(0,0,0,0.3)', backdropFilter: 'blur(4px)' }}
          onClick={() => setKakaoTarget(null)}
        >
          <motion.div
            initial={{ scale: 0.9, y: 20 }}
            animate={{ scale: 1, y: 0 }}
            exit={{ scale: 0.9, y: 20 }}
            className="rounded-2xl p-6 w-[480px] shadow-xl"
            style={{ background: C.surface, border: `1px solid ${C.border}` }}
            onClick={(e) => e.stopPropagation()}
          >
            {/* Header */}
            <div className="flex items-center gap-3 mb-4">
              <div
                className="w-10 h-10 rounded-xl flex items-center justify-center"
                style={{ background: '#FAE100' }}
              >
                <MessageCircle className="w-5 h-5" style={{ color: '#3C1E1E' }} />
              </div>
              <div>
                <h3 className="text-base font-black" style={{ color: C.heading }}>
                  카카오 알림톡 발송
                </h3>
                <p className="text-[11px]" style={{ color: C.sub }}>
                  {kakaoTarget.name} · {kakaoTarget.contactName || '담당자'} ·{' '}
                  {kakaoTarget.contactPhone || kakaoTarget.phone}
                </p>
              </div>
              <button
                onClick={() => setKakaoTarget(null)}
                className="ml-auto p-1 rounded-lg hover:bg-gray-100"
              >
                <X className="w-4 h-4" style={{ color: C.muted }} />
              </button>
            </div>

            {/* Template selection */}
            <p className="text-[11px] font-bold mb-2" style={{ color: C.muted }}>
              템플릿 선택
            </p>
            <div className="flex flex-col gap-2 mb-4">
              {getTemplates(kakaoTarget).map((t, i) => (
                <button
                  key={i}
                  onClick={() => setKakaoTemplate(i)}
                  className="text-left p-3 rounded-xl transition-all"
                  style={{
                    background: kakaoTemplate === i ? '#FFFDE7' : '#f8fafc',
                    border: `1.5px solid ${kakaoTemplate === i ? '#FAE100' : C.borderLight}`,
                  }}
                >
                  <div className="flex items-center gap-2">
                    <span
                      className="text-xs font-bold"
                      style={{ color: kakaoTemplate === i ? '#5D4037' : C.heading }}
                    >
                      {t.title}
                    </span>
                    {kakaoTemplate === i && (
                      <Check className="w-3.5 h-3.5" style={{ color: '#F9A825' }} />
                    )}
                  </div>
                  <p className="text-[10px] mt-0.5" style={{ color: C.sub }}>
                    {t.desc}
                  </p>
                </button>
              ))}
            </div>

            {/* Preview */}
            <div className="p-3 rounded-xl mb-4" style={{ background: '#FFFDE7', border: '1px solid #FFF9C4' }}>
              <p className="text-[10px] font-bold mb-1" style={{ color: '#5D4037' }}>
                미리보기
              </p>
              <pre
                className="text-[10px] whitespace-pre-wrap leading-relaxed"
                style={{ color: '#4E342E', fontFamily: 'inherit' }}
              >
                {getTemplates(kakaoTarget)[kakaoTemplate].msg}
              </pre>
            </div>

            {/* Actions */}
            <div className="flex gap-2">
              <button
                onClick={() => setKakaoTarget(null)}
                className="flex-1 py-2.5 rounded-xl text-xs font-bold"
                style={{ background: '#f8f9fc', color: C.sub, border: `1px solid ${C.border}` }}
              >
                취소
              </button>
              <button
                disabled={kakaoSending}
                onClick={async () => {
                  setKakaoSending(true);
                  await new Promise((r) => setTimeout(r, 1200));
                  setKakaoSending(false);
                  setKakaoTarget(null);
                  setToast(`💬 카카오 알림톡 발송 완료 → ${kakaoTarget.name}`);
                }}
                className="flex-1 py-2.5 rounded-xl text-xs font-black flex items-center justify-center gap-1.5 transition-transform hover:scale-[1.02]"
                style={{
                  background: kakaoSending ? '#FFF9C4' : '#FAE100',
                  color: '#3C1E1E',
                  border: '1px solid #F9A825',
                }}
              >
                {kakaoSending ? (
                  <>
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                    발송 중...
                  </>
                ) : (
                  <>
                    <Send className="w-3.5 h-3.5" />
                    알림톡 발송
                  </>
                )}
              </button>
            </div>

            <p className="text-center text-[9px] mt-3" style={{ color: C.faint }}>
              알리고 API 연동 · 건당 6.5원 · 카톡 미수신 시 SMS 자동 대체발송
            </p>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

'use client';
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Send, RefreshCw, BrainCircuit, Sparkles, Zap, Clock, Trash2, Download } from 'lucide-react';
import { Company, CompanyMemo } from '@/lib/types';
import { AIMemoService, type AIMemoResult } from '@/lib/salesAutomation';
import { useAuth } from '@/lib/AuthContext';

/* ── CRM 라이트 색상 ─────── */
const C = {
    surface: '#ffffff',
    borderLight: '#e5e7eb',
    heading: '#0f172a',
    body: '#1e293b',
    sub: '#475569',
    faint: '#94a3b8',
};

/* ── 날짜 포맷 유틸 ─────── */
function formatDateTime(iso: string): string {
    const d = new Date(iso);
    const pad = (n: number) => n.toString().padStart(2, '0');
    return `${d.getFullYear()}.${pad(d.getMonth() + 1)}.${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

/* ── Props ───────────────── */
export interface MemoTabProps {
    co: Company;
    onRefresh: () => void;
    setToast: (s: string) => void;
}

/* ── Component ───────────── */
export default function MemoTab({ co, onRefresh, setToast }: MemoTabProps) {
    const { user } = useAuth();
    const authorName = user?.name || '알 수 없음';
    const [note, setNote] = useState('');
    const [memos, setMemos] = useState<CompanyMemo[]>([]);
    const [aiResult, setAiResult] = useState<AIMemoResult | null>(null);
    const [aiLoading, setAiLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [resummarizingId, setResummarizingId] = useState<string | null>(null);

    // 메모 목록 로드
    const loadMemos = useCallback(async () => {
        try {
            const res = await fetch(`/api/memos?companyId=${co.id}`);
            if (res.ok) {
                const data = await res.json();
                setMemos(data.memos || []);
            }
        } catch (e) {
            console.error('Failed to load memos:', e);
        }
    }, [co.id]);

    // Reset when the target company changes
    useEffect(() => {
        setNote('');
        setAiResult(null);
        prevMemosLength.current = -1;
        loadMemos();
    }, [co.id, loadMemos]);

    const prevMemosLength = useRef(-1);

    // 자동 AI 분석: 메모 목록이 로드되거나 변경될 때마다 전체 히스토리를 기반으로 AI 요약 수행
    useEffect(() => {
        if (memos.length > 0 && memos.length !== prevMemosLength.current) {
            prevMemosLength.current = memos.length;

            const runAutoAI = async () => {
                setAiLoading(true);
                try {
                    const r = await AIMemoService.analyze(co, memos);
                    setAiResult(r);

                    const { supabaseCompanyStore } = await import('@/lib/supabaseStore');
                    await supabaseCompanyStore.update(co.id, {
                        aiMemoSummary: r.summary,
                        aiNextAction: r.nextAction,
                        aiNextActionType: r.nextActionType,
                    });
                } catch (e) {
                    console.error('Auto AI Analysis failed:', e);
                } finally {
                    setAiLoading(false);
                }
            };

            runAutoAI();
        }
    }, [memos, co]);

    const saveMemo = async () => {
        if (!note.trim() || saving) return;
        setSaving(true);
        try {
            const res = await fetch('/api/memos', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    companyId: co.id,
                    author: authorName,
                    content: note.trim(),
                }),
            });
            if (res.ok) {
                setNote('');
                setToast('💾 메모 저장 (내용 정리 중...)');
                await loadMemos();
                onRefresh();
            } else {
                const err = await res.json();
                setToast(`⚠️ 저장 실패: ${err.error}`);
            }
        } catch {
            setToast('⚠️ 저장 실패');
        } finally {
            setSaving(false);
        }
    };

    const deleteMemo = async (memoId: string) => {
        try {
            const res = await fetch(`/api/memos?id=${memoId}&companyId=${co.id}`, {
                method: 'DELETE',
            });
            if (res.ok) {
                setToast('🗑️ 메모 삭제');
                await loadMemos();
                onRefresh();
            }
        } catch {
            setToast('⚠️ 삭제 실패');
        }
    };

    const handleDownloadTxt = (memo: CompanyMemo) => {
        const scriptMatch = memo.content.split('[전문]');
        if (scriptMatch.length > 1) {
            const script = scriptMatch[1].replace(/^\n+/, ''); // 맨 앞 줄바꿈 제거
            const blob = new Blob([script], { type: 'text/plain' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `녹음내용_${formatDateTime(memo.createdAt).replace(/[^0-9]/g, '')}.txt`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
    };

    const handleReSummarize = async (memo: CompanyMemo) => {
        if (resummarizingId === memo.id) return;
        const parts = memo.content.split('[전문]');
        if (parts.length < 2) return;

        setResummarizingId(memo.id);
        const script = parts[1].trim();
        setToast('AI 요약을 다시 생성 중입니다...');

        try {
            const res = await fetch('/api/ai/resummarize-stt', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ memoId: memo.id, transcript: script, memoContent: memo.content })
            });

            const data = await res.json();
            if (data.success) {
                setToast('요약이 성공적으로 업데이트되었습니다.');
                await loadMemos();
                onRefresh();
            } else {
                setToast(`요약 업데이트 실패: ${data.error}`);
            }
        } catch (e) {
            setToast('요약 생성 중 서버 오류가 발생했습니다.');
        } finally {
            setResummarizingId(null);
        }
    };

    return (
        <div className="flex flex-col gap-4">
            {/* ── AI 분석 결과 패널 (1행) ── */}
            <div className="space-y-3">
                {aiLoading ? (
                    <div
                        className="rounded-xl p-6 text-center flex flex-col items-center justify-center"
                        style={{ background: '#faf5ff', border: '1px solid #e9d5ff' }}
                    >
                        <RefreshCw className="w-6 h-6 mx-auto mb-2 animate-spin" style={{ color: '#7c3aed' }} />
                        <p className="text-xs font-bold" style={{ color: '#7c3aed' }}>정리 중입니다...</p>
                    </div>
                ) : aiResult ? (
                    <div className="rounded-xl p-4" style={{ background: '#faf5ff', border: '1px solid #e9d5ff' }}>
                        <div className="flex items-center gap-2 mb-2">
                            <Sparkles className="w-4 h-4" style={{ color: '#7c3aed' }} />
                            <span
                                className="text-[9px] px-1.5 py-0.5 rounded-full border border-purple-200"
                                style={{ background: '#f3e8ff', color: '#7c3aed' }}
                            >
                                신뢰도 {aiResult.confidence}%
                            </span>
                        </div>
                        <p className="text-[11px] mb-2 leading-relaxed" style={{ color: C.body }}>
                            {aiResult.summary}
                        </p>
                        {aiResult.keyPoints && aiResult.keyPoints.length > 0 && (
                            <div className="mb-2">
                                {aiResult.keyPoints.map((p, i) => (
                                    <div key={i} className="text-[10px] py-0.5" style={{ color: C.sub }}>• {p}</div>
                                ))}
                            </div>
                        )}
                        <div
                            className="flex items-center gap-1.5 px-3 py-2 rounded-lg"
                            style={{ background: '#ecfdf5', border: '1px solid #a7f3d0' }}
                        >
                            <Zap className="w-3 h-3" style={{ color: '#059669' }} />
                            <span className="text-[10px] font-bold" style={{ color: '#059669' }}>
                                추천: {aiResult.nextAction}
                            </span>
                        </div>
                    </div>
                ) : memos.length === 0 ? (
                    <div
                        className="rounded-xl p-6 flex items-center justify-center text-center"
                        style={{ background: C.surface, border: `1px solid ${C.borderLight}`, minHeight: '96px' }}
                    >
                        <BrainCircuit className="w-8 h-8" style={{ color: C.faint }} />
                    </div>
                ) : co.aiMemoSummary ? (
                    <div
                        className="rounded-xl p-3"
                        style={{ background: '#f0fdf4', border: '1px solid #a7f3d0' }}
                    >
                        <p className="text-[10px] font-bold mb-1" style={{ color: '#059669' }}>📌 이전 정리 내용</p>
                        <p className="text-[10px]" style={{ color: C.body }}>{co.aiMemoSummary}</p>
                    </div>
                ) : (
                    <div
                        className="rounded-xl p-6 flex items-center justify-center text-center"
                        style={{ background: C.surface, border: `1px solid ${C.borderLight}`, minHeight: '96px' }}
                    >
                        <BrainCircuit className="w-8 h-8" style={{ color: C.faint }} />
                    </div>
                )}
            </div>

            {/* ── 메모 히스토리 (2행으로 변경됨) ── */}
            {memos.length > 0 && (
                <div className="flex flex-col gap-1.5">
                    <div className="flex items-center gap-1.5 mb-1">
                        <Clock className="w-3 h-3" style={{ color: C.sub }} />
                        <span className="text-[10px] font-bold" style={{ color: C.sub }}>
                            메모 이력 ({memos.length})
                        </span>
                    </div>
                    <div
                        className="flex flex-col gap-2 overflow-y-auto pr-1"
                        style={{ maxHeight: 250 }}
                    >
                        {memos.map((memo) => (
                            <div
                                key={memo.id}
                                className="group rounded-lg p-3 transition-colors hover:bg-slate-50"
                                style={{
                                    background: C.surface,
                                    border: `1px solid ${C.borderLight}`,
                                }}
                            >
                                <div className="flex items-center justify-between mb-1.5">
                                    <div className="flex items-center gap-2">
                                        <span className="text-[9px] font-bold px-1.5 py-0.5 rounded"
                                            style={{ background: '#eef2ff', color: '#4f46e5' }}>
                                            {memo.author}
                                        </span>
                                        <span className="text-[9px]" style={{ color: C.faint }}>
                                            {formatDateTime(memo.createdAt)}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-1">
                                        {memo.content.includes('[전문]') && (
                                            <>
                                                <button
                                                    onClick={() => handleDownloadTxt(memo)}
                                                    className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-slate-100 transition-all flex items-center text-[9px] text-slate-500 font-medium"
                                                    title="TXT 다운로드"
                                                >
                                                    <Download className="w-3 h-3 mr-0.5" /> TXT
                                                </button>
                                                <button
                                                    onClick={() => handleReSummarize(memo)}
                                                    disabled={resummarizingId === memo.id}
                                                    className={`opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-slate-100 transition-all flex items-center text-[9px] text-slate-500 font-medium ${resummarizingId === memo.id ? 'opacity-100 cursor-not-allowed text-purple-500' : ''}`}
                                                    title="다시 요약하기"
                                                >
                                                    <RefreshCw className={`w-3 h-3 mr-0.5 ${resummarizingId === memo.id ? 'animate-spin text-purple-500' : ''}`} /> 요약 재분석
                                                </button>
                                            </>
                                        )}
                                        {user?.role !== 'sales' && (
                                            <button
                                                onClick={() => deleteMemo(memo.id)}
                                                className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-red-50 transition-all"
                                                title="메모 삭제"
                                            >
                                                <Trash2 className="w-3 h-3" style={{ color: '#dc2626' }} />
                                            </button>
                                        )}
                                    </div>
                                </div>
                                <p className="text-[11px] leading-relaxed whitespace-pre-wrap break-words" style={{ color: C.body }}>
                                    {memo.content}
                                </p>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* ── 메모 입력 (3행으로 변경됨) ── */}
            <div className="flex flex-col gap-2">
                <textarea
                    value={note}
                    onChange={(e) => setNote(e.target.value)}
                    placeholder="새 메모를 입력하세요..."
                    className="flex-1 rounded-xl text-[12px] p-4 font-medium leading-relaxed"
                    style={{
                        background: C.surface,
                        border: `1px solid ${C.borderLight}`,
                        color: C.body,
                        outline: 'none',
                        resize: 'none',
                        minHeight: 100,
                    }}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
                            e.preventDefault();
                            saveMemo();
                        }
                    }}
                />
                <div className="flex gap-2">
                    <button
                        onClick={saveMemo}
                        disabled={!note.trim() || saving}
                        className="flex-1 flex items-center justify-center gap-1.5 py-2.5 rounded-xl text-xs font-bold transition-opacity"
                        style={{
                            background: '#eef2ff', color: '#4f46e5', border: '1px solid #c7d2fe',
                            opacity: (note.trim() && !saving) ? 1 : 0.5,
                        }}
                    >
                        <Send className="w-3.5 h-3.5" />{saving ? '저장중...' : '메모 저장'}
                    </button>
                    {aiLoading && (
                        <div className="flex items-center justify-center px-4 rounded-xl text-xs font-bold" 
                            style={{ background: '#f3e8ff', color: '#7c3aed', border: '1px solid #d8b4fe' }}>
                            <RefreshCw className="w-3.5 h-3.5 animate-spin mr-1.5" /> 정리 중입니다...
                        </div>
                    )}
                </div>
                <p className="text-[9px] text-right mt-1" style={{ color: C.faint }}>
                    Ctrl+Enter로 자동 저장 및 요약 진행
                </p>
            </div>
        </div>
    );
}

'use client';
import React, { useState } from 'react';
import { Volume2, Sparkles, RefreshCw } from 'lucide-react';
import { Company, type CaseStatus } from '@/lib/types';
import { STATUS_COLOR, STATUS_TEXT, STATUS_LABEL } from '@/lib/constants';
import { useEmployeeCRM } from '@/hooks/useEmployeeCRM';
import { getPromptConfig } from '@/lib/prompts/privacy';

const C = {
    surface: '#ffffff',
    border: '#d1d5db',
    borderLight: '#e5e7eb',
    heading: '#0f172a',
    body: '#1e293b',
    sub: '#475569',
    faint: '#94a3b8',
    accent: '#4f46e5',
    amber: '#d97706',
};

/* ── helpers ─────────────────────────────────────────────── */
function getLegacyScript(c: Company): string {
    const hi = c.contactName ? `${c.contactName} 님` : '담당자님';
    const issues = (c.issues || []).slice(0, 3);
    const it = issues.length > 0
        ? issues.map((i, x) => `  ${x + 1}. [${i.level}] ${i.title}`).join('\n')
        : '  (분석 결과 대기 중)';
    if (['analyzed'].includes(c.status))
        return `안녕하세요, ${hi}.\n법률사무소 IBS 영업팀입니다.\n\n${c.name}의 개인정보처리방침을 검토한 결과,\n아래와 같은 법적 리스크가 확인되었습니다:\n\n${it}\n\n사전 대응을 권고드립니다.`;
    if (['lawyer_confirmed', 'emailed'].includes(c.status))
        return `${hi}, 법률사무소 IBS입니다.\n앞서 발송드린 ${c.name} 개인정보 진단 보고서는 확인하셨을까요?\n\n주요 리스크:\n${it}\n\n전담 변호사의 상세 검토 의견이 준비되어 있습니다.`;
    if (['client_replied', 'client_viewed'].includes(c.status))
        return `${hi}, 법률사무소 IBS입니다.\n보고서를 검토해 주셔서 감사합니다.\n\n계약 진행을 위한 서류가 준비되어 있습니다.`;
    return `${hi}, 법률사무소 IBS 영업팀입니다.\n${c.name} 건 관련 안내드리고자 연락드렸습니다.`;
}

export interface ScriptTabProps {
    co: Company;
    setToast: (s: string) => void;
}

export default function ScriptTab({ co, setToast }: ScriptTabProps) {
    const [copied, setCopied] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const { updateCompany } = useEmployeeCRM();

    // Use AI custom script if available, fallback to legacy script
    const script = co.customScript?.call || getLegacyScript(co);

    const copyScript = () => {
        navigator.clipboard.writeText(script).then(() => {
            setCopied(true);
            setToast('📋 복사됨');
            setTimeout(() => setCopied(false), 2000);
        });
    };

    const handleGenerateAiScript = async () => {
        setIsGenerating(true);
        setToast('브랜드 맞춤형 스크립트 자동 생성 중...');
        try {
            const promptConfig = getPromptConfig();
            const systemPrompt = promptConfig.salesScriptPrompt;
            const model = promptConfig.promptModels?.salesScriptPrompt || promptConfig.model || 'gpt-4o';
            
            let apiKey = '';
            try {
                if (typeof window !== 'undefined') {
                    apiKey = localStorage.getItem(`ibs_ai_key_${model}`) || '';
                }
            } catch (e) {
                console.error('Failed to get API key from localStorage', e);
            }

            const res = await fetch('/api/sales/generate-script', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    companyId: co.id,
                    brandName: co.name,
                    issues: co.issues,
                    systemPrompt,
                    model,
                    apiKey
                })
            });
            const data = await res.json();
            if (data.success && data.script) {
                updateCompany(co.id, {
                    customScript: {
                        ...co.customScript,
                        call: data.script,
                        lastEditedAt: new Date().toISOString()
                    }
                });
                setToast('✨ 맞춤형 스크립트 생성 및 저장 완료');
            } else {
                setToast('❌ 스크립트 생성 실패: ' + (data.error || '알 수 없는 오류'));
            }
        } catch (error) {
            console.error('맞춤 스크립트 생성 오류:', error);
            setToast('❌ 스크립트 생성 중 단절 발생');
        } finally {
            setIsGenerating(false);
        }
    };

    const isCustom = !!co.customScript?.call;

    return (
        <div className="rounded-xl p-4 flex flex-col w-full h-full" style={{ background: C.surface, border: `1px solid ${C.borderLight}` }}>
            <div className="flex items-center justify-between mb-3 border-b pb-2" style={{ borderColor: C.borderLight }}>
                <div className="flex items-center gap-2">
                    <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: isCustom ? '#e0e7ff' : '#f1f5f9', color: isCustom ? '#4338ca' : C.sub }}>
                        {isCustom ? '✨ 브랜드 맞춤형 스크립트 (v2.0)' : '기본 템플릿'}
                    </span>
                    {co.customScript?.lastEditedAt && (
                        <span className="text-[10px]" style={{ color: C.faint }}>
                            업데이트: {new Date(co.customScript.lastEditedAt).toLocaleString()}
                        </span>
                    )}
                </div>
                <div className="flex items-center gap-2">
                    <button
                        onClick={handleGenerateAiScript}
                        disabled={isGenerating}
                        className="flex items-center gap-1 text-[10px] px-3 py-1 rounded-lg font-bold transition-colors"
                        style={{
                            background: isGenerating ? '#f1f5f9' : '#eef2ff',
                            color: isGenerating ? C.faint : '#4f46e5',
                            border: `1px solid ${isGenerating ? C.borderLight : '#c7d2fe'}`,
                        }}
                    >
                        {isGenerating ? <RefreshCw className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                        {isGenerating ? '생성 중...' : '스크립트 재작성'}
                    </button>
                    <button
                        onClick={copyScript}
                        className="text-[10px] px-3 py-1 rounded-lg font-bold transition-colors"
                        style={{
                            background: copied ? '#ecfdf5' : '#f1f5f9',
                            color: copied ? '#059669' : C.sub,
                            border: `1px solid ${copied ? '#a7f3d0' : C.borderLight}`,
                        }}
                    >
                        {copied ? '✅ 복사됨' : '📋 복사'}
                    </button>
                </div>
            </div>

            <div className="text-[13px] leading-[1.8] whitespace-pre-wrap flex-1 overflow-y-auto" style={{ color: C.heading }}>
                {script}
            </div>
        </div>
    );
}

