/* ══════════════════════════════════════════════════════════════
   3. 녹음 데이터 저장소 (localStorage + Supabase Write-Through)
   ══════════════════════════════════════════════════════════════ */

const RECORDINGS_KEY = 'ibs_call_recordings';

export const CallRecordingStore = {
    getAll(): CallRecording[] {
        if (typeof window === 'undefined') return [];
        try {
            return JSON.parse(localStorage.getItem(RECORDINGS_KEY) || '[]');
        } catch {
            return [];
        }
    },

    _save(recordings: CallRecording[]): void {
        localStorage.setItem(RECORDINGS_KEY, JSON.stringify(recordings));
        // 실시간 동기화 이벤트 발행 (다른 탭/기기)
        this._dispatchSync();
    },

    /** 동기화 이벤트 발행 */
    _dispatchSync(): void {
        if (typeof window === 'undefined') return;
        // BroadcastChannel (같은 브라우저 다른 탭)
        try {
            const bc = new BroadcastChannel('ibs-recordings');
            bc.postMessage({ type: 'voice-memo-sync', timestamp: Date.now() });
            bc.close();
        } catch { /* BroadcastChannel 미지원 환경 무시 */ }
        // 커스텀 이벤트 (같은 탭)
        window.dispatchEvent(new CustomEvent('voice-memo-sync'));
    },

    /** 새 녹음 저장 */
    save(recording: Omit<CallRecording, 'id' | 'createdAt' | 'updatedAt'>): CallRecording {
        const all = this.getAll();
        const now = new Date().toISOString();
        const entry: CallRecording = {
            ...recording,
            id: `rec-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
            createdAt: now,
            updatedAt: now,
        };
        all.unshift(entry);
        this._save(all);

        // 타임라인에도 기록
        this.addToTimeline(entry);

        // --- STT가 즉시 완료상태(수동 기록 등)라면 바로 메모이력(DB)에 추가 ---
        if (entry.sttStatus === 'completed' && typeof window !== 'undefined') {
            this._syncToMemo(entry);
        }

        return entry;
    },

    /** STT 결과 업데이트 */
    updateTranscript(
        recordingId: string,
        transcript: string,
        summary: string,
        status: CallRecording['sttStatus'] = 'completed',
        audioUrl?: string
    ): void {
        const all = this.getAll();
        const rec = all.find((r) => r.id === recordingId);
        if (rec) {
            rec.transcript = transcript;
            rec.transcriptSummary = summary;
            rec.sttStatus = status;
            if (audioUrl) rec.recordingUrl = audioUrl;
            rec.updatedAt = new Date().toISOString();
            this._save(all);

            // --- STT가 완료되면 메모이력(DB)에 추가 ---
            if (status === 'completed' && typeof window !== 'undefined') {
                this._syncToMemo(rec);
            }
        }
    },

    /** 통화 이력을 메모이력 기반으로도 저장 */
    _syncToMemo(entry: CallRecording): void {
        let contentStr = '';
        const mapRes = {
            'connected': '연결됨',
            'no_answer': '부재중',
            'callback': '콜백요청',
            'rejected': '거절',
            'invalid_site': '사이트이상'
        };
        const koRes = mapRes[entry.callResult] || entry.callResult;

        if (entry.transcriptSummary === '수동 통화 기록') {
            contentStr = `📞 [수동 통화 기록] 상태 변경: ${koRes}`;
        } else {
            contentStr = `📞 [통화 결과] ${koRes}\n\n[통화내용 요약]\n${entry.transcriptSummary || '내용 없음'}\n\n[전문]\n${entry.transcript || '내용 없음'}`;
        }

        fetch('/api/memos', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                companyId: entry.companyId,
                content: contentStr,
                authorName: entry.salesUserName || '시스템',
                isPinned: false
            })
        }).catch(e => console.error('Failed to sync call record to memos:', e));
    },

    /** 기업별 녹음 내역 조회 */
    getByCompany(companyId: string): CallRecording[] {
        return this.getAll().filter((r) => r.companyId === companyId);
    },

    /** 최근 녹음 (전체) */
    getRecent(limit = 10): CallRecording[] {
        return this.getAll().slice(0, limit);
    },

    /** 기업별 녹음 횟수 */
    getCount(companyId: string): number {
        return this.getByCompany(companyId).length;
    },

    /** 타임라인에 녹음 이벤트 추가 */
    addToTimeline(recording: CallRecording): void {
        const company = store.getById(recording.companyId);
        if (!company) return;

        const timelineEvent = {
            id: `tl-${Date.now()}`,
            createdAt: recording.createdAt,
            author: recording.salesUserName || '영업팀',
            type: 'call' as const,
            content: recording.sttStatus === 'completed'
                ? `📞 통화 녹음 (${formatDuration(recording.durationSeconds)}) — ${recording.transcriptSummary || 'STT 변환 완료'}`
                : `📞 통화 녹음 (${formatDuration(recording.durationSeconds)}) — STT 변환 중...`,
        };

        const updatedTimeline = [timelineEvent, ...(company.timeline || [])];
        store.update(recording.companyId, { timeline: updatedTimeline });
    },

    /** CRM callNote에도 자동 반영을 위한 텍스트 생성 */
    generateCallNoteText(recordingId: string, currentNote: string = ''): string | null {
        const rec = this.getAll().find((r) => r.id === recordingId);
        if (!rec || !rec.transcript) return null;

        const dateStr = new Date(rec.createdAt).toLocaleString('ko-KR', {
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit',
        });

        const newNote = [
            currentNote,
            '',
            `──── 🎙️ 자동 녹취 (${dateStr}, ${formatDuration(rec.durationSeconds)}) ────`,
            rec.transcript,
            '',
            rec.transcriptSummary
                ? `📌 통화내용 요약: \n${rec.transcriptSummary}`
                : '',
        ]
            .filter((line) => line !== undefined && line !== null)
            .join('\n')
            .trim();

        return newNote;
    },
};

/* ── 유틸 ───────────────────────────────────────────────── */

export function formatDuration(seconds: number): string {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}분 ${s}초`;
}

/* ══════════════════════════════════════════════════════════════
   4. 오디오 시각화 (파형 애니메이션)
   ══════════════════════════════════════════════════════════════ */

export class AudioVisualizer {
    private analyser: AnalyserNode | null = null;
    private dataArray: Uint8Array<ArrayBuffer> | null = null;
    private audioContext: AudioContext | null = null;

    connect(stream: MediaStream): void {
        this.audioContext = new AudioContext();
        const source = this.audioContext.createMediaStreamSource(stream);
        this.analyser = this.audioContext.createAnalyser();
        this.analyser.fftSize = 64;
        source.connect(this.analyser);
        this.dataArray = new Uint8Array(this.analyser.frequencyBinCount) as Uint8Array<ArrayBuffer>;
    }

    /** 현재 주파수 데이터 반환 (0~255 범위, 바 개수 = fftSize/2) */
    getFrequencyData(): number[] {
        if (!this.analyser || !this.dataArray) return new Array(16).fill(0);
        this.analyser.getByteFrequencyData(this.dataArray);
        return Array.from(this.dataArray).slice(0, 16);
    }

    disconnect(): void {
        if (this.audioContext) {
            this.audioContext.close();
            this.audioContext = null;
        }
        this.analyser = null;
        this.dataArray = null;
    }
}

/**
 * HWPX 주입 엔진 (PoC)
 * 
 * HWPX 파일 = ZIP 아카이브. 내부 Contents/section0.xml을 파싱하여
 * 플레이스홀더를 치환한 뒤 재압축하여 새로운 HWPX 파일을 생성합니다.
 * 
 * 핵심 흐름:
 * 1. 샘플 HWPX(ZIP) 를 메모리에서 해제
 * 2. Contents/section0.xml 읽기
 * 3. {{PLACEHOLDER}} → 실제 콘텐츠 치환
 * 4. 마크다운 → HWPX XML 단락 변환
 * 5. 재압축 → Buffer 반환
 */

import AdmZip from 'adm-zip';
import { markdownToHwpxParagraphs } from './markdown-to-hwpx';
import { PlaceholderMap, PLACEHOLDER_KEYS } from './placeholder-map';

/** HWPX 내부 파일 경로 상수 */
const SECTION_XML_PATH = 'Contents/section0.xml';
const CONTENT_TYPES_PATH = '[Content_Types].xml';
const META_PATH = 'META-INF/manifest.xml';
const HEADER_PATH = 'Contents/header.xml';

/**
 * 최소 HWPX 구조를 메모리에서 생성합니다.
 * 실제 HWPX 파일이 없을 때 기본 템플릿으로 사용합니다.
 */
export function createMinimalHwpxTemplate(placeholderContent = '{{OPINION_CONTENT}}'): Buffer {
  const zip = new AdmZip();

  // [Content_Types].xml
  const contentTypes = `<?xml version="1.0" encoding="UTF-8"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="xml" ContentType="application/xml"/>
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Override PartName="/Contents/section0.xml" ContentType="application/xml"/>
  <Override PartName="/Contents/header.xml" ContentType="application/xml"/>
  <Override PartName="/META-INF/manifest.xml" ContentType="application/xml"/>
</Types>`;
  zip.addFile(CONTENT_TYPES_PATH, Buffer.from(contentTypes, 'utf-8'));

  // META-INF/manifest.xml
  const manifest = `<?xml version="1.0" encoding="UTF-8"?>
